  delete from public.question_bank
  where md5(regexp_replace(trim(question), '\s+', ' ', 'g'))
    in (select h from target_hashes);

  get diagnostics v_deleted = row_count;
  raise notice '[0095] preguntas borradas: %', v_deleted;

  -- 2) INSERT las 3985 con content_hash correcto.
  -- Batch 1-200
  insert into public.question_bank (content_hash, question, options, correct_index, lang)
  values
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Constitución Española de 1978 indica que:', '["Los poderes residen en el pueblo, del que emana la soberanía nacional.", "Son valores superiores del ordenamiento jurídico la libertad, la igualdad y la fraternidad.", "La soberanía nacional reside en el Rey.", "Las respuestas a y b son incorrectas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En relación con la Constitución Española de 1978, deberá indicar la respuesta incorrecta:', '["Fue aprobada por las Cortes Generales.", "La respuesta a es correcta y se podría añadir que la fecha de esa aprobación parlamentaria fue el 31 de octubre de 1978.", "Se ratificó mediante referéndum el día 6 de diciembre de 1978.", "Entró en vigor al día siguiente de su publicación en el Boletín Oficial del Estado."]'::jsonb, 3, 'es'),
    ('2a6468bc4f93d82dcd681e03abfdd7d4', 'El Título I de la Constitución Española:', '["Se denomina De los derechos y deberes públicos.", "Se inicia en el artículo 11.", "Las respuestas a y b son correctas.", "Las respuestas a y b son incorrectas."]'::jsonb, 3, 'es'),
    ('042c55dcf70f38c4dffc4220b47071c9', 'El Capítulo I del Título I de la Constitución Española:', '["Se denomina De los españoles y sus derechos.", "Se inicia en el artículo 10.", "Las respuestas a y b son correctas.", "Las respuestas a y b son incorrectas."]'::jsonb, 3, 'es'),
    ('2b6edcfa0c4ac251d50667a54353381c', 'El Capítulo II del Título I de la Constitución Española:', '["Se denomina derechos y libertades.", "Se inicia en el artículo 14 y se extiende hasta el artículo 43.", "Las respuestas a y b son correctas.", "Las respuestas a y b son incorrectas."]'::jsonb, 0, 'es'),
    ('0a6b752e6f9f3cebb51c216efd5f389a', 'El Capítulo III del Título I de la Constitución de 1978 se denomina:', '["De los principios básicos económico-sociales.", "De la política social y económica.", "De los principios rectores socio-económicos.", "Ninguna respuesta es correcta."]'::jsonb, 3, 'es'),
    ('82702d5b5e27bb7e4a0f90ce13a4d44d', 'El reconocimiento constitucional al derecho a la protección de la salud se realiza en un artículo de la Carta Magna. Deberá decir en cuál.', '["Artículo 43.", "Artículo 44.", "Artículo 45.", "Artículo 46."]'::jsonb, 0, 'es'),
    ('183e5b4b31d7d16991eeafb86513c71f', 'Complete utilizando uno de las siguientes opciones el contenido constitucional del artículo 41. “Los poderes públicos mantendrán un régimen público de ................... ............... para todos los ciudadanos que garantice la asistencia y las prestaciones suficientes ante situaciones de necesidad, especialmente en casos de desempleo.”', '["Asistencia social.", "Asistencia sanitaria.", "Prestaciones sociales.", "Seguridad Social."]'::jsonb, 3, 'es'),
    ('183e5b4b31d7d16991eeafb86513c71f', 'Deberá señalar con qué artículo constitucional se corresponde el siguiente literal: “Los poderes públicos fomentarán la educación sanitaria, la educación física y el deporte. Asimismo facilitarán la adecuada utilización del ocio.”', '["Artículo 41.", "Artículo 42", "Artículo 43.2.", "Artículo 43.3."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Ley para la Reforma Política fue aprobada en referéndum:', '["El 15 de diciembre de 1976", "El 4 de enero de 1977", "El 7 de enero de 1976", "El 1 de diciembre de 1977."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién ratificó la Constitución española de 1978?:', '["El pueblo español", "Las Cortes Generales", "El Rey", "El Gobierno."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Constitución no ha sido influida en su redacción por:', '["La Constitución francesa de 1958", "La Constitución portuguesa de 1976", "La Constitución francesa de 1971", "La Ley fundamental de Bonn de 1949."]'::jsonb, 2, 'es'),
    ('5eb8d8e7d908348fab0a0aa8ab34f87f', 'El último artículo del Título II de la Constitución española de 1978 es:', '["El artículo 65", "El artículo 66", "El artículo 64", "El artículo 67."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El principio de legalidad se recoge en el artículo:', '["1.1", "1.3", "9.1", "9.2."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es la última disposición de la Constitución española de 1978?:', '["La disposición final", "La disposición derogatoria", "La disposición adicional cuarta", "La disposición transitoria novena."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Tribunal de Garantías Constitucional, antecedente directo del actual Tribunal Constitucional, fue creado por:', '["La Constitución de 1931", "La Constitución de 1978", "La Constitución de 1876", "El Estatuto Real de 1812."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En qué fecha fue proclamado Rey D. Juan Carlos I?', '["20 de noviembre de 1975.", "21 de noviembre de 1974.", "23 de noviembre de 1976.", "22 de noviembre de 1975."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Ante qué órgano fue proclamado Rey D. Juan Carlos I?', '["Ante el Congreso de los Diputados.", "Ante el Gobierno.", "Ante las Cortes Generales.", "Ante el Consejo del Reino."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En qué fecha fue promulgada la Ley para la Reforma Política?', '["El 15 de diciembre de 1977.", "El 4 de enero de 1977.", "El 12 de enero de 1976.", "El 15 de diciembre de 1976."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de las siguientes Constituciones extranjeras no se considera una influencia de la Constitución de 1978?', '["La Constitución francesa de 1958.", "La Constitución portuguesa de 1976.", "La Constitución italiana de 1974.", "La Ley fundamental de Bonn de 1949."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de las siguientes características no es predicable de la Constitución española de 1978?', '["Es una Constitución consensuada.", "Es una Constitución rígida.", "Es una Constitución extensa.", "Todas las otras características se consideran características de la Constitución española de 1978."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En qué fecha fue publicada la Constitución española en el Boletín Oficial del Estado?', '["El 6 de diciembre de 1978.", "El 27 de diciembre de 1978.", "El 29 de diciembre de 1978.", "Ninguna de las otras respuestas es correcta."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En qué fecha fue promulgada la Constitución española de 1978?', '["El 31 de octubre de 1978.", "El 6 de diciembre de 1978.", "El 27 de diciembre de 1978.", "El 29 de diciembre de 1978."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En qué fecha se creó la Comisión Constitucional que nombró a la ponencia encargada de redactar la Constitución española de 1978?', '["El 20 de julio de 1978.", "El 5 de enero de 1978.", "El 20 de julio de 1977.", "El 25 de julio de 1977."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Ante quién sancionó el Rey la Constitución española de 1978?', '["Ante el Congreso de los Diputados.", "Ante las Cortes Generales.", "Ante el Senado y el Gobierno.", "Ante el Gobierno y el Congreso de los Diputados."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién aprobó la Constitución española de 1978?', '["El Rey.", "El pueblo español.", "Las Cortes Generales.", "El Congreso de los Diputados."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién ratificó la Constitución española de 1978?', '["El pueblo español.", "Las Cortes Generales.", "El Rey.", "Ninguna de las otras respuestas es correcta."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En qué fecha fue sancionada la Constitución española de 1978?', '["El 6 de diciembre de 1978.", "El 31 de octubre de 1978.", "El 27 de diciembre de 1978.", "El 29 de diciembre de 1978."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué día entró en vigor la Constitución española de 1978?', '["El 1 de enero de 1979.", "El 29 de diciembre de 1978.", "El 28 de diciembre de 1978.", "El 27 de diciembre de 1978."]'::jsonb, 1, 'es'),
    ('e7635585740de7b10b819c221029a513', 'De las siguientes partes, ¿cuál abre el texto de la Constitución española de 1978?', '["El Título Preliminar.", "El Título I.", "El Preámbulo.", "Ninguna de las otras respuestas es correcta."]'::jsonb, 2, 'es'),
    ('e7635585740de7b10b819c221029a513', '¿Qué parte de la Constitución española de 1978 no tiene fuerza jurídica?', '["Todas las partes de la Constitución tienen fuerza jurídica.", "Las Disposiciones adicionales.", "El Título Preliminar.", "El Preámbulo."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿De cuántos Títulos consta la Constitución española de 1978?', '["De diez Títulos.", "De once Títulos.", "De doce Títulos.", "De trece Títulos."]'::jsonb, 1, 'es'),
    ('616cbf05a2a0a53389966e22179b5f92', '¿A qué materia está dedicado el Título IV?', '["A las Cortes Generales.", "Al Gobierno.", "Al Gobierno y a las Cortes Generales.", "Al Gobierno y a la Administración."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En qué año se aprobó la primera Constitución española?', '["1810.", "1812.", "1814.", "1815."]'::jsonb, 1, 'es'),
    ('e7635585740de7b10b819c221029a513', '¿Qué artículos comprende el Título Preliminar?', '["Del 1 al 8.", "Del 1 al 9.", "Del 1 al 12.", "Del 1 al 14."]'::jsonb, 1, 'es'),
    ('bb9d170d5aaac40ea8046813ab106375', '¿En qué Título de la Constitución española de 1978 encontramos regulado el Poder Judicial?', '["En el Título V.", "En el Título IV.", "En el Título VI.", "En el Título VII."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuántas Disposiciones Adicionales tiene la Constitución española de 1978?', '["Nueve.", "Cinco.", "Cuatro.", "Ninguna de las otras respuestas es correcta."]'::jsonb, 2, 'es'),
    ('27688c24b51134855be832acefe310a4', '¿Qué artículo abre el Título II de la Constitución española de 1978?', '["El artículo 55.", "El artículo 54.", "El artículo 57.", "Ninguna de las otras respuestas es correcta."]'::jsonb, 3, 'es'),
    ('c480f8e0b6a7a2bf595e0aca8f82ffb9', '¿Qué Título de la Constitución española de 1978 está dedicado a la organización territorial del Estado?', '["El Título VII.", "El Título VI.", "El Título IX.", "El Título VIII."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿De cuántos artículos consta la Constitución española de 1978?', '["De 167.", "De 169.", "De 170.", "De 165."]'::jsonb, 1, 'es'),
    ('36d2d9a6896c8d22a6d15b1b737d5789', '¿Qué artículo, de los indicados a continuación, abre el Título VII?', '["El artículo 127.", "El artículo 128.", "El artículo 130.", "El artículo 132."]'::jsonb, 1, 'es'),
    ('95286aa824b18e8857c72287aa97cd4c', '¿Qué artículos comprende el Título I de la Constitución española de 1978?', '["Del 10 al 55.", "Del 9 al 55.", "Del 14 al 55.", "Del 14 al 29."]'::jsonb, 0, 'es'),
    ('e947057ff2f42db277860ce0b90afaed', '¿En qué Título de la Constitución española de 1978 se trata la Corona?', '["En el Título II.", "En el Título III.", "En el Título I.", "En el Título Preliminar."]'::jsonb, 0, 'es'),
    ('81b4196a9a98f87bf76f9a564d328a4d', 'A tenor del contenido del artículo 1.1. de la Constitución española de 1978, ¿en qué tipo de Estado se constituyó el Estado español?', '["Social, liberal y de derecho.", "Democrático, de derecho y social.", "Social, democrático y capitalista.", "La constitución del estado español no se recoge en el artículo citado en la pregunta."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿De cuántas partes se compone la Constitución española de 1978?', '["De dos, dogmática y orgánica.", "De tres, orgánica, dogmática y estructural.", "De dos, orgánica y estructural.", "Ninguna respuesta es correcta."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué contenido tiene la Disposición Final de la Constitución española de 1978?', '["Contiene una cláusula derogatoria y el mandato de publicación en todas las lenguas españolas además del castellano.", "Contiene solamente el mandato de publicación en todas las lenguas españolas además del castellano.", "Contiene solamente el mandato de vigencia inmediata.", "Ninguna de las otras respuestas es correcta."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Dónde reside la soberanía nacional a tenor del contenido del art.1.2. de la Constitución española de 1978?', '["En las Cortes Generales.", "En el pueblo español.", "En el Jefe del Estado y en el pueblo español.", "En las distintas partes que forman el Estado español."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es la forma política del Estado español?', '["Estado democrático.", "Estado social y democrático de derecho.", "Monarquía parlamentaria.", "Constitucional y democrático."]'::jsonb, 2, 'es'),
    ('971eab75c602ebdbf689854ede4f018a', '¿En qué se fundamenta la Constitución, según el art. 2 de la misma?', '["En el pueblo español que la refrendó.", "En la indisoluble unidad de la nación española.", "En el poder soberano de las Cortes Generales.", "En el estado democrático."]'::jsonb, 1, 'es'),
    ('81b4196a9a98f87bf76f9a564d328a4d', '¿Qué artículo de la Constitución de 1978 recoge el principio de autonomía de nacionalidades y regiones?', '["En artículo 1.", "El artículo 2.", "El artículo 3.", "El artículo 4."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es la lengua oficial del Estado español?', '["El español exclusivamente.", "El castellano.", "El castellano y las demás lenguas de acuerdo con los Estatutos de las Comunidades Autónomas.", "Ninguna de las otras respuestas es correcta."]'::jsonb, 1, 'es'),
    ('0b5205571b6369524baaa85b314a873e', '¿Qué artículo de la Constitución española de 1978 recoge la bandera española?', '["El artículo 3.", "El artículo 5.", "El artículo 7.", "El artículo 4."]'::jsonb, 3, 'es'),
    ('0b5205571b6369524baaa85b314a873e', '¿Cuál es el artículo más corto de toda la Constitución?', '["El artículo 3.", "El artículo 5.", "El artículo 6.", "Ninguna de las otras respuestas es correcta."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿A quién le corresponde la defensa del ordenamiento constitucional?', '["Al Tribunal Constitucional.", "A las Fuerzas Armadas.", "A las Cortes Generales.", "Al Gobierno y a las Cortes Generales."]'::jsonb, 1, 'es'),
    ('1cf384e30cb1ca80449f88fc14235b2a', 'Según el artículo 9 de la Constitución española de 1978, ¿ a qué están sujetos los poderes públicos y los ciudadanos?', '["A la Constitución y a la ley.", "A la ley y al ordenamiento jurídico.", "A la Constitución y al resto del ordenamiento jurídico.", "A la Constitución, a la ley y al resto del ordenamiento jurídico."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué disposiciones son irretroactivas?', '["Las sancionadoras que limiten derechos individuales exclusivamente.", "Las normas de rango inferior a la ley que establezcan una limitación a las libertades individuales.", "Las disposiciones favorables que limiten derechos adquiridos.", "Ninguna de las otras respuestas es correcta."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué significado tiene el principio de publicidad normativa?', '["Que a los ciudadanos están obligados a conocer las normas para que les pueda ser exigible su contenido.", "Que todas las normas deben publicarse en un periódico de difusión nacional.", "Que todas las normas deben ser publicadas en un diario oficial.", "Ninguna de las otras respuestas es correcta."]'::jsonb, 2, 'es'),
    ('60fb06435a5327a11ecd38138d98be5d', '¿Qué artículo de la Constitución hace referencia a los sindicatos de trabajadores?', '["El artículo 5.", "El artículo 7.", "El artículo 8.", "El artículo 9."]'::jsonb, 1, 'es'),
    ('857475475c8a7246d12ca020018f4668', 'De los Títulos indicados a continuación, ¿cuál hace referencia a la reforma constitucional?', '["El Título X.", "El Título IX.", "El Titulo VIII.", "El Título VII."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuántos tipos de reforma constitucional existen?', '["Dos, ordinario y sumario.", "Dos, ordinario y extraordinario.", "Tres, ordinario, extraordinario y sumario.", "Uno, el extraordinario."]'::jsonb, 1, 'es'),
    ('c148172d9847d4ec309023a6bfe095f8', 'Según el procedimiento contenido en el artículo 167 de la Constitución, ¿qué mayoría es necesaria para aprobar una reforma constitucional que afecte a un artículo del Título VIII, en primera votación?', '["Mayoría simple.", "Mayoría absoluta.", "Mayoría de 3/5.", "Mayoría de 2/5."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿De qué plazo disponen los miembros de las Cámaras para solicitar, en el caso anterior, la celebración de un referéndum?', '["De diez días hábiles.", "De cinco días hábiles.", "De quince días.", "De veinte días."]'::jsonb, 2, 'es'),
    ('d72bcda010a660fe1c5d4593e30921f5', '¿En cuál de los siguientes casos se aplica el procedimiento reformista del artículo 168?', '["Cuando se pretenda reformar el artículo 2 de la Constitución.", "Cuando se pretenda la reforma del Título VI de la Constitución.", "Cuando se pretenda la reforma del Título X de la Constitución.", "Todas las otras respuestas son correctas."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La lengua oficial del Estado español es:', '["El español exclusivamente", "El castellano", "El castellano y las demás lenguas de acuerdo con los Estatutos de las Comunidades Autónomas", "Todas y cada una de las lenguas habladas en territorio español."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El único artículo reformado hasta la fecha ha sido el:', '["13.2", "21.1", "10", "12."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los poderes públicos y los ciudadanos están sometidos a:', '["La Constitución y a la ley", "La ley y al ordenamiento jurídico", "La Constitución y al resto del ordenamiento jurídico", "La Constitución, a la ley y al resto del ordenamiento jurídico."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El fundamento de la Constitución española de 1978 es:', '["El pueblo español que la refrendó", "La indisoluble unidad de la nación española", "El poder soberano de las Cortes Generales", "El estado democrático constituido."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La sanción de la Constitución española de 1978 se realizó por:', '["El Congreso de los Diputados", "Las Cortes Generales", "El Gobierno", "El Rey."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuántas Disposiciones adicionales tiene la Constitución?', '["4", "9", "1", "2."]'::jsonb, 0, 'es'),
    ('967c177f0466dc7212becc05a7eab32c', '¿En qué Título se regulan las Cortes Generales?:', '["En el Título VIII", "En el Título III", "En el Título VI", "En el Título IX."]'::jsonb, 1, 'es'),
    ('bb9d170d5aaac40ea8046813ab106375', 'Las relaciones entre el gobierno y las Cortes Generales se regulan el Título:', '["El Título V", "El Título VI", "El Título IX", "El Título VIII."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Disposición Final de la Constitución española de 1978 hace referencia a:', '["Una cláusula derogatoria y el mandato de publicación en todas las lenguas españolas además del castellano", "Contiene solamente el mandato de publicación en todas las lenguas españolas además del castellano", "Contiene solamente el mandato de vigencia inmediata", "Hace referencia a su entrada en vigor."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuándo se sancionó la Constitución española?:', '["El 6 de diciembre de 1978 por el pueblo", "El 31 de octubre de 1978 por las Cortes Generales", "El 27 de diciembre de 1978 por el Rey", "El 29 de diciembre de 1978 por el Gobierno."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La soberanía nacional reside en:', '["El Congreso de los Diputados", "El pueblo español", "El Jefe del Estado", "El Gobierno de la nación."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El principio de igualdad jurídica se recoge constitucionalmente en su artículo:', '["12", "15", "17", "14."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Rey fue proclamado:', '["El 21 de noviembre de 1975", "El 20 de noviembre de 1974", "El 22 de noviembre de 1975", "El 23 de noviembre de 1976."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué disposición de la Constitución española de 1978 establece el plazo de su entrada en vigor:', '["La disposición adicional cuarta", "La disposición transitoria primera", "La disposición final", "La disposición adicional segunda."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La fecha de publicación de la Constitución española es:', '["El 26 de diciembre de 1978", "El 17 de diciembre de 1978", "El 29 de diciembre de 1978", "El 31 de octubre de 1978."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El antecedente constitucional inmediato a la actual Constitución es del año:', '["1921", "1915", "1919", "1931."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La abolición de la pena de muerte se recoge en el artículo:', '["15", "17", "18", "14."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La promulgación de Constitución española se produjo:', '["El 31 de octubre de 1978", "El 6 de diciembre de 1978", "El 27 de diciembre de 1978", "El 29 de diciembre de 1978."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El derecho a la educación se encuentra recogido en el artículo:', '["17", "25", "27", "28."]'::jsonb, 2, 'es'),
    ('e7635585740de7b10b819c221029a513', '¿Qué parte de la Constitución española de 1978 no tiene fuerza jurídica?:', '["El Título Preliminar", "El Título I", "El Preámbulo", "Las disposiciones finales."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Estado español es:', '["Social, liberal y de derecho", "Democrático, de derecho y social", "Social, democrático y capitalista", "Democrático, occidental y capitalista."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El principio de publicidad normativa se traduce en:', '["Que a los ciudadanos están obligados a conocer las normas para que les pueda ser exigible su contenido", "Que todas las normas deben publicarse en un periódico de difusión nacional", "Que todas las normas deben ser publicadas en un diario oficial", "Que las normas deben ser conocidas para que puedan ser exigibles."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En cuántas partes se estructura la Constitución española de 1978?:', '["En dos partes: dogmática y orgánica", "En tres partes: orgánica, dogmática y estructural", "En dos partes: orgánica y estructural", "No tiene divisiones internas."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Están prohibidas por la Constitución:', '["Las asociaciones ilegales", "Los Tribunales de honor en el ámbito de la administración militar", "Las asociaciones secretas", "La celebración de manifestaciones que se realicen sin solicitar autorización previa."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'D. Juan Carlos I juró su cargo:', '["Ante el Congreso", "Ante el pueblo", "Ante las Cortes Generales", "Ante el Gobierno."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'No ha existido en la historia constitucional española la:', '["Constitución española de 1869", "Constitución española de 1827", "Constitución española de 1930", "Constitución española de 1876."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Constitución más extensa de toda la historia constitucional española es del año:', '["1869", "1827", "1812", "1876."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'No es un valor superior del ordenamiento:', '["La libertad", "La justicia", "La seguridad", "El pluralismo político."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Constitución española de 1978 tiene:', '["Nueve disposiciones adicionales", "Nueve disposiciones transitorias", "Cuatro disposiciones derogatorias", "Una disposición adicional."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El derecho de petición se recoge en el artículo:', '["29", "28", "25", "19."]'::jsonb, 0, 'es'),
    ('042c55dcf70f38c4dffc4220b47071c9', 'El principio de autonomía de las nacionalidades se recoge en el artículo:', '["En artículo 10", "El artículo 2", "El artículo 1", "El artículo 5."]'::jsonb, 1, 'es'),
    ('616cbf05a2a0a53389966e22179b5f92', '¿A qué está dedicado el Título IV de la Constitución?:', '["A las Cortes Generales", "Al Gobierno", "Al Gobierno y a las Cortes Generales", "A la Corona."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es el plazo máximo de detención preventiva sin prórroga?:', '["24 horas", "48 horas", "43 horas", "72 horas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Estado de las autonomías fue creado en:', '["La Constitución de 1930", "La Constitución de 1931", "La Constitución de 1932", "La Constitución de 1939."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Constitución Española de 1978 propugna como valores superiores de su ordenamiento jurídico:', '["La libertad y la igualdad.", "La libertad, la justicia y la igualdad.", "La igualdad, la solidaridad, la libertad y la justicia.", "La libertad, la justicia, la igualdad y el pluralismo político."]'::jsonb, 3, 'es'),
    ('c148172d9847d4ec309023a6bfe095f8', 'De conformidad con el artículo 167 del Título X de la Constitución Española de 1978 lleva por rúbrica “De la reforma constitucional”, teniendo que aprobarse los proyectos de reforma constitucional:', '["Por mayoría de 2/3 del Senado.", "Por mayoría de 3/5 del Congreso.", "Por una mayoría de 3/5 de cada una de las Cámaras.", "Por una mayoría de 2/3 de cada una de las Cámaras."]'::jsonb, 2, 'es'),
    ('67897ffeb86c09bac9a3b4193ddc7221', 'El artículo 21 de la Constitución Española de 1978 establece lo que sigue:', '["Se reconoce el derecho de reunión pacífica y sin armas. El ejercicio de este derecho necesitará de autorización previa.", "Se reconoce el derecho de reunión pacífica y sin armas. El ejercicio de este derecho no necesitará de autorización previa.", "Se reconoce el derecho de asociación. El ejercicio de este derecho no necesitará de autorización previa.", "Ninguna de las anteriores es correcta."]'::jsonb, 1, 'es'),
    ('0443cd9d0325285e781bec821e5c3ddd', 'En el artículo 62 de la Constitución Española de 1978 se regulan las atribuciones que corresponden al Rey, no siendo competencia de éste:', '["Sancionar y promulgar leyes.", "El Alto Patronazgo de las Reales Academias.", "Nombrar al Presidente del Senado.", "Nombrar y separar a los miembros del Gobierno, a propuesta de su Presidente."]'::jsonb, 2, 'es'),
    ('425d57b101ca23eb5a6fbd2f9eb19dab', 'El artículo 68 de la Constitución Española de 1978 regula que el Congreso se compone de:', '["Un mínimo de 200 y un máximo de 300 Diputados.", "Un mínimo de 300 y un máximo de 350 Diputados.", "Ninguna es correcta.", "Un mínimo de 300 y un máximo de 400 Diputados."]'::jsonb, 3, 'es'),
    ('4306b11ccdff5320e8d87fda3b90c64d', 'El Título VIII de la Constitución Española de 1978 lleva por rúbrica “De la Organización Territorial del Estado”, dividiéndose este Título en 2 Capítulos: “De los Principios Generales” y “De la Administración Local”. El art. 140 garantiza:', '["La autonomía de los municipios, que gozarán de personalidad jurídica propia.", "La autonomía de los municipios, que gozarán de personalidad jurídica delegada.", "La autonomía de las Provincias y municipios, que gozarán de personalidad jurídica propia.", "La autonomía de los municipios, que gozarán de personalidad jurídica plena."]'::jsonb, 3, 'es'),
    ('d609babe8b103700f9fd7ff929f920e5', 'El artículo 159 de la Constitución Española de 1978 regula la composición del Tribunal Constitucional, teniendo que componerse este Órgano:', '["De 12 miembros nombrados por el Rey.", "De 12 miembros nombrados por el Presidente del Gobierno.", "De 15 miembros nombrados por el Rey.", "De 15 miembros nombrados por el Presidente del Gobierno."]'::jsonb, 0, 'es'),
    ('87715a4750c94339b4ba74aa163ff884', 'Según el artículo 25 de la Ley 39/2015, de 1 de octubre, del Procedimiento Administrativo Común de las Administraciones Públicas, en el supuesto en el que el procedimiento se hubiera paralizado por causa imputable al interesado...', '["La Resolución que declare la caducidad ordenará el archivo de las actuaciones, con los efectos previstos en el art. 95.", "Se suspenderá el plazo máximo para resolver por un período máximo de tres meses.", "Se interrumpirá el cómputo del plazo para resolver y notificar la resolución.", "Se entiende desestimado por silencio administrativo."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Cuando un día fuese hábil en el municipio o Comunidad Autónoma en que reside el interesado e inhábil en la sede del órgano administrativo o a la inversa, según la Ley 39/15, se considerará:', '["Hábil, en todo caso.", "Inhábil, en todo caso.", "Según sea determinado con sujeción al calendario laboral oficial.", "Se considerará hábil o inhábil según la naturaleza del acto administrativo"]'::jsonb, 1, 'es'),
    ('e7635585740de7b10b819c221029a513', 'El contenido de la Constitución de 1978, se divide en dos grandes grupos: parte orgánica y parte dogmática. La parte dogmática está integrada:', '["Por ciertas disposiciones del Título Preliminar", "Por el Título I", "Por la sección 1ª, del Capítulo 2º, del Título I", "Todas las anteriores son correctas"]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Cuál de los siguientes derechos NO tiene carácter de derecho fundamental:', '["Derecho de asociación", "Derecho de huelga", "Derecho de reunión", "Derecho de negociación colectiva."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La institución autonómica análoga al defensor del pueblo es:', '["El Servicio Jurídico del Gobierno de Canarias", "El Delegado del Gobierno", "El Delegado del Común", "El Consejo Consultivo de Canarias."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los principios rectores de la política social y económica:', '["Son directamente invocables por los ciudadanos, ya que forman parte de la parte dogmática de la Constitución.", "Inspiran la actuación de los poderes públicos, pero solo pueden ser invocados en relación a las leyes que los desarrollan", "Las dos son correctas", "Ninguna es correcta."]'::jsonb, 1, 'es'),
    ('e947057ff2f42db277860ce0b90afaed', 'El procedimiento para la modificación del Título II de la Constitución, relativo a la Corona, requiere:', '["Aprobación por referéndum", "Aprobación por mayoría de 2/3 de cada cámara", "Disolución de las Cortes Generales y formación de unas nuevas", "Todas son correctas."]'::jsonb, 3, 'es'),
    ('e947057ff2f42db277860ce0b90afaed', 'Cuál de estas funciones NO corresponden al Rey de acuerdo con los establecido en el Título II de la Constitución:', '["Convocar a referéndum en los casos establecidos en la Constitución", "Declarar la guerra", "Nombrar al Presidente del Congreso de los Diputados", "Sancionar y promulgar las leyes"]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Para la elección de los Diputados y Senadores, la circunscripción electoral es:', '["La Comunidad Autónoma", "Los municipios", "La provincia", "Ninguna es correcta."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuántos senadores nombra cada una de las islas denominadas mayores?', '["3", "2", "1", "Depende del número resultante que corresponde a cada Comunidad Autónoma por cada millón de habitantes de su respectivo territorio..."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Presidente del Gobierno:', '["Es nombrado por las Cortes Generales", "Es nombrado por el Rey", "Es nombrado por los ciudadanos a través de sufragio universal, libre, directo y secreto", "Es nombrado por el Tribunal Constitucional"]'::jsonb, 1, 'es'),
    ('95286aa824b18e8857c72287aa97cd4c', 'El decreto legislativo no podrá afectar', '["Al Ordenamiento de las instituciones básicas del Estado, a los derechos, deberes y libertades de los ciudadanos regulados en el Título I, al régimen de las Comunidades Autónomas ni al derecho electoral general", "A materias reguladas a través de directivas de la Unión Europea traspuestas al derecho interno.", "A materias sujetas a Ley Orgánica", "A materias de derecho laboral"]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Consejo General del Poder Judicial es el órgano de gobierno del poder judicial y está presidido:', '["Por el Rey, aunque con carácter simbólico", "Por el Presidente del Tribunal Constitucional", "Por el Presidente del Consejo de Estado", "Por el Presidente del Tribunal Supremo"]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los juzgados y tribunales del orden jurisdiccional contencioso administrativo conocerán de las pretensiones que se deriven en relación a:', '["Actos de las administraciones públicas en general", "Actos de las administraciones públicas, pero solo los sujetos al derecho administrativo", "Decretos legislativos que no excedan de los límites de la delegación", "Tanto la b como la c son correctas."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Cuál de estos entes no se considera entidad local', '["Áreas Metropolitanas", "Mancomunidades de Municipios", "Comarcas", "Todas tienen la condición de entidad local."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'España se constituye en un Estado:', '["Social de Derecho", "Democrático de Derecho", "Social y democrático de Derecho", "Plural y democrático de Derecho."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'No es un valor superior del ordenamiento jurídico español:', '["La libertad", "La justicia y la igualdad", "El pluralismo político", "Todos lo son."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La soberanía nacional reside:', '["En la nación", "En el pueblo español", "En las Cortes Generales", "En el Rey."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los poderes del Estado emanan:', '["De la nación", "Del pueblo español", "De las Cortes Generales", "Del Rey."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La forma política del Estado español es:', '["La Monarquía parlamentaria", "La democracia parlamentaria", "La República", "La Monarquía hereditaria."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Constitución se fundamenta en:', '["La autonomía de la Nación española", "La imprescindible unidad de la Nación española", "La indisoluble unidad de la Nación española", "Ninguna de las contestaciones anteriores es correcta."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Constitución reconoce y garantiza el derecho a la autonomía:', '["De las nacionalidades que la integran", "De las regiones que la integran", "De las Comunidades Autónomas que la integran", "De las nacionalidades y regiones que la integran"]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los españoles, ¿tienen el deber de conocer la lengua oficial del Estado?', '["Sí", "No", "Sí, y también el deber de usarla", "Sí, y también el derecho a usarla."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Además de la lengua oficial del Estado español, ¿son también oficiales las otras lenguas españolas?', '["No, tendrán la consideración de dialectos", "Sí, en todo el territorio español", "Sí, en las respectivas Comunidades Autónomas", "Sí, en los respectivos territorios históricos."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La riqueza de las distintas modalidades lingüísticas de España es:', '["Un patrimonio cultural", "Un bien cultural", "Un patrimonio histórico y cultural", "Un bien protegible"]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las disposiciones de carácter general en el ámbito municipal pueden revestir la forma de:', '["Reglamentos, ordenanzas y bandos", "Reglamentos, ordenanzas, bandos y apercibimientos", "Únicamente reglamentos y ordenanzas", "Únicamente reglamentos y apercibimientos"]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La bandera de España está formada por:', '["Dos franjas horizontales", "Tres franjas verticales", "Tres rayas horizontales", "Tres franjas horizontales"]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los colores de las franjas de la bandera de España son:', '["Roja, amarilla y roja", "Amarilla, roja y amarilla", "Amarilla, roja y azul", "Roja, amarilla y amarilla."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En la bandera de España, la franja amarilla:', '["Es de igual anchura que las rojas", "Es la mitad de ancha que las rojas", "Es de doble anchura que las rojas", "Es de triple anchura que las rojas."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Comunidades Autónomas podrán tener:', '["Banderas propias", "Enseñas propias", "Banderas y enseñas propias", "Banderas, enseñas y estandartes propios."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los símbolos de las Comunidades Autónomas se reconocen:', '["En la Constitución", "En las leyes orgánicas", "En los respectivos Estatutos de Autonomía", "En sus propias leyes"]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La capital del Estado español es:', '["La ciudad de Madrid", "La villa de Madrid", "La Comunidad Autónoma de Madrid", "El municipio de Madrid."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los partidos políticos expresan:', '["La democracia alternativa", "El pluralismo social", "El pluralismo político", "La alternancia en el poder."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los partidos políticos son instrumento fundamental para:', '["La paz social", "La tranquilidad política", "La alternancia política", "La participación política"]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La creación de partidos políticos y el ejercicio de su actividad son:', '["Voluntarios", "Libres", "Coercitivos", "Plurales."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué debe ser democrático en un partido político?', '["Su funcionamiento", "Su estructura interna", "Su funcionamiento y estructura interna", "Sus órganos asamblearios."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quiénes concurren a la formación y manifestación de la voluntad popular?', '["Los ciudadanos", "Los poderes públicos", "Los partidos políticos", "Los sindicatos de trabajadores y las asociaciones empresariales."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quiénes contribuyen a la defensa y promoción de los intereses económicos y sociales que les son propios?', '["Los ciudadanos", "Los poderes públicos", "Los partidos políticos", "Los sindicatos de trabajadores y las asociaciones empresariales."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué debe ser democrático en los sindicatos de trabajadores y las asociaciones empresariales?', '["Su funcionamiento", "Su estructura interna", "Su funcionamiento y estructura interna", "Sus órganos asamblearios."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Fuerzas Armadas están constituidas por:', '["El Ejército", "El Ejército de Tierra, Mar y Aire", "La Infantería, la Marina y la Aviación", "El Ejército de Tierra, la Armada y el Ejército del Aire."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Fuerzas Armadas no tienen como misión:', '["Garantizar la soberanía e independencia de España", "Defender la integridad territorial de España", "Garantizar la neutralidad de España", "Defender el ordenamiento constitucional de España."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las bases de la organización militar de España se regularán:', '["Por Decreto", "Por ley orgánica", "Por ley ordinaria", "Por ley de bases."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los ciudadanos y los poderes públicos están sujetos:', '["A las leyes", "A la Constitución", "A la Constitución y al resto del ordenamiento jurídico", "A la Constitución y a las leyes"]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Promover las condiciones para que la libertad y la igualdad del individuo y de los grupos en que se integra sean reales y efectivas corresponde:', '["A los poderes públicos", "Al Gobierno", "A las Cortes Generales", "A los ciudadanos"]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Facilitar la participación de todos los ciudadanos en la vida política, económica, cultural y social corresponde:', '["A los poderes públicos", "Al Gobierno", "A las Cortes Generales", "A los ciudadanos"]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Constitución garantiza:', '["El principio de legalidad", "La jerarquía normativa", "La publicidad de las normas", "Todas las anteriores son ciertas"]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Es fundamento del orden político y de la paz social:', '["La dignidad de las Instituciones", "Los derechos consuetudinarios y la costumbre", "El respeto a los derechos especiales", "El libre desarrollo de la personalidad"]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las normas relativas a los derechos fundamentales y a las libertades que la Constitución reconoce no se interpretarán de conformidad con:', '["La Declaración Universal de Derechos Humanos", "Los tratados internacionales sobre las mismas materias ratificados por España", "Los acuerdos internacionales sobre las mismas materias ratificados por España", "Se interpretarán de acuerdo con todos los instrumentos citados."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La nacionalidad española se adquiere, se conserva y se pierde de acuerdo con lo establecido por:', '["La Constitución", "La ley", "Los Tratados Internacionales", "Los Códigos."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Un español de origen, ¿podrá ser privado de su nacionalidad?', '["Sí", "No", "Sí, temporalmente", "Solamente si adquiere la de otro país."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Estado español podrá concertar tratados de doble nacionalidad:', '["Con los países iberoamericanos", "Con los países que hayan tenido una particular vinculación con España", "Con los países que tengan una particular vinculación con España", "Con todos los países anteriores."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los españoles son mayores de edad:', '["A los dieciséis años", "A los dieciocho años", "A la edad que fijen las leyes", "A la edad que fije una ley orgánica."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Pueden participar los extranjeros en procesos electorales españoles?', '["No, nunca", "Sí, en todos", "Sí, en elecciones autonómicas exclusivamente", "Sí, en elecciones municipales exclusivamente"]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La extradición sólo se concederá:', '["En cumplimiento de un tratado", "En cumplimiento de un tratado o de la ley", "En cumplimiento de un tratado o de la ley, atendiendo al principio de reciprocidad", "Ninguna de las contestaciones anteriores es completa."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Quedan excluidos de la extradición los delitos:', '["Políticos", "Penales", "Civiles", "Sentenciados."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'A efectos de extradición, los actos de terrorismo:', '["Se equiparan a delitos políticos", "Se equiparan a delitos contra la humanidad", "No se consideran como delitos políticos", "Tienen un tratamiento específico."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los ciudadanos de otros países y los apátridas, ¿podrán gozar del derecho de asilo en España?', '["No, en ningún caso", "Solamente si son refugiados políticos", "Sí, en los términos que establece la propia Constitución", "Sí, en los términos que establece la ley."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los españoles son iguales:', '["Ante la Constitución", "Ante la ley", "Ante el Gobierno", "Ante las Cortes Generales."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La igualdad de los españoles significa que no podrá prevalecer discriminación alguna por razón de:', '["Nacimiento", "Religión", "Opinión", "Todas las anteriores son correctas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Constitución, ¿autoriza la tortura?', '["Sí, en tiempos de guerra", "No, ni las penas degradantes", "No, ni las penas o tratos inhumanos o degradantes", "Ninguna de las contestaciones anteriores es correcta."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Queda abolida la pena de muerte en la Constitución?', '["Sí, totalmente", "No", "Sí, salvo lo que puedan disponer las leyes penales militares para tiempos de guerra", "Sí, salvo lo que pueda disponer una ley orgánica para tiempos de guerra."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'A los individuos y las comunidades se les garantiza:', '["La libertad ideológica", "La libertad ideológica y religiosa", "La libertad ideológica, religiosa y de culto", "La libertad ideológica, religiosa, de culto y de rito."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La libertad ideológica y religiosa, ¿tendrá alguna limitación en sus manifestaciones?', '["No", "Sí, las que establezca una ley orgánica", "No, salvo para el mantenimiento del orden público protegido por la ley", "No, salvo para el mantenimiento del decoro y la moralidad pública."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Nadie podrá ser obligado a declarar:', '["Sobre su ideología", "Sobre su religión", "Sobre sus creencias", "Todas las anteriores son correctas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Ninguna confesión tendrá carácter:', '["Estatal", "Religioso", "Confesional", "Obligatorio."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los poderes públicos tendrán en cuenta las creencias religiosas de:', '["Los ciudadanos", "La sociedad española", "Los creyentes", "Residentes en el territorio nacional."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En materia de creencias religiosas, los poderes públicos mantendrán relaciones de cooperación con:', '["La Iglesia Católica y Evangelista", "Las confesiones inscritas en los Registros correspondientes", "La Iglesia Católica exclusivamente", "La Iglesia Católica y demás confesiones."]'::jsonb, 3, 'es'),
    ('6e0739035f08f3b057ebd3e7c103405e', 'Nadie puede ser privado de su libertad:', '["Nunca", "Salvo en los casos y forma previstos en la ley", "Salvo con la observancia de lo establecido en el artículo 17 de la Constitución", "Son ciertas las respuestas b. y c."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los valores superiores del ordenamiento se recogen en el artículo:', '["1.1", "1.2", "1.3", "2."]'::jsonb, 0, 'es'),
    ('e7635585740de7b10b819c221029a513', '¿Qué artículo es el último del Título Preliminar?:', '["El 8", "El 9", "El 7", "El 6."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Constitución española de 1978 no es:', '["Derivada", "Rígida", "Extensa", "Pactada."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La defensa del ordenamiento       constitucional    está encomendada a:', '["Al Tribunal Constitucional", "A las Fuerzas Armadas", "A las Cortes Generales", "Al Gobierno."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué tipo de indulto no puede realizar el Rey?:', '["Indulto a un condenado con sentencia firme", "Indulto a ciudadanos extranjeros penados en España", "Indultos generales", "Indultos políticos."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En cuál de los siguientes casos es imprescindible ser español de nacimiento?:', '["Para ejercer la Regencia", "Para ejercer la tutela testamentaria", "Para ser proclamado Rey", "Para ejercer la Regencia y la tutela testamentaria."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Salvo resolución judicial, se garantiza el secreto de las comunicaciones y:', '["Postales", "Postales y telegráficas", "Postales, telegráficas y telefónicas", "Postales, electrónicas, telegráficas y telefónicas."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La inviolabilidad del domicilio supone que:', '["Ninguna entrada podrá hacerse en él sin consentimiento del titular o resolución judicial", "Ninguna entrada o registro podrá hacerse en él sin consentimiento del titular, salvo en caso de flagrante delito", "Ninguna entrada o registro podrá hacerse en él sin consentimiento del titular o resolución judicial, salvo en caso de flagrante delito", "Ninguna entrada, registro o inspección podrá hacerse en él sin consentimiento del titular o resolución judicial."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La ley limitará el uso de la informática:', '["Para garantizar el honor de los ciudadanos", "Para garantizar la intimidad personal y familiar de los ciudadanos", "Para garantizar el pleno ejercicio de los derechos de los ciudadanos", "Para materializar todas las garantías anteriores."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los españoles tienen derecho:', '["A elegir libremente su residencia", "A elegir libremente su residencia y a circular por el territorio nacional", "A circular por territorio extranjero.", "A elegir libremente su residencia y a circular por el territorio nacional y extranjero"]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El derecho de los españoles a entrar y salir libremente de España en los términos que la ley establezca, ¿podrá ser limitado?', '["Sí, por cualquier motivo", "No, por ningún motivo", "No podrá serlo por motivos políticos", "No podrá serlo por motivos políticos o ideológicos."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Se podrán expresar y difundir libremente:', '["Los pensamientos", "Las ideas", "Las opiniones", "Todas las anteriores son correctas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La libertad de expresión podrá realizarse:', '["Mediante la palabra", "Mediante la palabra y el escrito", "Mediante la palabra, el escrito o cualquier otro medio de reproducción", "Ninguna de las contestaciones anteriores es correcta."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Se reconoce y protege el derecho:', '["A la producción y creación literaria", "A la producción y creación literaria y artística", "A la producción y creación literaria, artística y científica", "A la producción y creación literaria, artística, científica y técnica"]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La libertad de cátedra:', '["Es un derecho", "Es un deber", "Es una obligación", "No está reconocida expresamente como derecho en la Constitución."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La regulación legal de la cláusula de conciencia y el secreto profesional, ¿con qué derecho se relaciona?', '["Con ninguno", "Con el de comunicar libremente información veraz", "Con el de comunicar o recibir libremente información veraz por cualquier medio de difusión", "Con el de comunicar o recibir libremente información veraz."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El ejercicio de los derechos de expresión, ¿puede restringirse mediante algún tipo de censura previa?', '["Sí", "No", "Sí, durante el estado de alarma", "Sí, durante los estados de alarma y excepción."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La libertad de expresión tiene su límite:', '["En el derecho al honor", "En el derecho al honor y a la intimidad", "En el derecho al honor, a la intimidad y a la propia imagen", "En el derecho al honor, a la intimidad, a la propia imagen y a la protección de la juventud y de la infancia."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Podrá acordarse el secuestro de publicaciones, grabaciones y otros medios de información?', '["No, en ningún caso", "Solamente en virtud de resolución judicial", "Solamente en virtud de resolución administrativa o judicial", "Solamente durante la vigencia de los estados de alarma, excepción y sitio."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El ejercicio del derecho de reunión pacífica y sin armas, ¿necesitará autorización previa?', '["No", "Sí", "Depende del número de reunidos", "Depende del tema de la reunión."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Se podrán prohibir las reuniones y manifestaciones que se celebren en lugares de tránsito público?', '["No", "Únicamente cuando existan razones fundadas de alteración del orden público", "Únicamente cuando existan razones fundadas de alteración del orden público, con peligro para personas", "Únicamente cuando existan razones fundadas de alteración del orden público, con peligro para personas o bienes."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Se exige comunicación previa a la autoridad para celebrar reuniones y manifestaciones en lugares de tránsito público?', '["Sí", "No", "Depende del número de reunidos", "Depende de la hora del acontecimiento."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Reconoce la Constitución el derecho de asociación?', '["No", "Sí", "Sí, como obligación", "Sí, como libertad."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Son ilegales las asociaciones:', '["Que persigan fines tipificados como delito", "Que utilicen medios tipificados como delito", "Que persigan fines o utilicen medios tipificados como delito", "Que persigan fines delictivos o utilicen medios peligrosos."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las asociaciones, ¿deberán inscribirse en un registro?:', '["No", "Sí, a los solos efectos de control", "Sí, a efectos de publicidad y control", "Sí, a los solos efectos de publicidad"]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las asociaciones, ¿podrán ser disueltas o suspendidas en sus actividades?', '["No", "Sí, en virtud de resolución administrativa motivada", "Sí, en virtud de resolución judicial motivada", "Sí, en virtud de resolución administrativa o judicial."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Prohíbe la Constitución algún tipo de asociaciones?', '["No", "Sí, las asociaciones secretas", "Sí, las asociaciones secretas y las de carácter paramilitar", "Sí, las asociaciones secretas y las de carácter militar."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los ciudadanos tienen el derecho a participar en los asuntos públicos:', '["Sólo directamente o por medio de representantes", "Sólo por medio de representantes", "Directamente o por medio de representantes", "Directamente o por medio de representantes y delegados."]'::jsonb, 2, 'es');

  -- Batch 201-400
  insert into public.question_bank (content_hash, question, options, correct_index, lang)
  values
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los ciudadanos tienen derecho a acceder en condiciones de igualdad:', '["A las funciones públicas", "A los cargos públicos", "A las funciones, cargos y empleos públicos", "A las funciones y cargos públicos"]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los representantes de los ciudadanos para participar en los asuntos públicos:', '["Serán libremente elegidos", "Serán libremente elegidos por sufragio universal", "Serán libremente elegidos en elecciones frecuentes por sufragio censitario", "Serán libremente elegidos en elecciones periódicas por sufragio universal"]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En el ejercicio de sus derechos e intereses legítimos, todas las personas tienen derecho a obtener tutela efectiva de:', '["Los jueces", "Los tribunales", "Los jueces y tribunales", "Jueces, magistrados, juzgados y tribunales."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En materia de tutela judicial, todos tienen derecho:', '["Al Juez ordinario predeterminado por ley", "A la defensa", "A la asistencia de letrado", "Todas las anteriores son ciertas"]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En materia de tutela judicial, no se reconoce el derecho:', '["A no declarar contra sí mismo", "A no ser condenado", "A no confesarse culpables", "A la presunción de inocencia."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En determinados casos establecidos por la ley, no se estará obligado a declarar sobre hechos presuntamente delictivos:', '["Por razón de parentesco", "Por razón de secreto profesional", "Por razón de parentesco o de secreto profesional", "Por razón de parentesco, de secreto profesional o de obediencia debida."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Nadie puede ser condenado o sancionado por acciones u omisiones que en el momento de producirse no constituyan:', '["Delito", "Delito o falta", "Delito, falta o infracción administrativa", "Delito, falta e infracción administrativa o judicial."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las penas privativas de libertad y las medidas de seguridad están orientadas hacia:', '["La reeducación", "La resocialización", "La reeducación y reinserción social", "La reeducación, resocialización y reinserción social."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las penas privativas de libertad y las medidas de seguridad, ¿podrán consistir en trabajos forzados?', '["No", "Sí", "Sí, si no exceden de un año", "Sí, para casos de terrorismo."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El condenado a pena de prisión que estuviera cumpliendo la misma gozará de los derechos constitucionales a excepción de los que se vean expresamente limitados por:', '["El contenido del fallo condenatorio", "El contenido del fallo condenatorio y la duración de la pena", "El contenido del fallo condenatorio, el sentido de la pena y la ley penitenciaria", "El contenido del fallo condenatorio, la duración de la pena y la ley penitenciaria."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El condenado a pena de prisión que estuviera cumpliendo la misma no tendrá derecho:', '["A un trabajo remunerado", "A los beneficios correspondientes de la Seguridad Social", "Al acceso a la cultura y al desarrollo integral de su personalidad", "Tendrá todos los derechos anteriores."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Administración civil, ¿podrá imponer sanciones de privación de libertad?', '["Sí, mediante resolución motivada", "No podrá hacerlo de forma directa, pero sí subsidiariamente", "No podrá hacerlo ni de forma directa ni subsidiariamente", "Sí, mediante autorización judicial."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Constitución, ¿prohíbe los Tribunales de Honor?', '["No, en ningún ámbito", "Sí, en todos los ámbitos", "Sí, en el ámbito de la Administración civil", "Sí, en el ámbito de la Administración civil y de las organizaciones profesionales."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Reconoce la Constitución el derecho a la educación?', '["No", "Sí, y también la libertad de enseñanza", "Sí, pero no la libertad de enseñanza", "Sí, y también el deber de enseñanza."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La educación tendrá por objeto el pleno desarrollo de la personalidad humana en el respeto:', '["A los principios democráticos de convivencia", "A los principios democráticos de convivencia y tolerancia", "A los principios democráticos de convivencia, tolerancia e integración", "A los principios democráticos de convivencia y a los derechos y libertades fundamentales."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los poderes públicos garantizan el derecho que asiste a los padres para que sus hijos reciban la formación:', '["Integral que esté de acuerdo con sus propios ideales", "Religiosa que esté de acuerdo con sus propias convicciones", "Religiosa y moral que esté de acuerdo con sus propias convicciones", "Religiosa y moral que esté de acuerdo con sus propios ideales."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La enseñanza básica es:', '["Obligatoria e integral", "Gratuita", "Obligatoria y gratuita", "Obligatoria, gratuita e integral."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los poderes públicos garantizan el derecho de todos a la educación:', '["Mediante una programación general de la enseñanza", "Con participación efectiva de todos los sectores afectados", "Con la creación de centros docentes", "Todas las respuestas anteriores son correctas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Constitución, ¿reconoce la libertad de creación de centros docentes?', '["No", "Sí, a las personas físicas exclusivamente", "Sí, a las personas jurídicas exclusivamente", "Sí, a las personas físicas y jurídicas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quiénes intervendrán en el control y gestión de todos los centros sostenidos por la Administración con fondos públicos?', '["Los profesores", "Los profesores y los padres", "Los profesores, los padres y, en su caso, los alumnos", "Los profesores, los padres y, en todo caso, los alumnos."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Para garantizar el cumplimiento de las leyes, los poderes públicos:', '["Inspeccionarán el sistema educativo", "Homologarán el sistema educativo", "Inspeccionarán y homologarán el sistema educativo", "Inspeccionarán, coordinarán y homologarán el sistema educativo."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Constitución, ¿reconoce la autonomía de las Universidades?', '["No, solamente su autogestión", "Sí, en los términos que la propia Constitución establece", "Sí, en los términos que la ley establezca", "Ninguna de las contestaciones anteriores es cierta."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Constitución, ¿quiénes tienen derecho a sindicarse libremente?', '["Todos", "Los asalariados", "Los trabajadores", "Quienes presten servicios por cuenta ajena."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Constitución, la Ley podrá limitar o exceptuar el ejercicio del derecho de sindicación:', '["A las Fuerzas Armadas", "A las Fuerzas o Institutos armados", "A las Fuerzas o Institutos armados y los demás Cuerpos sometidos a disciplina militar", "A los funcionarios públicos."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Constitución, la ley regulará las peculiaridades del ejercicio del derecho de sindicación:', '["Para las Fuerzas Armadas", "Para las Fuerzas o Institutos armados", "Para las Fuerzas o Institutos armados y los demás Cuerpos sometidos a disciplina militar", "Para los funcionarios públicos."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué derecho no comprende la libertad sindical?', '["El de fundar sindicatos", "El de afiliarse al sindicato de su elección", "El derecho de los sindicatos a formar confederaciones y a fundar organizaciones sindicales internacionales", "Comprende todos los derechos anteriores."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Podrá ser obligado alguien a afiliarse a un sindicato?', '["Sí, mediante resolución motivada de la autoridad laboral", "Solamente por necesidades de la producción", "Solamente por necesidades de la economía", "Nadie podrá ser obligado."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Constitución, ¿reconoce el derecho a la huelga de los trabajadores?', '["No, lo encomienda a una ley", "Sí, para la defensa de sus salarios", "Sí, para la defensa de sus intereses", "Sí, para la defensa de sus contratos."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La ley que regule el ejercicio del derecho de huelga establecerá las garantías precisas para asegurar el mantenimiento:', '["De los servicios esenciales de la comunidad", "Del orden público", "De los sistemas productivos", "De la paz social."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Todos los españoles tendrán el derecho de petición:', '["Individual", "Individual y colectiva", "Individual y colectiva, por escrito", "Individual y colectiva, por escrito o verbalmente."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los miembros de las Fuerzas o Institutos armados o de los Cuerpos sometidos a disciplina militar, ¿podrán ejercer el derecho de petición?', '["No", "Sí, sin ninguna limitación", "Sólo individualmente", "Sólo individualmente y con arreglo a lo dispuesto en su legislación específica."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los españoles, ¿tienen el derecho de defender a España?', '["No", "Sí, y también el deber", "Sí, si han cumplido o están cumpliendo el servicio militar", "Sí, si son mayores de 18 años."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Constitución, ¿podrá establecerse un servicio civil?', '["No", "No, porque el servicio será militar", "Sí, para el cumplimiento de fines colectivos", "Sí, para el cumplimiento de fines de interés general."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Mediante ley podrán regularse los deberes de los ciudadanos en los casos de:', '["Grave riesgo", "Grave riesgo o catástrofe", "Grave riesgo, catástrofe o calamidad pública", "Grave riesgo, siniestro o catástrofe."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Todos contribuirán al sostenimiento de los gastos públicos mediante un sistema tributario justo inspirado en los principios de:', '["Igualdad y equidad", "Igualdad y proporcionalidad", "Igualdad y progresividad", "Igualdad, progresividad y proporcionalidad."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El sistema tributario, ¿podrá tener alcance confiscatorio?', '["No, en ningún caso", "No, salvo para las rentas más altas y grandes fortunas", "Sí, por razones de interés social", "Sí, dependiendo de la evolución de la economía nacional."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La programación y ejecución del gasto público responderá a los criterios de:', '["Eficacia y economía", "Eficiencia y economía", "Eficiencia y eficacia", "Eficiencia, productividad y economía."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Podrán establecerse por ley prestaciones personales de carácter público?', '["No, en ningún caso", "Sí, mediante ley orgánica", "Sí, y también patrimoniales", "Sí, y también económicas."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El hombre y la mujer tienen derecho a contraer matrimonio:', '["En cualquier momento", "Con plena igualdad jurídica", "Con plena igualdad económica", "Con plena igualdad económica y social."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Respecto del matrimonio, la ley regulará:', '["Las formas, edad y capacidad para contraerlo", "Las causas de separación y disolución y sus efectos", "Los derechos y deberes de los cónyuges", "Todas las cuestiones anteriores."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Reconoce la Constitución el derecho a la propiedad privada?', '["No", "Sí, y a la comunal", "Sí, y a la herencia", "Sí, y a la herencia y legados."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Nadie podrá ser privado de sus bienes y derechos sino por causa justificada de:', '["Utilidad pública", "Interés social", "Utilidad pública o interés social", "Utilidad pública, necesidad o interés social."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La privación de bienes y derechos mediando causa justificada se efectuará:', '["Mediante la correspondiente indemnización", "De conformidad con lo dispuesto por las leyes", "Mediante la correspondiente contraprestación", "Mediante la correspondiente indemnización y de conformidad con lo dispuesto por las leyes."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Se reconoce el derecho de fundación:', '["Para fines de interés específico", "Para fines de interés general", "Para fines lícitos", "Para fines educativos y sociales."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Todos los españoles tienen:', '["El deber de trabajar", "El derecho al trabajo", "El deber de trabajar y el derecho al trabajo", "El derecho a la ocupación plena."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Todos los españoles tienen el derecho:', '["A la libre elección de profesión u oficio", "A la promoción a través del trabajo", "A una remuneración suficiente para satisfacer sus necesidades y las de su familia", "Todas las anteriores son ciertas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Respecto del derecho al trabajo, en ningún caso pueda hacerse discriminación por razón de:', '["Sexo", "Raza", "Religión", "Opinión."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El estatuto de los trabajadores se regulará:', '["Por ley", "Por ley orgánica", "Por Decreto-Ley", "Por Real Decreto."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La estructura interna y el funcionamiento de los Colegios profesionales deberán ser:', '["Públicos", "Democráticos", "Flexibles", "Orgánicos."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Respecto de los convenios colectivos, la ley garantizará:', '["Su publicidad", "Su ámbito", "Su fuerza vinculante", "Su temporalidad."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La ley garantizará el derecho a la negociación colectiva laboral:', '["Entre los trabajadores y empresarios directamente", "Entre los representantes de los trabajadores y empresarios", "Entre organizaciones sindicales y empresariales", "Entre patrón y obrero."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El derecho a adoptar medidas de conflicto colectivo se reconoce en favor de:', '["Los trabajadores exclusivamente", "Los empresarios exclusivamente", "Los trabajadores y empresarios", "Los trabajadores, empresarios y autoridad laboral."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La ley que regule el ejercicio del derecho a adoptar medidas de conflicto colectivo incluirá las garantías precisas para asegurar el funcionamiento:', '["De servicios esenciales de la comunidad", "Del orden público", "De los sistemas productivos", "De los servicios esenciales de la comunidad y del orden público."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Se reconoce la libertad de empresa en el marco de:', '["La economía de mercado", "La economía capitalista", "La economía occidental", "La productividad nacional."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Respecto de la familia, los poderes públicos asegurarán su protección:', '["Social", "Social y económica", "Social, económica y jurídica", "Social, económica, administrativa y jurídica"]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Respecto de la protección de la familia, los hijos son iguales ante la ley con independencia de:', '["Su edad", "Su filiación", "Su nacimiento", "Su raza."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los poderes públicos aseguran la protección integral de las madres, cualesquiera que sea:', '["Su estado civil", "Su situación económica", "Su situación social", "Su situación económica y social."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿La ley posibilitará la investigación de la paternidad?', '["No", "Sí", "Sí, en caso de delito", "Sí, mediante resolución judicial."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los padres deben prestar asistencia de todo orden a los hijos:', '["Habidos dentro o fuera del matrimonio", "Durante su minoría de edad", "En los demás casos en que legalmente proceda", "Todas las anteriores son correctas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los niños gozarán de protección en:', '["Las leyes", "Los acuerdos internacionales que velan por sus derechos", "Los acuerdos internacionales ratificados por España", "La Constitución."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los poderes públicos promoverán las condiciones favorables:', '["Para el progreso social y económico", "Para una distribución de la renta regional más equitativa", "Para una distribución de la renta personal más equitativa", "Todas las anteriores son correctas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En el ámbito económico, los poderes públicos realizarán una política orientada:', '["A la disminución del desempleo", "Al pleno empleo", "A un incremento del P.I.B.", "Al libre mercado."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En materia laboral, los poderes públicos no garantizarán el descanso necesario:', '["Mediante limitación de la jornada laboral", "Mediante contratos a tiempo parcial", "Mediante la promoción de centros adecuados", "Mediante las vacaciones periódicas retribuidas."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En materia de Seguridad Social, los poderes públicos mantendrán un régimen:', '["Público", "Privado", "De reparto", "Capitalizado."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El régimen de Seguridad Social garantizará unas prestaciones sociales suficientes ante situaciones de necesidad, especialmente en caso de:', '["Desempleo", "Enfermedad", "Necesidad", "Contingencia protegible."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La asistencia y prestaciones complementarias de la Seguridad Social serán:', '["Obligatorias", "Universales", "Libres", "Contributivas."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La política del Estado respecto de los trabajadores españoles en el extranjero se orientará:', '["Hacia su igualdad", "Hacia su progreso", "Hacia su regreso", "Hacia su prosperidad."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Respecto de los trabajadores españoles en el extranjero, el Estado velará especialmente por la salvaguardia de sus derechos:', '["Económicos", "Sociales", "Económicos y sociales", "Políticos."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Respecto de la salud se reconoce el derecho:', '["A la protección", "A la curación", "A la prevención", "A la asistencia médica."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Compete a los poderes públicos organizar y tutelar la salud pública a través de:', '["Medidas preventivas", "Prestaciones necesarias", "Servicios necesarios", "Todas las contestaciones anteriores son correctas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los poderes públicos no fomentarán:', '["La educación sanitaria", "La educación física", "El deporte", "Fomentarán todas las actuaciones anteriores."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Respecto del ocio, los poderes públicos facilitarán:', '["Su adecuada utilización", "Su adecuada distribución", "Su adecuado disfrute", "Su adecuada promoción."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los poderes públicos promoverán la ciencia y la investigación científica y técnica en beneficio:', '["Del progreso", "Del interés general", "Del desarrollo nacional", "De la innovación tecnológica."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Respecto del medio ambiente la Constitución establece:', '["El derecho a disfrutarlo", "El deber de conservarlo", "El deber de disfrutarlo", "Son correctas las contestaciones a. y b."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los poderes públicos velarán por la utilización racional de todos los recursos naturales para:', '["Proteger la calidad de la vida", "Defender y restaurar el medio ambiente", "Mejorar la calidad de la vida", "Todas las contestaciones anteriores son correctas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Contra la violación de la utilización racional de los recursos naturales, ¿se podrán establecer sanciones penales?:', '["No, en ningún caso", "Sí, y también sanciones administrativas", "Sí, y también la obligación de reparar el daño causado", "Son ciertas las contestaciones b. y c."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los poderes públicos garantizarán la conservación y promoverán el enriquecimiento del patrimonio:', '["Histórico de los pueblos de España", "Histórico y cultural de pueblos de España", "Histórico, cultural y artístico de los pueblos de España", "Histórico, cultural, artístico y folclórico de los pueblos de España."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los atentados contra el patrimonio de los pueblos de España se sancionará mediante:', '["Multas", "Una ley especial", "La ley penal", "Multas coercitivas."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Todos los españoles tienen derecho a disfrutar de una vivienda:', '["Digna y adecuada", "Suficiente y adecuada", "Digna y suficiente", "Suficiente y económica."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los poderes públicos regularán la utilización del suelo de acuerdo con el interés general para impedir:', '["La construcción ilegal", "El urbanismo salvaje", "La especulación", "El enriquecimiento injusto."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Respecto de la acción urbanística de los entes públicos, la comunidad participará:', '["En el lucro que genere", "En las plusvalías que genere", "En las mejoras que genere", "En las alternativas que genere."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los poderes públicos promoverán las condiciones para la participación libre y eficaz de la juventud en el desarrollo:', '["Político", "Político y social", "Político, social y económico", "Político, social, económico y cultural."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Respecto de los disminuidos físicos, sensoriales y psíquicos, los poderes públicos realizarán:', '["Una política de previsión", "Una política de previsión y tratamiento", "Una política de rehabilitación e integración", "Una política de previsión, tratamiento, rehabilitación e integración."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los poderes públicos garantizarán la suficiencia económica a los ciudadanos durante la tercera edad mediante pensiones:', '["Adecuadas", "Periódicamente actualizadas", "Adecuadas y periódicamente actualizadas", "Adecuadas, suficientes y periódicamente actualizadas."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los poderes públicos promoverán el bienestar de la tercera edad mediante un sistema de servicios sociales que atenderán sus problemas específicos de:', '["Salud", "Salud y vivienda", "Salud, vivienda y ocio", "Salud, vivienda, cultura y ocio."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Respecto de los consumidores y usuarios, los poderes públicos protegerán mediante procedimientos eficaces:', '["La seguridad de los mismos", "Los legítimos intereses económicos de los mismos", "La seguridad y los legítimos intereses económicos de los mismos", "La seguridad, la salud y los legítimos intereses económicos de los mismos."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Respecto de los consumidores y usuarios, los poderes públicos:', '["Promoverán su información y su educación", "Fomentarán sus organizaciones", "Oirán a sus organizaciones en las cuestiones que puedan afectar a aquéllos", "Todas las anteriores son ciertas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La ley regulará las organizaciones profesionales que contribuyan a la defensa de los intereses económicos:', '["Nacionales", "Generales", "Sociales", "Que les sean propios."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La estructura interna y funcionamiento de las organizaciones profesionales deberán ser:', '["Públicos", "Democráticos", "Flexibles", "Orgánicos."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los derechos y libertades reconocidos en el Capítulo segundo del Título I de la Constitución vinculan:', '["A todos los poderes públicos", "A todos los españoles", "A todos los ciudadanos", "A ciudadanos y Administración."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El ejercicio de los derechos y libertades reconocidos en el Capítulo segundo del Título I de la Constitución se regulará:', '["Sólo mediante ley orgánica", "Sólo por ley", "Sólo mediante Decreto-ley", "Sólo mediante Real Decreto."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La regulación del ejercicio de los derechos y libertades reconocidos en el Capítulo segundo del Título I de la Constitución:', '["Deberá contar con los afectados", "Deberá respetar su contenido esencial", "Deberá armonizar su contenido esencial", "Deberá restringir su contenido esencial"]'::jsonb, 1, 'es'),
    ('95286aa824b18e8857c72287aa97cd4c', 'El ejercicio de los derechos y libertades reconocidos en el Capítulo 2º (Título I) de la Constitución se tutelará mediante:', '["Recurso de amparo", "Recurso de inconstitucionalidad", "Recurso contencioso-administrativo", "Recurso de protección jurisdiccional de los derechos fundamentales"]'::jsonb, 1, 'es'),
    ('2b6edcfa0c4ac251d50667a54353381c', 'Cualquier ciudadano podrá recabar la tutela de las libertades y derechos reconocidos en el artículo 14 y la Sección primera del Capítulo segundo del Título I de la Constitución:', '["Ante los Tribunales ordinarios", "Ante los Tribunales penales", "Ante el Ministerio Fiscal", "Ante el Defensor del Pueblo."]'::jsonb, 0, 'es'),
    ('2b6edcfa0c4ac251d50667a54353381c', 'Cualquier ciudadano podrá recabar en vía judicial la tutela de las libertades y derechos reconocidos en el artículo 14 y la Sección primera del Capítulo 2º (Título I) de la Constitución mediante un procedimiento basado en los principios de:', '["Precedencia y ejecutividad", "Preferencia y sumariedad", "Celeridad y equidad", "Juez predeterminado e imparcial."]'::jsonb, 1, 'es'),
    ('2b6edcfa0c4ac251d50667a54353381c', '¿Se podrá recabar la tutela de las libertades y derechos reconocidos en el artículo 14 y la Sección primera del Capítulo 2º (Título I) de la Constitución a través del recurso de amparo ante el Tribunal Constitucional?', '["Sí, en todo caso", "Sí, en su caso", "No, solamente a través del recurso de constitucionalidad", "No"]'::jsonb, 1, 'es'),
    ('2b6edcfa0c4ac251d50667a54353381c', 'El recurso de amparo ante el Tribunal Constitucional para recabar la tutela de las libertades y derechos reconocidos en el artículo 14 y la Sección primera del Capítulo 2º (Título I) de la Constitución:', '["No es aplicable", "Se aplicará también a la objeción de conciencia", "Se aplicará también al derecho de propiedad privada", "Se aplicará también al derecho a la vivienda."]'::jsonb, 1, 'es'),
    ('95286aa824b18e8857c72287aa97cd4c', 'El reconocimiento, el respeto y la protección de los principios reconocidos en el Capítulo 3º (Título I) de la Constitución informará:', '["La legislación positiva", "La práctica judicial", "La actuación de los poderes públicos", "Todas las anteriores son correctas"]'::jsonb, 3, 'es'),
    ('95286aa824b18e8857c72287aa97cd4c', 'Los principios reconocidos en el Capítulo 3º (Título I) de la Constitución, ¿podrán ser alegados ante la Jurisdicción ordinaria?', '["No", "Sí, en todo caso", "Sí, de acuerdo con lo que dispongan las leyes que los desarrollen", "Sí, siempre que no sean respetados por los poderes públicos."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La institución del Defensor del Pueblo se regulará:', '["Mediante una ley orgánica", "Mediante una ley ordinaria", "Mediante un Decreto-Ley", "Mediante un Decreto Legislativo"]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Constitución instituye la figura del Defensor del Pueblo como:', '["Defensor de todos los derechos de los ciudadanos", "Defensor del interés público ante la Justicia", "Alto comisionado de las Cortes Generales", "Alto comisionado del Congreso."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién designa al Defensor del Pueblo?:', '["El Gobierno", "El Congreso", "El Senado", "Las Cortes Generales."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Para cumplir sus cometidos, el Defensor del Pueblo podrá supervisar la actividad:', '["Del Gobierno", "De las Cortes Generales", "De la Administración", "Del Poder Judicial"]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿A quién dará cuenta de su actividad el Defensor del Pueblo?', '["Al Gobierno", "Al Congreso", "Al Senado", "A las Cortes Generales"]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En relación con las investigaciones correspondientes a la actuación de bandas armadas o elementos terroristas, no puede suspenderse para personas determinadas:', '["La duración máxima de la detención preventiva", "La libertad de residencia", "El secreto de las comunicaciones", "La inviolabilidad del domicilio."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué derecho podrá ser suspendido cuando se acuerde la declaración del estado de excepción o de sitio?', '["Derecho a la libertad", "Derecho a la seguridad", "Derecho a la inviolabilidad del domicilio", "Todos los derechos anteriores pueden ser suspendidos."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La forma y casos en los que podrán suspenderse derechos para personas determinadas en relación con las investigaciones correspondientes a la actuación de bandas armadas o elementos terroristas habrá de regularse:', '["Mediante una ley orgánica", "Mediante una ley ordinaria", "Mediante un Decreto-Ley", "Mediante decisión judicial."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La suspensión de derechos para personas determinadas en relación con las investigaciones correspondientes a la actuación de bandas armadas o elementos terroristas habrá de realizarse:', '["De forma individual", "Con la necesaria intervención judicial", "Con el adecuado control parlamentario", "Con todos los requisitos anteriores."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Jefe del Estado es:', '["El Presidente del Gobierno", "El Rey", "El Presidente del Congreso", "Ninguna de las contestaciones anteriores es correcta."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Respecto del Estado, el Rey es símbolo de su:', '["Unidad e integridad", "Unidad y permanencia", "Independencia y soberanía", "Integridad y soberanía."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La más alta representación del Estado español en las relaciones internacionales es asumida por:', '["El Presidente del Gobierno", "El Rey", "El Presidente del Congreso", "Ninguna de las anteriores es correcta."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Respecto del funcionamiento regular de las instituciones, el Rey:', '["Arbitra y modera las mismas", "Modera y dirige las mismas", "Impulsa y modera las mismas", "Modera y pacifica las mismas."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Constitución Española tiene:', '["Ciento sesenta y nueve artículos.", "Ciento cuarenta y nueve artículos.", "Ciento cincuenta y nueve artículos.", "Cientos setenta y nueve artículos"]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Cámaras se encuentran reguladas en nuestra Constitución:', '["El Capítulo Primero del Título Cuarto.", "El Capítulo Primero del Título Tercero.", "El Capítulo Cuarto del Título Primero.", "El Capítulo Segundo del Título Tercero."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Título Cuarto de la Constitución Española está dedicado a:', '["Las relaciones entre el Gobierno y las Cortes Generales.", "El Poder Judicial.", "El Gobierno y la Administración.", "Las Cortes Generales."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Disposición Derogatoria de la Constitución Española ostenta:', '["Cuatro apartados.", "Tres apartados.", "Un solo apartado.", "Dos apartados."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Título Tercero de la Constitución Española está dedicado a:', '["El Gobierno y la Administración.", "El Poder Judicial.", "La Corona.", "Las Cortes Generales."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La estructura básica y común a todos los Títulos de la Constitución Española es:', '["La Sección.", "El Capítulo.", "El Libro.", "El artículo."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Constitución Española posee:', '["Cuatro Disposiciones Transitorias.", "Dos Disposiciones Finales.", "Disposición Derogatoria con tres puntos.", "Nueve Disposiciones Adicionales."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Título Noveno de la Constitución Española está dedicado a:', '["El Tribunal Constitucional.", "Economía y Hacienda.", "La organización territorial del Estado.", "La reforma constitucional."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Título Cuarto de la Constitución Española tiene:', '["Once artículos.", "Ocho artículos.", "Nueve artículos.", "Diez artículos."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Disposiciones Transitorias en la Constitución Española son:', '["Cinco.", "Diez.", "Nueve.", "Cuatro."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Constitución se fundamenta:', '["En la unidad de la Nación Española.", "En el compromiso de unidad de todos los pueblos y nacionalidades integrantes de la Nación Española.", "En la indisoluble unidad de España.", "En la pluralidad de pueblos integrantes de la Nación Española."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los valores superiores del ordenamiento jurídico son:', '["La libertad, justicia, igualdad y pluralismo político.", "La libertad, justicia y libre competencia.", "La libertad, la igualdad y el pluralismo político y sindical.", "La libertad, la igualdad y la fraternidad."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Sólo uno de los siguientes principios está garantizado constitucionalmente:', '["La responsabilidad e interdicción de la arbitrariedad de la Administración Pública, tanto nacional, como autonómica o local.", "Responsabilidad de la Administración Pública.", "La interdicción de la arbitrariedad del poder judicial.", "La responsabilidad e interdicción de la arbitrariedad de los poderes públicos."]'::jsonb, 3, 'es'),
    ('e7635585740de7b10b819c221029a513', 'Una de las siguientes materias no es regulada en el Título Preliminar de la Constitución Española:', '["Las Cortes Generales.", "Las Asociaciones de Empresarios.", "Las Fuerzas Armadas.", "Los Partidos Políticos."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Una de las siguientes afirmaciones referentes a las misiones de las Fuerzas Armadas, no es cierta:', '["Defienden el ordenamiento constitucional, impidiendo, por ejemplo, un golpe de estado antidemocrático.", "Defienden la integridad territorial del Estado, lo cual no es obstáculo para que consientan la independencia de alguna o algunas nacionalidades o regiones de España, tras decisión libremente adoptada al efecto en referéndum de autodeterminación.", "Garantizan la independencia de España, luchando, por ejemplo, contra la invasión militar de nuestro territorio por un ejército extranjero.", "Defienden la integridad territorial del Estado, no consintiendo, por ejemplo, la ruptura de la unidad de España."]'::jsonb, 1, 'es'),
    ('e7635585740de7b10b819c221029a513', 'Las bases de la organización militar conforme a los principios constitucionales:', '["Se regulan en la propia Constitución, en el Título Octavo.", "Se regulan por Ley Ordinaria, conforme al mandato constitucional.", "Se regulan por Ley Orgánica, conforme al mandato constitucional.", "Se regulan en la propia Constitución, en el Título Preliminar."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los sindicatos de trabajadores:', '["Contribuyen junto con las asociaciones de empresarios a la defensa y promoción de los intereses económicos y sociales que le son propios.", "Contribuyen en solitario a la promoción de los intereses sociales.", "Contribuyen a la defensa de sus exclusivos intereses económicos.", "Contribuyen junto a las asociaciones de empresarios a la defensa de los intereses sociales, pero no de naturaleza propia, sino general."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las demás lenguas de las respectivas Comunidades Autónomas:', '["Serán las únicas lenguas oficiales en las respectivas comunidades de acuerdo con sus Estatutos.", "Debe ser conocidas y empleadas por todos los españoles que residan o visiten la comunidad autónoma afectada.", "Serán también oficiales en las respectivas comunidades autónomas de acuerdo con sus Estatutos.", "Son oficiales también el resto del Estado."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La forma política del Estado es:', '["El Parlamentarismo Bicameral.", "La Monarquía Parlamentaria.", "El Parlamentarismo Democrático.", "La Monarquía Institucional."]'::jsonb, 1, 'es'),
    ('87715a4750c94339b4ba74aa163ff884', 'Los Tribunales de Honor:', '["Se prohíben en el ámbito de la Administración Militar.", "Se prohíben por el art. 25.4 de la Constitución española.", "Se prohíben en el ámbito de las organizaciones profesionales.", "Permanecen vigentes tras la aprobación de la Constitución española."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Defensor del Pueblo:', '["Es designado por el Congreso de los Diputados, dando cuenta de su actividad al Rey.", "Es designado por las Cortes Generales, a las que dará cuenta.", "Es designado por el Gobierno de la Nación, al que dará cuenta.", "Es designado por el Rey, dando cuenta de su actividad a las Cortes Generales."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las prestaciones personas o patrimoniales de carácter público:', '["Podrán establecerse, según afirma nuestra Constitución, en cualquier caso.", "No podrán establecerse, en ningún caso.", "Podrán establecerse con arreglo a la Ley.", "Sólo podrán establecerse en los casos concretos determinados por la Constitución."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El derecho a sindicarse libremente:', '["El ejercicio de tal derecho por parte de los funcionarios no presenta peculiaridad alguna.", "Lo tienen todos los trabajadores.", "Podrá ser limitado, o exceptuado, a las Fuerzas Armadas.", "No podrá ser restringido su ejercicio a otros cuerpos aunque estén sometidos a la disciplina militar."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿De quién recibe órdenes el Defensor del Pueblo?', '["De las Cortes Generales.", "No está sometido a mandato imperativo.", "De los Tribunales.", "Del Gobierno."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En relación con el derecho a la libertad religiosa', '["La reconoce, la garantiza y la protege.", "La reconoce.", "La garantiza.", "La reconoce y la garantiza."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En cuanto a la religión estatal:', '["Es la religión católica la confesión oficial del Estado español.", "Ninguna confesión religiosa tiene carácter estatal.", "El Estado ostenta como religiones oficiales la católica, la protestante, la islámica y la judía.", "La Constitución no establece precepto alguno que imponga a los poderes públicos la necesidad de mantener relaciones de cooperación con iglesia alguna."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es el tiempo máximo de duración de la detención preventiva?', '["36 horas.", "48 horas.", "72 horas.", "24 horas."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El ejercicio, por ejemplo, del derecho a expresar opiniones por escrito:', '["No puede restringirse mediante ningún tipo de censura previa.", "Puede restringirse mediante censura previa por parte de los organismos oficiales en los casos en los que esté en peligro la seguridad nacional.", "Sólo puede restringirse mediante censura previa cuando la opinión sea vertida a través de los medios de comunicación del Estado.", "Puede restringirse mediante censura previa cuando los destinatarios de la opinión sean menores de edad."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Constitución dedica a la Corona el Título:', '["I.", "II.", "III.", "IV."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Constitución, las abdicaciones y renuncias a la Corona, ¿cómo se resolverán?', '["Por las Cortes Generales en sesión conjunta de ambas Cámaras.", "Mediante una ley orgánica, si plantean dudas de hecho o Derecho.", "Mediante el mecanismo previsto en la Constitución.", "Mediante una ley orgánica."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué tratamiento recibe el Consorte de la Reina?', '["Excelentísimo.", "Majestad.", "Alteza Real.", "Alteza."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién debe reconocer la imposibilidad del Rey para ejercer sus funciones?', '["El Gobierno.", "La Familia Real.", "El Congreso de los Diputados.", "Las Cortes Generales."]'::jsonb, 3, 'es'),
    ('d8328ce402b7f69a855c4d8b91460daa', 'Respecto a los actos del Rey, ¿cuál de las siguientes alternativas es correcta?', '["Los refrenda el Presidente del Gobierno, los Ministros, en su caso, y el Presidente del Congreso de los Diputados en la disolución del art. 99.", "Los actos no necesitan ser refrendados.", "Es responsable el Rey de sus propios actos.", "Los refrenda el Presidente del Gobierno y, en su caso, los Ministros correspondientes."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién concede indultos generales?', '["El Rey.", "El Presidente del Gobierno.", "No se pueden conceder.", "El Presidente del Tribunal Supremo."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En caso de que el rey sea menor de edad:', '["Ejercerá la Regencia el Príncipe Heredero.", "Ejercerá la Regencia su cónyuge.", "Ninguna de las otras respuestas en válida.", "No tomará cargo de su cargo hasta su mayoría de edad."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién nombra a los miembros de la Casa Real?', '["El Jefe de la Casa Real.", "El Rey.", "El Ministro del Interior.", "El Presidente del Gobierno."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Existe algún acto del Rey que pueda realizarse sin refrendo?', '["Sí, la designación de su Sucesor.", "Sí, los relacionados con la Casa Real y la distribución del Presupuesto de la misma.", "Sí, los relacionados con nombramientos constitucionales.", "No."]'::jsonb, 1, 'es'),
    ('f4f854fbb239510c6688b54af5969668', '¿Qué carácter tiene la Corona de España, a tenor del artículo 57.1 de la Constitución?', '["Constitucional.", "Prioritaria.", "Hereditaria.", "Formal."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes no es un órgano interno de las Cámaras?', '["La Comisión de Plenos.", "El Presidente de la Cámara.", "Las Comisiones.", "El Pleno."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las elecciones tendrán lugar:', '["Entre treinta y noventa días después de que termine el mandato.", "60 días después de terminar el mandato.", "30 días después de terminar el mandato.", "Entre treinta y sesenta días después de que termine el mandato."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es el número mínimo de Senadores necesario para constituir Grupo Parlamentario en el Senado?', '["15 Senadores.", "18 Senadores.", "10 Senadores.", "20 Senadores."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'No puede delegarse por el Pleno del Congreso en una Comisión Legislativa Permanente del mismo la aprobación de:', '["Todas las otras respuestas son válidas.", "Decretos-Leyes.", "Proyectos de Ley.", "Proposiciones de Ley."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿De qué órgano constitucional depende el Tribunal de Cuentas?', '["Del Gobierno.", "Del Tribunal Supremo.", "Del Congreso de los Diputados.", "De las Cortes Generales."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Sobre la cuestión de confianza planteada por el Presidente del Gobierno de la Nación debe pronunciarse el/las:', '["Propio Gobierno.", "Mismo Presidente.", "Congreso.", "Cortes Generales."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En cuál de estas materias cabe delegación de las Cámaras en las Comisiones Legislativas Permanentes?', '["Reforma constitucional.", "Aprobación de los Presupuestos Generales del Estado.", "Aprobación de leyes tributarias.", "Cuestiones internacionales."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'De cuántos Diputados se compone el Congreso:', '["De un máximo de 600 y de un mínimo de 500.", "De un máximo de 400 y de un mínimo de 300.", "De un máximo de 350 y de un mínimo de 200.", "De un máximo de 1.000 y de un mínimo de 700..."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La elección de los Diputados se verificará en cada circunscripción atendiendo a criterios de:', '["Representación indirecta.", "Representación proporcional.", "Representación directa.", "Representación redistributiva."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La aprobación, modificación o derogación de las leyes orgánicas exigirá:', '["La mayoría absoluta de Congreso y Senado.", "La mayoría absoluta del Congreso.", "La mayoría de dos tercios de Congreso y Senado.", "La mayoría de dos tercios del Congreso."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes órganos indicados es un órgano superior de un departamento ministerial?', '["El Director General", "El Secretario General Técnico", "El Secretario de Estado", "El Secretario General."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Si, estando disuelto el Congreso, se produjere alguna de las situaciones que dan lugar a la declaración de alguno de los estados de anormalidad de la vida constitucional:', '["Quedan automáticamente convocadas las Cámaras.", "Se convocará al Congreso y se reunirá éste en el plazo máximo de un mes.", "El Presidente del Congreso ejerce las competencias propias del Congreso.", "La Diputación Permanente del Congreso será la que actúe."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La estructura orgánica de la Presidencia del Gobierno se aprueba por:', '["Ley.", "Consejo de Ministros.", "Presidente del Gobierno.", "Ministro de la Presidencia."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Ante quién responde solidariamente el Gobierno de su gestión política?', '["Ante las Cortes Generales", "Ante el Rey", "Ante el pueblo español", "Ante el Congreso de los Diputados."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En la primera votación, para ser nombrado Presidente del Gobierno deberá ser otorgada por la Cámara correspondiente la confianza:', '["Por mayoría absoluta.", "Por mayoría simple.", "Por mayoría de dos tercios.", "Por mayoría de tres quintos."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Si la acusación contra el Presidente o contra los demás miembros del Gobierno fuere por traición o por cualquier delito contra la seguridad del Estado en el ejercicio de sus funciones:', '["Deberá ser aprobada por mayoría absoluta del Congreso, al margen del número de sus miembros que lo haya propuesto.", "Sólo podrá ser planteada por la tercera parte de los miembros del Congreso.", "Deberá ser aprobada por mayoría absoluta del Congreso, tras propuesta realizada por la parte de sus miembros que corresponde.", "Sólo podrá ser planteada por la cuarta parte de los miembros del Congreso y del Senado."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de las siguientes funciones no le corresponde ejercer al Presidente del Gobierno?', '["Ante la Sala de lo Penal de la Audiencia Provincial de Madrid.", "Ante la Sala de lo Penal de la Audiencia Nacional.", "Ante la Sala de lo Penal del Tribunal Superior de Justicia de Madrid.", "Ante la Sala de lo Penal del Tribunal Supremo."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuántos Vicepresidentes deben existir en la composición del Gobierno?', '["Tres", "Uno", "Ninguno", "Dos."]'::jsonb, 2, 'es'),
    ('2a4ba259076b977b77507b8216bd6b29', '¿Qué Título de la Constitución está dedicado a la regulación del Gobierno?', '["El Título III", "El Título IV", "El Título V", "El Título VII."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La suplencia de un Ministro para el despacho ordinario de los asuntos de su competencia se determina por el:', '["Presidente del Gobierno.", "Vicepresidente Primero del Gobierno.", "Consejo de Ministros.", "Propio Ministro."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Disuelto el Congreso, o expirado su mandato, si se produjere alguna de las situaciones que dan lugar a cualquiera de los estados de alarma, excepción o sitio:', '["Las competencias del Congreso serán asumidas por el Gobierno de la Nación.", "Quedarán automáticamente convocadas las Cámaras, sin que hasta su constitución asuma organismo alguno sus competencias en esta materia.", "Todas las otras respuestas son falsas.", "Las competencias del Congreso serán asumidas por su Diputación Permanente."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La disolución de las Cámaras será decretada:', '["Por el Rey.", "Por el Presidente del Congreso.", "Por el Presidente del Gobierno.", "Por el Gobierno de la Nación."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Cámaras y sus Comisiones podrán recabar la información y ayuda que precisen:', '["A través de sus Presidentes y sólo del Gobierno y de sus Departamentos.", "La información y ayuda de las Comunidades Autónomas sólo podrá ser recabada por los Parlamentos autónomos y sus Comisiones.", "A través de la Mesa o los portavoces, del Gobierno, de sus Departamentos y de cualesquiera autoridades del Estado.", "La información y ayuda será recabada por los Presidentes, incluso de las Comunidades Autónomas"]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los signatarios de la moción de censura planteada, caso de ser rechazada la misma:', '["No podrán presentar otra durante la misma legislatura.", "No podrán presentar otra antes de que transcurran seis meses desde que fue presentada la primera.", "No podrán presentar otra durante el mismo periodo de sesiones.", "No podrán presentar otra antes de que transcurra un año desde que se haya votado el rechazo de la primera."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La moción de censura no podrá ser votada hasta que, desde su presentación, hayan transcurrido:', '["Cinco días.", "Diez días.", "Tres días.", "Quince días."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El ámbito territorial, duración y condiciones del estado de sitio serán determinados por:', '["Las Cortes Generales.", "El Congreso.", "El Rey.", "El Gobierno."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los estados de alarma, excepción y sitio, así como las competencias y limitaciones correspondientes:', '["Están regulados plenamente en la Constitución, sin que sea preciso su desarrollo legal en disposición distinta.", "Podrán ser regulados por Ley Ordinaria, sólo en lo relativo a competencias.", "Se regularán, por mandado constitucional, mediante Ley Orgánica.", "Podrán ser reguladas incluso por Decreto Ley, en caso de extraordinaria y urgente necesidad."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los miembros del Gobierno, por su parte:', '["Podrán solicitar que informen miembros de sus Departamentos ante las cámaras y sus Comisiones.", "No tienen facultad para hacerse oír en ellas.", "Tienen acceso limitado a las sesiones de las Cámaras y de sus Comisiones.", "Podrán obligar a las Comisiones, no a las Cámaras, a admitir que informen ante ellas funcionarios de sus Departamentos."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Al ser órgano deliberante la Comisión de Asistencia al Subdelegado del Gobierno:', '["Decide en las materias en que intervenga.", "Sólo asesora al Subdelegado del Gobierno en la provincia.", "Debe estar integrado por funcionarios, en su condición de tales.", "Vincula al Subdelegado del Gobierno con sus informes."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Una de las siguientes afirmaciones no es cierta:', '["Los Jueces y Magistrados son independientes, inamovibles e irresponsables.", "Los Jueces y Magistrados integran el Poder Judicial.", "Los Jueces y Magistrados únicamente están sometidos al imperio de la Ley.", "La justicia emana del pueblo, y se administra en nombre del Rey."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes órganos no forma parte de la composición del Consejo General del Poder Judicial?', '["La Comisión de Igualdad.", "La Comisión Permanente.", "La Comisión de Estudios.", "La Comisión Disciplinaria."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Presidente del Tribunal Supremo:', '["Será simultáneamente Presidente del Tribunal Constitucional.", "Será nombrado por el Consejo General del Poder Judicial a propuesta del Congreso de los Diputados.", "Será nombrado por el Rey a propuesta del Gobierno.", "Será nombrado por el Rey a propuesta del Consejo General del Poder Judicial."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de las siguientes es la Ley Orgánica del Poder Judicial?', '["La LO 6/ 1985, de 1 de julio.", "La LO 6/ 1984, de 21 de julio.", "La LO 6/ 1985, de 11 de julio.", "La LO 6/ 1984, de 1 de julio."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La constitución, funcionamiento y gobierno de los Juzgados y Tribunales, se determinará, según la Constitución:', '["Por medio de la ley orgánica de Juzgados y Tribunales.", "Por medio de la ley orgánica del poder judicial.", "Por medio de la ley orgánica de la Administración de Justicia.", "Por medio de la ley del poder judicial."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién nombra al Fiscal General del Estado?', '["El Rey, a propuesta del Congreso, oído el Consejo General del Poder Judicial.", "El Rey, a propuesta del Gobierno, oído el Consejo General del Poder Judicial.", "El Rey, a propuesta del Tribunal de Cuentas, oído el Consejo General del Poder Judicial.", "El Rey, a propuesta del Tribunal Constitucional, oído el Consejo General del Poder Judicial."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El régimen de incompatibilidades de los miembros del poder judicial deberá asegurar:', '["Todas las otras respuestas son correctas.", "La total austeridad de los mismos.", "La total dedicación de los mismos.", "La total independencia de los mismos."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes Tribunales o Juzgados no existe?', '["Juzgado de Paz", "Juzgado de lo Penal", "Juzgado de Instrucción", "Magistratura de Trabajo."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Ministerio Fiscal ejerce sus funciones:', '["Conforme a los principios de unidad de poder e independencia jerárquica.", "Conforme a los principios de independencia y unidad jurisdiccional.", "Conforme a los principios de unidad de actuación y dependencia jerárquica.", "Conforme al principio de unidad jurisdiccional."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cómo se realiza el nombramiento del Presidente del Consejo General del Poder Judicial?', '["Por Ley ordinaria", "Por Decreto", "Por Orden Ministerial", "Por Real Decreto."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Uno de los siguientes bienes no es de dominio público estatal según la Constitución:', '["La zona marítimo terrestre.", "Los recursos naturales de la zona económica.", "El mar meridional.", "La plataforma continental."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Estado, mediante Ley, podrá planificar la actividad económica general:', '["Para equilibrar y armonizar el desarrollo nacional y sectorial.", "Para lograr la más justa distribución de la renta y la riqueza.", "Para atender a las necesidades de cada sector.", "Para estimular el crecimiento de la calidad de vida."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las cuentas del Estado y del Sector público:', '["Se rendirán a las Cortes Generales, que las censurará.", "Se rendirán al Tribunal de Cuentas, que las censurará.", "Se rendirán a las Cortes Generales y serán censuradas por el Tribunal de Cuentas.", "Todas las otras respuestas son falsas."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Gobierno elaborará los proyectos de planificación:', '["De acuerdo con el asesoramiento y colaboración del Tribunal de Cuentas.", "Al margen de la opinión de las organizaciones sindicales.", "De acuerdo con los informes vinculantes emitidos por las asociaciones empresariales.", "De acuerdo con las previsiones que le sean suministradas por las comunidades Autónomas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La potestad para establecer los tributos:', '["Corresponde originariamente a los Municipios.", "Corresponde originariamente al Estado.", "Corresponde originariamente a las Comunidades Autónomas.", "Corresponde originariamente, y según el tipo de tributo, tanto a los Municipios como al Estado."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El régimen jurídico de los bienes de dominio público y de los comunales se inspirará, entre otros, en el principio de:', '["Prescribilidad.", "Alienabilidad.", "Desafectación de los mismos.", "Embargabilidad."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Una de las siguientes afirmaciones no es correcta. El Tribunal de Cuentas:', '["Es el supremo órgano fiscalizador de las cuentas del sector público.", "Es el supremo órgano fiscalizador de la gestión económica del sector público.", "Es el supremo órgano contable de las cuentas del Estado.", "Es el supremo órgano fiscalizador de la gestión económica del Estado."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La composición, organización y funciones del Tribunal de Cuentas vendrá determinada mediante una:', '["Decreto legislativo.", "Ley ordinaria.", "Ley de bases.", "Ley orgánica."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Ley de Presupuestos:', '["No puede modificar tributos.", "Puede crear tributos.", "Podrá modificar tributos cuando una ley tributaria adjetiva así lo provea.", "No podrá crear tributos."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Título Séptimo de la Constitución finaliza en el artículo:', '["133.", "134.", "136.", "135"]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cómo se denomina generalmente, al órgano de gobierno de la Comunidad Autónoma?', '["Consejo.", "Consejo de Gobierno.", "Consejo ejecutivo.", "Consejo colegiado."]'::jsonb, 1, 'es');

  -- Batch 401-600
  insert into public.question_bank (content_hash, question, options, correct_index, lang)
  values
    ('4b830eab8fe6b21a82865850ecac45f6', 'Se reconoce autonomía en la Constitución española a:', '["A las nacionalidades y comunidades autónomas", "A las regiones y a las nacionalidades", "A las regiones", "A las comunidades autónomas y a las regiones."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El plazo de ampliación inicial de competencias era de:', '["Cinco años", "Tres años", "Cuatro años", "Dos años."]'::jsonb, 0, 'es'),
    ('44cc9e46336e3d76940017f17f9a8879', '¿Qué artículos de la Constitución recogen las vías de acceso a la autonomía, de los indicados a continuación?', '["Art. 143 y art. 151.", "Art. 146 y 157.", "Art. 153 y 151.", "Art. 144 y art. 143."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Por qué tipo de sufragio se elige a los Diputados autonómicos?', '["Por sufragio universal igual, libre, directo y secreto, en la forma establecida por el derecho", "Por sufragio universal igual, libre, directo y secreto, en la forma establecida por la Constitución", "Por sufragio universal igual, libre, directo y secreto, en la forma establecida por el Gobierno", "Por sufragio universal igual, libre, directo y secreto, en la forma establecida por la ley."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las competencias exclusivas del Estado se recogen en la Constitución en su artículo:', '["151", "150", "149", "151."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En los Estatutos aprobados por el procedimiento al que nos venimos refiriendo, la organización institucional se basará en una Asamblea Legislativa:', '["Elegida por sufragio universal.", "Todas las otras respuestas son ciertas.", "Dicho sufragio universal deberá efectuarse con arreglo a un sistema de representación proporcional.", "Dicho sistema proporcional deberá asegurar la representación de las diversas zonas del territorio."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Respecto de una de las siguientes materias, por ser exclusiva del Estado, no podrán ser asumidas competencias, en principio, por las Comunidades Autónomas:', '["Regulación de las condiciones de obtención, expedición y homologación de títulos académicos.", "Patrimonio monumental de interés de la Comunidad Autónoma.", "Ferias interiores.", "Aguas minerales y termales."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En qué año se firmaron los pactos Autonómicos?', '["1994.", "1991.", "1992.", "1993."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La organización judicial en el ámbito de la Comunidad Autónoma, estará culminada:', '["Por un Tribunal Superior de Justicia, sin perjuicio de la jurisdicción que corresponde al Tribunal Supremo.", "Por un Tribunal Superior de Justicia, que asumirá en el ámbito territorial de la Comunidad Autónoma la jurisdicción que sobre el mismo ostentaba el Tribunal Supremo.", "Por una Audiencia Territorial, sin perjuicio de la jurisdicción que corresponde al Tribunal Supremo.", "Por las respectivas Audiencias Provinciales, sin perjuicio de la jurisdicción que corresponde al Tribunal Supremo."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuántos miembros componen el Pleno del Tribunal Constitucional?', '["Once.", "Doce.", "Diez.", "Catorce."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuántos miembros del Tribunal Constitucional son nombrados a propuesta del Pleno del Consejo General del Poder Judicial?', '["Cuatro.", "Dos.", "Cinco.", "Tres."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las sentencias dictadas por el Tribunal Constitucional:', '["Tienen valor de cosa juzgada a partir del día siguiente a su publicación.", "Tienen valor de cosa juzgada a partir del día siguiente al de su notificación.", "No tienen valor de cosa juzgada.", "Tienen valor de cosa juzgada a partir del día siguiente al que se dicten."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Uno de los siguientes colectivos no podrá proporcionar miembros al Tribunal Constitucional:', '["Funcionarios Públicos.", "Profesores de Universidad.", "Abogados.", "Jueces."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Título Noveno de la Constitución finaliza en el artículo:', '["162.", "161.", "163.", "165."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El funcionamiento del Tribunal Constitucional, y demás cuestiones vinculadas al mismo, están reguladas, por mandato constitucional a través:', '["De una ley orgánica.", "Consta tal normativa en la propia Constitución.", "De una ley de bases.", "De una ley ordinaria."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los miembros del Tribunal Constitucional se renovarán:', '["Por cuartas partes cada dos años.", "Por terceras partes cada tres años.", "Por mitades cada tres años. íntegramente cada nueve años.", ""]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'No está/n legitimado/s para interponer recurso de amparo:', '["Toda persona jurídica que invoque interés legítimo.", "El Ministerio Fiscal.", "El Defensor del Pueblo.", "Las Asambleas legislativas de las Comunidades Autónomas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Para que la cuestión de inconstitucionalidad pueda ser interpuesta, será preciso:', '["Que la norma tenga rango de Ley Orgánica.", "Que la norma, a criterio del órgano judicial, sea o no aplicable al caso, vulnere la Constitución.", "Todas las otras respuestas son correctas.", "Que de la validez de tal norma dependa el fallo."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los miembros del Tribunal Constitucional, en el desempeño de su mandato:', '["Serán independientes y responsables.", "Serán independientes e inamovibles.", "Serán inamovibles e irresponsables.", "Serán irresponsables e independientes."]'::jsonb, 1, 'es'),
    ('81b4196a9a98f87bf76f9a564d328a4d', 'El artículo 1.1 de la Constitución Española de 1978 propugna como valores superiores de su ordenamiento jurídico la libertad, la justicia, la igualdad y el pluralismo político. Estos valores:', '["Tienen valor meramente declarativo.", "Tienen carácter normativo.", "Suponen una mera declaración retorica.", "Carecen de valor normativo alguno."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En qué fecha se aprobó en referéndum el texto constitucional?.', '["El 31 de octubre de 1978.", "El 6 de diciembre de 1978.", "El 27 de diciembre de 1978.", "El 29 de diciembre de 1978."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'De los siguientes derechos fundamentales, podrán ser suspendidos cuando se acuerda la declaración del estado de excepción, en los términos previstos en la Constitución Española:', '["El derecho de asociación.", "El derecho de sindicación.", "La inviolabilidad del domicilio.", "El derecho a asistencia letrada."]'::jsonb, 2, 'es'),
    ('17701fa7464e882e55b72f1614866155', 'El artículo 31.1 de la Constitución Española dispone que todos contribuirán al sostenimiento de los gastos públicos de acuerdo con su capacidad económica mediante un sistema tributario justo inspirado en los principios de:', '["Igualdad y progresividad, que en ningún caso, tendrán alcance confiscatorio.", "Igualdad y solidaridad, que en ningún caso, tendrán alcance confiscatorio.", "Legalidad y solidaridad, que en ningún caso, tendrán alcance confiscatorio.", "Proporcionalidad y legalidad, que en ningún caso, tendrán alcance confiscatorio."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La solicitud de referéndum deberá efectuarse:', '["Dentro de ese mismo plazo, pero a partir de la sanción y promulgación real de la misma.", "Dentro de los quince días siguientes a la aprobación de la reforma por las Cortes Generales.", "Dentro de los diez días siguientes a la publicación de la reforma en el Boletín Oficial del Estado.", "Nunca se celebrará referéndum en este supuesto."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Aprobada la reforma por las Cortes Generales:', '["Será sometida a referéndum para su ratificación.", "El Rey la sancionará, promulgándose a continuación.", "Será sometida a control previo de constitucionalidad del Tribunal Constitucional.", "Será sometida a dictamen del Consejo de Estado."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Cuando se propusiere la revisión total de la Constitución, se procederá a la aprobación del principio:', '["Por mayoría de tres quintos de cada Cámara.", "Por mayoría de dos tercios de ambas Cámaras reunidas en sesión conjunta.", "Por mayoría de dos tercios de cada Cámara.", "Por mayoría absoluta de cada Cámara."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La iniciativa de reforma constitucional:', '["Sólo corresponderá al Gobierno.", "Sólo corresponderá al Congreso y al Senado.", "Se ejercerá en los mismos términos que la iniciativa legislativa. No podrá corresponder en ningún caso, ni directa ni indirectamente, a las Comunidades Autónomas.", ""]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El nuevo texto analizado por las Cámaras recién elegidas, deberá ser aprobado:', '["Por mayoría absoluta de ambas Cámaras.", "Todas las otras respuestas son falsas.", "Por mayoría de tres quintos de ambas Cámaras.", "Por mayoría de dos tercios de ambas Cámaras."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Finalmente, la Constitución contenía un mandato para que fuese guardada y hecha guardar dirigido a:', '["Todos los españoles y residentes en España.", "Todas las autoridades de España.", "Todos los particulares del Estado.", "Todos los españoles, particulares y autoridades."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'También consideró nuestra Constitución definitivamente derogada la Ley de 25 de octubre de 1839:', '["En lo que pudiera afectar a las provincias catalanas.", "En lo que pudiera afectar a Álava, Guipúzcoa y Vizcaya.", "En lo que pudiera afectar a Navarra.", "En lo que pudiere afectar a Gibraltar, Ceuta y Melilla."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El proyecto de Estatuto de los territorios que en el pasado hubieran plebiscitado afirmativamente proyectos de Estatuto de autonomía, se tramitaron en su día de acuerdo con lo establecido en el artículo:', '["148.1 de la Constitución.", "151.2 de la Constitución.", "151.1 de la Constitución.", "148.2 de la Constitución."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La actualización del régimen foral:', '["No se producirá en caso alguno, al haber sido derogados los derechos forales históricos por la Constitución.", "Se llevará a cabo sólo en el marco de los Estatutos de Autonomía.", "Se llevará a cabo al margen del marco Constitucional.", "Se llevará a cabo, en su caso, en el marco de la Constitución y de los Estatutos de Autonomía."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En los territorios dotados de un régimen provisional de autonomía, la iniciativa autonómica atribuida a las Diputaciones Provinciales o a los órganos interinsulares correspondientes:', '["Se asumió por sus órganos colegiados superiores.", "Pudo ser sustituida por acuerdo de sus órganos colegiados superiores.", "Tal acuerdo al que se refiere la opción debió haberse adoptado por mayoría de tres quintos de sus miembros.", "Se sustituyó por acuerdo del Consejo Provisional de Gobierno."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La declaración de la mayoría de edad contenida en el artículo doce de la Constitución:', '["Deroga las situaciones amparadas por los derechos forales en el ámbito del Derecho Privado.", "Todas las otras respuestas son falsas.", "No perjudica dichas situaciones.", "Traslada dichas situaciones y las ampara en el ámbito del Derecho Privado Estatal."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'A los tres años de la elección por vez primera de los miembros del Tribunal Constitucional:', '["Se procederá a la renovación y designación de cuatro de sus miembros, por sorteo.", "Se procederá a su íntegra renovación.", "Se procederá a tal renovación, cesando los cuatro miembros más jóvenes.", "Se procederá a tal renovación, cesando los cuatro miembros de mayor edad."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En las Comunidades Autónomas donde tengan su sede más de una Audiencia Territorial, hoy Tribunales Superiores de Justicia, los Estatutos de Autonomía respectivos:', '["Transformarán en Audiencias Provinciales todas las existentes, menos una.", "Podrán mantener las existentes, pero acumulando en una de ellas todas las competencias.", "Podrán mantener las existentes.", "Deberán mantener las existentes."]'::jsonb, 2, 'es'),
    ('e7635585740de7b10b819c221029a513', 'La Constitución Española:', '["No contiene una disposición derogatoria genérica.", "Contiene una disposición derogatoria genérica.", "La disposición derogatoria genérica está referida a las leyes que se opongan al contenido del Título Preliminar.", "La disposición derogatoria genérica está referida a las normas que se opongan al contenido de los Títulos Primero y Segundo."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El texto constitucional fue firmado en el Palacio de las Cortes por el Rey y el resto de autoridades:', '["El 29 de diciembre de 1978.", "El 28 de diciembre de 1978.", "El 27 de diciembre de 1978.", "El 26 de diciembre de 1978."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Título Segundo de la Constitución Española está dedicado a:', '["Los Derechos y Deberes fundamentales.", "Las Cortes Generales.", "El Gobierno y la Administración.", "La Corona."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Título Décimo de la Constitución Española tiene:', '["Cuatro artículos.", "Siete artículos.", "Cinco artículos.", "Seis artículos."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Título Quinto de la Constitución Española tiene:', '["Once artículos.", "Nueve artículos.", "Diez artículos.", "Ocho artículos."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Título en el que la Constitución regula los Tratados Internacionales es el:', '["Segundo.", "El Quinto.", "El Cuarto.", "El Tercero."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Disposición Final de la Constitución Española contiene:', '["Cinco apartados.", "Tres apartados.", "Todas las otras respuestas son falsas.", "Cuatro apartados"]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Por su parte, al Tribunal Constitucional, se dedica el Título:', '["Ninguno.", "Décimo.", "Octavo.", "Noveno."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La firma por parte del Jefe del Estado, el Presidente de las Cortes Generales, y los Presidentes del Congreso de los Diputados y del Senado de la Constitución Española de 1978, se produjo en el Palacio de las Cortes:', '["El veintisiete de diciembre de 1978.", "El veintiocho de diciembre de dicho año.", "El uno de enero de 1979.", "Todas las otras respuestas son falsas."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Título Undécimo de la Constitución Española está dedicado a:', '["No existe el título undécimo en la Constitución Española.", "La organización territorial del Estado.", "El Tribunal Constitucional. La reforma constitucional.", ""]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En la Constitución Española:', '["Algunos Títulos están divididos en Secciones.", "En todos los Títulos existen Capítulos divididos a su vez en Secciones.", "Algunos Títulos están divididos en Capítulos.", "Todos los Títulos están divididos en Capítulos."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Título en el que la Constitución regula la elaboración de las leyes es el:', '["27 de diciembre de 1978.", "31 de octubre de 1978.", "1 de enero de 1979.", "29 de diciembre de 1978."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los derechos y deberes de los ciudadanos se encuentran regulados en nuestra Constitución:', '["En la Sección Segunda del Capítulo Segundo del Título Primero.", "En la Sección Segunda del Capítulo Primero del Título Segundo.", "En la Sección Primera del Capítulo Primero del Título Preliminar.", "En la Sección Primera del Capítulo Segundo del Título Primero."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Título Décimo de la Constitución Española está dedicado a:', '["La organización territorial del Estado.", "Las relaciones entre el Gobierno y las Cortes Generales.", "La reforma constitucional.", "El Tribunal Constitucional."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Título Noveno de la Constitución Española tiene:', '["Cinco artículos.", "Siete artículos.", "Seis artículos.", "Cuatro artículos."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La autoridad para prohibir una manifestación en capital de provincia es el:', '["Juez de Instrucción.", "Subdelegado del Gobierno en la Provincia.", "Delegado de Gobernación de la Comunidad Autónoma respectiva", "Alcalde."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Título en el que la Constitución se pronuncia sobre la suspensión de derechos y libertades de los ciudadanos es el:', '["Primero.", "Décimo.", "Preliminar.", "Sexto."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Título en el que la Constitución regula la Administración Local es el:', '["Octavo.", "Séptimo.", "Quinto.", "Sexto."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Título Séptimo de la Constitución Española tiene:', '["Once artículos.", "Ocho artículos.", "Diez artículos.", "Nueve artículos."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El pueblo español ratificó la Constitución en referéndum celebrado:', '["El 7 de diciembre de 1978.", "El 4 de diciembre de 1978.", "El 5 de diciembre de 1978.", "El 6 de diciembre de 1978."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Cuando la Constitución Española fue aprobada, el Presidente del Congreso de los Diputados era:', '["Félix Pons.", "Landelino Lavilla.", "Leopoldo Torres Esquivias.", "Fernando Álvarez de Miranda y Torres."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Constitución Española de mil novecientos setenta y ocho fue publicada en el Boletín Oficial del Estado:', '["De 28 de diciembre de 1978.", "De 27 de diciembre de 1978.", "De 29 de diciembre de 1978.", "De 30 de diciembre de 1978..."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Cortes constituyentes aprobaron el texto constitucional en sesiones plenarias de ambas cámaras celebradas:', '["El 30 de octubre de 1978.", "El 1 de noviembre de 1978.", "El 3 de noviembre de 1978.", "El 31 de octubre de 1978..."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Título en el que la Constitución indica cuáles son las lenguas oficiales del Estado es:', '["El Segundo.", "El Primero.", "El Preliminar.", "El Tercero."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Título Primero de la Constitución Española está dedicado a:', '["Los Derechos y Deberes fundamentales.", "La Corona.", "El Poder Judicial.", "Las Cortes Generales..."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Disposiciones Adicionales en la Constitución Española son:', '["Cuatro.", "Una.", "Cinco.", "Nueve."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Título Segundo de la Constitución Española tiene:', '["Diez artículos.", "Nueve artículos.", "Once artículos.", "Ocho artículos."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Constitución Española fue aprobada siendo Presidente de las Cortes:', '["Félix Pons.", "Antonio Hernández Gil.", "Antonio Fontán Pérez.", "Fernando Álvarez de Miranda y Torres."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Título Quinto de la Constitución Española está dedicado a:', '["Economía y Hacienda.", "El Poder Judicial.", "Las relaciones entre el Gobierno y las Cortes Generales.", "El Gobierno y la Administración..."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Título Primero de la Constitución Española tiene:', '["Cuarenta y cuatro artículos.", "Cincuenta artículos.", "Cuarenta y seis artículos.", "Cuarenta y ocho artículos..."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En qué título de la Constitución se regula la suspensión de los derechos y libertades?', '["II.", "III.", "Preliminar.", "I..."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La soberanía nacional:', '["Reside en el Rey.", "Reside en el pueblo.", "Reside en los ciudadanos mayores de edad.", "Reside en el Congreso y en el Senado."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La lengua oficial del Estado es:', '["El español.", "El idioma autóctono en aquellas comunidades que gocen de lengua propia.", "El castellano en aquellas comunidades autónomas que no sean bilingües.", "El castellano."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Respecto a las nacionalidades y regiones que integran a la Nación Española, la Constitución les reconoce y garantiza:', '["El derecho a la solidaridad entre ellas, pero no el derecho a la autonomía políticamente entendida.", "El Derecho a su libre federación o confederación.", "El Derecho a la libre autodeterminación.", "El derecho a la autonomía."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La riqueza de las distintas modalidades lingüísticas de España:', '["Es un patrimonio político que no podrá vulnerar el principio de solidaridad entre las distintas nacionalidades y regiones.", "Es un patrimonio cultural que será objeto de especial respeto y protección.", "Es un patrimonio natural que deberá ser desarrollado exclusivamente por las Comunidades Autónomas afectadas.", "Es un patrimonio cultural cuya gestión corresponderá a Naciones Unidas."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Todos los españoles, con respecto al idioma oficial del Estado:', '["Tienen el deber de usarlo.", "Tienen el deber de conocerlo y el derecho de usarlo.", "Tienen el deber y el derecho de conocerlo.", "Tienen el deber y el derecho de usarlo."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Banderas y enseñas propias de las Comunidades Autónomas, reconocidas en sus Estatutos:', '["Se utilizarán junto con la española sólo en los actos oficiales de carácter estatal.", "Se utilizarán junto a la española en sus edificios públicos y en sus actos oficiales.", "La utilización conjunta de la bandera de España y la de cada Comunidad Autónoma es potestad de las autoridades de la administración autonómica.", "Se utilizarán en sustitución de la española en los edificios públicos oficiales propios de cada Comunidad."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Uno de los siguientes principios no está garantizado por la constitución:', '["El de jerarquía reglamentaria.", "El de irretroactividad de las disposiciones sancionadoras no favorables.", "El de publicidad de las normas.", "El de legalidad."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La estructura interna y el funcionamiento de los Partidos Políticos deberá ser:', '["Jerárquica.", "Estructurada.", "Democrática.", "Transparente."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La capital del Estado es la villa de:', '["Madrid, situada en la Comunidad Autónoma de Castilla León.", "Madrid, ubicada en la Comunidad Autónoma de Castilla La Mancha.", "Madrid, no perteneciente por tal motivo a Comunidad Autónoma alguna.", "Madrid, situada en la Comunidad Autónoma del mismo nombre."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Corresponde a los poderes públicos promover las condiciones para que la libertad y la igualdad del individuo y de los grupos en que se integra:', '["Se empleen por los ciudadanos dentro del respeto a la Constitución y las leyes.", "Alcancen el nivel más alto posible.", "Sean comunes a todos los miembros de la sociedad.", "Sean reales y efectivas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La bandera de España está formada por tres franjas, roja, amarilla y roja:', '["Verticalmente colocadas, siendo la amarilla de doble anchura que cada una de las rojas.", "Horizontalmente colocadas, siendo la roja de doble anchura que cada una de las amarillas.", "Horizontalmente colocadas, siendo las tres franjas de igual anchura.", "Horizontalmente colocadas, siendo la amarilla de doble anchura que cada una de las rojas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Sólo una de los siguientes principios está garantizado constitucionalmente:', '["La seguridad jurídica.", "La seguridad mercantil.", "La seguridad del tráfico.", "La seguridad ciudadana."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Constitución Española, nuestro país se ha constituido:', '["En una Monarquía democrática de Derecho.", "En un Estado social y democrático de Derecho.", "En una Nación socialdemocrática de Derecho.", "En un Estado respetuoso del Derecho y de la Democracia."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La creación y el ejercicio de la actividad de los Partidos Políticos', '["Es libre, dentro del respeto a la dignidad de las personas y de las instituciones públicas.", "Es libre, dentro del respeto a las reglas del juego democrático establecidas en la Ley reguladora de los Partidos Políticos.", "Es libre, dentro del respeto a la Constitución y a la Ley.", "Es libre, sin limitación de clase alguna."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los partidos políticos', '["Concurren a la formación de la voluntad institucional.", "Expresan el pluralismo ideológico en todos los campos.", "Son instrumento fundamental para la participación política.", "Participan en la manifestación de la voluntad de las agrupaciones políticas."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Corresponde a los podes públicos:', '["Afianzar los obstáculos que impidan un equivocado o desmesurado empleo de la libertad individual.", "Regular los cauces necesarios para alcanzar el disfrute por los ciudadanos de una seguridad plena.", "Facilitar la participación de los ciudadanos en la vida cultural y social.", "Facilitar la participación de los ciudadanos con capacidad en la vida política."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El principio de irretroactividad garantizado en la Constitución abarca:', '["A las disposiciones sancionadoras no favorables o restrictivas de derechos individuales.", "A todas las disposiciones legales de cualquier orden.", "A todas las normas de carácter penal.", "A las disposiciones sancionadoras, más aquellas que impongan penas privativas de libertad no superior a los seis años, o de multa cualquiera que fuese su cuantía."]'::jsonb, 0, 'es'),
    ('f2b1d0058935cd2de44729c198f92a7b', 'Según el artículo 18 de la Constitución Española de 1978, para entrar en un domicilio sin la autorización de su propietario es preciso:', '["Resolución judicial, salvo en caso de flagrante delito.", "Resolución judicial, salvo situación de emergencia con peligro para la vida e integridad física de las personas", "Resolución judicial, salvo supuestos de ocupación ilegal de la vivienda.", ""]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En el supuesto de declaración del estado de excepción o de sitio no puede ser suspendido el derecho de:', '["Secreto de comunicaciones.", "Huelga.", "Asociación.", ""]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En virtud de qué principio constitucional se predica que las diferencias entre los distintos Estatutos de Autonomía de las distintas CCAA, no podrán implicar privilegios económicos y sociales?', '["Principio de igualdad.", "Principio de no discriminación.", "Principio de solidaridad.", ""]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los Estatutos de Autonomía deberán contener (señale la incorrecta.:', '["La delimitación de su territorio", "La denominación, organización y sede de las instituciones del Estado en las que participa.", "Las competencias asumidas dentro del marco establecido en la Constitución y las bases para el traspaso de los servicios correspondientes a las mismas.", ""]'::jsonb, 1, 'es'),
    ('564f502bc59e577409dabd5e3c302caa', 'Según el artículo 58 del Estatuto de Autonomía de Aragón, el Consejo Consultivo de Aragón:', '["Depende orgánicamente del Departamento de Presidencia y Relaciones Instituciones.", "Está vinculado a la Cámara de Cuentas de Aragón.", "Ejerce sus funciones con autonomía orgánica y funcional.", ""]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué efecto tiene el refrendo?:', '["Confiere validez al acto refrendado", "Implanta la responsabilidad en el Rey", "Traslada la responsabilidad a las Cortes Generales", "Traslada la responsabilidad del acto, al Gobierno."]'::jsonb, 0, 'es'),
    ('28c562f4839afaef4b7d5af7d5a0b3d8', 'Según el artículo 103 de la Constitución Española, la Administración Pública actúa:', '["Con sometimiento pleno a la Constitución, a la ley y al Derecho.", "Con sometimiento pleno a la ley y al Derecho.", "Con sometimiento previo a la ley y al Derecho.", ""]'::jsonb, 1, 'es'),
    ('0e2f03652b13a7299db1a1ecb0d8028a', 'Según el artículo 30.3 de la Ley 39/2015, de 1 de octubre, del procedimiento administrativo común de las Administraciones Públicas, los plazos expresados en días se contarán a partir de:', '["El día siguiente a aquel en que tenga lugar la notificación o publicación del acto.", "El mismo día en que tenga lugar la notificación o publicación del acto.", "El día siguiente a aquel en que la Administración tenga constancia de la notificación o publicación del acto.", ""]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿La presentación de una denuncia ante la Administración confiere, por si sola, al denunciante la consideración de interesado en el procedimiento?', '["Si.", "No.", "Solo en los supuestos de defensa de derechos fundamentales.", ""]'::jsonb, 1, 'es'),
    ('4306b11ccdff5320e8d87fda3b90c64d', 'Según el artículo 140 de la Constitución Española, los municipios:', '["Tienen personalidad jurídica plena.", "Tienen personalidad jurídica limitada.", "Son entes administrativos descentralizados.", ""]'::jsonb, 0, 'es'),
    ('9dbcd2067cc5ed75443e66d05e1c6adc', 'La relación entre la Ley 7/1985, LRBRL y la Ley 7/1999, LALA, es la siguiente:', '["Es de jerarquía, la LALA está subordinada a la LRBRL y no la puede contradecir", "La ley estatal es una ley de Bases en el sentido del artículo 82.2 de la Constitución, siendo la LALA el resultado del texto articulado.", "La relación entre ambas leyes es de competencia de conformidad con los artículos 148 y 149 CE.", ""]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Existe algún acto del Rey que pueda realizarse sin refrendo?:', '["No", "Sí, la designación de su Sucesor", "Sí, los relacionados con la Casa Real y la distribución del Presupuesto de la misma", "Sí, los relacionados con nombramientos constitucionales."]'::jsonb, 2, 'es'),
    ('042c55dcf70f38c4dffc4220b47071c9', 'En el artículo 10.1 de la constitución podemos encontrar unos límites generales que afectan el ejercicio de los derechos fundamentales y libertades públicas que se reconocen en dicho texto normativo. En concreto uno de dichos límites es:', '["El respeto a las autoridades.", "No podrán exigirse en los supuestos de estados de alarma.", "El respeto al derecho de los demás.", ""]'::jsonb, 2, 'es'),
    ('95286aa824b18e8857c72287aa97cd4c', 'Los derechos fundamentales y libertades públicas, esta relacionados en nuestra constitución en la sección 1ª del título I, pero ¿entre qué artículos?', '["Entre el 15 y el 29.", "Entre el 16 y el 30.", "Entre el 14 y el 29.", ""]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'De acuerdo con la ley 2/2002, 11 noviembre, la participación de los ciudadanos en las labores de protección civil se hará:', '["Cuando estén adscritos a un plan de emergencia municipal, y aparezcan como voluntarios.", "Cuando tengan mayoría de edad.", "A partir de los 16 años.", ""]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes órganos ejerce la función ejecutiva?', '["Corona", "El Gobierno", "Senado", "Congreso."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Constitución Española determina la existencia de tres figuras de la Administración Local, obligatorias. Señale cuál de las siguientes no lo es:', '["Provincia", "La Región", "El Municipio", "La Isla."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Comunidades Autónomas, en su relación entre ellas, se pueden constituir en Federaciones de Comunidades Autónomas:', '["Sí, siempre y cuando se trate de Comunidades vecinas", "Sí, con la condición que no sean más de tres Comunidades", "Sí, mientras no se trate de Comunidades históricas", "Las Federaciones de Comunidades Autónomas estan expresamente prohibidas por la Constitución Española."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Estatuto de Autonomía es una ley:', '["Ordinaria", "Orgánica", "Marco", "De armonización."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La forma política del Estado Español es:', '["Unitaria y regionalizada", "Federal", "La monarquía parlamentaria", "La propia de un estado social y democrático."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El derecho de reunión requerirá autorización previa:', '["De la autoridad gubernativa", "De la autoridad judicial", "No necesitará autorización previa", "Sólo en los casos de reuniones de índole política."]'::jsonb, 2, 'es'),
    ('2b6edcfa0c4ac251d50667a54353381c', '¿Qué clase de derechos pueden protegerse a través del recurso de amparo?', '["Todos los contenidos en el capítulo segundo del título Primero de la Constitución.", "Los reconocidos en el artículo 14 y en la sección 1ª del Capítulo Segundo del título Primero y en el artículo 30 de dicho título.", "Cualquier clase de derechos o libertades públicas", "Tanto los derechos como los deberes fundamentales."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'De acuerdo con la Constitución Española, las entidades que forman parte de la organización territorial del Estado tienen la nota común de:', '["Autogobierno", "Independencia", "Autonomía", "Autofinanciación."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'De las siguientes respuestas, ¿Cuál de ellas no responde a una entidad supramunicipal según la Ley de Bases de Régimen Local?', '["La región", "Las mancomunidades voluntarias de municipios", "El área metropolitana", "La comarca."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En un municipio con 20.000 habitantes serán elegidos el siguiente número de concejales:', '["17", "13", "11", "9."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuáles son las Entidades Locales Territoriales, según la Ley de Bases de Régimen Local?', '["Municipios, provincias y entidades locales menores", "Municipios, provincial e islas", "Municipios, provincias y comarcas.", "Municipios y provincias."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Por quién es elegido el Alcalde?', '["Por los concejales exclusivamente", "Por los concejales o por los vecinos", "Por los vecinos exclusivamente", "Por los concejales o por los residentes."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La relación entre la Alcaldía y el Pleno del Ayuntamiento:', '["Es jerárquica siendo el Pleno el órgano superior de la Alcaldía", "Es jerárquica siendo el Alcalde el órgano superior del Pleno", "Carece de relación jerárquica.", "Tiene carácter de apoyo, corresponde al Pleno el informe de asuntos para la Resolución de la Alcaldía."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Es un órgano potestativo de los municipios de menos de 5.000 habitantes:', '["Pleno.", "Junta de Gobierno Local", "Comisión Especial de Cuentas.", "Teniente de Alcalde."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Constitución Española de 1978 entró en vigor:', '["Al día siguiente de su aprobación por las Cortes Generales", "Al día siguiente de su ratificación por el pueblo español por referéndum", "El día de su publicación en el Boletín Oficial del Estado", "A los veinte días de su publicación en el Boletín Oficial del Estado."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Como consecuencia de la doble naturaleza que tiene la provincia, ésta, además de ente local, es:', '["Administración territorial", "División territorial para la prestación de los servicios estatales", "Agrupación de municipios", "Parte integrante de las Comunidades Autónoma."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los empleados públicos se clasifican en:', '["Funcionarios de carrera, funcionarios interinos, personal laboral fijo", "Funcionarios de carrera, funcionarios interinos, personal laboral fijo y personal eventual", "Funcionarios de carrera, funcionarios interinos", "Todas son incorrectas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Dónde se encuentra la sede de la asociación del GCPHE (Grupo de ciudades Patrimonio de la humanidad de España.?', '["Toledo", "Córdoba", "Segovia", "Ávila."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En qué año se fundó el grupo de ciudades patrimonio de la humanidad de España?', '["Es jerárquica siendo el Pleno el órgano superior de la Alcaldía", "Es jerárquica siendo el Alcalde el órgano superior del Pleno", "Carece de relación jerárquica.", "Tiene carácter de apoyo, corresponde al Pleno el informe de asuntos para la Resolución de la Alcaldía."]'::jsonb, 2, 'es'),
    ('b3613a30125ec0ff5ac8b58c795a693c', 'En el Artículo 20 de la Constitución Española, se reconocen y protegen los derechos:', '["De reunión pacífica y sin armas, y de asociación.", "A participar en los asuntos públicos, directamente o por medio de representantes, libremente elegidos en elecciones periódicas por sufragio universal.", "A expresar y difundir libremente los pensamientos, ideas y opiniones mediante la palabra, el escrito o cualquier otro medio de reproducción.", "Ninguno de los anteriores."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El recurso de amparo para recabar la tutela de los derechos y libertades se presenta ante:', '["El Tribunal Supremo.", "El Tribunal Superior de Justicia de la comunidad autónoma donde su ejercicio haya sido privado", "Indistintamente ante cualquiera de los dos anteriores.", "El Tribunal Constitucional."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Constitución garantiza la autonomía de los municipios.', '["Estos no gozarán de personalidad jurídica plena.", "Estos gozarán de personalidad jurídica limitada. Su gobierno y administración corresponde a sus respectivos Ayuntamientos.", "Estos gozarán de personalidad jurídica plena. Su gobierno y administración corresponde a sus respectivos Ayuntamientos.", "Ninguna de las anteriores es cierta."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los poderes públicos pondrán en marcha mecanismos adecuados de:', '["Lucha para mejorar la calidad de vida de la población, salvo en materia de las distintas formas de contaminación.", "Lucha contra la desertificación, la deforestación y la erosión en Andalucía, realizarán planes de prevención de incendios forestales y extinción, pero no en cuanto a la recuperación medioambiental de las zonas afectadas.", "Lucha contra la desertificación, la deforestación y la erosión en Andalucía, pero no tendrán competencias en materias de prevención de incendios forestales y extinción, ni en la recuperación medioambiental de las zonas afectadas.", "Lucha contra la desertificación, la deforestación y la erosión en Andalucía, realizarán planes de prevención de incendios forestales y extinción, así como la recuperación medioambiental de las zonas afectadas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Son entidades locales territoriales:', '["Las áreas metropolitanas y las mancomunidades de municipios.", "Las comunidades autónomas.", "El municipio, la provincia y la Isla en los archipiélagos balear y canario.", "Tan solo los municipios."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las haciendas locales se nutren fundamentalmente, según la Constitución Española de:', '["Tributos propios, participación de los del Estado, comunidades autónomas y fondos europeos.", "Tributos propios y capacidad de venta de su patrimonio.", "Tributos propios, participación de los del Estado y de las comunidades autónomas.", "Exclusivamente de sus propios tributos."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Administraciones Públicas establecerán la jornada general y las especiales de trabajo de sus funcionarios públicos:', '["La jornada de trabajo nunca será a tiempo parcial", "La jornada de trabajo será exclusivamente a tiempo completo.", "La jornada de trabajo podrá ser a tiempo completo o a tiempo parcial.", "La jornada de trabajo podrá ser a tiempo completo o a tiempo parcial, dependiendo de cada comunidad autónoma."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Ley 53/1984, de 26 de diciembre, de Incompatibilidades del Personal al Servicio de las Administraciones Públicas:', '["Solo será de aplicación al personal al servicio de las Administraciones de las Comunidades Autónomas y de los Organismos de ellas dependientes, así como de sus Asambleas Legislativas y órganos institucionales.", "Solo será de aplicación al personal al servicio de las Corporaciones Locales y de los Organismos de ellas dependientes.", "Será de aplicación al personal recogido en los apartados a. y b. anteriores.", "No será de aplicación al personal civil y militar al servicio de la Administración del Estado y de sus Organismos Públicos."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'A efectos del Reglamento (UE) 2016/679 del Parlamento Europeo y del Consejo, de 27 de abril de 2016, relativo a la protección de las personas físicas en lo que respecta al tratamiento de datos personales y a la libre circulación de estos datos, se entenderá por «datos personales»:', '["Toda información sobre una actividad empresarial.", "Cualquier información no relacionada con una persona física.", "Toda información sobre una persona física no identificable.", "Toda información sobre una persona física identificada o identificable."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Reglamento (UE) 2016/679 del Parlamento Europeo y del Consejo, de 27 de abril de 2016, relativo a la protección de las personas físicas en lo que respecta al tratamiento de datos personales y a la libre circulación de estos datos:', '["Protege los derechos y libertades fundamentales de las personas físicas y, en particular, su derecho a la protección de los datos personales.", "Tan solo protege los derechos y libertades fundamentales de las personas físicas.", "Protege la libre circulación de todos/as los/as ciudadanos/as europeos/as por todos los Estados de la Unión.", "No protege los derechos y libertades fundamentales de las personas físicas ni sus datos personales."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Serán motivados, con sucinta referencia de hechos y fundamentos de derecho:', '["Los actos que limiten derechos subjetivos o intereses legítimos.", "Los actos que no se separen del criterio seguido en actuaciones precedentes o del dictamen de órganos consultivos.", "Los actos que rechacen pruebas que no hayan sido propuestas por los interesados.", "Los actos que limiten derechos objetivos e intereses legítimos."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los actos de las Administraciones Públicas sujetos al Derecho Administrativo:', '["Se presumirán válidos y producirán efectos desde la fecha en que se dicten, salvo que en ellos se disponga otra cosa.", "Se presumirán válidos y producirán efectos pasados diez días desde la fecha en que se dicten.", "No se presumirán válidos y producirán efectos hasta el día siguiente de su publicación en el Boletín Oficial de la Provincia.", "Se presumirán válidos y producirán efectos desde la fecha en que se dicten, siempre que así se disponga en ellos mismos."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El referéndum será convocado por:', '["El Presidente del Gobierno mediante propuesta del Congreso.", "Por el Rey a propuesta del Presidente del Gobierno.", "Por el Rey a propuesta del Presidente del Gobierno, previamente autorizado por la Comisión Permanente del Congreso.", "Podrá ser solicitado por la ciudadanía a través de una Iniciativa Legislativa Popular, previa recogida de 500.000 firmas acreditadas."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las iniciativas populares deberán ir suscritas al menos por el siguiente porcentaje de número de vecinos:', '["Hasta 5.000 habitantes, el 10%", "De 5.001 a 20.000 habitantes, el 20%", "A partir de 20.001 habitantes, el 10%", "Todas son incorrectas."]'::jsonb, 2, 'es'),
    ('27688c24b51134855be832acefe310a4', 'Según el artículo 55.1 de la Constitución Española, cuál de los siguientes derechos podrá ser suspendido, cuando se acuerde la declaración del estado de excepción o de sitio', '["Libertad de Cátedra.", "Integridad Física y Moral.", "Libre elección de residencia.", "Negociación colectiva laboral entre los representantes de los trabajadores y empresarios."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La convocatoria de elecciones municipales se efectuará por Real Decreto de Consejo de Ministros, a propuesta de quién.', '["Presidente de la Comunidad Autónoma", "Presidente del Gobierno", "Ministro de Administraciones Públicas", "El Rey."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los municipios gozarán de:', '["Personalidad jurídica plena", "Personalidad jurídica propia", "Personalidad jurídica independiente", "Personalidad jurídica autónoma."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los Estatutos de autonomía no deberán contener:', '["La denominación de la Comunidad que mejor corresponda a su identidad histórica.", "La delimitación de su territorio respecto a provincias y municipios", "La denominación, organización y sede de las instituciones autónomas propias.", "Las competencias asumidas dentro del marco establecido en la Constitución."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La figura impositiva que ha sustituido al Impuesto Municipal sobre la Radicación es el de:', '["Bienes inmuebles", "Construcciones, Instalaciones y Obras", "Licencias Fiscales de Actividades Comerciales e Industriales", "Ninguno de los anteriores."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En qué anexo de la Ley de Prevención de Riesgos Laborales (Ley 31/1995, de 8 de Noviembre) se encuentra el Inventario de los riesgos con el fin de utilizar Equipos de Protección Individual?', '["Anexo I", "Anexo II", "Anexo III", "Ninguna es correcta."]'::jsonb, 3, 'es'),
    ('12237ba96a770fcb5a967965c77827b5', '¿En que artículo de la Constitución Española de 1978 se contemplan las competencias que pueden asumir las Comunidades Autónomas?', '["Artículo 151", "Artículo 137", "Artículo 148", "Artículo 139."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El recurso de amparo para la tutela de los derechos y libertades se presenta ante:', '["El Tribunal Supremo", "El Tribunal Constitucional", "Los dos anteriores indistintamente", "El Tribunal Superior de Justicia."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El derecho a la libertad personal se encuentra regulado en la Constitución Española de 1978 en el artículo:', '["17", "14", "18", "Ninguna respuesta es correcta."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La forma política del Estado Español en la Constitución Española es:', '["Una Monarquía Parlamentaria", "Un Gobierno democrático, expresión de la mayoría parlamentaria", "Un Parlamento refrendado por la Corona", "La Corona inviolable y hereditaria."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la actual Constitución Española, y conforme a sus principios, las bases de la organización militar serán reguladas:', '["Mediante Estatuto Básico", "Mediante Ley Orgánica", "Mediante Ley Ordinaria", "Mediante Ley de Bases."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Constitución Española, la ley regulará, para toda persona detenida ilegalmente:', '["Un plazo máximo de setenta y dos horas para la realización de las averiguaciones tendentes al esclarecimiento de los hechos", "Un procedimiento de “habeas corpus” para la inmediata puesta en libertad", "Un procedimiento de “habeas corpus” para la inmediata puesta a disposición judicial", "El plazo de detención preventiva, que no podrá durar más del tiempo estrictamente necesario para la realización de las averiguaciones tendentes al esclarecimiento de los hechos."]'::jsonb, 2, 'es'),
    ('2b6edcfa0c4ac251d50667a54353381c', '¿Sobre qué tipo de derechos y libertades se pueden dar los procedimientos basados en los principios de preferencia y sumariedad ante los tribunales ordinarios, según la Constitución Española?', '["Sobre los contemplados en el Título I", "Sobre los contemplados en Título I Secc. 1ª del Capítulo II y art. 14", "Sobre los de b., pudiendo anteponer también recurso de amparo ante el Tribunal Constitucional", "Todas son ciertas."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién designa al Defensor del Pueblo según la Constitución Española?', '["Los ciudadanos", "Las Cortes Generales", "El Gobierno", "El Rey."]'::jsonb, 1, 'es'),
    ('930467abfd206c2faa2b5a38ec5f2b5a', '¿En qué casos, según el artículo 67 de la Constitución Española, las reuniones de Parlamentarios no vinculan a las Cámaras?', '["Cuando estas se celebren sin convocatoria reglamentaria", "Cuando se celebren fuera de los periodos de sesiones", "Cuando sean reuniones de deliberación de los Grupos Parlamentarios", "Dichas reuniones son vinculantes siempre."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Aplicando lo establecido en la Constitución Española, es inelegible e incompatible por su cargo con la condición de Senador:', '["Un Diputado autonómico", "Cualquier alto cargo de la Administración del Estado", "El Fiscal General del Estado", "Todas las opciones anteriores son ciertas."]'::jsonb, 2, 'es'),
    ('616cbf05a2a0a53389966e22179b5f92', 'Según el Título IV de la Constitución Española, se exceptúa el acceso de los ciudadanos a los registros administrativos en lo que afecte a:', '["La elaboración de disposiciones de carácter general", "La averiguación de los delitos", "Procedimientos judiciales", "En ningún caso, si el ciudadano actúa en condición de interesado."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'De acuerdo con la Constitución Española, la base de la organización y funcionamiento de los Tribunales es:', '["La justicia gratuita", "La publicidad de las actuaciones judiciales", "El principio de unidad jurisdiccional", "Los Jueces y Magistrados."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué artículo de la Constitución Española reconoce el derecho al acceso al autogobierno y a constituirse como Comunidad Autónoma?', '["140", "143", "145", "137."]'::jsonb, 1, 'es'),
    ('967c177f0466dc7212becc05a7eab32c', 'El Título VIII de la Constitución, en el que se regula la Organización Territorial del Estado, está dividido en:', '["Tres capítulos", "Dos capítulos", "Cuatro capítulos.", ""]'::jsonb, 0, 'es'),
    ('693f71bb3d5175bdba8c71e67b094cbb', 'Los Derechos y Deberes de los ciudadanos, previstos en el Título I de la Constitución Española de 1978, se encuentran regulados:', '["En el Capítulo I", "En el Capítulo II Sección 2ª", "En el Capítulo II Sección 1ª.", ""]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la disposición adicional primera de la ley Orgánica, 3/2007, de Igualdad Efectiva de Mujeres y Hombres, se entiende por composición equilibrada:', '["Hombres y mujeres al 50 %", "Que cada sexo no supere el 60 % ni sea inferior al 40 %", "Que ninguno de los sexos supere el 70% del total", "a y c son correctas."]'::jsonb, 1, 'es'),
    ('c35a32ed836554f43ef68b4f3036c79e', '¿A cuál de los siguientes conceptos corresponde la definición del art. 6 de la ley Orgánica, 3/2007, de Igualdad Efectiva de Mujeres y Hombres? ” La situación en que una disposición, criterio o práctica aparentemente neutros, pone a una persona de un sexo en desventaja particular respecto de personas de otro sexo”', '["Principio de Igualdad de trato entre mujeres y hombres.", "Discriminación Directa.", "Discriminación Indirecta.", "Acoso Sexual."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En qué Título de la vigente Constitución Española está recogida la Organización Territorial del Estado:', '["VIII", "V", "I", "IX."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La plantilla de personal de una Corporación Local se aprueba:', '["Anualmente por el Pleno de la Corporación al comienzo de su mandato.", "Anualmente por el Pleno de la Corporación a través del Presupuesto.", "Anualmente por el Presidente de la Corporación junto con la Oferta de Empleo Público.", "Por el Presidente de la Corporación si esta función se la hubiese delegado el Pleno."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'No es un elemento del Municipio:', '["El territorio", "La población", "La administración", "La organización."]'::jsonb, 2, 'es'),
    ('2a6468bc4f93d82dcd681e03abfdd7d4', 'La Constitución Española de 1978 en su artículo 11. 2., establece:', '["Ningún español de origen podrá ser privado de su nacionalidad.", "Ningún español podrá ser privado de su nacionalidad.", "Ninguna persona podrá ser privada de su nacionalidad.", "Ningún ciudadano que resida en España podrá ser privado de su nacionalidad."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Se necesita el voto favorable en el Pleno de la mayoría absoluta del número legal de miembros de la Corporación para:', '["La modificación del Reglamento Orgánico propio de la Corporación", "La aprobación definitiva del Presupuesto Municipal", "La aprobación de las Ordenanzas Fiscales Municipales", "Ninguna de las tres anteriores es correcta."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Es obligatorio que exista en todos los ayuntamientos:', '["La Comisión Especial de Cuentas", "La Comisión Informativa de Cultura", "La Comisión de Participación Ciudadana", "Ninguna de las tres anteriores es correcta."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La reforma de los Estatutos de Autonomía se ajustará al procedimiento establecido en los mismos y requerirá, en todo caso:', '["La aprobación por una ley autonómica de reforma", "La aprobación por una ley ordinaria de las Cortes Generales", "La aprobación por una ley Orgánica de las Cortes Generales", "La aprobación por una ley de Armonización de las Cortes Generales."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Estado se organiza territorialmente en municipios, provincias y Comunidades Autónomas, teniendo autonomía para la gestión de sus respectivos intereses:', '["Sólo las Comunidades Autónomas", "Sólo las Comunidades Autónomas y las provincias con entidad regional histórica", "Las Comunidades Autónomas y los Municipios de gran población", "Las Comunidades Autónomas, las Provincias y los Municipios."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Cada una de las ciudades de Ceuta y Melilla, elegirá:', '["Dos Senadores", "Tres Senadores", "Un Senador", "Cuatro Senadores."]'::jsonb, 0, 'es'),
    ('2a4ba259076b977b77507b8216bd6b29', '¿Qué Título de la Constitución trata de las relaciones entre el Gobierno y las Cortes Generales?', '["El Título III.", "El Título VI.", "El Título V.", "El Título VII."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Una de las siguientes no es función del Rey:', '["Ser informado de los asuntos de Estado.", "Recibir la acreditación de los representantes extranjeros en España.", "Presidir regularmente el Consejo de Ministros.", "Acreditar a los Embajadores."]'::jsonb, 2, 'es'),
    ('81b4196a9a98f87bf76f9a564d328a4d', '¿Qué artículo de la Constitución determina que corresponde a los poderes públicos remover los obstáculos que impidan o dificulten la plenitud de la libertad e igualdad y facilitar la participación de todos los ciudadanos en la vida política, económica, social y cultural?', '["En el artículo 1.1.", "En el artículo 14.", "En el artículo 2.", "En el artículo 9.2."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Una de las siguientes no es función de las Cortes generales:', '["Ejercer la potestad legislativa del Estado.", "Elaborar los presupuestos del Estado.", "Controlar la acción del Gobierno.", "Autorizar al Rey a declarar la guerra."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Estado garantiza la realización efectiva del principio de solidaridad…', '["Velando por el establecimiento de un equilibrio económico entre las diversas partes del territorio español.", "Velando por el establecimiento de un equilibrio adecuado y justo, entre las diversas partes del territorio español.", "Velando por el establecimiento de un equilibrio económico, adecuado, eficaz y justo, entre las diversas partes del territorio español.", "Velando por el establecimiento de un equilibrio económico, adecuado y justo, entre las diversas partes del territorio español."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Ley 31/95 de Prevención de Riesgos Laborales no será de aplicación en aquellas actividades cuyas particulares circunstancias lo impidan en el ámbito de qué funciones públicas. Señale la correcta:', '["Actividades militares de la Policía.", "Actividades preventivas no militares de la Guardia Civil.", "Servicios operativos de protección civil en caso de grave riesgo.", "a. y c. son correctas."]'::jsonb, 2, 'es'),
    ('c35a32ed836554f43ef68b4f3036c79e', 'Según el artículo 6 de la Ley 31/95 de Prevención de Riesgos laborales el gobierno debe elaborar normas reglamentarias para la regulación de las siguientes materias:', '["Implantación de sistemas de información que permitan elaborar mapas de riesgos laborales.", "Procedimiento de calificación de enfermedades profesionales.", "Régimen de sanciones aplicables a los que incumplan la legislación en la materia.", "Las tres anteriores son correctas."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En relación a los principios de la acción preventiva previstos en la Ley 31/ 95 de Prevención de Riesgos Laborales no es correcto que:', '["El empresario adoptará las medidas necesarias para que sólo los trabajadores con información suficiente y adecuada accedan a zonas con riesgo grave.", "El empresario debe adoptar medidas que no antepongan la protección colectiva a la individual.", "El empresario debe dar las debidas instrucciones a los trabajadores.", "El empresario debe tener en cuenta la evolución de la técnica."]'::jsonb, 1, 'es'),
    ('d41f6986d7506aa4d004e7025c582847', 'Son instrumentos esenciales para la gestión y aplicación del plan de prevención de riesgos según el artículo 16 de la Ley 31/95 de Prevención de Riesgos Laborales:', '["La planificación de la actividad preventiva y la revisión continua de la implantación del plan.", "La evaluación de los riesgos laborales y la implantación de las medidas correctoras.", "La planificación de la actividad preventiva y la ejecución del plan preventivo.", "La evaluación de los riesgos laborales y la planificación de la actividad preventiva."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En relación al derecho de asociación mencionado en la Constitución, señala la respuesta incorrecta:', '["Las asociaciones que persigan fines o utilicen medios tipificados como delitos son ilegales.", "Las asociaciones que constituidas al amparo de este artículo deberán inscribirse en un registro a los solos efectos de publicidad.", "Las asociaciones sólo podrán ser disueltas o suspendidas en sus actividades en virtud de resolución administrativa motivada.", "Se prohíben las asociaciones secretas y las de carácter paramilitar."]'::jsonb, 2, 'es'),
    ('2a6468bc4f93d82dcd681e03abfdd7d4', 'En virtud de lo establecido en el artículo 11.2 de la Constitución Española de 1978', '["Ningún español de origen podrá ser privado de su nacionalidad, salvo resolución judicial en los casos previsto por la ley.", "Ningún español de origen podrá ser privado de su nacionalidad, salvo lo que puedan disponer las leyes penales militares en tiempos de guerra.", "Ningún español de origen podrá ser privado de su nacionalidad", "Ningún español de origen podrá ser privado de su nacionalidad salvo sentencia penal."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Constitución reconoce:', '["El derecho a la asistencia de abogado únicamente en las diligencias judiciales.", "El derecho a la asistencia de abogado en las diligencias policiales y judiciales.", "La obligación para toda persona detenida de declarar.", "La posibilidad de ser detenido sin ser informado de las razones de su detención."]'::jsonb, 1, 'es'),
    ('6e0739035f08f3b057ebd3e7c103405e', 'De acuerdo con el artículo 17 de la Constitución Española de 1978,', '["La detención preventiva podrá durar más del tiempo estrictamente necesario para la realización de las averiguaciones tendentes al esclarecimiento de los hechos.", "El detenido deberá ser puesto en libertad o a disposición de la autoridad judicial en el plazo máximo de sesenta y dos horas.", "Toda persona detenida deberá ser informada de forma inmediata de sus derechos y de las razones de su detención, pudiendo ser obligada a declarar.", "El plazo máximo de duración de la prisión provisional se determinará por ley."]'::jsonb, 3, 'es'),
    ('a242ab8f2b380cc084f53a86e8cf42f0', 'En qué Artículo de la C.E. se reconoce el Derecho de reunión:', '["Art. 22", "Art. 29", "Art. 21", "Art. 23."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Mediante qué tipo de Ley se regula la composición y competencia del Consejo de Estado:', '["Ley Ordinaria", "Ley Orgánica", "Real Decreto", "Reglamento."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En qué plazo deberá ser convocado el Congreso electo?', '["Dentro de los 15 días siguientes a la celebración de las elecciones.", "Dentro de los 20 días siguientes a la celebración de las elecciones.", "Dentro de los 25 días siguientes a la celebración de las elecciones.", "Dentro de los 30 días siguientes a la celebración de las elecciones."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de las siguientes Constituciones no existió en España?', '["Constitución española de 1837.", "Constitución española de 1869.", "Constitución española de 1876.", "Constitución española de 1875."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En qué año se aprobó la Constitución inmediata anterior a la actual de 1978?', '["1936.", "1933.", "1931.", "1940."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'De las siguientes Constituciones españolas, ¿cuál no establece la división de poderes?', '["La Constitución de 1837.", "La Constitución de 1865.", "La Constitución de 1879.", "El Estatuto Real de 1834."]'::jsonb, 3, 'es'),
    ('81b4196a9a98f87bf76f9a564d328a4d', '¿Cuál de los siguientes no es uno de los valores superiores del ordenamiento jurídico proclamados en el artículo 1.1. de la Constitución Española?.', '["La legalidad.", "La libertad.", "La justicia.", "El pluralismo político."]'::jsonb, 0, 'es'),
    ('f2b1d0058935cd2de44729c198f92a7b', '¿Qué artículo de la Constitución Española garantiza, en primer lugar, el derecho al honor, en segundo lugar, el derecho a la intimidad, tanto personal como familiar y , en tercer lugar, el derecho a la propia imagen?', '["El artículo 18.1.", "El artículo 18.3.", "El artículo 19.", "El artículo 21.1."]'::jsonb, 0, 'es'),
    ('0b5205571b6369524baaa85b314a873e', 'Según el artículo 3.1 de la CE, el castellano es la lengua española oficial del Estado. Todos los españoles tienen:', '["El deber de usarla.", "El derecho a conocerla.", "El deber de conocerla y el derecho a usarla.", "Ninguna respuesta es correcta."]'::jsonb, 2, 'es'),
    ('2e3621adc4c962251d9e195efd8b0393', 'El artículo 36 de la CE señala que la Ley regulará las peculiaridades propias del régimen jurídico de los Colegios Profesionales y el ejercicio de las profesiones tituladas, debiendo, su estructura interna y el funcionamiento de los Colegios, ser:', '["Paritarios.", "Democráticos.", "Homogéneos.", "Proporcionales."]'::jsonb, 1, 'es'),
    ('2b6edcfa0c4ac251d50667a54353381c', '¿Qué artículo de la CE establece que todos tienen derecho a la vida y a la integridad física y moral sin que, en ningún caso, puedan ser sometidos a tortura ni a penas o tratos inhumanos o degradantes?.', '["El artículo 14.", "El artículo 15.", "El artículo 17.", "El artículo 21."]'::jsonb, 1, 'es'),
    ('81b4196a9a98f87bf76f9a564d328a4d', 'El artículo 1.3 de la CE establece que, la forma política del Estado es:', '["La democracia.", "El estado social y democrático de Derecho.", "La Monarquía Parlamentaria.", "El Estado constitucional."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La detención preventiva no podrá durar más del tiempo estrictamente necesario para la realización de las averiguaciones tendentes al esclarecimiento de los hechos, y, en todo caso, el detenido deberá ser puesto en libertad o a disposición de la autoridad judicial, en el plazo máximo de:', '["Doce horas.", "Veinticuatro horas.", "Cuarenta y ocho horas.", "Setenta y dos horas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién es el Alto Comisionado de las Cortes Generales, designado por estas para supervisar la actividad de la Administración?.', '["El Rey.", "El Presidente del Gobierno.", "El Defensor del Pueblo.", "El Tribunal Constitucional."]'::jsonb, 2, 'es'),
    ('81b4196a9a98f87bf76f9a564d328a4d', '¿En qué artículo de la Constitución Española se reconoce y garantiza el derecho a la autonomía de las nacionalidades y regiones?', '["En su artículo 1.", "En su artículo 2.", "En su artículo 3.", "En su artículo 9."]'::jsonb, 1, 'es'),
    ('b8911eea94f4c829211669faec5cb38c', '¿En qué apartado de la Constitución Española aparecen regulados los Derechos Fundamentales y Libertades Públicas?', '["En la Sección I del Capítulo II del Título I.", "En la Sección II del Capítulo II del Título I.", "En el Capítulo III del Título I.", "En el Capítulo IV del Título I."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La nacionalidad española se adquiere, se conserva y se pierde:', '["Según lo que establezca el Ministerio de Justicia.", "Según lo que establezca el Ministerio del Interior.", "Según lo que establezca el Presidente del Gobierno.", "Según lo que establezca la ley."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Constitución, las asociaciones solo podrán ser disueltas o suspendidas:', '["En virtud de resolución judicial no motivada.", "En virtud de resolución judicial motivada.", "Por decisión del Tribunal Constitucional.", "Por decisión del Ministerio de Justicia."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Tendrán el derecho de petición colectiva por escrito:', '["Únicamente los sindicatos.", "Únicamente los partidos políticos.", "Todos los ciudadanos excepto los miembros de los Institutos y Fuerzas Armadas.", "Todos los ciudadanos incluidos los Institutos de Fuerzas Armadas."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los españoles pueden elegir su residencia:', '["Libremente.", "Previa autorización judicial.", "Previa autorización gubernativa.", "Previa autorización municipal."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El secuestro de una publicación podrá efectuarse:', '["Solamente en virtud de resolución judicial.", "Por orden del Gobernador Civil.", "Por orden del Ministro del Interior o de Justicia.", "Por resolución del Consejo General del Poder Judicial."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las primeras elecciones democráticas celebradas en España tras la muerte de Frnaco tuvieron lugar en:', '["1975.", "1976.", "1977.", "1978."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Titulo de la Constitución que trata de la reforma constitucional es el:', '["Primero.", "Decimo.", "Noveno.", "Undécimo."]'::jsonb, 1, 'es');

  -- Batch 601-800
  insert into public.question_bank (content_hash, question, options, correct_index, lang)
  values
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los Tribunales de Honor están prohibidos respecto de los/la/ las:', '["Sindicatos y Organizaciones Profesionales.", "Administración Civil y Militar.", "Organizaciones Profesionales y la Administración Civil.", "Anteriores."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El secreto profesional, constitucionalmente, sirve para:', '["Ejercer con libertad una profesión titulada.", "La libertad de creación científica y literaria.", "No declarar sobre hechos presuntamente delictivos.", "Todo lo anterior."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La inmediata puesta a disposición judicial derivada del habeas corpus, se produce por:', '["Detención ilegal.", "Prisión ilegal.", "Prisión preventiva.", "Detención preventiva."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Además de en la vida económica y política, los poderes públicos deben fermentar la participación de los ciudadanos en la vida:', '["Cultural.", "Social.", "Corporativa.", "Las respuestas a y b son correctas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Deben tener una estructura interna y un funcionamiento democrático los/las:', '["Partidos políticos.", "Colegios profesionales.", "Organizaciones profesionales.", "Todos ellos."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La iniciativa popular pública en España:', '["Debe ser subsidiaria de la privada.", "Se prohíbe al consagrarse la libertad de empresa en el marco de la economía de mercado.", "Está reconocida por la Constitución.", "Se ejercerá solo cuando la planificación la imponga."]'::jsonb, 2, 'es'),
    ('693f71bb3d5175bdba8c71e67b094cbb', 'El artículo recogido en la Constitución Española “Ningún español de origen podrá ser privado de su nacionalidad”, aparece en el:', '["Capítulo I de los españoles y los extranjeros", "Capítulo II derechos y libertades", "Capítulo III de los principios rectores de la política social y económica", "Capítulo IV de las garantías de las libertades y derechos fundamentales."]'::jsonb, 0, 'es'),
    ('693f71bb3d5175bdba8c71e67b094cbb', 'El artículo recogido en la Constitución Española “Toda persona tiene derecho a la libertad y a la seguridad”, aparece en el:', '["Capítulo I de los españoles y los extranjeros", "Capítulo II derechos y libertades", "Capítulo III de los principios rectores de la política social y económica", "Capítulo IV de las garantías de las libertades y derechos fundamentales."]'::jsonb, 1, 'es'),
    ('693f71bb3d5175bdba8c71e67b094cbb', 'El artículo recogido en la Constitución Española “Se reconoce el derecho a la propiedad privada y a la herencia, aparece en el:', '["Capítulo I de los españoles y los extranjeros", "Capítulo II derechos y libertades", "Capítulo III de los principios rectores de la política social y económica", "Capítulo IV de las garantías de las libertades y derechos fundamentales."]'::jsonb, 1, 'es'),
    ('910b8c5757a93539fd90094f741ec710', 'El Defensor del Pueblo recogido en el artículo 54 de la Constitución se encuadra en el:', '["Capítulo I de los españoles y los extranjeros", "Capítulo II derechos y libertades", "Capítulo III de los principios rectores de la política social y económica", "Capítulo IV de las garantías de las libertades y derechos fundamentales."]'::jsonb, 3, 'es'),
    ('82702d5b5e27bb7e4a0f90ce13a4d44d', 'El derecho a la protección de la salud recogido en el artículo 43 de la Constitución Española es:', '["Un derecho fundamental de la sección 1ª del capítulo segundo del título I", "Una libertad publica de la sección 1ª del capítulo segundo del título I", "Un principio rector de la política social y económica del capítulo tercero del título I", "Un derecho de los ciudadanos de la sección 2ª del capítulo segundo del título I."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Constitución se fundamenta en la indisoluble unidad de la Nación española, patria común e indivisible de:', '["Todos los ciudadanos", "Todos los españoles", "Todos los españoles y extranjeros", "Todos los extranjeros."]'::jsonb, 1, 'es'),
    ('1cf384e30cb1ca80449f88fc14235b2a', 'La Constitución en su artículo 9.3 garantiza los principios de: (Señale la proposición INCORRECTA)', '["Proporcionalidad", "Legalidad", "Responsabilidad", "Seguridad Jurídica."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién podrá concertar tratados de doble nacionalidad con los países iberoamericanos o con aquellos que hayan tenido o tengan una particular vinculación con España?', '["Las Cortes Generales", "El Presidente del Gobierno", "El Rey", "El Estado."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Se garantiza el secreto de las comunicaciones y, en especial, de las: (Señale la proposición CORRECTA)', '["Postales, telegráficas y telemáticas, salvo resolución judicial.", "Postales, telegráficas y telefónicas, salvo resolución judicial.", "Postales, telegráficas y telefónicas, salvo resolución policial.", "Postales, telemáticas y telefónicas, salvo resolución policial."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En los casos de reuniones en lugares de tránsito público y manifestaciones se dará comunicación previa a la autoridad, que:', '["No necesitará autorización previa.", "Necesitará autorización previa.", "Sólo podrá prohibirlas cuando existan razones fundadas de alteración del orden público, con peligro para personas o bienes.", "Podrá prohibirlas cuando exista cualquier razón fundada de alteración del orden público, con peligro grave para personas o bienes."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Señale la proposición INCORRECTA.', '["Nadie puede ser condenado o sancionado por acciones u omisiones que en el momento de producirse no constituyan delito, falta o infracción administrativa, según la legislación vigente en aquel momento.", "Las penas privativas de libertad y las medidas de seguridad estarán orientadas hacia la reeducación y reinserción social y así como a realizar trabajos forzados por orden del Juez o Tribunal competente.", "El condenado a pena de prisión que estuviere cumpliendo la misma gozará de los derechos fundamentales de este Capítulo, a excepción de los que se vean expresamente limitados por el contenido del fallo condenatorio, el sentido de la pena y la ley penitenciaria.", "En todo caso, tendrá derecho a un trabajo remunerado y a los beneficios correspondientes de la Seguridad Social, así como al acceso a la cultura y al desarrollo integral de su personalidad."]'::jsonb, 1, 'es'),
    ('1cf384e30cb1ca80449f88fc14235b2a', 'Según el artículo 9 de la Constitución española de 1978, ¿a qué están sujetos los poderes públicos y los ciudadanos?', '["A la Constitución y a la ley.", "A la ley y al ordenamiento jurídico.", "A la Constitución y al resto del ordenamiento jurídico.", "A la Constitución, a la ley y al resto del ordenamiento jurídico."]'::jsonb, 2, 'es'),
    ('95286aa824b18e8857c72287aa97cd4c', '¿En cuántos Capítulos se estructura el Título I de la Constitución española de 1978?', '["En cuatro.", "En cinco.", "En seis.", "En tres."]'::jsonb, 1, 'es'),
    ('a4081b50999b05cd6634630ecd0c54b6', '¿Qué artículo cierra el Título I?', '["El artículo 53.", "El artículo 54.", "El artículo 55.", "El artículo 56."]'::jsonb, 2, 'es'),
    ('b8911eea94f4c829211669faec5cb38c', '¿De cuántas secciones consta el Capítulo II del Título I?', '["De dos.", "De tres.", "De ninguno.", "De cuatro."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué artículos forman la sección denominada " Derechos fundamentales y libertades públicas?', '["Los artículos del 14 al 29 ambos inclusive.", "Los artículos del 15 al 29 ambos inclusive.", "Los artículos del 14 al 30 ambos inclusive.", "Los artículos del 15 al 30 ambos inclusive."]'::jsonb, 1, 'es'),
    ('27688c24b51134855be832acefe310a4', '¿Qué artículo del Título I recoge la regulación de la suspensión de los derechos y libertades?', '["El artículo 55.", "El artículo 53.", "El artículo 51.", "El artículo 57."]'::jsonb, 0, 'es'),
    ('541dd3bc47e362ba70ca2c63a651b3ed', '¿Qué artículo del Título I recoge el principio de igualdad jurídica de los españoles ante la ley?', '["El artículo 12.", "El artículo 11.", "El artículo 14.", "El artículo 16."]'::jsonb, 2, 'es'),
    ('042c55dcf70f38c4dffc4220b47071c9', '¿A qué edad se alcanza la mayoría de edad a tenor del contenido del artículo 10 de la Constitución?', '["A los dieciocho años.", "A los dieciocho años, pero se establece en el artículo 15.", "A los dieciocho años pero no se regula en el artículo 10.", "A los dieciocho años pero se regula en el artículo 18."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de las siguientes afirmaciones no es correcta?', '["La pena de muerte está abolida en todos los casos.", "La pena de muerte solo está abolida en su vertiente civil.", "La pena de muerte no está abolida en España en el campo militar aún en tiempo de paz.", "La pena de muerte está abolida en la actualidad incluso en el campo militar y en tiempo de guerra."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de las siguientes normas contiene la respuesta correcta de la pregunta anterior?', '["La Ley Orgánica 11/ 1995, de 27 de noviembre.", "La Ley Orgánica 1/ 1995, de 27 de enero.", "La Ley Orgánica 21/ 1995, de 24 de febrero.", "La Ley Orgánica 3/ 1995, de 2 de marzo."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En relación con el derecho a la libertad religiosa ¿qué declara la Constitución española?', '["La reconoce.", "La garantiza.", "La reconoce y la garantiza.", "La reconoce, la garantiza y la protege."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En qué casos se puede obligar a un ciudadano a declarar sobre su ideología?', '["En ningún caso.", "En caso de ciudadanos extranjeros.", "En casos de riesgo grave de la seguridad ciudadana.", "En cualquier caso."]'::jsonb, 0, 'es'),
    ('d41f6986d7506aa4d004e7025c582847', '¿Qué carácter tiene el estado español a tenor del contenido del artículo 16 de la Constitución española de 1978?', '["Estado laico.", "Estado católico.", "Estado aconfesional.", "Estado civil."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En qué año fue aprobada la Ley Orgánica de Libertad Religiosa?', '["En 1980.", "En 1979.", "En 1980.", "En 1981."]'::jsonb, 0, 'es'),
    ('f2b1d0058935cd2de44729c198f92a7b', '¿En qué artículo de la Constitución española de 1978 se contiene el derecho a la libertad y seguridad individual?', '["En el artículo 18.", "En el artículo 20.", "En el artículo 21.", "En el artículo 17."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es el tiempo máximo de duración de la detención preventiva a tenor del contenido del artículo anterior?', '["48 horas.", "24 horas.", "72 horas.", "36 horas"]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué debe hacerse con un detenido en el momento en que se agote el tiempo máximo de detención preventiva?', '["Ponerlo en libertad.", "Ponerlo a disposición judicial para que declare la puesta en libertad.", "Ponerlo en libertad o a disposición judicial.", "Declarar el ingreso en prisión."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En el caso de la detención preventiva ¿en qué trámites está garantizada por la Constitución, la asistencia de abogado?', '["En las diligencias policiales.", "En las diligencias policiales y en judiciales.", "Sólo en las diligencias judiciales.", "Sólo en las diligencias policiales en las que lo solicite el interesado."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cómo se denomina el procedimiento judicial por el que se debe poner a un detenido a disposición inmediata de la autoridad judicial?', '["Proceso sumario.", "Habeas Corpus.", "Recurso de amparo.", "Proceso de amparo."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En qué casos se puede proceder a la entrada en un domicilio particular?', '["En caso de resolución judicial exclusivamente.", "En caso de delito flagrante o resolución judicial exclusivamente.", "En caso de autorización del titular o resolución judicial exclusivamente.", "En caso de autorización del titular, resolución judicial o flagrante delito."]'::jsonb, 3, 'es'),
    ('b3613a30125ec0ff5ac8b58c795a693c', '¿Qué artículo de la Constitución recoge el secreto de las comunicaciones?', '["En el artículo 20.", "En el artículo 22.", "En el artículo 24.", "En el artículo 18."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Pueden interceptarse las comunicaciones postales?', '["Sí, por medio de resolución administrativa.", "Sí, por medio de resolución judicial o administrativa.", "No, en ningún caso.", "Sólo mediante resolución judicial."]'::jsonb, 3, 'es'),
    ('5e746570e70c4c273203b1dfee1d9a4a', '¿Puede limitarse el derecho a la entrada y salida de territorio español por motivos ideológicos a los ciudadanos españoles?', '["No, a tenor del contenido del artículo 19 de la Constitución.", "Sí, a tenor del contenido del artículo 20 de la Constitución.", "No, a tenor del artículo 21 de la Constitución.", "Sí, a tenor del artículo 23 de la Constitución."]'::jsonb, 0, 'es'),
    ('b3613a30125ec0ff5ac8b58c795a693c', '¿En qué artículo de la Constitución se regula el derecho a la cláusula de conciencia y al secreto profesional?', '["En el artículo 20.", "En el artículo 24.", "En el artículo 27.", "En el artículo 19."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quiénes tienen derecho a la tutela judicial efectiva de jueces y tribunales?', '["Todos los españoles, pero no los extranjeros no legalizados.", "Todos los ciudadanos de la Unión Europea y los españoles, pero no los extranjeros ajenos a ese ámbito.", "Todas las personas.", "Solo los ciudadanos españoles y los nacionales de países de la Unión Europea legalizados."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En qué ámbito están prohibidos los Tribunales de Honor?', '["En el ámbito de la Administración civil.", "En el ámbito de la Administración civil y militar.", "En el ámbito de la Administración civil y en el de las organizaciones profesionales.", "En el ámbito de la Administración civil y militar y en el de las organizaciones profesionales."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Puede, la Administración civil, imponer sanciones que impliquen privación de libertad?', '["No, ni de forma directa ni de forma indirecta o subsidiaria.", "No de forma directa, pero si de forma subsidiaria.", "Sólo de forma directa.", "Sí, tanto de forma indirecta como directa."]'::jsonb, 0, 'es'),
    ('5ad7c64f39fd1a1442e43a426a7b76dc', 'Las penas privativas de libertad ¿pueden consistir en trabajos forzados?', '["Sólo en caso de suspensión del derecho contemplado en el artículo 26 de la Constitución española de 1978.", "En ningún caso.", "Sí, mediante resolución judicial.", "Sólo en casos excepcionalmente recogidos en la legislación vigente."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes derechos no se engloba en el derecho a la tutela judicial efectiva?', '["La libertad de acceso a jueces y tribunales.", "El derecho al cumplimiento de las resoluciones judiciales.", "El derecho a obtener una decisión por parte de los jueces y tribunales.", "El derecho al juez subsidiario."]'::jsonb, 3, 'es'),
    ('17701fa7464e882e55b72f1614866155', '¿En qué articulo de la Constitución se contempla el derecho al matrimonio?', '["En el artículo 31.", "En el artículo 33.", "En el artículo 32.", "En el artículo 34."]'::jsonb, 2, 'es'),
    ('a242ab8f2b380cc084f53a86e8cf42f0', '¿Se delimita, en la Constitución española de 1978, el derecho a la propiedad privada?', '["Sí, de acuerdo con las leyes y en virtud de su función social.", "Sí, de acuerdo con las normas extraordinarias dictadas por el Tribunal Constitucional.", "No. La propiedad privada no tiene delimitación constitucional.", "Sí, en el artículo 22 de la Constitución."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué asociaciones son ilegales?', '["Las que no estén inscritas en el registro correspondiente del Ministerio del Interior.", "Las que persigan fines o utilicen medios tipificados como delito.", "Las que se reúnan sin autorización previa.", "Las asociaciones prohibidas."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué asociaciones están prohibidas?', '["Las asociaciones secretas y las ilegales.", "Las asociaciones ilegales y las paramilitares.", "Las asociaciones paramilitares y las secretas.", "Las asociaciones paramilitares, ilegales y secretas."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué españoles pueden ejercer el derecho de petición solo de manera individual?', '["Los jueces y magistrados.", "Los miembros de las Fuerzas Armadas.", "Los miembros de las Fuerzas Armadas y los miembros del Poder Judicial.", "Los miembros de los institutos armados con disciplina militar y los pertenecientes a las Fuerzas Armadas."]'::jsonb, 3, 'es'),
    ('20ee6516d34f1b346bd2afade410d7c8', '¿Qué artículo de la Constitución recoge el derecho y el deber de trabajar?', '["El artículo 35.", "El artículo 33.", "El artículo 37.", "El artículo 39."]'::jsonb, 0, 'es'),
    ('1b9a277bb58e199b88cab3ab9e80c5ff', '¿Qué contenido tiene el artículo 44 de la Constitución?', '["El derecho a la salud.", "El derecho de acceso a la cultura.", "El derecho a una vivienda adecuada.", "El derecho a vacaciones retribuidas."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cómo se adquiere, se conserva y se pierde la nacionalidad española?', '["De acuerdo con la Constitución.", "De acuerdo con la ley.", "De acuerdo con las normas internacionales.", "De acuerdo con los Tratados internacionales."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué tipo de delitos están excluidos de la extradición?', '["Los delitos de terrorismo.", "Los delitos políticos.", "Los delitos sociales y políticos.", "Los delitos sociales, pero no los políticos."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Ante quién se presenta el recurso de amparo?', '["Ante el Tribunal Supremo.", "Ante el Tribunal Constitucional.", "Ante el Consejo General del Poder Judicial.", "Ante cualquier juzgado o tribunal."]'::jsonb, 1, 'es'),
    ('ffcd8d83ab18292a0e214616f467cfba', '¿A qué órgano le encomienda el artículo 124 de la Constitución la defensa de los derechos de los ciudadanos?', '["Al Tribunal Constitucional.", "Al Tribunal Supremo.", "Al Ministerio Fiscal.", "A los poderes públicos."]'::jsonb, 2, 'es'),
    ('67897ffeb86c09bac9a3b4193ddc7221', '¿Qué tipo de ley es necesaria para regular el desarrollo del artículo 21 de la Constitución española de 1978?', '["Ley ordinaria.", "Ley de bases.", "Ley orgánica.", "Ley marco."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es el origen de la figura del Defensor del Pueblo?', '["Los tribunales consuetudinarios.", "El Ombudsman.", "Los jurados populares.", "Los Tribunales de Honor."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Ante quién debe rendir cuenta el Defensor del Pueblo?', '["Ante el Gobierno y la Administración.", "Ante las Cortes Generales.", "Ante el Congreso de los Diputados.", "Ante los Tribunales y el Congreso de los Diputados."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Por qué tipo de mayoría se adoptan las decisiones en la Comisión Mixta Congreso-Senado para las relaciones con el Defensor del Pueblo?', '["Por mayoría simple.", "Por mayoría absoluta.", "Por mayoría de 1/3.", "Por mayoría de 3/5."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuánto dura el mandato del Defensor del Pueblo?', '["Tres años.", "Cuatro años.", "Cinco años.", "Dos años."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuántos adjuntos asisten al Defensor del Pueblo?', '["Tres.", "Dos.", "Cuatro.", "Cinco."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién nombra al Defensor del Pueblo?', '["El Rey.", "Las Cortes Generales.", "El Presidente del Gobierno.", "La Comisión Mixta Congreso-Senado para las relaciones con el Defensor del Pueblo."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es el mandato del Presidente del Tribunal Constitucional?', '["Dos años.", "Tres años.", "Cinco años.", "Seis años."]'::jsonb, 1, 'es'),
    ('0b5205571b6369524baaa85b314a873e', '¿Qué artículo de la Constitución recoge el principio de autonomía?', '["El artículo 3.", "El artículo 2.", "El artículo 5.", "El articulo 1."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿A quién se reconoce autonomía en la Constitución española?', '["A las nacionalidades y comunidades autónomas.", "A las comunidades autónomas y a las regiones.", "A las regiones y a las nacionalidades.", "A las regiones."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En qué año se establecen las provincias como división territorial del Estado?', '["1833.", "1834.", "1835.", "1835."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes nombres está relacionado con la división del territorio en provincias?', '["Javier de Burgos.", "Rafael de Burgos.", "Vicente Burgos.", "Manuel Burgos."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cómo se denominan a las dos principales vías de acceso a la autonomía?', '["Vía lenta y vía rápida.", "Vía común y vía lenta.", "Vía especial y vía rápida.", "Vía constitucional y vía histórica."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de las siguientes Comunidades Autónomas no es pluriprovincial?', '["Castilla y León.", "Cataluña.", "Baleares.", "Canarias."]'::jsonb, 2, 'es'),
    ('444cb125c36ed231f964fc64c4501b29', '¿Qué competencias del art. 148 asumen las Comunidades Autónomas que accedieron por la vía rápida?', '["Todas.", "Las negociadas con el gobierno central en el proceso autonómico.", "Las negociadas con el gobierno central tras el proceso autonómico.", "Ningunas."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuántos municipios debían formar parte de la iniciativa autonómica en el caso de las Comunidades que accedieron por la vía especial, en el caso de que si hubieran plesbiscitado estatutos en el pasado?', '["2/3 partes.", "1/3 parte.", "2/4 partes.", "Ningún porcentaje. (ver disposición transitoria 2ª de la CE)."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes extremos no debe aparecer obligatoriamente en un Estatuto de Autonomía?', '["La sede de las Instituciones.", "La delimitación del territorio.", "Las competencias asumidas.", "Las competencias por asumir."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué artículo prevé que las Comunidades Autónomas puedan reclamar como propias competencias sobre materias no atribuidas expresamente al Estado por la Constitución?', '["149.3.", "156.2.", "134.2.", "151.3."]'::jsonb, 0, 'es'),
    ('17b0de0db55795b44abc1d0057137f31', 'Además del contenido mínimo ordinario, ¿cuál de los siguientes debe incluir en su estatuto, una Comunidad Autónoma de vía especial?', '["Un Tribunal Superior de Justicia. (Artículo 152 CE)", "Un Tribunal Supremo.", "Un Defensor autonómico.", "Una Cámara de Cuentas."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué artículo de la Constitución recoge las competencias exclusivas del Estado?', '["149.", "150.", "151.", "151."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuánto tiempo debieron esperar las Comunidades Autónomas de vía común para acceder a mayor número de competencias que las reconocidas inicialmente en el Estatuto de Autonomía?', '["Dos años.", "Tres años.", "Cuatro años.", "Cinco años."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿De qué año es la Ley Reguladora de las Bases del Régimen Local?', '["1983.", "1984.", "1985.", "1986."]'::jsonb, 2, 'es'),
    ('feba4d61a34a3d0ffc926ece6b77e6da', '¿Qué artículo de la Constitución establece el derecho de autonomía de provincias y municipios?', '["El art.2.", "El art. 137.", "El art. 153.2.", "Ningún artículo de la Constitución establece ese principio."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes artículos no hace referencia a la Administración Local en la Constitución española de 1978?', '["140.", "141.", "142.", "143."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué artículo de la Constitución establece la autonomía de los municipios?', '["140.", "141.", "142.", "Ningún artículo de la Constitución establece el principio de autonomía para los municipios."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿De qué tipo de personalidad jurídica gozan las provincias?', '["Propia.", "Plena.", "Organizativa.", "Orgánica."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿A quién corresponde el Gobierno y Administración de los Municipios?', '["Al Alcalde.", "Al Alcalde y Concejales.", "Al Ayuntamiento.", "Al Pleno de los Ayuntamientos."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes órganos no aparece como obligatorio en los municipios?', '["pleno", "teniente de alcalde", "comisión especial de cuentas", "todos son obligatorios."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Cualquier alteración de los límites de una provincia deberá ser aprobada por:', '["Ley orgánica de las Cortes Generales.", "Ley ordinaria de las Cortes Generales.", "Decreto ley del Gobierno.", "Acuerdo entre las Cortes Generales y la Comunidad Autónoma afectada."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué es un Cabildo Insular?', '["El órgano de gobierno de las Islas Baleares.", "El órgano de administración propio de las Islas Canarias.", "Un órgano de consulta provincial.", "La Asamblea parlamentaria de la provincia."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes entes locales cuenta en su gobierno y administración con un régimen especial?', '["El Concejo abierto.", "El municipio.", "La provincia.", "El ayuntamiento."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes no se considera un elemento configurador del municipio?', '["El territorio.", "La población.", "El ayuntamiento.", "La organización."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'De qué administración es competencias la creación, modificación o supresión de municipios?', '["Municipio/s afectado/s.", "Gobierno de la nación", "Diputación provincial.", "Comunidad Autónoma."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de las siguientes potestades no puede ser ejercida por los Ayuntamientos?', '["La potestad reglamentaria.", "La potestad sancionadora.", "La potestad expropiatoria.", "La potestad legislativa."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué mayoría se precisa para ser elegido Alcalde en votación?', '["Mayoría simple.", "Mayoría absoluta.", "Mayoría de 2/3.", "Mayoría de 1/3."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En caso de que ningún candidato a la Alcaldía obtenga el número de votos necesario para ser proclamado como tal ¿quién será elegido?', '["El candidato que obtenga mayoría simple en segunda votación.", "El candidato que encabece la lista más votada.", "El candidato de mayor edad.", "El candidato que obtenga mayoría absoluta en segunda votación."]'::jsonb, 1, 'es'),
    ('feba4d61a34a3d0ffc926ece6b77e6da', '¿En qué artículo de la Constitución se consagra el principio de solidaridad territorial?', '["En el artículo 137", "En el artículo 136", "En el artículo 139", "En el artículo 138."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién nombra a los Tenientes de Alcalde?', '["El Pleno.", "El Alcalde.", "La Comisión de Gobierno.", "La Comisión informativa respectiva."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En cuál de los siguientes municipios rige el sistema de concejo abierto?', '["En un municipio de menos de 300 habitantes.", "En un municipio de menos de 250 habitantes.", "En un municipio de menos de 200 habitantes.", "En un municipio de menos de 100 habitantes."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién plantea la cuestión de confianza en un ayuntamiento?', '["El Pleno.", "La Comisión de Gobierno.", "El Alcalde.", "Los vecinos."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En qué año se aprobó la Ley orgánica de régimen electoral general?', '["1985.", "1986.", "1987.", "1988."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿A quién corresponde el gobierno y administración de la Provincia?', '["Al Ayuntamiento.", "A la Diputación.", "A la Comunidad autónoma.", "A los vecinos."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuántas provincias componen las Islas Canarias?', '["Una.", "Dos.", "Tres.", "Ninguna."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién elige al Presidente de la Diputación?', '["El Pleno.", "Los Diputados electos.", "La Comisión de Gobierno.", "Los municipios de la provincia."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuánto tiempo dura el mandato de los Diputados provinciales?', '["Dos años.", "Tres años.", "Cuatro años.", "Seis años."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es el número mínimo de miembros que debe tener una Junta Vecinal?', '["Dos.", "Tres.", "Cinco.", "Siete."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es el número máximo de componentes de una Asamblea vecinal?', '["Un tercio del número de concejales que integran el ayuntamiento respectivo.", "Un medio del número de concejales que integran el ayuntamiento respectivo.", "Dos tercios del número de concejales que integran el ayuntamiento respectivo.", "No existe limite al número de componentes."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Pueden agruparse en una Comarca municipios pertenecientes a más de una provincia?', '["En ningún caso.", "Solo en caso de fuerza mayor.", "Sí, con informe previo de las diputaciones respectivas. (siempre que sean de la misma Comunidad.", "Sí, en cualquier caso."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién debe establecer el ámbito territorial de las comarcas?', '["La Comunidad Autónoma respectiva mediante ley.", "La Diputación respectiva.", "El Ministerio de Administraciones Públicas.", "Los Ayuntamientos que la integren."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El control de la actividad de los órganos de las Comunidades autónomas, en lo relativo a la administración autónoma y sus normas reglamentarias:', '["Al Tribunal de Cuentas.", "Al Gobierno, previo dictamen del Consejo de Estado.", "Al Tribunal Constitucional.", "A la jurisdicción contencioso administrativa."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Estado tiene competencia exclusiva sobre todas las materias siguientes, menos sobre una:', '["Régimen aduanero y arancelario.", "Gestión en materia de protección del medio ambiente.", "Comercio exterior.", "Determinación de la hora oficial."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Es uniprovincial, la Comunidad Autónoma de:', '["Murcia", "Aragón", "Canarias", "Valencia."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Presidente de una Comunidad Autónoma es nombrado por:', '["El Jefe del Estado", "El Senado", "La Asamblea Autonómica", "El Presidente del Gobierno."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los Estatuto de Autonomía fueron aprobados por:', '["Una Ley orgánica", "Una ley ordinaria", "Un Real Decreto", "Un Decreto ley."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La mayoría necesaria para aprobar la reforma de un Estatuto de Autonomía en el Senado es:', '["1/3", "Simple", "Absoluta", "2/3."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Título Octavo de la Constitución cuenta con:', '["Tres Capítulos.", "Ningún Capítulo.", "Dos Capítulos.", "Un Capítulo."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuántos municipios debían formar parte de la iniciativa autonómica en el caso de las Comunidades que accedieron por la vía común, en el caso de que no tuvieran régimen provisional de autonomía?', '["1/3 parte", "2/3 partes", "2/4 partes", "¾ partes."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Si una Comunidad Autónoma no cumpliere las obligaciones que la Constitución u otras leyes le impongan, o actuare de forma que atente gravemente al interés general de España:', '["El Gobierno requerirá al efecto a la Asamblea Legislativa de la Comunidad Autónoma con la que se ha originado el incidente.", "Se efectuará un requerimiento previo por parte del Congreso de los Diputados al Presidente de la Comunidad Autónoma.", "Si el requerimiento no es atendido, por mayoría absoluta del Senado, podrá adoptar las medidas necesarias para obligar a aquélla al cumplimiento forzoso de dichas obligaciones. (Art 155 CE)", "Si el requerimiento no es atendido, podrá ser declarado en el territorio de la Comunidad Autónoma afectada el estado de alarma, el de excepción, o el de sitio, dependiendo de la gravedad de la causa que motive la adopción de tal medida."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién encomienda a los poderes Públicos, velar por la seguridad e higiene en el trabajo?', '["La Constitución Española", "Seguridad e Higiene en el Trabajo", "La Comunidad Autónoma respectiva", "Ninguna es correcta."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Ley de Prevención de Riesgos Laborales, tiene por objeto?', '["Desarrollar la seguridad de los trabajadores mediante prohibiciones.", "Promover la seguridad y la salud de los trabajadores mediante la aplicación de medidas", "Potenciar la estadística de los accidentes de trabajo", "Ninguna es correcta."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Ley de Prevención de Riesgos Laborales, tiene por objeto?', '["Promover la seguridad y la salud de los trabajadores mediante el desarrollo de las actividades necesarias para la prevención de riesgos derivados del trabajo", "Potenciar el trabajo y los trabajadores", "Desarrollar las prohibiciones de prevención de riesgos?", "Ninguna es correcta."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las disposiciones de carácter laboral contenidas en la Ley de Prevención de Riesgos Laborales, tienen carácter de?', '["Derecho necesario mínimo", "Normas prohibitivas", "Normas de actuación", "Ninguna es correcta."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Ley de Prevención de Riesgos Laborales, es de aplicación?', '["A las sociedades económicas aunque no tengan trabajadores", "A las sociedades cooperativas, en las que existan socios cuya actividad consista en la prestación de su trabajo personal", "A las sociedades mercantiles aunque no tengan trabajadores", "Ninguna es correcta."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Ley de Prevención de Riesgos Laborales, el conjunto de actividades o medidas adoptadas o previstas en todas las fases de actividad de la empresa con el fin de evitar o disminuir los riesgos derivados del trabajo, se entenderán a.', '["Protección a los trabajadores", "Previsión de los trabajadores", "Prevención", "Ninguna es correcta."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Ley de Prevención de Riesgos Laborales, la posibilidad de que un trabajador sufra un determinado daño derivado del trabajo, se entenderá por...', '["Protección de los trabajadores", "Prevención.", "Riesgo laboral", "Ninguna es correcta."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Ley de Prevención de Riesgos Laborales, aquello que resulte probable racionalmente que se materialice en un futuro inmediato y pueda suponer un daño grave para la salud de los trabajadores, se entenderá como...', '["Protección de los trabajadores", "Daño derivados del trabajo", "Riesgo Laboral grave e inminente", "Ninguna es correcta."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Ley de Prevención de Riesgos Laborales, las enfermedades, patologías o lesiones sufridas con motivo u ocasión del trabajo, se considerarán como', '["Protección de los trabajadores", "Daños derivados del trabajo", "Riesgo Laboral grave e inminente", "Ninguna es correcta."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Ley de Prevención de Riesgos Laborales, aquellos procesos, actividades, operaciones, equipos o productos que, en ausencia de medidas preventivas específicas, originen riesgos para la seguridad y la salud de los trabajadores se considerarán', '["Protección específica preventiva", "Potencialmente peligrosos", "Prevención laboral", "Ninguna es correcta."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Ley de Prevención de Riesgos Laborales, cualquier máquina, aparato, instrumento o instalación utilizada en el trabajo, se entenderá como', '["Prevención de riesgos del trabajador", "Equipo de trabajo", "Peligro a estudiar", "Ninguna es correcta."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Ley de Prevención de Riesgos Laborales, cualquier característica del puesto de trabajo que pueda tener una influencia significativa en la generación de riesgos para la seguridad y la salud del trabajador, se entenderá como', '["Condición de trabajo", "Estudio de Riesgos de Protección", "Peligro a estudiar", "Ninguna es correcta."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Ley de Prevención de Riesgos Laborales, cualquier equipo destinado a ser llevado o sujetado por el trabajador para que le proteja de uno o varios riesgos, se entenderá por', '["Ropa de trabajo", "Estudio de Riesgos de Protección", "Equipo de Protección Individual", "Ninguna es correcta."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Ley de Prevención de Riesgos Laborales, la elaboración de la política preventive se llevará a cabo con la participación de', '["Los empresarios", "Los trabajadores", "Los empresarios y los trabajadores", "Ninguna es correcta."]'::jsonb, 2, 'es'),
    ('c35a32ed836554f43ef68b4f3036c79e', 'Según la Ley de Prevención de Riesgos Laborales, ¿a quién debe consultar el Gobierno para que las normas reglamentarias regulen las materias que se relacionan en el artículo 6?', '["A los empresarios", "A las organizaciones sindicales y empresariales", "A los sindicatos", "Ninguna es correcta."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Ley de Prevención de Riesgos Laborales, las modalidades de organización, funcionamiento y control de los servicios de prevención, estarán reguladas por', '["Norma reglamentaria", "Real Decreto", "Decreto", "Ninguna es correcta."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Ley de Prevención de Riesgos Laborales, el procedimiento de calificación de las enfermedades profesionales, estará regulado por', '["Decreto Ley", "Decreto autonómico preventivo", "Norma reglamentaria.", "Ninguna es correcta."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Ley de Prevención de Riesgos Laborales, el órgano científico técnico especializado de la Administración General del Estado, es el', '["Instituto de Prevención de Riesgos", "Instituto Nacional de Seguridad e Higiene en el Trabajo", "Instituto Nacional de Protección Laboral", "Ninguna es correcta."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Ley de Prevención de Riesgos Laborales, quién tiene como misión el análisis y estudio de las condiciones de seguridad y salud en el trabajo, así como la promoción y apoyo a la mejora de las mismas es', '["Instituto Nacional de Seguridad e Higiene en el Trabajo", "Instituto de Prevención de Riesgos", "Instituto Nacional de Protección Laboral", "Ninguna es correcta."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Ley de Prevención de Riesgos Laborales, quién tiene como función vigilar el cumplimiento de la normativa sobre prevención de riesgos laborales es', '["Instituto de Gobernación", "Inspección de Trabajo y Seguridad Social", "Inspección de Trabajo y Justicia", "Ninguna es correcta."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Ley de Prevención de Riesgos Laborales, quién puede ordenar la paralización inmediata de trabajos cuando, a juicio del inspector, se advierta la existencia de riesgo grave e inminente para la seguridad o salud, es', '["Instituto de Gobernación", "Protección Civil", "Inspección de Trabajo y Seguridad Social", "Ninguna es correcta."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Ley de Prevención de Riesgos Laborales, ¿Por quién estará integrada la Comisión nacional de Seguridad e Higiene en el Trabajo?', '["Un representante de cada una de las Comunidades Autónomas y por?", "Dos representantes de cada Comunidad Autónoma y por?", "Solo representantes de la Administración del Estado.", "Ninguna es correcta."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Comisión Nacional de Seguridad y Salud en el Trabajo, conocerá las actuaciones que desarrollen las Administraciones públicas competentes en materia de promoción de la prevención de riesgos laborales, referente a:', '["Criterios y programas generales de actuación", "Costo económico de la prevención", "Costo administrativo de la prevención", "Ninguna es correcta."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Comisión Nacional de Seguridad y Salud en el Trabajo, contará con', '["Un Ministro, Un Presidente y Cuatro Vicepresidentes", "Un Presidente y Cuatro Vicepresidentes", "Un Presidente y Ocho Vicepresidentes", "Ninguna es correcta."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Ley de Prevención de Riesgos Laborales, los trabajadores tienen derecho a', '["Una protección eficaz en materia de seguridad", "Una prevención laboral", "Una prevención total en su trabajo y fuera de él.", "Ninguna es correcta."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Ley de Prevención de Riesgos Laborales, el empresario tiene el', '["Derecho de proteger a los trabajadores frente a los riesgos laborales", "Derecho de prevención a los trabajadores, frente a los riesgos laborales", "Deber de protección de los trabajadores, frente a los riesgos laborales", "Ninguna es correcta."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Ley de Prevención de Riesgos Laborales, las Administraciones Públicas tienen el', '["Derecho de proteger a sus trabajadores, frente a los riesgos laborales", "Deber de protección del personal a su servicio, frente a los riesgos laborales", "Derecho de prevención a sus trabajadores, frente a los riesgos laborales", "Ninguna es correcta."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Ley de Prevención de Riesgos Laborales, el empresario deberá cumplir las obligaciones establecidas en.', '["Decretos de prevención contra incendios", "Decretos en materia de relaciones laborales", "Normativa sobre prevención de riesgos laborales", "Ninguna es correcta."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Ley de Prevención de Riesgos Laborales, es principio de la acción preventiva', '["Evaluar los riesgos que no se puedan evitar", "Evaluar los edificios en acústica", "Evaluar la protección de actividades externas", "Ninguna es correcta."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Ley de Prevención de Riesgos Laborales, es principio de la acción preventiva.', '["Sustituir lo peligroso por lo que entrañe más peligro", "Sustituir lo peligroso por lo que entrañe poco peligro", "Sustituir siempre lo peligroso por lo que entrañe ningún peligro", "Ninguna es correcta."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Ley de Prevención de Riesgos Laborales, es principio de la acción preventiva?', '["Adoptar medidas que antepongan la protección colectiva a la individual.", "Adoptar medidas que antepongan la prevención individual a la colectiva", "Adoptar medidas que antepongan la prevención colectiva a la individual", "Ninguna es correcta."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Ley de Prevención de Riesgos Laborales, ¿Qué tomará el empresario en consideración en el momento de encomendarles las tareas?', '["Las capacidades profesionales de dicha tarea", "Las capacidades profesionales para ejecutar la tarea", "Las capacidades profesionales de los trabajadores en materia de seguridad y de salud", "Ninguna es correcta."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Ley de Prevención de Riesgos Laborales, ¿Qué medida adoptará el empresario para que los trabajadores puedan acceder a las zonas de riesgo grave y específico?', '["Que accedan los trabajadores que hayan recibido información suficiente y adecuada y los que no, en pareja", "Que accedan solo los trabajadores que hayan recibido información suficiente y adecuada", "Que no debe acceder nadie, al ser riesgo grave", "Ninguna es correcta."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Ley de Prevención de Riesgos Laborales, ¿Qué deberá integrarse en el Sistema general de gestión de la empresa?', '["La protección contra incendios", "La prevención contra incendios", "La prevención de riesgos laborales", "Ninguna es correcta."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Ley de Prevención de Riesgos Laborales, el plan de prevención de riesgos laborales de una empresa, deberá incluir', '["La estructura organizativa, las responsabilidades, las funciones,", "Las practicas, los procedimientos, los procesos,", "Los recursos necesarios para realizar la acción de prevención de riesgos", "Las respuestas anteriores son correctas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Ley de Prevención de Riesgos laborales, El empresario deberá proporcionar a sus trabajadores equipos de protección individual adecuados?', '["Para el desempeño de sus funciones y velar por el uso efectivo de los mismos", "Para el desempeño de sus funciones y el trabajador velar por su uso", "Sea el trabajo que sea, el trabajador velará por su uso efectivo de los mismos", "Ninguna es correcta."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Ley de Prevención de Riesgos laborales, Cuando los trabajadores estén o puedan estar expuestos a un riesgo grave e inminente con ocasión de su trabajo, el empresario estará obligado a:', '["Informar lo antes posible a todos los trabajadores afectados acerca de la existencia de dicho riesgo...", "Formar a los trabajadores en curso?", "Informar cuando pueda y formar a los trabajadores?", "Ninguna es correcta."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Ley de Prevención de Riesgos laborales, el trabajador, cuando considere que dicha actividad entraña un riesgo grave e inminente para su vida o su salud, tendrá derecho a?', '["a seguir trabajando según el lugar?", "a interrumpir su actividad y abandonar el lugar de trabajo?", "a seguir trabajando con equipos de prevención adecuados?", "ninguna es correcta."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Ley de Prevención de Riesgos laborales, no será de aplicación a los', '["Servicios de Administración Autonómica", "Servicios de Administración estatal", "Servicios operativos de protección civil", "Ninguna es correcta."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Ley de Prevención de Riesgos laborales, Se constituirá un Comité de Seguridad y Salud en todas las empresas o centros de trabajo que cuenten con?', '["100 o más trabajadores", "50 o más trabajadores", "150 o más trabajadores", "Ninguna es correcta."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Ley de Prevención de Riesgos laborales, El Comité estará formado por los Delegados de Prevención, de una parte, y por el empresario y/o sus representantes en número', '["Igual al de los Delegados de Prevención, de la otra.", "Uno más de los Delegados de Prevención, de la otra.", "Dos más de los Delegados de Prevención, de la otra.", "Ninguna es correcta."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Ley de Prevención de Riesgos laborales, es competencia del Comité de Seguridad y Salud', '["Proyectar y aprobar la elaboración, puesta en práctica y evaluación de los planes y programas de protección de riesgos en la empresa.", "Participar en la elaboración, puesta en práctica y evaluación de los planes y programas de prevención de riesgos en la empresa.", "Aprobar solo, sin participar, la elaboración, puesta en práctica y evaluación de los planes y programas de prevención de riesgos en la empresa.", "Ninguna es correcta."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Ley de Prevención de Riesgos laborales, Los fabricantes de maquinaria, equipos, productos y útiles de trabajo están obligados a asegurar que éstos no constituyan', '["Una fuente de peligro para el trabajador", "Una fuente de esfuerzo para el trabajador", "Una fuente de temperatura para el trabajador", "Ninguna es correcta."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Ley de Prevención de Riesgos laborales, es obligación del trabajador?', '["Utilizar correctamente los medios y equipos de protección que ha adquirido a su costa, de acuerdo con las instrucciones recibidas de éste.", "Utilizar correctamente los medios y equipos de protección facilitados por el empresario, de acuerdo con las instrucciones recibidas de éste.", "No existe obligación del trabajador, son del empresario", "Ninguna es correcta."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Ley de Prevención de Riesgos laborales, los trabajadores designados por el empresario para constituir un servicio de prevención', '["No podrán sufrir ningún perjuicio derivado de sus actividades de protección y prevención en la empresa", "Deberá facilitar a los trabajadores designados el acceso a la información y documentación", "Deberán tener la capacidad necesaria, disponer del tiempo y de los medios precisos", "Las respuestas anteriores son correctas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Ley de Prevención de Riesgos laborales, el conjunto de medios humanos y materiales necesarios para realizar las actividades preventivas a fin de garantizar la adecuada protección de la seguridad y la salud de los trabajadores.', '["Proyecto de Prevención", "Proyecto de Protección", "Servicio de Prevención", "Ninguna es correcta."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Ley de Prevención de Riesgos laborales, la presencia de los recursos preventivos será necesaria?', '["Cuando sea requerida por la Inspección de Hacienda y Seguridad Social", "Cuando sea requerida por la Inspección de Trabajo y Seguridad Social", "Cuando sea requerida por la Inspección de Prevención de Incendios", "Ninguna es correcta."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Ley de Prevención de Riesgos laborales, se considera recursos preventivos a?', '["Uno o varios miembros del servicio de protección propio de la empresa", "Uno o varios miembros del servicio de prevención propio de la empresa", "Uno o varios miembros del servicio de protección externo de la empresa", "Ninguna es correcta."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Ley de Prevención de Riesgos laborales, El empresario deberá consultar a los trabajadores, con la debida antelación, la adopción de las decisiones relativas a:', '["El proyecto y la organización de la formación en materia de protección", "El proyecto y la organización de la información en materia de protección", "El proyecto y la organización de la formación en materia preventiva", "Ninguna es correcta."]'::jsonb, 2, 'es'),
    ('e947057ff2f42db277860ce0b90afaed', '¿Qué Título de la Constitución de 1978 está dedicado a la regulación de la Corona?', '["El Título II.", "El Título III.", "El Título IV.", "El Título V."]'::jsonb, 0, 'es'),
    ('27688c24b51134855be832acefe310a4', '¿Qué artículo abre el Título de la Constitución dedicado a la regulación de la Corona?', '["El artículo 55.", "El artículo 56.", "El artículo 57.", "El artículo 54."]'::jsonb, 1, 'es'),
    ('322a5d2fb845f2e5dec6bda4f1678641', '¿Qué artículo de la Constitución concluye el Título dedicado a la regulación de la Corona?', '["El artículo 63.", "El artículo 64.", "El artículo 65.", "El artículo 66."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué carácter tiene el Rey de España dentro de la estructura general del Estado?', '["Es Jefe de gobierno.", "Es Jefe de Estado.", "Es Jefe de Estado y de Gobierno.", "No es Jefe de Estado ni de Gobierno."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Rey asume la más alta representación del Estado en las relaciones internacionales, pero la Constitución matiza que dicha representación será especialmente con:', '["Con los países integrantes de la Unión Europea.", "Con los países Iberoamericanos.", "Con los países de su comunidad histórica.", "Con los países de su entorno cultural y geográfico."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué Real Decreto de los indicados a continuación regula los Títulos, Tratamientos y Honores de la Familia Real?', '["RD 1386/ 1987, de 6 de noviembre.", "RD 1385/ 1987, de 6 de noviembre.", "RD 1386/ 1986, de 6 de noviembre.", "RD 1686/ 1987, de 6 de noviembre."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Ante quien se proclama al Rey?', '["Ante el Congreso de los Diputados.", "Ante el Senado.", "Ante el Gobierno.", "Ante las Cortes Generales."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuándo debe prestar juramento el Rey?', '["Al cumplir la mayoría de edad.", "Al ser proclamado como tal.", "Al ser proclamado heredero.", "Dentro de los veinte días siguientes a su proclamación."]'::jsonb, 1, 'es'),
    ('0443cd9d0325285e781bec821e5c3ddd', '¿Puede el Príncipe Heredero, pasar a ejercer la Regencia?', '["No, en ningún caso.", "Sólo si es mayor de edad en el momento en que se produzca el llamamiento.", "Sí, en cualquier caso.", "La Constitución lo excluye expresamente en su artículo 62."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de las siguientes funciones no es ejercida por el Rey?', '["Sancionar las leyes.", "Expedir los Decretos acordados en el Consejo de Ministros.", "Declarar la guerra y hacer la paz, previa autorización del Congreso de los Diputados.", "Nombrar al Presidente del Tribunal Constitucional."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de las siguientes funciones sí es ejercida por el Rey?', '["Sancionar los Estatutos de Autonomía.", "Proponer el nombramiento de los miembros del Gobierno.", "Nombrar al Defensor del Pueblo.", "Nombrar al Presidente de las Comunidades Autónomas, con el refrendo del Presidente del Senado."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿A cuál de los siguientes cargos no nombra el Rey?', '["Al Fiscal General del Estado.", "Al Presidente del Tribunal Supremo.", "A los vocales de los Tribunales Consuetudinarios.", "A los vocales del Consejo General del Poder Judicial."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué línea es preferida en la Sucesión?', '["La colateral sobre la secundaria.", "La directa sobre la colateral.", "La descendente sobre la colateral.", "La colateral sobre la indirecta."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién tiene preferencia en la Sucesión en el caso de que se de un supuesto de igualdad de grado?', '["Las mujeres sobre los varones.", "Los varones sobre las mujeres.", "La persona de más edad sobre la de menos.", "La persona más próxima a la más lejana."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes principios se aplica a la Sucesión?', '["El principio de representación.", "El principio de prioridad.", "El principio de igualdad.", "El principio de asunción."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué grado es preferido en el caso de que se dé un supuesto de igualdad de línea?', '["El grado más remoto al más cercano.", "El grado más próximo al más remoto.", "El grado más directo al indirecto.", "La Constitución no establece ese supuesto."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué tipos de Regencia existen?', '["Dativa y legítima.", "Legítima y por sucesión.", "Dativa y representativa.", "Dativa exclusivamente."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En nombre de quien se ejerce la Regencia?', '["En nombre de la Constitución.", "En nombre del Rey.", "En nombre de España.", "En nombre del pueblo español."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Por qué mandato se ejerce la Regencia?', '["Por mandato constitucional.", "Por mandato real.", "Por mandato popular.", "Por mandato soberano."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Ante quién presta juramento el Regente?', '["Ante las Cortes Generales.", "Ante el Congreso de los Diputados.", "Ante el Gobierno.", "Ante el Senado y el Gobierno."]'::jsonb, 0, 'es'),
    ('f4f854fbb239510c6688b54af5969668', '¿Qué artículo de la Constitución establece los supuestos de exclusión a la Sucesión?', '["El artículo 57.4.", "El artículo 57.6.", "El artículo 57.2.", "El artículo 57.3."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién es llamado en primer lugar en caso de que se deba declarar la Regencia por inhabilitación del Rey?', '["El Príncipe Heredero si es mayor de edad.", "El Príncipe Heredero en cualquier caso.", "El padre o la madre del Rey.", "El pariente de más edad del Rey."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En el caso de que no exista Tutor testamentario del Rey menor ¿quién será Tutor del mismo?', '["Las personas nombradas por las Cortes Generales en cualquier caso.", "El padre o la madre, mientras permanezcan viudos.", "El pariente de más edad del Rey menor.", "El padre o la madre, en cualquier caso."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuándo es nombrado el Tutor del Rey menor por las Cortes Generales?', '["En cualquier caso.", "En ningún caso.", "Cuando no exista Tutor testamentario ni legítimo.", "Cuando no exista Tutor testamentario."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Pueden acumularse los cargos de Tutor y Regente en una misma persona?', '["No, en ningún caso.", "Sólo en el caso de la madre o el padre del Rey menor.", "Sólo en el caso de ascendientes indirectos del Rey menor.", "Sí, en el padre, la madre, o ascendientes directos del Rey menor."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En cuál de los siguientes casos es imprescindible ser español de nacimiento?', '["Para ejercer la Regencia.", "Para ejercer la tutela testamentaria.", "Para ser proclamado Rey.", "Para ejercer la Regencia y la tutela testamentaria."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cómo deben regularse las dudas relacionadas con la abdicación?', '["Por Real Decreto.", "Por Ley orgánica.", "Por Ley ordinaria.", "Por Decreto ley."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Rey confiere empleos civiles y militares con arreglo a...:', '["La Constitución.", "La Ley.", "Las Leyes.", "La Constitución y las leyes."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué tipo de indulto no puede realizar el Rey?', '["Indulto a un condenado con sentencia firme.", "Indulto a ciudadanos extranjeros penados en España.", "Indultos generales.", "Indultos políticos."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de las siguientes funciones no es realizada por el Rey?', '["La convocatoria de elecciones generales.", "La convocatoria de referéndum.", "La convocatoria de las Cortes Generales.", "La convocatoria de la Diputación Permanente del Congreso de los Diputados."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Puede presidir el Rey el Consejo de Ministros?', '["No, en ningún caso.", "Sólo en casos excepcionales en el caso de declaración del estado de excepción.", "Sí, previa petición del Presidente del Gobierno.", "Sí, cuando lo estime oportuno sin más requisitos."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuándo nombra el Rey al Presidente del Gobierno?', '["En todos los casos.", "En ningún caso, es nombrado por las Cortes Generales.", "En ningún caso, es nombrado por el Congreso de los Diputados.", "En ningún caso."]'::jsonb, 0, 'es'),
    ('993b8cad1801d5ace1cbd3b9317a045d', '¿En qué artículo de la Constitución se recoge el juramento del Príncipe Heredero?', '["En el artículo 61.2.", "En el artículo 61.3.", "En el artículo 63.1.", "En el artículo 64.2."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes contenidos no aparece en el juramento del Rey?', '["El respeto a los derechos de los ciudadanos.", "El respeto a los derechos de las Comunidades Autónomas.", "El desempeño fiel de sus funciones.", "El respeto a los derechos de las colectividades históricas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El juramento del Príncipe es el mismo que el del Rey, pero se añade un contenido relativo a:', '["El respeto a los derechos humanos.", "El respeto a las funciones sociales.", "La fidelidad al Rey.", "No se añade ningún contenido al juramento del Príncipe Heredero."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué función tiene el Rey según la Constitución?', '["Arbitra y modera el funcionamiento de las instituciones.", "Es garante de la paz.", "Representa los derechos históricos de los españoles.", "Es símbolo de la diversidad del Estado."]'::jsonb, 0, 'es');

