  insert into public.question_bank (content_hash, question, options, correct_index, lang)
  values
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes cargos no tiene competencia para refrendar los actos del Rey?', '["El Presidente del Gobierno.", "El Presidente del Senado.", "El Presidente del Congreso.", "Un Ministro."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué efecto tiene el refrendo?', '["Confiere validez al acto refrendado.", "Implanta la responsabilidad en el Rey.", "Traslada la responsabilidad a las Cortes Generales.", "Traslada la responsabilidad del acto, al Gobierno."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién refrenda al Rey en la propuesta de nombramiento de candidato a la Presidencia del Gobierno?', '["El Presidente del Gobierno saliente.", "El Presidente del Congreso de los Diputados.", "El Jefe de la Casa Real.", "Este acto se realiza sin refrendo."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién refrenda al Rey en la convocatoria de elecciones generales periódicas?', '["El Presidente del Congreso de los Diputados en cualquier caso.", "El Presidente del Gobierno.", "El Presidente de las Cortes Generales.", "Ese acto no requiere refrendo."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué Real Decreto regula la Casa Real?', '["El Real Decreto 434/ 1988, de 6 de mayo.", "El Real Decreto 434/ 1984, de 6 de mayo.", "El Real Decreto 434/ 1998, de 6 de mayo.", "El Real Decreto 434/ 1987, de 6 de mayo."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿De quién dependen todos los Servicios de la Casa Real?', '["Del Jefe de la Casa Real.Página 18", "De la Secretaría General.", "Del Ministro del Interior.", "Del Rey."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿De qué año es el Real Decreto que regula el Registro Civil de la Familia Real?', '["De 1981.", "De 1881.", "De 1781.", "De 1681."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué Tratamiento se aplica a los hijos de los Infantes de España?', '["El Presidente del Gobierno.", "El Presidente del Congreso.", "El Presidente del Tribunal Supremo.", "Ese nombramiento no tiene propuesta."]'::jsonb, 1, 'es'),
    ('e947057ff2f42db277860ce0b90afaed', '¿Qué Título de la Constitución de 1978 está dedicado a la regulación de las Cortes Generales?', '["El Título II.", "El Título III.", "El Título IV.", "El Título VI."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de las siguientes características no es predicable de las Cortes Generales?', '["Es un órgano permanente.", "Es un órgano legislativo.", "Es un órgano unicameral.", "Es un órgano representativo."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué principio rige para la elección de los Diputados?', '["El Proporcional.", "El Mayoritario.", "El Censitario.", "El Equivalente."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué principio rige para la elección de los Senadores?', '["El equivalente.", "El proporcional.", "El mayoritario.", "El Censitario."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En caso de que se celebre sesión conjunta del Congreso de los Diputados y del Senado ¿quién debe presidirla?', '["El Jefe del Estado.", "El Presidente del Congreso de los Diputados.", "El Presidente del Gobierno.", "El Presidente del Senado."]'::jsonb, 1, 'es'),
    ('52ea1ec9e53ce7c070dcf68594fba2a1', '¿En qué casos deben proveer las Cortes Generales a la Sucesión?', '["En cualquier caso, es una función asignada por la Constitución en su art. 72.", "En ningún caso, porque los criterios de Sucesión están establecidos constitucionalmente.", "En caso de que se agoten las líneas de Sucesión a la Corona.", "En caso de que se produzca la abdicación del Rey en el Heredero."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué órgano asume la función de las Cámaras entre los periodos de sesiones?', '["La Diputación Permanente de las Cortes Generales.", "La Diputación Permanente de cada Cámara.", "La Diputación Permanente del Congreso.", "La Diputación Permanente del Senado."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es el número máximo de miembros del Congreso de los Diputados, según la Constitución?', '["300.", "350.", "400.", "500."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de las siguientes funciones no está asignada a las Cortes Generales?', '["Reconocer la incapacidad del Rey en caso de que se produzca.", "Autorizar los acuerdos de cooperación entre Comunidades Autónomas.", "Otorgar autorización al Rey para declarar la guerra.", "Nombrar al Presidente del Gobierno."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué meses abarca el primer periodo de sesiones de las Cámaras?', '["De septiembre a diciembre.", "De enero a junio.", "De septiembre a enero.", "De enero a julio."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué meses abarca el segundo periodo de sesiones del Senado?', '["De febrero a junio.", "De septiembre a diciembre.", "De enero a julio.", "De enero a mayo."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién elabora el reglamento interno de cada Cámara?', '["La Mesa.", "Cada una de las Cámaras.", "La Diputación Permanente.", "Los Presidentes de las Cámaras."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿De qué fecha es el Reglamento interno del Congreso de los Diputados?', '["De 10 de febrero de 1982.", "De 9 de febrero de 1982.", "De 8 de febrero de 1982.", "De 7 de febrero de 1982."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿De qué fecha es el Reglamento interno del Senado?', '["De 3 de mayo de 1994.", "De 2 de mayo de 1994.", "De 1 de mayo de 1994.", "De 5 de mayo de 1994."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién ostenta la representación del Congreso de los Diputados?', '["El Pleno.", "El Presidente.", "La Diputación Permanente.", "Los Diputados."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿A quién le corresponde fijar el calendario de trabajo del Pleno?', '["Al Presidente de la Mesa.", "A la Mesa.", "A la Comisión de Plenos.", "A la Junta de Diputados."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de las siguientes funciones no le corresponde ejercer a la Mesa del Senado?', '["La dirección de los trabajos del Senado.", "Ordenar los trabajos parlamentarios.", "Elaborar el presupuesto del Senado.", "Fijar el calendario de actividades."]'::jsonb, 0, 'es'),
