    ('4b830eab8fe6b21a82865850ecac45f6', '¿Por qué tipo de mayoría se adoptan las decisiones en el seno de la Junta de Portavoces?', '["Por mayoría simple.", "Por mayoría absoluta.", "Por medio del voto ponderado.", "Por unanimidad."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es el número mínimo de miembros de un partido político para constituir grupo parlamentario en el Congreso de los Diputados?', '["10 Diputados.", "15 Diputados.", "20 Diputados.", "30 Diputados."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de las siguientes funciones no puede ser ejercida por los Grupos Parlamentarios?', '["Ejercer la iniciativa legislativa.", "Determinar la elección de los miembros de la Mesa de la Cámara.", "Designar los miembros que de cada Grupo Parlamentario, han de formar parte de las Comisiones.", "Ser consultados por la Mesa antes de fijar el calendario de actividades."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es el número de miembros que componen la Diputación Permanente del Congreso?', '["20.", "15.", "21.", "24."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es la circunscripción electoral del Congreso de los Diputados?', '["La provincia.", "El municipio.", "La Comunidad Autónoma.", "El territorio español."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuántos Senadores se eligen por cada provincia?', '["Uno.", "Dos.", "Tres.", "Cuatro."]'::jsonb, 3, 'es'),
