    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué Tribunal es competente en una causa penal que se siga contra un Diputado?', '["La Sala II del Tribunal Supremo.", "La Sala II del Tribunal Constitucional.", "La Sala II de la Audiencia Nacional.", "La Sala I del Tribunal Supremo."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuántos Senadores elige una Comunidad Autónoma por el simple hecho de serlo?', '["Dos.", "Uno.", "Tres.", "Ninguno."]'::jsonb, 1, 'es'),
