    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuánto tiempo dura el mandato del Presidente del Tribunal de Cuentas?', '["Dos años.", "Tres años.", "Cuatro años.", "Cinco años"]'::jsonb, 1, 'es'),
