    ('638d85fb26187e2d28e5b312b40ea5d6', '¿Qué artículo de la Constitución recoge las funciones del Gobierno?', '["El artículo 97.", "El artículo 98.", "El artículo 99.", "El artículo 96."]'::jsonb, 0, 'es'),
