    ('c3a53bd0b979669b354eb63235cd3bbc', '¿Qué artículo de la Constitución está dedicado a establecer la composición del Gobierno?', '["El artículo 105.", "El artículo 98.", "El artículo 109.", "El artículo 87."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de las siguientes figuras no es imprescindible en la composición del Gobierno?', '["El Presidente.", "Los Ministros.", "Los Vicepresidentes.", "Los Vicepresidentes y los Ministros."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de las siguientes es la Ley del Gobierno?', '["Ley 50/ 1997, de 27 de noviembre.", "Ley 50/ 1997, de 24 de noviembre.", "Ley 50/ 1997, de 22 de noviembre.", "Ley 50/ 1997, de 21 de noviembre."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es el máximo órgano consultivo del Gobierno?', '["El Consejo del Reino.", "El Consejo de Estado.", "El Consejo Real.", "El Consejo Consultivo."]'::jsonb, 1, 'es'),
    ('c3a53bd0b979669b354eb63235cd3bbc', '¿En qué artículo de la Constitución se regula el máximo órgano consultivo del Gobierno?', '["En el artículo 105.", "En el artículo 106.", "En el artículo 107.", "En el artículo 108."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes Ministerios no existe en la actualidad?', '["Ministerio de Administraciones Públicas.", "Ministerio de Economía y Hacienda.", "Ministerio de Fomento.", "Ministerio de Sanidad y Consumo."]'::jsonb, 1, 'es'),
