    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué rango ostentan los Delegados del Gobierno en las Comunidades Autónomas?', '["Subdirector General.", "Subsecretario General.", "Secretario de Estado.", "Subsecretario."]'::jsonb, 3, 'es'),
