    ('4b830eab8fe6b21a82865850ecac45f6', '¿Por medio de qué documento se nombra a un ministro?', '["Por ley.", "Por Decreto.", "Por Real Decreto.", "Por Orden Ministerial."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En cuál de los siguientes casos no cesa el Gobierno?', '["Por fallecimiento del Presidente.", "Por la celebración de elecciones generales.", "Por dimisión del Vicepresidente.", "Por pérdida de la confianza parlamentaria."]'::jsonb, 2, 'es'),
    ('18063efe1bcece549c4579598468f9fb', '¿Qué artículo de la Constitución recoge la institución del Gobierno en funciones?', '["El artículo 106.", "El artículo 107.", "El artículo 108.", "El artículo 19."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de las siguientes funciones puede ser ejercida por un Presidente del Gobierno en funciones?', '["El planteamiento de una cuestión de confianza.", "La propuesta al Rey de celebración de un referéndum consultivo.", "La propuesta al Rey de disolución de las Cámaras.", "La celebración de Consejos de Ministros."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes no es un órgano de colaboración y apoyo al Gobierno?', '["La Comisión de Secretarios de Estado y Subsecretarios.", "Los Gabinetes.", "Los Secretarios de Estado.", "Los Secretarios Generales Técnicos."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Ante quien es exigible la responsabilidad penal del Presidente del Gobierno?', '["Ante la Sala II del Tribunal Constitucional.", "Ante la Sala I del Tribunal Supremo.", "Ante la Sala II del Tribunal Supremo.", "Ante la Sala I del Tribunal Constitucional."]'::jsonb, 2, 'es'),
    ('616cbf05a2a0a53389966e22179b5f92', '¿En qué Título de la Constitución se regulan las relaciones entre el Gobierno y las Cortes Generales?', '["En el Título IV.", "En el Título VII.", "En el Título V.", "En el Título III."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién puede plantear una cuestión de confianza?', '["El Congreso de los Diputados.", "El Gobierno.", "El Rey.", "El Presidente del Gobierno."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes trámites es necesario realizar antes de plantear una cuestión de confianza?', '["Deliberación del Presidente del Gobierno.", "Deliberación del Consejo de Ministros.", "Comunicación al Jefe del Estado.", "No es necesario realizar ningún trámite previo."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué mayoría es necesario alcanzar para entender otorgada la confianza en un proceso de cuestión de confianza?', '["Mayoría absoluta.", "Mayoría simple.", "Mayoría de 1/3.", "Mayoría de 2/3."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿A quién debe presentar el Presidente del Gobierno su dimisión en el supuesto de que no obtenga la mayoría necesaria en una votación de cuestión de confianza?', '["Ante el Congreso de los Diputados.", "Ante el Rey.", "Ante las Cortes Generales.", "Ante el Consejo de Ministros."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué número de Diputados es necesario para interponer una moción de censura?', '["Mayoría simple de la Cámara.", "Mayoría absoluta de la Cámara.", "Una décima parte de la Cámara.", "Dos tercios de la Cámara."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuántos días deben transcurrir desde que se presente una moción de censura hasta que pueda ser votada?', '["Dos días.", "Tres días.", "Cuatro días.", "Cinco días."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué mayoría es necesaria para que se entienda aprobada una moción de censura?', '["Mayoría simple.", "Mayoría absoluta.", "Mayoría de 2/3.", "Mayoría de 1/3."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cómo son nombrados los Secretarios de Estado?', '["Por Real Decreto del Consejo de Ministros.", "Por Decreto del Presidente del Gobierno.", "Por Real Decreto refrendado por el Presidente del Gobierno.", "Por Decreto del Consejo de Ministros."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cómo se crean las unidades administrativas que no tengan la consideración de órganos de la Administración General del Estado?', '["A través de las relaciones de puestos de trabajo.", "Por Real Decreto del Consejo de Ministros.", "Por Decreto de la Presidencia del Gobierno.", "Por Orden Ministerial."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién actúa como Secretario de las reuniones del Consejo de Ministros?', '["El Presidente del Gobierno.", "El Ministro de la Presidencia.", "El Ministro de Administraciones Públicas.", "El Ministro del Interior."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de las siguientes funciones no está asignada al Consejo de Ministros?', '["Aprobar el proyecto de ley de presupuestos generales del Estado.", "Remitir al Congreso o, en su caso, al Senado proyectos de Ley.", "Aprobar los decretos leyes.", "Declarar el estado de sitio."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué carácter tienen las deliberaciones del Consejo de Ministros?', '["Secretas.", "Públicas.", "Solemnes.", "Solemnes y públicas."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién representa al Gobierno?', '["El Presidente.", "El Ministro de la Presidencia.", "El Ministro portavoz del Gobierno.", "Los Ministros."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué rango ostentan los Secretarios Generales Técnicos?', '["De Director General.", "De Subdirector General.", "De Secretario General.", "De Subsecretario."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes principios no es aplicable a la organización administrativa?', '["Jerarquía.", "Descentralización.", "Desconcentración.", "Territorialidad."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién nombra a los Subdelegados del Gobierno?', '["El Delegado del Gobierno.", "El Ministro de Administraciones Públicas.", "El Consejo de Ministros.", "El Presidente del Gobierno."]'::jsonb, 0, 'es'),
    ('28c562f4839afaef4b7d5af7d5a0b3d8', '¿Qué artículo de la Constitución recoge los principios a los que debe ajustarse la Administración en su actuación?', '["El artículo 103.", "El artículo 102.", "El artículo 104.", "El artículo 106."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En cuál de las siguientes Comunidades Autónomas no existen Subdelegados del Gobierno?', '["Cantabria.", "Extremadura.", "Cataluña.", "Andalucía."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿De qué año es el Real Decreto que establece la regulación de las figuras de los Delegados y Subdelegados del Gobierno?', '["1996.", "1997.", "1998.", "1999."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuántos Ministerios existen en la actualidad?', '["14.", "12.", "15.", "17."]'::jsonb, 2, 'es'),
    ('81b4196a9a98f87bf76f9a564d328a4d', '¿Cuál de las siguientes notas características es predicable de la ley como fuente del derecho?', '["Es una fuente indirecta.", "Es una fuente secundaria.", "Es una fuente recogida en el art. 1 del Código Civil.", "Es una fuente recogida en el art. 23 de la Constitución."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuándo entran en vigor las leyes?', '["A los quince días de su completa publicación en el Boletín Oficial del Estado.", "A los veinte días de su publicación íntegra en el Boletín Oficial del Estado salvo que en ellas se disponga otra cosa.", "Cuando sean sancionadas por el Rey.", "En el mismo día de su publicación íntegra en el Boletín Oficial del Estado."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La regla general en relación con el contenido de las leyes es:', '["Que siempre tienen efecto retroactivo.", "Que nunca tienen efecto retroactivo.", "Que sólo tienen efecto irretroactivo cuando se establece en las mismas.", "Que sólo tienen efecto retroactivo cuando lo establezca su contenido."]'::jsonb, 3, 'es'),
    ('1cf384e30cb1ca80449f88fc14235b2a', '¿Qué artículo de la Constitución está dedicado a la irretroactividad de las disposiciones desfavorables o restrictivas de derechos individuales?', '["El art. 9.3.", "El art. 9.2.", "El art. 9.4.", "El art. 10."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de las siguientes materias no requiere desarrollo por medio de ley orgánica?', '["La alteración de los límites provinciales.", "La alteración del nombre de una provincia.", "La regulación de las funciones de los Cuerpos y Fuerzas de Seguridad del Estado.", "La regulación del funcionamiento del Tribunal de Cuentas."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En cuál de los siguientes órganos puede delegarse la elaboración de leyes orgánicas?', '["En las comisiones legislativas de las Cámaras.", "En el Gobierno.", "En la Diputación permanente de las Cámaras.", "Su elaboración es indelegable."]'::jsonb, 3, 'es'),
    ('4a6496eacb370328674243ee6729c106', '¿Qué artículo de la Constitución establece las materias que deben ser desarrolladas por medio de ley orgánica?', '["El art. 90.", "El art. 85.", "El art. 81.", "El art. 83."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes no tiene capacidad para ejercer la iniciativa legislativa?', '["Las Asambleas legislativas de las Comunidades Autónomas.", "El Gobierno.", "El pueblo.", "Los Gobiernos de las Comunidades Autónomas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En cuál de las siguientes materias el gobierno ejerce el monopolio de la iniciativa legislativa?', '["En materia de desarrollo de derechos fundamentales.", "En materia de planificación económica y presupuestaria.", "En materia de desarrollo de la institución de la Corona.", "El Gobierno no tiene iniciativa legislativa."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es el número mínimo de Diputados necesario para presentar una proposición de ley?', '["Doce en cualquier caso.", "Catorce.", "Quince o un grupo parlamentario.", "Un grupo parlamentario o catorce."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es el número mínimo de Senadores necesario para presentar una proposición de ley?', '["Quince o un grupo parlamentario.", "Veinticinco o un grupo parlamentario.", "Doce o un grupo parlamentario.", "Un grupo parlamentario en todo caso."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuántos componentes tiene que tener la delegación autonómica encargada de la defensa de una proposición de ley autonómica?', '["Dos.", "Tres.", "Cuatro.", "Las Comunidades Autónomas no tienen iniciativa legislativa."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es el número de firmas necesario para el ejercicio de la iniciativa legislative popular?', '["No menos de 500.000.", "500.000.", "Más de 600.000.", "600.000."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En cual de las siguientes materias procede la iniciativa legislativa popular?', '["En materias tributarias.", "En materias de carácter internacional.", "En materias relativas a la prerrogativa de gracia.", "En materias relacionadas con las comunidades de vecinos."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes requisitos debe cumplirse en la tramitación de proposiciones de ley?', '["Deben ser remitidas exclusivamente a la Mesa del Congreso.", "Deben remitirse al Gobierno para que de su aprobación antes de ser tramitadas en algunos casos.", "Deben remitirse siempre a la Mesa del Senado.", "No deben remitirse a ningún órgano externo al Congreso en ningún caso."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué mayoría se necesita en el Senado para oponer un veto a una proposición de ley aprobada en el Congreso de los Diputados?', '["Mayoría simple.", "Mayoría absoluta.", "Mayoría de 2/3.", "El Senado no puede vetar materias aprobadas por el Congreso."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿De qué plazo dispone el Rey para sancionar las leyes?', '["Diez días.", "Quince días.", "Veinte días.", "Treinta días."]'::jsonb, 1, 'es'),
    ('d5b1ff9fec5ed8de8e483562272e8a2b', '¿Qué artículo de la Constitución está dedicado a la regulación de los decretos leyes?', '["El art. 86.", "El art. 91.", "El art. 87.", "El art. 82."]'::jsonb, 0, 'es'),
    ('95286aa824b18e8857c72287aa97cd4c', '¿Cuál de las siguientes materias si es regulable por medio de decreto ley?', '["El régimen de las Comunidades Autónomas.", "El derecho electoral general.", "Los derechos y deberes de los ciudadanos regulados en el Título I de la Constitución.", "Las materias objeto de ley ordinaria."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién convalida un decreto ley?', '["El Congreso de los Diputados.", "El Senado.", "Las Cortes Generales.", "El Gobierno."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿De qué plazo dispone el órgano competente para convalidar o no un decreto ley?', '["Veinte días.", "Quince días.", "Veinticinco días.", "Treinta días."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién convalida un decreto ley en caso de que sea aprobado durante el mes de agosto?', '["El Gobierno.", "El Senado.", "La Diputación permanente del Congreso.", "La Diputación permanente del Senado."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué otro nombre reciben los decretos legislativos?', '["Legislación ejecutiva.", "Legislación delegada.", "Legislación delegante.", "Legislación secundaria."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Si se dicta una ley de bases ¿qué contenido tendrá el decreto legislativo de desarrollo?', '["Texto articulado.", "Ley ordinaria.", "Texto refundido.", "Texto delegado."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Si la delegación se realiza por medio de ley ordinaria ¿qué contenido tendrá el decreto legislativo de desarrollo?', '["Texto articulado.", "Ley ordinaria.", "Texto refundido.", "Texto delegado."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de las siguientes materias puede autorizar una ley de bases?', '["Facultar la aprobación de normas de carácter retroactivo.", "Autorizar la modificación de la propia ley de bases.", "Autorizar la aprobación de normas de carácter irretroactivo.", "Facultar y autorizar la modificación de la propia ley de bases, dictando normas de carácter retroactivo."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de las siguientes afirmaciones no es correcta en relación con la autorización contenida en la ley de delegación?', '["Debe otorgarse para materia concreta.", "Puede otorgarse de forma tácita.", "Debe otorgarse por tiempo determinado.", "Debe otorgarse de forma expresa."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Puede el Gobierno subdelegar la facultad de dictar legislación delegada?', '["En ningún caso.", "Sí, siempre que lo autorice la ley de delegación.", "Sí, siempre que delegue en autoridades administrativas.", "No, salvo que delegue en órganos administrativos."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cómo se denominan las normas con rango de ley aprobadas por el Gobierno, que contienen legislación delegada?', '["Decretos leyes.", "Reales Decretos.", "Decretos legislativos.", "Decretos."]'::jsonb, 2, 'es'),
    ('2a4ba259076b977b77507b8216bd6b29', '¿En qué Capítulo del Título III se regulan los Tratados Internacionales?', '["En el I.", "En el II.", "En el III.", "En el IV."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes tratados no requiere de autorización previa de las Cortes Generales?', '["Los tratados de carácter político.", "Los tratados de carácter militar.", "Los tratados de impliquen obligaciones financieras para la hacienda pública.", "Los tratados de colaboración social."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué procedimiento debe seguirse para la denuncia de un Tratado Internacional?', '["El mismo que para su aprobación.", "Es suficiente denuncia del Gobierno.", "Denuncia del Gobierno previa autorización del Senado.", "Denuncia de las Cortes Generales en cualquier caso."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuándo pasan a formar parte del ordenamiento nacional, los tratados firmados válidamente por España?', '["El mismo día de su publicación.", "Al día siguiente de su completa publicación en el Boletín Oficial de las Cortes Generales.", "Una vez publicados íntegramente en España.", "En el momento de su firma solemne."]'::jsonb, 2, 'es'),
    ('88f687385bed79ed556d261e5b494cb7', '¿Qué artículo de la Constitución recoge las delegaciones legislativas a favor de las Comunidades Autónomas?', '["El art. 149.", "El art. 150.", "El art. 159.", "El art. 167."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Si el Estado quiere dictar una ley que contenga los principios necesarios para armonizar las disposiciones normativas de las Comunidades Autónomas en una materia, dictará:', '["Una ley orgánica.", "Una ley de armonización.", "Una ley de bases.", "Una ley de delegación."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cómo se denominan los reglamentos que se encargan de desarrollar el contenido de una ley?', '["Reglamentos independientes.", "Reglamentos normativos.", "Reglamentos ad extra.", "Reglamentos ejecutivos."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué requisito debe cumplirse para dictar un reglamento general de ejecución de una ley?', '["Dictamen favorable del Consejo de Estado.", "Informe previo del Consejo de Estado.", "Dictamen favorable del Tribunal Constitucional.", "Dictamen previo del Ministerio de Presidencia."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Si la Administración ejercita su facultad de autoorganización y dicta un reglamento para regular sus servicios, estamos ante un reglamento:', '["De necesidad.", "Organizativo.", "Independiente.", "Ejecutivo."]'::jsonb, 1, 'es'),
    ('913657972c03f72eda057943f8f031d5', '¿Qué artículo de la ley del Gobierno establece las normas de jerarquía de los reglamentos?', '["El art. 23.", "El art. 43.", "El art. 32", "El art. 37."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuándo se aplica la costumbre como fuente del derecho?', '["En defecto de ley aplicable.", "En cualquier caso en que resulte de aplicación por la materia.", "En cualquier caso aunque exista ley aplicable.", "Cuando no existan principios generales del derecho aplicables al caso."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Si un reglamento está dirigido a todos los ciudadanos y ha de ser cumplido por los nacionales que actúan en un Estado, estamos ante un reglamento:', '["General.", "Especial.", "Inaplicable.", "Nulo de pleno derecho."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de las siguientes clases de leyes no existe?', '["Leyes marco.", "Leyes armonizadoras.", "Leyes de transferencia.", "Leyes reglamentarias."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las disposiciones que contradigan lo establecido en una norma de carácter superior:', '["Son nulas de pleno derecho.", "Deben ser adaptadas.", "Deben ser recurridas ante el Tribunal Supremo.", "Son anuladas por las Cortes Generales."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué mayoría se requiere en el Congreso de los Diputados para la aprobación de una ley orgánica?', '["Simple.", "Absoluta.", "De 2/3.", "De 1/3."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué mayoría se requiere en el Senado para la aprobación de una ley orgánica?', '["Simple.", "Absoluta.", "De 2/3.", "De 1/3."]'::jsonb, 0, 'es'),
    ('81b4196a9a98f87bf76f9a564d328a4d', '¿Qué artículo del Código Civil establece las fuentes del Derecho?', '["Ninguno.", "El art. 1.", "El art. 18.", "El art. 35."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Dónde deben publicarse las leyes?', '["En cualquier diario oficial.", "En el BOE.", "En todos los Boletines oficiales del territorio español.", "En el Diario de la Unión Europea."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué norma puede regular la institución del Defensor del Pueblo?', '["Una ley ordinaria.", "Una ley orgánica.", "Un decreto ley.", "Un decreto legislativo."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué norma puede regular la institución del Tribunal de Cuentas?', '["Una ley ordinaria.", "Una ley orgánica.", "Un decreto ley.", "Un decreto legislativo."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué norma puede regular la institución del Consejo de Estado?', '["Una ley ordinaria.", "Una ley orgánica.", "Un decreto ley.", "Un decreto legislativo."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué clases de órganos existen en todos los ayuntamientos?', '["Ordinarios y extraordinarios.", "Ordinarios y especiales.", "Obligatorios y necesarios.", "Complementarios y necesarios."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué tipo de órgano es el Pleno del Ayuntamiento?', '["Complementario.", "Ordinario.", "Especial.", "Necesario."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué tipo de órgano son los consejos sectoriales?', '["Complementario.", "Ordinario.", "Especial.", "Necesario."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué tipo de órgano son los Tenientes de Alcalde?', '["Complementario.", "Ordinario.", "Especial.", "Necesario."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué tipo de órgano son las Juntas Municipales de Distrito?', '["Complementario.", "Ordinario.", "Especial.", "Necesario."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cómo se denominan los concejales que ostentan aquellas atribuciones que les delegue el Alcalde dentro de sus propias competencias?', '["Concejales delegados.", "Concejales especiales.", "Concejales sectoriales.", "Concejales de distrito."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién puede acordar la creación de Juntas Municipales de Distrito?', '["El Pleno.", "El Alcalde.", "La Comunidad Autónoma respectiva.", "La Comisión de Gobierno."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué carácter tienen las Juntas Municipales de Distrito?', '["Órganos territoriales.", "Órganos necesarios.", "Órganos organizativos.", "Órganos supramunicipales."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué carácter tienen los Consejos Sectoriales?', '["Órganos territoriales.", "Órganos necesarios.", "Órganos organizativos.", "Órganos supramunicipales."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿A qué órgano le corresponde ejercer el examen de todas las cuentas presupuestarias de la Corporación?', '["Al Pleno.", "A la Comisión sectorial correspondiente.", "A la Comisión Especial de Cuentas.", "Al Alcalde."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién puede acordar la creación de Consejos Sectoriales?', '["El Pleno.", "La Junta Municipal de Distrito.", "La Comunidad Autónoma respectiva.", "La Comisión de Gobierno."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué órgano tiene como función canalizar la participación de los ciudadanos en los asuntos municipales?', '["El Pleno del Ayuntamiento.", "Los Consejos sectoriales.", "Los Tenientes de Alcalde.", "Los representantes del alcalde."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué competencias ejercen las Juntas Municipales de Distrito?', '["Las delegadas por el Pleno.", "Las delegadas por el Alcalde.", "Las delegadas por los Tenientes de Alcalde.", "Las delegadas por el Ayuntamiento."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué tipo de competencias puede ejercer un consejo sectorial?', '["De informe y propuesta.", "Sólo de informe.", "Sólo de propuesta.", "Ejecutivas, informativas y de gestión."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién puede establecer la composición de un consejo sectorial?', '["El Alcalde.", "El Pleno.", "La Comisión de Gobierno.", "La Junta Municipal de Distrito."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién puede ser candidato a la Alcaldía en el ayuntamiento de un municipio que cuente con 200 habitantes?', '["Todos los vecinos.", "Todos los concejales.", "Los concejales que encabecen sus listas respectivas.", "Todos los vecinos que tengan derecho de sufragio pasivo."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién puede ser candidato a la Alcaldía en el ayuntamiento de un municipio quePágina 63 cuente con 2000 habitantes?', '["Todos los vecinos.", "Todos los concejales.", "Los concejales que encabecen sus listas respectivas.", "Todos los vecinos que tengan derecho de sufragio pasivo."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En caso de empate ¿cómo se resuelve la provisión de la Alcaldía?', '["Por mayoría de edad.", "Por antigüedad en la Corporación.", "Por sorteo.", "Por nuevas elecciones."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién puede presentarse a la Alcaldía en un municipio que cuente con 87 habitantes?', '["Todos los vecinos.", "Todos los concejales.", "Los concejales que encabecen sus listas respectivas.", "Todos los vecinos que tengan derecho de sufragio pasivo y no estén incursos en causa de incompatibilidad."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Ante quién debe tomar posesión el Alcalde?', '["Ante el órgano competente de la Comunidad Autónoma.", "Ante el Pleno.", "Ante la Comisión de Gobierno.", "Ante el Alcalde saliente."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En caso de que el candidato proclamado Alcalde, no se encuentre presente en la sesión de constitución, ¿qué ocurrirá?', '["Que deberá celebrarse una nueva votación.", "Que será requerido para que comparezca en el plazo de 48 horas.", "Que será requerido para que comparezca en el plazo de 24 horas.", "Que será requerido para que comparezca en el plazo de 72 horas."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cómo debe presentar su renuncia el Alcalde?', '["Renunciando previamente a su cargo de concejal.", "Por escrito ante la Comisión de Gobierno.", "De cualquier forma que estime conveniente.", "Por escrito ante el Pleno."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿De qué plazo dispone el órgano competente para adoptar acuerdo de conocimiento de la renuncia del Alcalde?', '["Cinco días.", "Diez días.", "Quince días.", "Veinte días."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué Tratamiento ostenta el Alcalde de Madrid?', '["Ilustrísima.", "Señoría.", "Vuecencia.", "Excelentísimo."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué Tratamiento ostenta el Alcalde de Barcelona?', '["Ilustrísima.", "Señoría.", "Vuecencia.", "Excelentísimo."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué Tratamiento ostenta el Alcalde de Castellón?', '["Ilustrísima.", "Señoría.", "Vuecencia.", "Excelentísimo."]'::jsonb, 0, 'es'),
    ('44d79b874d664c3660e0439b3f2a6755', '¿Qué artículo de la Ley 7/ 1985, de 2 de abril, establece las normas de moción de censura?', '["El art. 197.", "El art. 198.", "El art. 119.", "El art. 120."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué mayoría de concejales puede presentar una moción de censura?', '["La mayoría simple del número legal.", "La mayoría absoluta del número legal.", "2/3 del número legal.", "1/5 del número legal."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién debe autenticar las firmas del escrito de interposición de una moción de censura contra el Alcalde?', '["El Secretario de la Corporación en cualquier caso.", "Un notario en cualquier caso.", "El Secretario de la Corporación o un Notario.", "El Pleno."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuántas mociones de censura puede presentar un concejal durante todo su mandato?', '["No existe límite prefijado.", "Dos.", "Una.", "Tres."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿A cuál de las siguientes materias no puede vincularse una cuestión de confianza?', '["A la aprobación de una ordenanza fiscal.", "A la aprobación de los presupuestos anuales.", "A la aprobación del reglamento orgánico.", "A la aprobación de una moción de censura."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién representa al Ayuntamiento?', '["El Pleno.", "La Comisión de Gobierno.", "El Alcalde.", "Todos los Concejales."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién ejerce la Jefatura de la Policía Municipal?', '["El Pleno.", "La Comisión de Gobierno.", "El Alcalde.", "Un Teniente de Alcalde."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué instrumento normativo debe utilizar el Alcalde para realizar una delegación de competencias?', '["Un Decreto.", "Un Bando.", "Una ordenanza.", "El reglamento orgánico."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿A qué órgano le corresponde ejercer las funciones de asistencia al Alcalde?', '["Al Pleno de la Corporación.", "A los Tenientes de Alcalde.", "A la Comisión de Gobierno.", "A las Comisiones informativas."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién nombra a los miembros de la Comisión de Gobierno?', '["La mitad del número legal de miembros de la corporación.", "Un tercio del número legal de miembros de la corporación.", "Tres.", "Cuatro."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué día se constituye el Ayuntamiento?', '["El día siguiente a la celebración de las elecciones.", "El vigésimo primer día posterior a la celebración de las elecciones.", "El vigésimo quinto día posterior a la celebración de las elecciones.", "El vigésimo día posterior a la celebración de las elecciones."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuánto tiempo dura el mandato de los concejales?', '["Dos años.", "Tres años.", "Cuatro años.", "Cinco años."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de las siguientes funciones es delegable por el Alcalde?', '["Convocar las sesiones del Pleno.", "Ejercer la jefatura superior de todo el personal.", "Ordenar la publicación de los acuerdos de la Corporación.", "Presidir las sesiones de la Comisión de Gobierno."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuáles son los dos tipos de delegaciones que puede realizar el Alcalde?', '["Ordinarias y extraordinarias.", "Ordinarias y genéricas.", "Genéricas y especiales.", "Especiales y ordinarias."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuántas cuestiones de confianza pueden plantearse en un año?', '["Dos.", "Una.", "Tres.", "Cinco."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En qué año se aprobó el Reglamento de organización y funcionamiento de las entidades locales?', '["1885.", "1986.", "1987.", "1988."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué día se aprobó el Reglamento de organización y funcionamiento de las entidades locales?', '["27 de noviembre.", "28 de noviembre.", "29 de noviembre.", "30 de noviembre."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de las siguientes clases de sesiones no existe?', '["Sesiones ordinarias.", "Sesiones urgentes.", "Sesiones secretas.", "Sesiones especiales."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cómo se denominan aquellas sesiones               cuya periodicidad está establecida de antemano por el Pleno?', '["Sesiones ordinarias.", "Sesiones comunes.", "Sesiones constitutivas.", "Sesiones especiales."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En qué tipo de sesión se acuerda la celebración de las sesiones cuya periodicidad se conoce con antelación?', '["En sesión nominal.", "En sesión ordinaria.", "En sesión extraordinaria.", "En sesión común."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuándo se celebra la sesión del pleno para establecer la periodicidad de las sesiones que se celebran periódicamente?', '["Veinte días después de la constitución del ayuntamiento.", "Dentro de los diez días hábiles siguientes a la constitución del ayuntamiento.", "En el plazo de los treinta días siguientes a la constitución del ayuntamiento.", "No existe normativa al respecto."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es el número mínimo de concejales que pueden solicitar la celebración de una sesión extraordinaria del Pleno?', '["Mayoría absoluta.", "Una décima parte del número legal.", "Una quinta parta del número legal.", "Dos tercios del número legal."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es el plazo máximo del que dispone el alcalde para convocar una sesión extraordinaria solicitada por los concejales?', '["Diez días.", "Un mes.", "Veinte días.", "Dos meses."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es el primer punto del orden del día de una sesión extraordinaria urgente del Pleno?', '["La lectura del orden del día.", "La presentación de credenciales.", "La apreciación de la urgencia de la sesión.", "La lectura del acta de la sesión anterior."]'::jsonb, 2, 'es');

