  insert into public.question_bank (content_hash, question, options, correct_index, lang)
  values
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuándo son secretas las sesiones del Pleno?', '["Siempre.", "Nunca.", "Cuando se trate de la aprobación de los presupuestos municipales.", "Cuando se traten asuntos que puedan afectar a la intimidad de las personas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Dónde celebra sus sesiones el Pleno?', '["En cualquier sede del Ayuntamiento.", "En la casa consistorial o sede de la corporación en cualquier caso.", "En la casa consistorial o sede de la corporación salvo fuerza mayor.", "En cualquier lugar habilitado al efecto."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es el quórum de una sesión del pleno?', '["Dos tercios del número legal de concejales.", "Un tercio del número legal de concejales.", "Mayoría absoluta del número legal de concejales.", "Basta con la asistencia del Alcalde y del Secretario."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es, en todo caso, el número de miembros de la Corporación que deben estar presentes en las sesiones del Pleno?', '["Dos.", "Cinco.", "Siete.", "Tres."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué ocurre si no existe quórum suficiente para celebrar una sesión del Pleno?', '["Que se celebra la sesión de todas formas.", "Que se entiende convocada a la misma hora, dos días después.", "Que se entiende convocada para dos horas después.", "Que la sesión no se celebrará."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién levanta la sesión del Pleno?', '["El Secretario de la Corporación.", "El Alcalde.", "Cualquiera de los miembros de la Corporación habilitado al efecto.", "Un miembro de la Comisión de Gobierno."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Puede interrumpirse una votación durante su celebración?', '["Sí, mediante acuerdo de la mesa correspondiente.", "Sí, por el Alcalde.", "No, en ningún caso.", "Sí, en cualquier momento."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es la regla para la adopción de acuerdos en el Pleno?', '["Mayoría simple.", "Mayoría absoluta.", "Mayoría de dos tercios.", "Mayoría de tres quintos."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué carácter tiene el voto de los concejales?', '["Personal y delegable.", "Impersonal e indelegable.", "Personal e indelegable.", "Impersonal y delegable."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién decide los empates en las votaciones del Pleno?', '["El Alcalde.", "El Secretario de la Corporación.", "El concejal de mayor edad.", "El grupo político con mayor número de concejales."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cómo se denominan las votaciones que se realizan mediante signos convencionales de asentimiento, disentimiento o abstención?', '["Secretas.", "Nominales.", "Ordinarias.", "Comunes."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cómo no pueden ser las votaciones del Pleno?', '["Ordinarias.", "Extraordinarias.", "Secretas.", "Nominales."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de las siguientes mayorías no existe en las votaciones del Pleno?', '["Absoluta.", "Extraordinaria.", "Especial.", "Unanimidad."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes acuerdos no debe adoptarse por mayoría absoluta del Pleno?', '["La modificación del reglamento orgánico de la corporación.", "Disolución de mancomunidades.", "Cesión del aprovechamiento de bienes comunales.", "Denominación de una calle del municipio."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién debe abrir una sesión del Pleno?', '["El Alcalde.", "El Secretario de la Corporación.", "El concejal de mayor edad.", "El grupo político con mayor número de concejales."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién debe leer el acta de la sesión anterior del Pleno?', '["El Alcalde.", "El Secretario de la Corporación.", "El concejal de mayor edad.", "El grupo político con mayor número de concejales."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cómo se debaten los asuntos del día en la sesión del Pleno?', '["Por el orden que marque el Alcalde.", "Por el orden incluido en la sesión del día.", "Por el orden establecido por el Secretario.", "En cualquier orden"]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuándo se celebra el turno de mociones de urgencia?', '["Antes de leer la sesión del día.", "Después del turno de ruegos y preguntas.", "Antes del turno de ruegos y preguntas.", "Antes del debate ordinario de asuntos."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién puede llamar al orden a los asistentes a una sesión del Pleno?', '["El Alcalde.", "El Secretario de la Corporación.", "El concejal de mayor edad.", "El grupo político con mayor número de concejales."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuándo puede ordenarse a un concejal que abandone la sesión del Pleno?', '["A la segunda llamada al orden.", "A la tercera llamada l orden.", "A la cuarta llamada al orden.", "A la quinta llamada al orden."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuándo celebra sesión ordinaria el Pleno de un Ayuntamiento cuyo municipio cuenta con una población de 200.000 habitantes?', '["Una vez al mes.", "Una vez cada quince días.", "Una vez a la semana.", "Dos veces al mes"]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cada cuánto tiempo como mínimo celebra sesión la Comisión de Gobierno?', '["Cada semana.", "Cada quince días.", "Una vez al mes.", "Una vez cada tres semanas."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién debe fijar el día y la hora de celebración de las sesiones de la Comisión de Gobierno?', '["El Pleno.", "El Alcalde.", "La propia Comisión.", "Se fija por la normativa vigente."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué instrumento normativo se utiliza para establecer la periodicidad de las sesiones de la Comisión de Gobierno?', '["Decreto.", "Ordenanza.", "Bando.", "Orden."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Dónde celebra sus sesiones la Comisión de Gobierno?', '["En cualquier sede del Ayuntamiento.", "En la casa consistorial o sede de la corporación en cualquier caso.", "En la casa consistorial o sede de la corporación salvo fuerza mayor.", "En cualquier lugar habilitado al efecto."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién establece la periodicidad de las sesiones de las Comisiones Informativas?', '["El Pleno.Página 71", "La Comisión de Gobierno.", "El Alcalde.", "La Comunidad Autónoma."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Por qué tipo de mayoría se aprueban los dictámenes de las Comisiones Informativas?', '["Por mayoría simple.", "Por mayoría absoluta.", "Por mayoría de dos tercios.", "Por unanimidad."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En cuál de las siguientes sesiones se debe incluir siempre un turno de ruegos y preguntas?', '["En las sesiones ordinarias.", "En las sesiones extraordinarias.", "En las sesiones urgentes.", "En las sesiones extraordinarias."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué calificación tienen los acuerdos adoptados en una sesión extraordinaria si no estaba incluido en el orden del día?', '["Nulo de pleno derecho.", "Anulable.", "Válido si era urgente.", "Válido si lo acuerda el Pleno."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cada cuánto tiempo celebra sesión ordinaria el Pleno del ayuntamiento de un municipio que cuente con menos de 5.000 habitantes?', '["Una vez al mes.", "Una vez cada dos meses.", "Una vez cada tres meses.", "Una vez cada seis meses."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes datos no debe constar en el contenido del acta de una sesión del Pleno?', '["La parte dispositiva de los acuerdos que se adopten.", "El carácter ordinario o extraordinario de la sesión.", "La hora en que comienza.", "La relación nominal de los votos realizados."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién debe custodiar el Libro de Actas de la corporación?', '["El Alcalde.", "El miembro de la corporación designado por el Alcalde.", "El Secretario de la Corporación.", "Cualquier miembro de la Comisión de Gobierno."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Puede salir el Libro de Actas de la Casa Consistorial?', '["No, en ningún caso.", "Sí, en caso de fuerza mayor.", "Sólo con autorización judicial previa.", "Sólo por resolución judicial."]'::jsonb, 0, 'es'),
