    ('4b830eab8fe6b21a82865850ecac45f6', '¿En cuál de los siguientes casos no es posible crear una comarca?', '["Si se oponen a ello alguno de los municipios que deben formarla.", "Si se oponen a ello expresamente las dos quintas partes de los municipios que deben agruparse en ella.", "Si se oponen a ello expresamente la tercera parte de los municipios que deben integrarse en ella.", "Si se oponen a ello expresamente la quinta parte de los municipios que deben integrarse en ella."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién debe establecer la composición de las comarcas?', '["La Comunidad Autónoma respectiva mediante ley.", "La Diputación respectiva.", "El Ministerio de Administraciones Públicas.", "Los Ayuntamientos que la integren."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién debe establecer los órganos de gobierno de las comarcas?', '["La Comunidad Autónoma respectiva mediante ley.", "La Diputación respectiva.", "El Ministerio de Administraciones Públicas.", "Los Ayuntamientos que la integren."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién debe establecer el funcionamiento de las comarcas?', '["La Comunidad Autónoma respectiva mediante ley.", "La Diputación respectiva.", "El Ministerio de Administraciones Públicas.", "Los Ayuntamientos que la integren."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de las siguientes características no es predicable de las mancomunidades?', '["Entidades territoriales.", "Son entidades privadas.", "Son entidades municipales.", "Son entes institucionales."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Es indispensable que los municipios de una mancomunidad pertenezcan a la misma provincia?', '["No, en ningún caso.", "Sí, en cualquier caso.", "Sólo si existe oposición por parte de la Diputación provincial.", "Sólo si existe oposición por parte de la Comunidad Autónoma."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes extremos no es necesario que conste en los estatutos de una mancomunidad?', '["Las causas de disolución.", "Los fines que tiene.", "El plazo de vigencia.", "Procedimiento de creación de estatutos."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién establece el procedimiento de aprobación de los estatutos de una mancomunidad?', '["La Comunidad Autónoma.", "La mancomunidad.", "La Diputación respectiva.", "Los Ayuntamientos que la integran."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién realiza la elaboración de los estatutos de una mancomunidad?', '["La Comunidad Autónoma.", "La mancomunidad.", "La Diputación respectiva.", "Los Ayuntamientos que la integran."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién debe emitir informe sobre el proyecto de estatutos de una mancomunidad?', '["La Comunidad Autónoma.", "La mancomunidad.", "La Diputación respectiva.", "Los Ayuntamientos que la integran."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién debe aprobar los estatutos de una mancomunidad?', '["La Comunidad Autónoma.", "La mancomunidad.", "La Diputación respectiva.", "Pleno de ayuntamientos que la integran"]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién establece la supresión de una mancomunidad?', '["La Comunidad Autónoma.", "La mancomunidad.", "La Diputación respectiva.", "Pleno de ayuntamientos que la integran"]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes no forma parte del órgano de gobierno de una mancomunidad?', '["Un representante de la Comunidad Autónoma respectiva.", "Un Presidente.", "Un Vicepresidente.", "Un Secretario."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cómo se denominan a las agrupaciones de municipios que rodean a las grandes aglomeraciones urbanas, entre cuyos núcleos de población existan vinculaciones económicas y sociales que hagan necesaria la planificación conjunta?', '["Mancomunidad.", "Comarca.", "Entidad local municipal.", "Área Metropolitana."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cómo se denomina la entidad local formada por la agrupación de municipios para la gestión en común de obras y servicios?', '["Mancomunidad.", "Comarca.", "Área Metropolitana.", "Provincia."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cómo se denomina la entidad local formada por la agrupación de municipios para la gestión de intereses comunes?', '["Mancomunidad.", "Comarca.", "Área Metropolitana.", "Provincia."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién puede crear un área metropolitana?', '["Los Ayuntamientos respectivos.", "La Diputación respectiva.", "La Comunidad Autónoma respectiva.", "El Ministerio de Administraciones Públicas."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién puede suprimir un área metropolitana?', '["Los Ayuntamientos respectivos.", "La Diputación respectiva.", "La Comunidad Autónoma respectiva.", "El Ministerio de Administraciones Públicas."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién establece los órganos de gobierno de un área metropolitana?', '["Los Ayuntamientos respectivos.", "La Diputación respectiva.", "La Comunidad Autónoma respectiva.", "El Ministerio de Administraciones Públicas."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién establece el régimen económico de un área metropolitana?', '["Los Ayuntamientos respectivos.", "La Diputación respectiva.", "La Comunidad Autónoma respectiva.", "El Ministerio de Administraciones Públicas."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién puede establecer los servicios que puede prestar un área metropolitana?', '["Los Ayuntamientos respectivos.", "La Diputación respectiva.", "La Comunidad Autónoma respectiva.", "El Ministerio de Administraciones Públicas."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes no puede constituir un recurso para un área metropolitana?', '["El recargo sobre el Impuesto de Bienes Inmuebles.", "Las Tasas.", "Las subvenciones.", "Los precios públicos."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes es un requisito imprescindible para que nos encontremos ante un acto administrativo?', '["Que sea dictado por una administración pública.", "Que contenga una resolución definitiva.", "Que afecte a los ciudadanos.", "Que contenga disposiciones sancionadoras."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de las siguientes clases de actos no existe?', '["Actos simples.", "Actos complejos.", "Actos administrativos privados.", "Actos firmes."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué es un acto de trámite?', '["El que no decide sobre el fondo del asunto ni da lugar a la terminación del expediente sino que prepara la decisión final.", "El que agota la vía administrativa en vía de recurso.", "El que causa estado.", "El que crea una relación jurídica."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué es un acto constitutivo?', '["El que no decide sobre el fondo del asunto ni da lugar a la terminación del expediente sino que prepara la decisión final.", "El que agota la vía administrativa en vía de recurso.", "El que causa estado.", "El que crea una relación jurídica."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué entendemos por acto firme?', '["Es el que no se puede recurrir.", "Es el que pone fin al procedimiento administrativo.", "Es el dictado por la Administración en vía de recurso exclusivamente.", "El dictado al inicio del procedimiento."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué es un acto definitivo?', '["Es el que no se puede recurrir.", "Es el que pone fin al procedimiento administrativo.", "Es el dictado por la Administración en vía de recurso exclusivamente.", "El dictado al inicio del procedimiento."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes actos administrativos no es impugnable?', '["Un acto definitivo.", "Un acto de trámite que decida sobre el fondo del asunto.", "Un acto de trámite que provoque indefensión.", "Un acto que no ponga fin a la vía administrativa en determinados casos."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué artículo de la ley 30/ 1992, de 26 de noviembre, establece los actos que ponen fin a la vía administrativa?', '["El 108.", "El 107.", "El 108.", "El 109."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes actos es impugnable?', '["Un acto firme.", "Un acto que reproduce el contenido de otro anterior definitivo y firme.", "Un acto confirmatorio de un acuerdo no recurrido en tiempo y forma.", "Un acto definitivo."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué es un acto expreso?', '["Un acto en el que se manifiesta la voluntad expresada por la Administración y normalmente en forma escrita.", "Un acto que no se produce directamente por la Administración.", "Cualquier acto que agote la vía administrativa.", "Un acto firme."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes elementos no conforma un acto administrativo?', '["El fin.", "La forma.", "El sujeto.", "El contenido."]'::jsonb, 3, 'es'),
    ('a4081b50999b05cd6634630ecd0c54b6', '¿Qué artículo de la Ley 30/ 1992, de 26 de noviembre, establece los casos en los que debe motivarse un acto administrativo?', '["El artículo 53.", "El artículo 54.", "El artículo 55.", "El artículo 56."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes actos no debe motivarse?', '["Un acto que acuerde la aplicación del procedimiento de urgencia.", "Un acto que acuerde la limitación de un interés legítimo.", "Un acto que acuerde la aplicación del precedente administrativo.", "Un acto que acuerde ampliar los plazos del procedimiento."]'::jsonb, 2, 'es'),
    ('564f502bc59e577409dabd5e3c302caa', '¿Qué artículo de la Ley 30/ 1992, de 26 de noviembre, establece los casos en los que debe notificarse un acto administrativo?', '["El artículo 58.", "El artículo 53.", "El artículo 52.", "El artículo 59."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Debe notificarse un acto de trámite?', '["Sí, en cualquier caso.", "No.", "Sólo si lo solicita el interesado.", "Sólo si hay causa de fuerza mayor."]'::jsonb, 1, 'es'),
    ('a4081b50999b05cd6634630ecd0c54b6', '¿Qué artículo de la Ley 30/ 1992, de 26 de noviembre, establece la regulación de las notificaciones personales de un acto administrativo?', '["El artículo 53.2.", "El artículo 54.4.", "El artículo 55.2.", "El artículo 59."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué se debe hacer con la acreditación de una notificación?', '["Incorporarla al expediente.", "Remitirla al interesado.", "Remitirla al registro correspondiente.", "Notificarla al interesado inmediatamente."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cómo deben practicarse las notificaciones?', '["Siempre por escrito.", "De manera directa.", "De manera indirecta.", "De cualquier forma que permita tener constancia de su recepción."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Si un interesado presenta una solicitud ¿dónde se realizarán las notificaciones?', '["En el domicilio indicado en la misma.", "En el domicilio que conste en el padrón", "En el tablón de edictos del Ayuntamiento.", "En la propia sede administrativa."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuántas veces debe intentarse una notificación?', '["Dos veces.", "Una vez.", "Tres veces.", "Cuantas veces sea necesario."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes extremos es imprescindible que conste en una notificación?', '["El texto íntegro del acto.", "La fecha de inicio del expediente.", "Fecha de terminación del procedimiento.", "Identificación de la autoridad firmante."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Desde cuándo surten efectos los actos administrativos, como regla general?', '["Desde el momento en que se dictan.", "Desde el día siguiente al que sean dictados.", "Desde que se notifiquen.", "Desde el día en que se publiquen."]'::jsonb, 0, 'es'),
    ('06ae87cb561aaaaa22c7aeb0c1f6f679', '¿En qué artículo de la Ley 30/ 1992,de 26 de noviembre, se establecen los supuestos en los que queda demorada la eficacia de un acto administrativo?', '["En el artículo 56.", "En el artículo 57.", "En el artículo 58.", "En el artículo 59."]'::jsonb, 1, 'es'),
    ('be999e13ce150c6e7e90d2d342b4e2b7', '¿En qué artículo de la Ley 30/ 1992,de 26 de noviembre, se establecen los supuestos de anulabilidad de un acto administrativo?', '["En el artículo 66.", "En el artículo 62.", "En el artículo 63.", "En el artículo 69."]'::jsonb, 2, 'es'),
    ('0443cd9d0325285e781bec821e5c3ddd', '¿En qué artículo de la Ley 30/ 1992,de 26 de noviembre, se establecen los supuestos de nulidad de un acto administrativo?', '["En el artículo 62.", "En el artículo 63.", "En el artículo 64.", "En el artículo 69."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes actos se considera nulo de pleno derecho?', '["El que restrinja intereses legítimos.", "El que tenga un contenido posible.", "El que se dicte por un órgano incompetente por razón del territorio.", "El que contenga un defecto de forma."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes actos es anulable?', '["El que incurra en desviación de poder.", "El que tenga un contenido imposible.", "El que se dicte prescindiendo parcialmente del procedimiento.", "El que lesione un derecho susceptible de amparo."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de las siguientes características es predicable de los actos anulables?', '["No producen efectos.", "Sólo afecta a los interesados.", "No puede ser convalidado.", "Producen ineficacia por sí mismos."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de las siguientes características no es predicable de los actos nulos?', '["No producen efectos.", "Sólo afecta a los interesados.", "No puede ser convalidado.", "Producen ineficacia por sí mismos."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las actuaciones administrativas realizadas fuera de plazo ¿invalidan el acto que se dicte?', '["Sí, en cualquier caso.", "No, en ningún caso.", "Sólo si provocan indefensión.", "Sólo si el término es esencial."]'::jsonb, 3, 'es'),
    ('425d57b101ca23eb5a6fbd2f9eb19dab', '¿En qué artículo de la Ley 30/1992, de 26 de noviembre, se establecen los supuestos de convalidación de un acto administrativo?', '["En el artículo 68.", "En el artículo 63.", "En el artículo 61.", "En el artículo 67."]'::jsonb, 3, 'es'),
    ('dadaf5d59a71b5e405e17158a0bbfb19', '¿En qué artículo de la Ley 30/ 1992,de 26 de noviembre, se establece la regulación de la declaración de lesividad de los actos anulables?', '["En el artículo 116.", "En el artículo 106.", "En el artículo 108.", "En el artículo 103."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es el plazo del que dispone la Administración para declarar de oficio, la nulidad de los actos que dicte?', '["Un año.", "Dos años.", "No existe plazo alguno.", "Cinco años."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es el plazo de caducidad de un procedimiento de revisión de actos nulos?', '["Dos meses.", "Un mes.", "Tres meses.", "Quince días."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es el plazo de caducidad de un procedimiento de declaración de lesividad de actos anulables?', '["Dos meses.", "Un mes.", "Tres meses.", "Quince días."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué órgano es competente para revisar de oficio los actos dictados por un órgano dependiente de una Secretaría de Estado?', '["El Secretario de Estado.", "El Ministro del Departamento correspondiente.", "El Consejo de Ministros.", "El Presidente del Gobierno."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Pueden revocarse actos de gravamen por parte de la Administración?', '["No, en ningún caso.", "Sí, en cualquier momento.", "Sí, pero siempre que no constituya dispensa de la ley o sea contraria al principio de igualdad, al interés público o al ordenamiento jurídico.", "Sólo por el órgano superior al que lo dictó."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuándo puede solicitarse la revisión de errores materiales de un acto administrativo?', '["En cualquier momento.", "Diez días desde que fuera dictado.", "Un mes desde que fuera dictado.", "Un año desde que fuera dictado."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuándo puede solicitarse la revisión de errores de hecho de un acto administrativo?', '["En cualquier momento.", "Diez días desde que fuera dictado.", "Un mes desde que fuera dictado.", "Un año desde que fuera dictado."]'::jsonb, 0, 'es'),
    ('5ad7c64f39fd1a1442e43a426a7b76dc', '¿En qué artículo de la Ley 30/ 1992,de 26 de noviembre, se establecen las causas de abstención de las autoridades y funcionarios en un procedimiento administrativo?', '["En el artículo 26.", "En el artículo 21.", "En el artículo 28.", "En el artículo 23."]'::jsonb, 2, 'es'),
    ('5ad7c64f39fd1a1442e43a426a7b76dc', '¿En qué artículo de la Ley 30/ 1992, de 26 de noviembre, se establecen las causas de recusación de las autoridades y funcionarios en un procedimiento administrativo?', '["En el artículo 26.", "En el artículo 21.", "En el artículo 28.", "En el artículo 23."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de las siguientes no se considera causa de abstención en el procedimiento administrativo?', '["Haber tenido intervención como perito en el procedimiento.", "Haber mantenido relación de servicios con una persona interesada en el año anterior inmediato al inicio del procedimiento.", "Tener parentesco de afinidad de tercer grado con un interesado en el procedimiento.", "Tener parentesco de consanguinidad de cuarto grado con un interesado en el procedimiento."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de las siguientes no se considera causa de recusación en el procedimiento administrativo?', '["Haber tenido intervención como perito en el procedimiento.", "Haber mantenido relación de servicios con una persona interesada en el año anterior inmediato al inicio del procedimiento.", "Tener parentesco de afinidad de tercer grado con un interesado en el procedimiento.", "Tener parentesco de consanguinidad de cuarto grado con un interesado en el procedimiento."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de las siguientes características no debe reunir el contenido de un acto?', '["Lícito.", "Posible.", "Indeterminado.", "Determinable."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes actos del Ayuntamiento, como regla general, agota la vía administrativa?', '["Un acto dictado por el Alcalde.", "Un acto dictado por el Pleno.", "Un acto dictado por la Comisión de Gobierno.", "Un acto dictado por los Tenientes de Alcalde."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué actos dictados por un Director General de un Ministerio agotan la vía administrativa?', '["Los dictados en materia de gestión presupuestaria.", "Los dictados en materia de autorización presupuestaria.", "Los dictados en materia de personal.", "Los dictados en materia organizativa."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Debe motivarse un acto administrativo que se separe del criterio administrative precedente?', '["En ningún caso.", "Siempre.", "Siempre que medie orden de un superior jerárquico.", "Sólo si lo solicita expresamente el interesado."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cómo deben motivarse los actos que pongan fin a un procedimiento selectivo?', '["Siempre por escrito.", "De manera individualizada.", "En la forma que establezcan las normas que regulen su convocatoria.", "En el tablón de anuncios del órgano convocante."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuándo deben notificarse a los interesados un acto administrativo?', '["Cuando afecte a sus intereses.", "Cuando se produzca sea de la clase que sea.", "Cuando lo solicite por escrito.", "Cuando lo indique en la solicitud de iniciación del procedimiento."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cómo se denomina el elemento del acto administrativo que es la razón justificadora del mismo?', '["Elemento formal.", "Elemento causal.", "Elemento objetivo.", "Elemento subjetivo."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de las siguientes leyes se encarga de regular el procedimiento administrative común?', '["La Ley 30/ 1992, de 26 de noviembre.", "La ley 30/ 1991, de 26 de noviembre.", "La ley 30/ 1990, de 26 de noviembre.", "La Ley 3/ 1992, de 21 de noviembre."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de las siguientes personas no tiene capacidad de obrar ante las Administraciones públicas?', '["Un menor de edad.", "Un penado de prisión.", "Una persona declarada incapaz para ello por sentencia judicial firme.", "Un funcionario inhabilitado para ejercer funciones públicas."]'::jsonb, 2, 'es'),
    ('4ed946112b9521dd4550bc43abd6b4f4', '¿Qué artículo de la ley reguladora del procedimiento establece quien tiene capacidad de obrar ante las administraciones públicas?', '["El artículo 29.", "El artículo 30.", "El artículo 31.", "El artículo 32."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de las siguientes personas no se considera interesado en un procedimiento?', '["Quien lo promueva como titular de un interés legítimo.", "Quien tenga derechos que puedan resultar afectados por la resolución que se adopte.", "Quien sea titular de intereses subjetivos que puedan resultar afectados por la resolución que se adopte.", "Quien tenga un interés legítimo que pueda resultar afectado por la resolución que se adopte siempre que se persone en el procedimiento."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Puede considerarse como interesado a una asociación?', '["No, en ningún caso.", "Si, siempre que represente a intereses subjetivos de una colectividad.", "Si, siempre que represente intereses legítimos colectivos.", "Sólo en casos de fuerza mayor."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Es heredable la condición de interesado?', '["No, porque los derechos del interesado concluyen con el fallecimiento.", "Sí.", "No, salvo en casos excepcionales.", "Sólo si el fallecido era titular de un derecho legítimo."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién ejerce la legitimación activa en un procedimiento?', '["Todos los interesados.", "La Administración afectada.", "Quienes promuevan el procedimiento.", "Quienes se personen en el procedimiento."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién puede ser representante de un interesado en el procedimiento?', '["Cualquier persona mayor de edad.", "Cualquier persona con capacidad de obrar.", "Cualquier interesado en el procedimiento.", "Cualquier persona designada por la Administración."]'::jsonb, 1, 'es'),
    ('4ed946112b9521dd4550bc43abd6b4f4', '¿Qué artículo de la ley reguladora del procedimiento establece quien puede ser representante ante las administraciones públicas?', '["El artículo 29.", "El artículo 30.", "El artículo 31.", "El artículo 32."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En cuál de los siguientes casos no es necesario que se acredite la representación?', '["Para entablar un recurso administrativo.", "Para desistir de una acción administrativa.", "Para presentar un documento.", "Para renunciar a derechos en nombre de otra persona."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué plazo debe conceder la administración para que se subsane un defecto de acreditación de la representación?', '["Cinco días.", "Diez días.", "Siete días.", "Veinte días."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Pueden acudir los interesados con un asesor a las actuaciones del procedimiento?', '["En ningún caso porque no estamos en un proceso jurisdiccional.", "No, salvo que lo soliciten de manera expresa en la solicitud de inicio del procedimiento.", "Sí, cuando lo consideren oportuno.", "No, salvo en casos de fuerza mayor."]'::jsonb, 2, 'es'),
    ('ac2842cb28fc1b51e5fe9d5ea3303e0f', '¿Qué artículo de la ley reguladora del procedimiento establece la posibilidad de que se dé una pluralidad de interesados?', '["El artículo 33.", "El artículo 35.", "El artículo 37.", "El artículo 32."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En caso de que una solicitud se presente por varios interesados ¿con quién se realizarán las actuaciones a que haya lugar?', '["Con quien sea designado en el escrito de solicitud.", "Con quien designe la administración.", "Con quien firme en último lugar la solicitud.", "Con cualquiera de los firmantes."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En caso de que una solicitud se presente por varios interesados ¿con quién se realizarán las actuaciones a que haya lugar, en caso de que los interesados no especifiquen nada al respecto?', '["Con quien sea designado en el trámite de audiencia.", "Con quien designe la administración.", "Con quien firme en último lugar la solicitud.", "Con cualquiera de los firmantes."]'::jsonb, 0, 'es'),
    ('9cf4b14b0001ecf4d56cac837baa5cb4', '¿Qué artículo de la ley reguladora del procedimiento establece los derechos de los ciudadanos en sus relaciones con las administraciones públicas?', '["El artículo 32.", "El artículo 35.", "El artículo 31.", "El artículo 34."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes derechos no se considera un derecho de los ciudadanos en sus relaciones con la administración?', '["El derecho a utilizar las lenguas oficiales en su Comunidad Autónoma.", "El derecho a identificar a las personas responsables del procedimiento.", "El derecho a obtener copias de los documentos que presenten.", "El derecho a presentar alegaciones en cualquier momento del procedimiento."]'::jsonb, 3, 'es');

  -- Batch 1201-1400
  insert into public.question_bank (content_hash, question, options, correct_index, lang)
  values
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuándo puede negarse un ciudadano a presentar documentos ante la Administración?', '["En ningún caso.", "En cualquier caso porque no es una obligación jurídica.", "Cuando ya los hubieran presentado con anterioridad.", "Cuando se exijan por normas reglamentarias, pero no cuando se exijan por normas de rango legal."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En qué lengua se deben tramitar los procedimientos que se desarrollen en el ámbito de la Administración General del Estado?', '["En castellano en algunos casos.", "En español.", "En castellano o en la lengua cooficial de la Comunidad Autónoma respectiva, a elección de la Administración.", "En la lengua elegida por el interesado en cualquier caso."]'::jsonb, 0, 'es'),
    ('2e3621adc4c962251d9e195efd8b0393', '¿Qué artículo de la ley reguladora del procedimiento establece las reglas para ejercer el derecho al uso de la propia lengua?', '["El artículo 36.", "El artículo 39.", "El artículo 32.", "El artículo 34."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En qué casos están obligados los ciudadanos a facilitar informes a la Administración?', '["En cualquier caso.", "Siempre que se establezca en una norma de rango legal.", "Siempre que se establezca en una norma reglamentaria.", "Siempre que se establezca en una norma independientemente de su rango jerárquico."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En qué casos están obligados los ciudadanos a comparecer ante la Administración?', '["En cualquier caso.", "Siempre que se establezca en una norma de rango legal.", "Siempre que se establezca en una norma reglamentaria.", "Siempre que se establezca en una norma independientemente de su rango jerárquico."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En cuál de los siguientes casos pueden los ciudadanos acceder a un archive administrativo?', '["En caso de que se encuentren instalados en un archivo sonoro.", "En caso de que no se encuentren en soporte de papel.", "En caso de que se correspondan con procedimientos actualizados.", "En caso de que se correspondan con procedimientos concluidos en esa fecha."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Es compatible el derecho de acceso a un registro con el derecho a obtener copias de los documentos consultados?', '["Sólo en bibliotecas públicas.", "No, en el caso de que se trate de la consulta de los documentos de un procedimiento administrativo.", "Sí, si existe el derecho de acceso existe el derecho a obtener copias de los documentos consultados.", "Sólo con autorización escrita y expresa del responsable del registro."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes archivos si se puede consultar?', '["Los archivos sanitarios.", "Los archivos urbanísticos.", "Los archivos que contengan actuaciones del Gobierno.", "Los archivos que contengan actuaciones de las Comunidades Autónomas."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cómo definiría el procedimiento administrativo?', '["El cauce formal de la serie de actos en que se concreta la actuación administrativa para realizar un fin.", "El cauce material de la serie de actos en que se concreta la actuación administrativa para realizar un fin.", "El cauce formal de la serie de actos en que se concreta la actuación administrativa para la adecuación a un fin.", "El cauce formal de la serie de actos en que se concreta la actuación administrativa para la realización de un objeto."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de las siguientes no es una fase del procedimiento administrativo?', '["Iniciación.", "Conclusión.", "Instrucción.", "Ordenación."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Con cuántos Títulos cuenta la ley reguladora del procedimiento administrativo?', '["Cinco.", "Siete.", "Nueve.", "Diez."]'::jsonb, 3, 'es'),
    ('e947057ff2f42db277860ce0b90afaed', '¿En qué Título de la ley reguladora del procedimiento administrativo común se recoge la regulación de las fases del procedimiento administrativo?', '["En el Título II.", "En el Título VI.", "En el Título III.", "En el Título IV."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes principios no es predicable del procedimiento administrativo?', '["El principio de unidad.", "El principio de parcialidad.", "El principio de oficialidad.", "El principio de antiformalismo."]'::jsonb, 1, 'es'),
    ('e953422e8963af63db051da225c8ca30', '¿Qué artículo de la ley reguladora del procedimiento establece el contenido de las solicitudes de iniciación de procedimientos administrativos?', '["El artículo 69.", "El artículo 71.", "El artículo 70.", "El artículo 73."]'::jsonb, 2, 'es'),
    ('e953422e8963af63db051da225c8ca30', 'Cuando las pretensiones correspondientes a una pluralidad de personas tengan un contenido y fundamento idéntico o sustancialmente similar:', '["Podrán ser formuladas en una única solicitud.", "Se entenderán las actuaciones sólo con un representante.", "No se permitirá la presentación en una única solicitud como regla general.", "Se aplicarán las normas del art. 69.1 de la ley reguladora del procedimiento."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes datos constará en el recibo que acredite la presentación de un escrito ante la Administración?', '["La fecha de presentación.", "El nombre del interesado.", "La fecha de terminación.", "El objeto del procedimiento."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En qué casos debe establecer la Administración modelos y sistemas normalizados de solicitudes?', '["En cualquier caso.", "Cuando se presuma la acudida masiva de ciudadanos.", "Cuando se trate de procedimientos que impliquen la resolución numerosa de una serie de procedimientos.", "Cuando la Administración lo estime oportuno."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Por cuál de las siguientes formas decimos que el procedimiento no comienza de oficio?', '["Mediante solicitud.", "Por orden superior.", "Por denuncia.", "Por petición razonada de un órgano administrativo."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes extremos no consta en una solicitud de inicio del procedimiento administrativo?', '["La fecha.", "El lugar.", "El órgano al que se dirige.", "El teléfono del interesado."]'::jsonb, 3, 'es'),
    ('885a45e11d61e4ce6a9c5c025e04e05c', '¿Qué artículo de la ley reguladora del procedimiento administrativo establece el contenido de las solicitudes?', '["El art. 70.", "El art. 71.", "El art. 72.", "El art. 73."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de las siguientes reglas no se aplica a la tramitación del procedimiento administrativo común?', '["Celeridad.", "Eficacia.", "Suspensión de la tramitación en caso de que se suscite cualquier tipo de cuestión incidental.", "Oficialidad."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes puede adoptar las medidas provisionales en un procedimiento administrativo común?', '["El órgano que deba resolverlo.", "El órgano que lo inicie.", "El órgano que lo instruya.", "El órgano que fije el periodo de solicitudes."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cómo debe realizarse una comunicación entre órganos administrativos pertenecientes a una misma Administración pública?', '["Siempre por escrito.", "Directamente.", "Indirectamente.", "A través de órganos intermediarios."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué tipo de recurso cabe contra el acuerdo de acumulación de expedientes?', '["El recurso de potestativo de reposición.", "El recurso de alzada.", "El recurso extraordinario de revisión.", "No cabe recurso."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué implica la realización de actuaciones administrativas fuera de plazo?', '["La nulidad de pleno derecho.", "La anulabilidad del acto en todo caso.", "La anulabilidad del acto cuando lo disponga así la naturaleza del término.", "La nulidad del acto cuando lo disponga así la naturaleza del término."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cómo se computan los plazos salvo que se indique otra cosa?', '["En días hábiles.", "En días naturales.", "Por semanas.", "Por meses."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué tipo de recurso cabe contra el acuerdo de ampliación de plazos del procedimiento?', '["El recurso de potestativo de reposición.", "El recurso de alzada.", "El recurso extraordinario de revisión.", "No cabe recurso."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué tipo de recurso cabe contra el acuerdo de aplicación de la tramitación de urgencia al procedimiento?', '["El recurso de potestativo de reposición.", "El recurso de alzada.", "El recurso extraordinario de revisión.", "No cabe recurso."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es el plazo máximo de realización de la prueba en el procedimiento?', '["Diez días.", "Treinta días.", "Quince días.", "Veinte días."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es el plazo máximo de emisión de un informe en el procedimiento?', '["Diez días.", "Treinta días.", "Quince días.", "Veinte días."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es el plazo máximo de realización del trámite de audiencia en el procedimiento administrativo común?', '["Diez días.", "Treinta días.", "Quince días.", "Veinte días."]'::jsonb, 2, 'es'),
    ('4a6496eacb370328674243ee6729c106', '¿En qué artículo de la ley reguladora del procedimiento se regula el desistimiento?', '["En el art. 90.", "En el art. 91.", "En el art. 92.", "En el art. 93."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de las siguientes formas no es un modo de terminación del procedimiento administrativo común?', '["Renuncia.", "Caducidad.", "Allanamiento.", "Res olución."]'::jsonb, 2, 'es'),
    ('6ce7d35adef6802708db74c5bf25243e', '¿Qué artículo de la ley reguladora del procedimiento se encarga de conceptuar el recurso de alzada?', '["El artículo 114.", "El artículo 116.", "El artículo 119.", "El artículo 121."]'::jsonb, 0, 'es'),
    ('f65a8b25a2a416352dc09de8e1b3f64c', '¿Qué artículo de la ley reguladora del procedimiento se encarga de establecer los plazos de interposición del recurso potestativo de reposición?', '["El artículo 113.", "El artículo 111.", "El artículo 117.", "El artículo 112."]'::jsonb, 2, 'es'),
    ('f65a8b25a2a416352dc09de8e1b3f64c', '¿Qué artículo de la ley reguladora del procedimiento se encarga de conceptuar los casos en los que cabe interponer el recurso extraordinario de revisión?', '["El artículo 113.", "El artículo 115.", "El artículo 118.", "El artículo 111."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes extremos no debe constar en el escrito de interposición de un recurso administrativo?', '["El acto que se recurre.", "El nombre del recurrente.", "El teléfono personal del recurrente.", "La firma del recurrente."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es el efecto inmediato de la interposición de un recurso administrativo?', '["La obligación de resolverlo.", "La suspensión del acto impugnado.", "La anulación del acto impugnado y la obligación de resolverlo.", "La obligación de resolverlo y la suspensión del acto impugnado."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué órgano puede acordar la suspensión del acto impugnado en un recurso administrativo?', '["El órgano que lo presentó.", "El órgano que lo instruya.", "El órgano que deba resolverlo.", "El superior jerárquico del órgano que deba resolverlo."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En qué causas debe basarse un recurso administrativo para solicitar la suspensión del acto impugnado?', '["En cualquiera de las causas de nulidad.", "En cualquiera de las causas de anulabilidad.", "En cualquiera de las causas de irregularidad.", "En cualquiera de las causas de atemporalidad."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es el plazo pasado el cual se entiende denegada la solicitud de suspensión de ejecución de un acto impugnado?', '["Quince días.", "Veinte días.", "Treinta días.", "Siete días."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes actos puede ser recurrido mediante la interposición de un recurso de alzada?', '["Un acto que ponga fin a la vía administrativa.", "Un acto que no ponga fin a la vía administrativa.", "Un acto que no incurra en una causa de nulidad.", "Un acto que no incurra en causa de anulabilidad."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Ante quien se interpone el recurso de alzada?', '["Ante el órgano que instruyó el acto recurrido.", "Ante el órgano que inició el procedimiento por el que se dictó el acto que se impugna.", "Ante el órgano que dictó el acto impugnado o ante su superior jerárquico.", "Ante el órgano que dictó el acto impugnado, en cualquier caso."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es el plazo de interposición del recurso de alzada si se interpone contra un acto administrativo expreso?', '["Diez días.", "Veinte días.", "Un mes.", "Treinta días."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es el plazo de interposición del recurso de alzada si se interpone contra un acto administrativo presunto?', '["Tres meses.", "Quince días.", "Un mes.", "Treinta días."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es el plazo máximo para la resolución del recurso de alzada?', '["Un mes.", "Veinte días.", "Tres meses.", "Dos meses."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En caso de que no se dicte resolución de un recurso de alzada dentro del plazo establecido al efecto, ¿cuál será el sentido del silencio administrativo?', '["Positivo como regla general.", "Negativo como regla general.", "Positivo en todo caso.", "Negativo en todo caso."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es el plazo de interposición del recurso potestativo de reposición si se interpone contra un acto administrativo expreso?', '["Diez días.", "Veinte días.", "Un mes.", "Treinta días."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es el plazo de interposición del recurso potestativo de reposición si se interpone contra un acto administrativo presunto?', '["Veinte días.", "Tres meses.", "Un mes.", "Treinta días."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es el plazo máximo para la resolución del recurso potestativo de reposición?', '["Un mes.", "Veinte días.", "Tres meses.", "Dos meses."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Ante quien se interpone el recurso potestativo de reposición?', '["Ante el órgano que instruyó el acto recurrido.", "Ante el órgano que inició el procedimiento por el que se dicto el acto que se impugna.", "Ante el órgano que dictó el acto impugnado o ante su superior jerárquico.", "Ante el órgano que dictó el acto impugnado en cualquier caso."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes actos puede ser recurrido mediante la interposición de un recurso potestativo de reposición?', '["Un acto que ponga fin a la vía administrativa.", "Un acto que no ponga fin a la vía administrativa.", "Un acto que no incurra en una causa de nulidad.", "Un acto que no incurra en causa de anulabilidad."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Ante quien se interpone el recurso extraordinario de revisión?', '["Ante el órgano que instruyó el acto recurrido.", "Ante el órgano que inició el procedimiento por el que se dictó el acto que se impugna.", "Ante el órgano que dictó el acto impugnado o ante su superior jerárquico.", "Ante el órgano que dictó el acto impugnado, en cualquier caso."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es el plazo máximo para la resolución del recurso extraordinario de revisión?', '["Un mes.", "Veinte días.", "Tres meses.", "Dos meses."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En caso de que se incurra en un error de hecho al dictar un acto administrativo ¿cuál es el plazo de interposición del recurso extraordinario de revisión?', '["Un mes.", "Quince días.", "Cuatro años.", "Tres meses."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En caso de que aparezca un documento de valor tras dictar un acto administrative ¿cuál es el plazo de interposición del recurso extraordinario de revisión?', '["Un mes.", "Quince días.", "Cuatro años.", "Tres meses."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En caso de que en la resolución de un acto administrativo hayan influido documentos declarados falsos por sentencia judicial firme ¿cuál es el plazo de interposición del recurso extraordinario de revisión?', '["Un mes.", "Quince días.", "Cuatro años.", "Tres meses."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En caso de que en la resolución de un acto administrativo se haya dictado como consecuencia de una maquinación fraudulenta declarada como tal por sentencia judicial firme ¿cuál es el plazo de interposición del recurso extraordinario de revisión?', '["Un mes.", "Quince días.", "Cuatro años.", "Tres meses."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En caso de que no se dicte resolución de un recurso potestativo de reposición dentro del plazo establecido al efecto, ¿cuál será el sentido del silencio administrativo?', '["Positivo como regla general.", "Negativo como regla general.", "Positivo en todo caso.", "Negativo en todo caso."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En caso de que no se dicte resolución de un recurso extraordinario de revisión dentro del plazo establecido al efecto, ¿cuál será el sentido del silencio administrativo?', '["Positivo como regla general.", "Negativo como regla general.", "Positivo en todo caso.", "Negativo en todo caso."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes actos puede ser recurrido mediante la interposición de un recurso extraordinario de revisión?', '["Un acto firme en vía administrativa.", "Un acto no firme en vía administrativa.", "Un acto que no incurra en una causa de nulidad.", "Un acto que no incurra en causa de anulabilidad."]'::jsonb, 0, 'es'),
