    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cómo se denomina a la actividad administrativa en la que la Administración remueve un obstáculo que para el particular viene impuesto por la normativa establecida?', '["Licencia.", "Autorización.", "Dispensa.", "Exención."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes medios no lo es de ejecución forzosa?', '["Ejecución subsidiaria.", "Apremio sobre el patrimonio.", "Multa subsidiaria.", "Compulsión sobre las personas."]'::jsonb, 2, 'es'),
    ('cbe1da40c4d9d2c28a34c5d31f053595', '¿Qué artículo de la ley reguladora del procedimiento establece cuales son los medios de ejecución forzosa?', '["El artículo 96.", "El artículo 97.", "El artículo 98.", "El artículo 99."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de las siguientes normas establece el procedimiento para la concesión de subvenciones públicas?', '["Real Decreto 2225/ 1993, de 17 de diciembre.", "Real Decreto 2235/ 1993, de 17 de diciembre.", "Real Decreto 2215/ 1993, de 17 de diciembre.", "Real Decreto 2205/ 1993, de 17 de diciembre."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes medios se puede considerar como un medio de subvención?', '["Una beca.", "Una dispensa.", "Una prima.", "Un gasto de ayuda personal."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de las siguientes normas no es predicable del otorgamiento de subvenciones?', '["Pueden ser invocadas como precedente.", "No permiten exigir su revisión.", "Pueden ser revocables.", "Tienen, como regla general, carácter voluntario y eventual."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los acuerdos de concesión de subvenciones que respondan a mera liberalidad:', '["Están permitidos por el ordenamiento jurídico.", "Son nulos de pleno derecho.", "Son anulables.", "Son irregulares."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes no es un medio de intervención en la actividad de los ciudadanos por parte de las Corporaciones locales?', '["Las ordenanzas.", "Los bandos.", "El sometimiento a previa licencia.", "Las subvenciones."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En qué año se aprobó el reglamento de servicios de las corporaciones locales?', '["1955.", "1965.", "1975.", "1985."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En cuál de los siguientes casos puede intervenir un Ayuntamiento en la actividad de sus administrados?', '["Cuando exista perturbación o peligro de perturbación de la tranquilidad pública.", "Para velar por el incumplimiento de los planes de ordenación urbanística que hayan de aprobarse.", "Para asegurar el abasto de artículos de consumo de primera necesidad.", "En los casos autorizados legalmente."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de las siguientes notas no es predicable de las licencias administrativas?', '["Es un acto administrativo.", "Es un acto reglado.", "Otorga intereses legítimos.", "No crea derechos subjetivos."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de las siguientes no se considera una licencia urbanística a tenor de lo establecido en el Reglamento de Servicios de las Corporaciones Locales?', '["Los movimientos de tierra.", "Las obras de nueva planta.", "La demolición de construcciones.", "La supresión de carteles de propaganda."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es el plazo, contado desde la fecha de entrada en registro de una solicitud de licencia, en el que deben remitirse los duplicados del proyecto técnico a los órganos que deban informar sobre ellos?', '["Siete días.", "Cinco días.", "Diez días.", "Quince días."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es el plazo de emisión de informes sobre las solicitudes de licencia?', '["Siete días antes de que concluya el plazo de resolución.", "Cinco días antes de que concluya el plazo de resolución.", "Diez días antes de que concluya el plazo de resolución.", "Quince días antes de que concluya el plazo de resolución."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es el plazo que debe concederse para subsanar las deficiencias que se contengan en una solicitud de licencia?', '["Siete días.", "Cinco días.", "Diez días.", "Quince días."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es el plazo de resolución de una solicitud de licencia para el ejercicio de actividades personales?', '["Veinte días.", "Un mes.", "Treinta días.", "Dos meses."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es el plazo de resolución de una solicitud de licencia para el ejercicio de parcelaciones?', '["Veinte días.", "Un mes.", "Treinta días.", "Dos meses."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es el plazo de resolución de una solicitud de licencia para el ejercicio de obras e instalaciones nuevas?', '["Veinte días.", "Un mes.", "Treinta días.", "Dos meses."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es el plazo de resolución de una solicitud de licencia para la apertura de pequeños establecimientos?', '["Veinte días.", "Un mes.", "Treinta días.", "Dos meses."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es el plazo de resolución de una solicitud de licencia de nueva construcción?', '["Veinte días.", "Un mes.", "Treinta días.", "Dos meses."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es el plazo de resolución de una solicitud de licencia de reforma de edificios?', '["Veinte días.", "Un mes.", "Treinta días.", "Dos meses."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es el plazo de resolución de solicitud de licencia apertura de mataderos?', '["Veinte días.", "Un mes.", "Treinta días.", "Dos meses."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es el plazo de resolución de una solicitud de licencia de apertura de un gran establecimiento?', '["Veinte días.", "Un mes.", "Treinta días.", "Dos meses."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué sentido tiene el silencio administrativo en caso de que se produzca en un procedimiento administrativo que tenía por objeto la resolución de una solicitud para realizar actividades en la vía pública?', '["Negativo.", "Positivo.", "Positivo en cualquier caso.", "Depende de la regulación municipal concreta."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Es transmisible una licencia relativa a las condiciones de una instalación o servicio?', '["En ningún caso.", "Sólo si existe aceptación previa por parte del Ayuntamiento interesado.", "Sí, previa comunicación, realizada en cualquier forma, al Ayuntamiento respectivo.", "Sí, pero deben comunicar la transmisión por escrito, a la Corporación."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En cuál de los siguientes casos el interesado tiene derecho a una indemnización por daños y perjuicios?', '["Si se anula la licencia por haber resultado otorgada erróneamente.", "Si existe dolo imputable al interesado en la concesión de una licencia.", "Si se produce la anulación de la licencia en algunos casos.", "Si se produce la anulación de la licencia en cualquier caso."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes no tiene el carácter de subvención de fomento?', '["La cesión de bienes a favor de entidades públicas.", "Los auxilios de carácter social.", "Las subvenciones impropias reguladas por la legislación tributaria.", "La cesión de bienes muebles a favor de entidades públicas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Cómo regla general ¿cuál de los siguientes no tiene competencia para conceder una subvención?', '["El Alcalde.", "Los Teniente de Alcalde.", "La Comisión de Gobierno.", "El Pleno."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Por cuál de las siguientes causas no se puede producir la revocación de una subvención?', '["Por el incumplimiento de la carga modal.", "Por la falta de justificación del cumplimiento de la finalidad para la cual fue otorgada.", "Por el cambio de criterio de la Administración.", "Por falta de consignación presupuestaria."]'::jsonb, 3, 'es'),
    ('d5b1ff9fec5ed8de8e483562272e8a2b', 'Según el artículo 86.3 de la ley reguladora de las bases del régimen local ¿cuál de los siguientes servicios no está reservado a favor de las Entidades Locales?', '["Mercados centrales.", "Transporte público de viajeros.", "Abastecimiento y depuración de aguas.", "Construcción."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién debe aprobar un expediente de iniciativa pública para el ejercicio de actividades económicas por el Ayuntamiento?', '["El Alcalde.", "El Pleno.", "La Comisión de Gobierno.", "El Pleno y el Alcalde."]'::jsonb, 1, 'es'),
    ('94023c78be28516390f3a256ad0bbdaf', '¿En qué artículos de la ley reguladora de las bases del régimen local consultaría los modos de gestión directa, de un servicio público, por una entidad local?', '["En los artículos 109 y 110.", "En los artículos 101 y 102.", "En los artículos 102 y 103.", "En los artículos 113 y 114."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién designa al Gerente de una organización especializada creada por el Ayuntamiento para realizar la gestión directa de un servicio público?', '["La Comisión de Gobierno.", "El Alcalde.", "El Pleno.", "La Comunidad Autónoma."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cómo se denomina la forma de asociación entre un Ayuntamiento y un particular con vistas a la prestación de un servicio público?', '["Concierto.", "Gestión interesada.", "Gestión directa.", "Gestión mixta."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cómo se denomina la forma de prestación de un servicio público en el que un Ayuntamiento se vale para ello de la existencia de instalaciones de otras personas o entidades?', '["Concierto.", "Gestión interesada.", "Arrendamiento.", "Gestión mixta."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cómo se denomina la forma de prestación de un servicio público en la que las obras e instalaciones pertenece a la Entidad local y en la que ésta los cede por un tiempo determinado a cambio de un precio cierto?', '["Concierto.", "Gestión interesada.", "Arrendamiento.", "Gestión mixta."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cómo se denomina la forma de prestación de un servicio público que se realiza por un particular, por su cuenta y riesgo, mediante una retribución y durante un plazo determinado?', '["Concierto.", "Gestión interesada.", "Arrendamiento.", "Concesión."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes extremos no debe comprenderse en las cláusulas mínimas de una concesión?', '["Los derechos de las partes.", "Las causas de resolución.", "Las características del objeto de la concesión.", "La expresión escrita de que el plazo máximo, de la concesión, no puede exceder de setenta y cinco años."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cómo se califica las concesiones que se otorguen sin ajustarse a las formalidades establecidas normativamente?', '["Nulas de pleno derecho.", "Irregulares.", "Anulables.", "Viciadas."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuándo se perfecciona la concesión?', '["Con la adjudicación.", "Con la firma del contrato.", "Con la presentación de solicitudes.", "Con la ejecución del servicio."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es el procedimiento establecido para adjudicar una concesión?', '["La subasta en algunos casos.", "El concurso como regla general.", "La subasta en todo caso.", "El designado por el Alcalde."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué procedimiento de adjudicación de la concesión se utiliza si va a tener una duración superior a cinco años?', '["El negociado.", "El abierto.", "El restringido.", "La subasta."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes derechos no mantiene la Administración municipal frente al concesionario?', '["Derecho a rescatar la concesión.", "Derecho a suprimir el servicio.", "Derecho a fiscalizar la gestión del concesionario.", "Derecho a mantener el equilibrio financiero de la concesión."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes no se configura como un deber de la Administración frente al concesionario?', '["Otorgar al concesionario la protección adecuada para que pueda prestar el servicio.", "Revisar las tarifas en determinados casos.", "Indemnizar al concesionario por daños y perjuicios ocasionados por la gestión directa del servicio.", "Admitir al goce a cualquier persona que quiera acceder al servicio."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de las siguientes no es una forma de gestión indirecta?', '["Organismo Autónomo local.", "Arrendamiento.", "Concierto.", "Gestión interesada."]'::jsonb, 2, 'es'),
    ('a923c0631cb745366fc1ef24d35f29f3', '¿En qué artículos de la ley reguladora de las bases del régimen local consultaría los modos de gestión directa de los servicios públicos locales?', '["En el artículo 85.", "En los artículos 101 y 102.", "En el artículo 87.", "En los artículos 113 y 114."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿A cuál de los siguientes principios debe ajustarse en todo caso la actividad de intervención?', '["Al principio de igualdad.", "Al principio de equivalencia.", "Al principio de simetría.", "Al principio de subjetividad."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es el porcentaje máximo del coste de una actividad que puede ser objeto de subvención pública?', '["25%.", "30%.", "35%.", "50%."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué tipo de personalidad jurídica tienen los consorcios?', '["Propia.", "Plena.", "Directa.", "Indirecta."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En qué año fue aprobado el reglamento de bienes de las entidades locales?', '["1988.", "1987.", "1986.", "1990."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de las siguientes normas aprueba el reglamento de bienes de las entidades locales?', '["Real Decreto 1372/ 1988 de 13 de junio.", "Real Decreto 1372/ 1987 de 13 de junio.", "Real Decreto 1372/ 1986 de 13 de junio.", "Real Decreto 1372/ 1990 de 13 de junio."]'::jsonb, 2, 'es'),
    ('2a4ba259076b977b77507b8216bd6b29', '¿Qué título de la ley 7/ 1985, de 2 de abril, está dedicado a la regulación de los bienes de las entidades locales?', '["El Título III.", "El Título IV.", "El Título V.", "El Título VI."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué artículos de la ley 7/ 1985, de 2 de abril, regulan el régimen jurídico de los bienes de las entidades locales?', '["Del 79 al 83.", "Del 83 al 93.", "Del 76 al 79.", "Del 79 al 87."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué artículos del Texto refundido sobre disposiciones vigentes en materia de régimen local, regulan el régimen jurídico de los bienes de las entidades locales?', '["Del 74 al 87.", "Del 83 al 92.", "Del 76 al 81.", "Del 69 al 84."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes bienes no se considera de dominio público?', '["Los bienes de uso público.", "Los bienes de servicio público.", "Los bienes comunales.", "Los bienes patrimoniales."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes bienes no se considera de uso público?', '["Una calle.", "Una plaza.", "Una fuente.", "La sede del Ayuntamiento."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes bienes no se considera de servicio público?', '["Un puente.", "Un banco.", "Una fuente.", "La sede del Ayuntamiento."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes entes locales no puede tener bienes comunales?', '["Un municipio de menos de 5.000 habitantes.", "Un municipio de menos de 3.000 habitantes.", "Una entidad local de ámbito territorial inferior al municipio.", "Una comarca."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de las siguientes características no es predicable de los bienes comunales?', '["La inembargabilidad.", "La inalienabilidad.", "La imprescriptibilidad.", "La embargabilidad."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Al pago de qué tributo están sujetos los bienes comunales?', '["Al pago del Impuestos de Bienes Inmuebles.", "Al pago del Impuesto sobre Instalaciones, construcciones y obras.", "Al pago del Impuesto sobre el Patrimonio.", "No están sujetos al pago de tributos."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿A quién le corresponde el aprovechamiento de los bienes comunales?', '["A todos los ciudadanos.", "A los vecinos.", "A los vecinos y a todos los ciudadanos.", "Al Ayuntamiento."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿A quién le corresponde realizar la conservación de los bienes de uso público?', '["A los vecinos.", "A los ciudadanos.", "A la entidad local a la que estén adscritos.", "A los vecinos y a la entidad local a la que estén adscritos."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué extremos hay que acreditar en el expediente de alteración de la calificación jurídica de los bienes comunales?', '["La legalidad y la oportunidad.", "La proporcionalidad y la legalidad.", "La oportunidad y la proporcionalidad.", "La proporcionalidad y la normatividad."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál debe ser el plazo de información pública de un expediente de alteración de la calificación jurídica?', '["Dos meses.", "Un mes.", "Quince días.", "Diez días."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En cuál de los siguientes casos no se produce la alteración automática de la calificación de un bien?', '["Cuando se realice la aprobación de los planes de ordenación urbana.", "Cuando se realice la aprobación de los proyectos de obras y servicios.", "Cuando se produzca la adscripción de bienes patrimoniales por más de veinticinco años.", "Cuando se produzca la adscripción de bienes patrimoniales por más de diez años."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Puede adquirir automáticamente, una entidad local, un bien que esté destinado a un uso o servicio público comunal?', '["Sí, por arrendamiento.", "No, en ningún caso.", "Sí, por usucapión.", "Sí, en cualquier momento sin consentimiento del interesado."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué tipo de capacidad tienen las entidades locales para adquirir y poseer bienes?', '["Jurídica plena.", "Jurídica propia.", "Jurídica directa.", "Jurídica indirecta."]'::jsonb, 0, 'es');

  -- Batch 1401-1600
  insert into public.question_bank (content_hash, question, options, correct_index, lang)
  values
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué tipo de acciones deben ejercer las entidades locales para la defensa de sus bienes y derechos?', '["Las que estime oportunas.", "Exclusivamente, acciones civiles.", "Las que sean necesarias.", "Las que se acuerden de acuerdo con los vecinos."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién debe emitir informe previo antes de que una entidad local ejerza una acción de defensa de un bien propio?', '["El Alcalde.", "El Secretario.", "El Pleno.", "La Comunidad Autónoma."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Por cual de los siguientes medios no puede una entidad local adquirir un bien?', '["Por ocupación.", "Por donación.", "A título oneroso.", "Por atribución reglamentaria."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿A qué restricciones está sujeta la adquisición de bienes a título gratuito?', '["A las derivadas de su categoría.", "Nacidas de la relación jurídica de base.", "No está sujeta a restricción alguna.", "A las establecidas por el Pleno en sesión extraordinaria."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cómo se entiende hecha la aceptación de una herencia por una entidad local?', '["A beneficio de resultas.", "A beneficio de inventario.", "A restos de inventario.", "A inventario."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Si se adquiere un bien mediante una herencia por medio de condición ¿cuánto tiempo debe transcurrir para que se entienda cumplida y consumada?', '["Diez años.", "Veinte años.", "Veinticinco años.", "Treinta años."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes no es un epígrafe del inventario de bienes de una entidad local?', '["Los vehículos.", "Los semovientes.", "Los derechos reales.", "Los derechos invertibles."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿A quién le corresponde realizar la aprobación del Inventario de bienes de una entidad local?', '["Al Alcalde.", "Al Pleno.", "A la Comisión de Gobierno.", "A la Comunidad Autónoma respectiva."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿A quién le corresponde realizar la rectificación del Inventario de bienes de una entidad local?', '["Al Alcalde.", "Al Pleno.", "A la Comisión de Gobierno.", "A la Comunidad Autónoma respectiva."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿A quién le corresponde realizar la comprobación del Inventario de bienes de una entidad local?', '["Al Alcalde.", "Al Pleno.", "A la Comisión de Gobierno.", "A la Comunidad Autónoma respectiva."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué documento es necesario para inscribir en el Registro de la propiedad los bienes inmuebles de una entidad local?', '["Certificación del Pleno.", "Certificación expedida por el Alcalde.", "Certificación expedida por el Secretario.", "Certificación expedida por la Comunidad Autónoma respectiva."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién debe dar el visto bueno a la certificación para inscribir un bien inmueble en el registro de la propiedad?', '["El Pleno.", "El Alcalde.", "El Secretario.", "La Comunidad Autónoma respectiva."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de las siguientes potestades no están asignadas a las corporaciones locales en relación con sus bienes?', '["La potestad de investigación.", "La potestad de recuperación.", "La potestad de autorecuperación.", "La potestad de deslinde."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué operación consiste en practicar las operaciones técnicas de comprobación y de rectificación de situaciones jurídicas acreditadas, en relación con un bien?', '["Desahucio.", "Deslinde.", "Investigación.", "Recuperación."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿De qué tiempo disponen las entidades locales para recuperar por sí mismas la tenencia de bienes públicos?', '["De un año.", "De dos años.", "De cinco años.", "No existe plazo máximo."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿De qué tiempo disponen las entidades locales para recuperar por sí mismas la tenencia de bienes patrimoniales', '["De un año.", "De dos años.", "De cinco años.", "No existe plazo máximo."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Se admiten interdictos contra actuaciones de agentes de la autoridad en materia de recuperación de bienes?', '["Sí, en cualquier caso.", "Sólo en casos excepcionales.", "Sí, con aprobación previa del Pleno.", "No, en ningún caso."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El uso anormal de bienes públicos:', '["Está sujeto a la obtención de licencia.", "Se destina al Ayuntamiento.", "Es libre con la naturaleza de los bienes", "Está sujeto a concesión administrativa."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cómo se denomina el uso que corresponde por igual a todos los ciudadanos indistintamente, de modo que el uso de unos no impida el de los demás interesados, pero en el que concurren circunstancias singulares?', '["Uso común general.", "Uso común especial.", "Uso privativo.", "Uso normal."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cómo se denomina el uso que corresponde por igual a todos los ciudadanos indistintamente, de modo que el uso de unos no impida el de los demás interesados, pero en el que concurren circunstancias de peligrosidad?', '["Uso común general.", "Uso común especial.", "Uso privativo.", "Uso normal."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cómo se denomina el uso constituido por la ocupación de una porción de dominio público de modo que excluya la utilización por los demás interesados?', '["Uso privativo.", "Uso normal.", "Uso anormal.", "Uso general."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cómo se denomina el uso que es conforme con el destino principal del dominio público al que afecte?', '["Uso especial.", "Uso ordinario.", "Uso normal.", "Uso común."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cómo se ejerce el uso común general de los bienes de dominio público?', '["Por los ciudadanos que obtengan licencia.", "Exclusivamente por el Ayuntamiento.", "Libremente de acuerdo con la naturaleza de los bienes.", "Con sometimiento a autorización previa."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cómo se ejerce el uso especial normal de los bienes de dominio público?', '["Por ciudadanos que obtengan licencia.", "Exclusivamente por el Ayuntamiento.", "Libremente de acuerdo con la naturaleza de los bienes.", "Con sometimiento a autorización previa."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El uso privativo de bienes de dominio público:', '["Está sujeto a la obtención de licencia.", "Se destina exclusivamente al Ayuntamiento.", "Es libre de acuerdo con la naturaleza de los bienes.", "Está sujeto a concesión administrativa."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cómo se denomina el uso que corresponde por igual a todos los ciudadanos indistintamente, de modo que el uso de unos no impida el de los demás interesados?', '["Uso común.", "Uso propio.", "Uso normal.", "Uso ordinario"]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cómo se denominan los bienes que siendo propiedad de la entidad local, no están destinados al uso público ni afectados a ningún servicio público y pueden constituir una fuente de mejora del erario de la entidad?', '["Bienes de dominio público.", "Bienes de comunal.", "Bienes patrimoniales.", "Bienes demaniales."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cómo se considera una parcela sobrante?', '["Como bien patrimonial.", "Como bien de dominio público.", "Como bien demanial.", "Como bien comunal."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cómo se consideran los efectos no utilizables?', '["Como bien patrimonial.", "Como bien de dominio público.", "Como bien demanial.", "Como bien comunal."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En cual de los siguientes casos debe utilizarse la subasta para poder ceder un bien patrimonial?', '["Cuando el tiempo de cesión sea superior a dos años.", "Cuando el tiempo de cesión sea superior a un año.", "Cuando el tiempo de cesión sea superior a tres años.", "Cuando el tiempo de cesión sea superior a cinco años."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuándo se adjudicará el disfrute de un bien comunal por lotes?', '["Cuando el disfrute sea impracticable en el modo común.", "En cualquier caso.", "En ningún caso.", "Cuando lo establezca el Pleno."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién debe autorizar la adjudicación del disfrute de un bien comunal por un precio?', '["El Alcalde.", "El Secretario de la Corporación local.", "El Pleno de la Entidad local.", "La Comunidad Autónoma respectiva."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La federación de comunidades autónomas:', '["Está admitida expresamente por la Constitución.", "Está contemplada en la Constitución como posibilidad para el momento en que todas las Comunidades Autónomas alcancen el mismo techo competencial.", "Está excluida expresamente por la Constitución.", "No está prevista constitucionalmente."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Constitución española, la soberanía nacional:', '["Corresponde al Rey.", "Reside en el pueblo español.", "Corresponde a las Cortes Generales, al estar compuestas por los representantes del pueblo.", "Corresponde al Gobierno de la Nación elegido directamente por el pueblo."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Guardia Civil, Policía Nacional, Policía Local, en funciones de Policía Judicial, dependen de:', '["Sus Jefes naturales, que actuarán en íntima relación con Jueces y Tribunales.", "Los Jueces, los Tribunales y del Ministerio Fiscal.", "Los Jueces y Tribunales.", "El Ministerio de Justicia e Interior en coordinación con Jueces, Tribunales y Ministerio Fiscal."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Constitución española de 1978, los ciudadanos y los poderes públicos están sujetos:', '["Al Gobierno de la nación.", "Al poder del Rey.", "Exclusivamente al Presidente del Gobierno nombrado por el pueblo", "A la Constitución y al resto del ordenamiento jurídico."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los poderes del Estado emanan de:', '["El Rey.", "La Constitución.", "Las Cortes Generales.", "El pueblo español."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Constitución española de 1978, ¿qué delitos están excluidos de la extradición?', '["Los delitos ocasionados por actos terroristas.", "Los delitos políticos.", "Los delitos de adulterio.", "Los delitos de robo de menos de un millón de pesetas."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Uno de los siguientes principios no inspirará el régimen jurídico de los bienes de dominio público y de los comunales:', '["Desafectación.", "Inembargabilidad.", "Inalienabilidad.", "Prescriptibilidad."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los Derechos Fundamentales y las Libertades Públicas son regulados en nuestra Constitución por:', '["La Sección primera del Capítulo segundo del Título primero.", "La Sección primera del Capítulo segundo del Título segundo.", "La Sección tercera del Capítulo segundo del Título segundo.", "La Sección segunda del Capítulo primero del Título primero."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Administración del Estado en el territorio de la Comunidad Autónoma será dirigida por:', '["Los Gobernadores Civiles.", "Un Delegado nombrado por el Gobierno de la Nación en coordinación con el Gobierno Autónomo.", "Un Delegado nombrado por el Gobierno.", "Un Coordinador nombrado por el Gobierno Autónomo."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién de los siguientes no está legitimado para solicitar del Defensor del Pueblo la investigación o esclarecimiento de actos o conductas de las Administraciones Públicas que afecten a un ciudadano o grupo de ciudadanos?', '["Comisión de Investigación.", "Comisión mixta Congreso-Senado.", "Cualquier Diputado.", "Cualquier miembro del Gobierno."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Constitución española surgió como:', '["El resultado del consenso del Gobierno de la nación y la Junta de Jefes de Estado Mayor.", "El resultado del consenso entre las fuerzas políticas existentes.", "Todas las otras respuestas son falsas.", "El resultado del consenso entre las fuerzas políticas y los sindicatos obreros de carácter más representativo."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los derechos y libertades públicas:', '["Sólo podrán ser suspendidos cuando se declare el estado de sitio.", "Sólo podrán ser suspendidos o anulados en tiempo de guerra.", "Sólo podrán ser suspendidos cuando se declare el estado de excepción o de sitio.", "Nunca podrán ser suspendidos ni anulados."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En caso de flagrante delito, se puede registrar un domicilio:', '["Previa resolución judicial, que es indispensable.", "Con la presencia de un vecino.", "Con el consentimiento del interesado.", "Sin autorización ninguna."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los principios rectores de la política económica-social pueden ser alegados ante la jurisdicción ordinaria:', '["De conformidad con la Constitución.", "De acuerdo con lo dispuesto por sus leyes de desarrollo.", "En todo caso.", "Todas las otras respuestas son falsas."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La ordenación del territorio, el urbanismo y la vivienda, así como los proyectos, construcción y explotación de aprovechamientos hidráulicos, canales y regadíos:', '["Son competencia exclusiva de la Administración del Estado.", "Son competencias asumibles por las Comunidades Autónomas.", "Todas las otras respuestas son falsas.", "Son competencias exclusivas de las Administraciones locales."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Indicar cuál de las siguientes afirmaciones es correcta de acuerdo con la Constitución española de 1978:', '["La Administración Civil puede interponer sanciones que impliquen privaciones de libertad.", "El condenado a una pena de prisión que estuviere cumpliendo la misma solo ostenta el derecho a la vida ya que la Constitución abole la pena de muerte.", "El condenado a pena de prisión que estuviere cumpliendo la misma tendrá derecho a un trabajo remunerado ya los beneficios correspondientes de la Seguridad Social.", "El condenado a pena de prisión que estuviere cumpliendo la misma carece de cualquiera de los derechos contemplados en la Constitución."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La reforma constitucional:', '["No podrá iniciarse fuera de los periodos ordinarios de sesiones.", "No podrá iniciarse en tiempo de guerra, ni cuando esté declarado el estado de excepción o de sitio.", "No podrá iniciarse en tiempo de guerra, ni cuando esté declarado el estado de alarma, el de excepción o el de sitio.", "Podrá iniciarse en cualquier momento."]'::jsonb, 2, 'es'),
    ('67baeed5bf3bb081f8126569ba3d013f', 'La legitimación para interponer los diferentes recursos ante el Tribunal Constitucional está regulada en la Constitución Española', '["Art. 160.", "Art. 162.", "Art. 163.", "Art. 161."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La institución del Defensor del Pueblo está regulada mediante:', '["Decreto-Ley.", "Ley Orgánica.", "Decreto Legislativo.", "Ley de Bases."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La fecha de entrada en vigor de la Constitución es:', '["28-12-78.", "27-12-78.", "1-1-79.", "29-12-78."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿A quién corresponde, según la Constitución, promover las condiciones para que la libertad y la igualdad de todos los individuos en España, sean reales y efectivas?', '["Exclusivamente al Gobierno de la Nación.", "Exclusivamente al Tribunal Constitucional.", "Exclusivamente a los Tribunales de Justicia.", "A todos los poderes públicos."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Una de las siguientes afirmaciones no es cierta. Los Tribunales controlan, respecto a la Administración y al Gobierno:', '["El sometimiento de la actuación administrativa a la potestad reglamentaria.", "La potestad reglamentaria.", "La legalidad de la actuación administrativa.", "El sometimiento de la actuación administrativa a los fines que la justifican."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La seguridad jurídica es un principio garantizado en:', '["La Ley de Protección Jurisdiccional de los Derechos Fundamentales de la persona.", "La Ley Orgánica de Garantía de la Seguridad Jurídica.", "La Ley de Cuerpos y Fuerzas de la Seguridad del Estado.", "La Constitución."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En caso de extraordinaria y urgente necesidad el Gobierno podrá dictar disposiciones legislativas provisionales:', '["Recibirán el nombre de Decretos, y no podrán afectar, entre otras materias, al ordenamiento de las instituciones básicas del Estado.", "Recibirán el nombre de Decretos Leyes y, por dictarse por razones de urgencia, podrán versar sobre cualquier materia no limitadora de los Derechos Fundamentales y las libertades públicas.", "Recibirán el nombre de Decretos Legislativos y no podrán afectar, entre otras materias, a los derechos, deberes y libertades públicas.", "Recibirán el nombre de Decretos Leyes y no podrán afectar, entre otras materias, al régimen de las Comunidades Autónomas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Título de la Constitución trata de:', '["El Poder Judicial.", "La Corona.", "Derechos y deberes fundamentales de la persona.", "Las Cortes."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Señalar, de entre los que se proponen, los tres principios básicos que consagra la Constitución y que presiden las relaciones entre el Estado y las Comunidades Autónomas:', '["Autonomía, coordinación y centralización.", "Coordinación, centralización y unidad.", "Desconcentración, especialización y unidad.", "Unidad, autonomía y solidaridad."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Constitución española de 1978 entró en vigor:', '["El mismo día de su publicación en el Boletín Oficial del Estado.", "Al día siguiente de su aprobación por las Cortes Generales.", "A los veinte días de su publicación en el Boletín Oficial del Estado.", "Al día siguiente de su ratificación por el pueblo español en referéndum."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La parte de la Constitución que regula los derechos y deberes de los ciudadanos se denomina:', '["Parte contractual y de obligaciones.", "Parte orgánica.", "Parte legal.", "Parte dogmática."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La forma política del Estado español:', '["Democracia Parlamentaria.", "Gobierno Parlamentario.", "República Democrática.", "Monarquía Parlamentaria."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El derecho de todos a la educación se garantiza por los poderes públicos mediante:', '["Una programación general de la enseñanza.", "Una enseñanza pública gratuita.", "Una enseñanza pública de calidad.", "Una enseñanza intensiva."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Constitución española son fundamentos del orden político y la paz social:', '["La dignidad de la persona, los derechos violables que le son inherentes y el respeto a la Ley.", "La dignidad de la persona, los derechos inviolables que le son inherentes, el libre desarrollo de la personalidad, y el respeto a la Ley ya los derechos de los demás.", "El respeto a la Ley, a los Reglamentos Administrativos y demás disposiciones legales.", "La dignidad de la persona, el desarrollo limitado de la personalidad y el respeto a la Ley."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Constitución española el derecho a disfrutar de una vivienda digna y adecuada es:', '["Un deber fundamental de los poderes públicos.", "Un principio rector de la política social y económica.", "Un derecho fundamental de los españoles.", "Una libertad pública."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los daños causados por error judicial, así como los que sean consecuencia del funcionamiento anormal de la Administración de Justicia:', '["Darán derecho a una indemnización a cargo del Estado, cuando el daño tenga su origen en el anormal funcionamiento de la Administración de Justicia, pero si el daño se produjere a consecuencia de error judicial responderá civilmente el Juez o Tribunal que pronunció el fallo.", "Darán derecho a una indemnización a cargo del Juez o Tribunal responsable de los mismos, si se acredite su negligencia profesional.", "Darán derecho a una indemnización a cargo del Estado, conforme a la Ley.", "Darán derecho a una indemnización a cargo del Estado ya la publicación en los boletines oficiales de una nota aclaratoria de lo sucedido, si así lo pide el perjudicado."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La libertad de empresa en nuestra Constitución:', '["Se reconoce dentro del marco de la economía de mercado.", "Se reconoce dentro del marco de la economía liberal.", "Se reconoce dentro del marco de la economía liberal, matizada por el carácter social de la misma.", "Se reconoce dentro del marco de la economía socialista."]'::jsonb, 0, 'es'),
    ('e7635585740de7b10b819c221029a513', '¿De cuántos artículos consta el Título Preliminar de la Constitución española?', '["De 54, que son los 54 primeros artículos de la Constitución.", "De 9, que son los 9 primeros artículos de la Constitución.", "De 14, que son los 14 primeros artículos de la Constitución.", "De 9, que son los artículos del 3 al 11, inclusives."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La parte de la Constitución que regula la estructura de los principales órganos del Estado recibe el nombre de:', '["Parte estatal.", "Parte orgánica.", "Parte dogmática.", "Parte estructural."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La designación de que sean objeto los miembros del Tribunal constitucional será:', '["Por tres años, renovándose íntegramente a su vencimiento.", "Por nueve años, renovándose por terceras partes cada tres", "Por cinco años.", "Por seis años, renovándose por terceras partes cada dos."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Uno de los siguientes principios no es inspirador de la actuación de la Administración Pública:', '["Jerarquía.", "Eficacia.", "Centralización.", "Desconcentración."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La iniciativa para la reforma constitucional se ejercerá:', '["Por el Gobierno, el Congreso y el Senado.", "Por el Gobierno, el Congreso, el Senado y las Asambleas de las Comunidades Autónomas.", "Por el Gobierno, el Congreso, el Senado, las Asambleas de las Comunidades Autónomas y el pueblo, a través de la iniciativa popular.", "Podrá ejercerla el Defensor del Pueblo."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Cualquier alteración de los límites de una Comunidad Autónoma deberá ser aprobada por:', '["Decreto ley del Gobierno", "Ley orgánica de las Cortes Generales", "Acuerdo entre las Cortes Generales y la Comunidad Autónoma afectada", "Ley ordinaria de las Cortes Generales."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las materias no atribuidas por la Constitución de manera expresa al Estado:', '["Podrán corresponder a las Comunidades Autónomas, en virtud de sus respectivos Estatutos.", "Corresponderán en cualquier caso a las Comunidades Autónomas que las reivindiquen.", "Corresponderán en cualquier caso a dicho Estado.", "Podrán corresponder al Estado, si asume las competencias correspondientes en virtud de Ley Orgánica."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Presidente y los miembros del Consejo de Gobierno:', '["Carecerán de responsabilidad política alguna.", "Serán políticamente responsables ante las Cortes Generales del Estado.", "Serán penalmente responsables ante la Asamblea Legislativa.", "Serán políticamente responsables ante la Asamblea Legislativa."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Respecto de una de las siguientes materias, por ser exclusiva del Estado, no podrán ser asumidas, en principio, competencias por las Comunidades Autónomas:', '["Administración de Justicia.", "Artesanía.", "Organización de las instituciones básicas de autogobierno de las Comunidades Autónomas.", "Ordenamiento del territorio, urbanismo y vivienda."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Título Octavo de la Constitución finaliza en el artículo:', '["158.", "156.", "157.", "159."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En qué año fue plesbiscitado, por primera vez, el Estatuto Gallego?', '["1932", "1931", "1936", "1933."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuántos municipios debían formar parte de la iniciativa autonómica en el caso de las Comunidades que accedieron por la vía especial, en el caso de que no hubieran plesbiscitado estatutos en el pasado?', '["2/3 partes", "2/4 partes", "3/4 partes", "1/3 parte."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Fondo de Compensación Interterritorial se recoge en la Constitución en su artículo:', '["158.2", "158.3", "158.4", "158.1."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'EL poder ejecutivo de una Comunidad Autónoma se ejerce por el:', '["Consejo", "Consejo de Gobierno", "Consejo ejecutivo", "Consejo colegiado."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Ceuta aprobó su estatuto de autonomía en el año:', '["1992", "1995", "1993", "1994."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Constitución establece los contenidos mínimos que deben recoger los Estatutos de autonomía en su artículo:', '["151.2", "156.1", "148.4", "147.2."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La reforma de los Estatutos de Autonomía:', '["Se ajustará al procedimiento establecido en dichos Estatutos, sin más trámite.", "Requerirá, en determinados casos, la aprobación por las Cortes Generales, mediante Ley Ordinaria.", "Requerirá, en todo caso, la aprobación por las Cortes Generales, mediante Ley Orgánica.", "Se ajustará al mismo procedimiento utilizado para su aprobación."]'::jsonb, 2, 'es'),
    ('20bc0ea92eb63d34c503f6f420e6d3c6', '¿En qué Título de la Constitución se regula la Administración Local?', '["El Título VI.", "El Título VIII.", "El Título VII.", "El Título IX."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las vías de acceso a la autonomía son:', '["Vía especial y vía rápida", "Vía constitucional y vía histórica", "Vía lenta y vía rápida", "Vía común y vía lenta."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En qué año se aprobó el último estatuto de autonomía, tras la aprobación de la Constitución de 1978?', '["1995", "1992", "1993", "1994."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Para ejecutar las medidas necesarias para obligar a una Comunidad Autónoma al cumplimiento forzoso de sus obligaciones:', '["El Gobierno podrá dar instrucciones al Ejército de Tierra, la Armada, o el Ejército del Aire.", "Podrá ser declarado en el territorio de la Comunidad Autónoma afectada el estado de alarma, el de excepción, o el de sitio, dependiendo de la gravedad de la causa que motive la adopción de tal medida.", "Todas las otras respuestas son correctas.", "El Gobierno podrá dar instrucciones a todas las autoridades de las Comunidades Autónomas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Federación de Comunidades Autónomas:', '["Se admitirá en determinados casos.", "No se admitirán en caso alguno, aunque sí la Confederación de Comunidades Autónomas.", "Podrá ser autorizada por las Cortes Generales por motivos de interés nacional.", "No se admitirá en ningún caso."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La alteración de los límites provinciales:', '["Habrá de ser aprobada por las Cortes Generales mediante Ley Orgánica.", "Habrá de ser aprobada por mayoría absoluta del Congreso de los Diputados.", "Está prohibida por la Constitución.", "Habrá de ser aprobada por los Parlamentos autonómicos de las Comunidades Autónomas afectadas, o exclusivamente por el de aquella a la que pertenezca la provincia en cuestión."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de las siguientes Comunidades Autónomas es histórica?', '["Cataluña.", "Extremadura.", "Castilla la Mancha.", "Valencia."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La no aprobación del Estatuto por una o varias provincias:', '["Obligará a reiniciar el proceso autonómico por las provincias que hayan aprobado el Estatuto.", "No impedirá la constitución de la Comunidad Autónoma entre las restantes de la Comunidad Autónoma proyectada.", "No impedirá la constitución de la Comunidad Autónoma entre todas las provincias originalmente iniciadoras del proceso autonómico.", "Impedirá la constitución de la Comunidad Autónoma."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las normas dictadas por el Estado:', '["Prevalecerán sobre las de las Comunidades Autónomas cuando así se disponga en los respectivos Estatutos de Autonomía y en las Leyes Orgánicas.", "No se aplicarán, al prevalecer la normativa autonómica.", "Prevalecerán sobre las de las Comunidades Autónomas en todo lo que no esté atribuido a la exclusiva competencia de éstas.", "Prevalecerán en todo caso sobre la normativa autonómica."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El órgano legislativo de la Comunidad Autónoma es:', '["El Consejo legislativo", "El Congreso autonómico", "La Asamblea", "El Senado."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las condiciones y el procedimiento de las distintas modalidades de referéndum:', '["Es materia tratable mediante Decreto Ley.", "Es materia sobre la que cabe la iniciativa popular.", "Es materia reservada a Ley Orgánica.", "Es materia tratable mediante Ley Ordinaria."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El TÍTULO Tercero de la Constitución consta de:', '["Un capítulo.", "Dos capítulos.", "Cuatro capítulos.", "Tres capítulos."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las disposiciones de los tratados internacionales que entren a formar parte del ordenamiento interno, podrán ser derogadas, modificadas o suspendidas:', '["En la forma prevista en los propios tratados, en cualquier caso.", "Mediante acuerdos adoptados por mayoría absoluta.", "En la forma prevista para cualquier norma nacional con rango de Ley.", "De acuerdo con las normas generales de Derecho Internacional, cuando los propios tratados no indiquen el procedimiento a seguir para ello."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los miembros de las Cortes Generales:', '["No están ligados a las mismas por mandato imperativo.", "Están ligados a las mismas por mandato constitucional.", "Están ligados a las mismas por mandado potestativo.", "Están ligados a las mismas por mandato imperativo."]'::jsonb, 0, 'es'),
    ('dadaf5d59a71b5e405e17158a0bbfb19', 'En los supuestos de disolución de las Cortes Generales:', '["El Gobierno presentará en pleno su dimisión ante el Rey.", "No procederá nueva disolución antes de que transcurra un año desde la anterior.", "Se restablece el equilibrio entre el legislativo y el ejecutivo.", "El funcionario de la misma se puede interrumpir durante la vigencia de algunos de los estados regulados en el art. 116 de la Constitución."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'A la Gran Canaria, Mallorca y Tenerife le corresponderán:', '["Un Senador a cada una de ellas.", "Tres Senadores a cada una de ellas.", "Tres, dos y un Senador, respectivamente.", "Uno, dos y tres Senadores, respectivamente."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los tratados internacionales formarán parte del ordenamiento interno:', '["Desde su sanción por el Rey.", "Desde su publicación oficial en España, sólo si han sido celebrados válidamente.", "En todo caso, desde su publicación oficial en España.", "Desde su autorización por las Cortes Generales."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El TÍTULO Tercero de la Constitución finaliza en el artículo:', '["95.", "97.", "96.", "94."]'::jsonb, 2, 'es'),
    ('69cc02d6fa341204e8baa32de1fad3f6', 'La iniciativa legislativa popular del artículo 87.3 de la Constitución requiere:', '["700.000 firmas acreditadas.", "400.000 firmas acreditadas.", "300.000 firmas acreditadas.", "500.000 firmas acreditadas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En los proyectos declarados urgentes por el Gobierno o por el Congreso de los Diputados, el plazo con el que cuenta el Senado para vetar o enmendar se reduce a:', '["Veinte días.", "Treinta días.", "Veinticinco días.", "Quince días."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Una de las siguientes afirmaciones no es válida:', '["Las Cámaras reforman sus propios Reglamentos.", "Las Cámaras establecen sus propios Reglamentos.", "Cada Cámara regula el Estatuto de Personal de las Cortes Generales.", "Las Cámaras aprueban autónomamente sus presupuestos."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Todas las materias indicadas a continuación, menos una, son indelegables:', '["La reforma constitucional.", "Los Presupuestos Generales del Estado.", "Las leyes ordinarias.", "Las cuestiones internacionales."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El sistema unicameral se estableció en nuestro país:', '["En el régimen de Franco.", "Con la Constitución de 1931.", "Con la Constitución vigente.", "Con la Ley de Reforma Política de 1977."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Dentro del plazo de treinta días ya conocido, los Decretos Leyes:', '["Podrán ser tramitados por las Cortes como proyectos de Ley por el procedimiento de urgencia.", "Todas las otras respuestas son falsas.", "Podrán ser tramitados por el Congreso de los Diputados como proyectos de Ley por el procedimiento ordinario.", "Podrán ser tramitados por el Gobierno como proposiciones de Ley por el procedimiento de urgencia."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Cámaras se reunirán anualmente:', '["En dos periodos ordinarios de sesiones, conforme a lo indicado en la opción c., y en un periodo extraordinario durante el mes de agosto.", "En un solo periodo ordinario de sesiones, de septiembre a junio.", "En dos periodos ordinarios de sesiones, el primero de septiembre a diciembre, y el segundo de febrero a junio.", "En dos periodos ordinarios de sesiones, el primero de septiembre a enero, y el segundo de febrero a julio."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El segundo período de sesiones ordinarias es:', '["Septiembre a diciembre.", "Febrero a junio.", "Septiembre a junio.", "Febrero a julio."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Reglamento de las Cortes Generales, por el que se regirán las sesiones conjuntas de ambas Cámaras, será aprobado:', '["Por mayoría absoluta de ambas Cámaras.", "Por mayoría absoluta de cada Cámara.", "Por mayoría de dos tercios de cada Cámara.", "Por mayoría de dos tercios de ambas Cámaras."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En cuál de las siguientes decisiones no interviene el Senado?', '["Nombramiento del Regente.", "Aprobación de los Presupuestos Generales del Estado.", "Aprobación de leyes orgánicas.", "Adopción de una moción de censura."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Cortes Generales representan al pueblo español y están formadas:', '["Por la Cámara Baja y la Cámara Alta.", "Por la Cámara de los Comunes y por la Cámara de los Senadores.", "Por el Congreso de los Diputados y por el Senado.", "Por el Congreso y por el Senado."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La atribución de representar al pueblo español corresponde al/a las:', '["Rey.", "Congreso de los Diputados.", "Gobierno de la Nación.", "Cortes Generales."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las decisiones que podrán ser sometidas a referéndum de todos los españoles:', '["Serán todas aquellas que el Gobierno estime de interés.", "Serán sólo decisiones políticas de especial trascendencia.", "Serán, preceptivamente, las que afecten a la seguridad nacional y las decisiones políticas de especial trascendencia.", "Se someterán a referéndum que podrá ser decisorio."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los decretos leyes deberán ser inmediatamente sometidos a debate y votación de totalidad al Congreso de los Diputados:', '["En el plazo de treinta días siguientes a su promulgación si estuviere reunido, o desde que se reúna.", "Se someterá al Congreso en el plazo de treinta días a su promulgación, pero sólo para votación, no para debate.", "En el plazo de treinta días siguientes a su promulgación, en cualquier caso.", "Sólo si estuviere reunido."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Senado es la Cámara de representación:', '["Autonómica.", "Territorial.", "Proporcional.", "Local."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La delegación legislativa se efectuará:', '["Mediante una ley ordinaria, en cualquier caso.", "Mediante una ley de bases, en cualquier caso.", "Mediante una ley de bases cuando su objeto sea la formación de un texto articulado.", "Mediante una ley de bases cuando se trate de refundir varios textos legales en uno solo."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Defensor del Pueblo da cuenta del ejercicio de sus atribuciones al/la las:', '["Tribunal Constitucional.", "Al gobierno.", "Cortes.", "Poder Judicial."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La elección del Defensor del Pueblo compete a:', '["Plenos del Congreso Senado.", "Comisión creada al efecto en el Congreso.", "Al Gobierno.", "Al Rey."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La inviolabilidad, respecto al Defensor del Pueblo:', '["No la posee.", "La posee sobre cualquier actuación que realice.", "La ostenta en cuanto a los actos que realice en el ejercicio de sus competencias como tal.", "Supone que está exento de dar cuenta de su trabajo a las Cortes."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Si se presenta una queja anónima ante el Defensor del Pueblo:', '["Deberá darle trámite con prioridad.", "Sólo la tramitará si el asunto es de interés general.", "No está obligado a darle trámite.", "Se deja a su arbitrio el darle o no trámite."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las quejas deben presentarse al Defensor del Pueblo:', '["Por medio de abogado y procurador.", "En papel de pagos al Estado.", "Con el justificante de haber pagado las tasas indicadas al efecto.", "En papel común."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El auxilio al Defensor del Pueblo por parte de los Funcionarios Públicos:', '["Se supedita a lo que, en cada caso, determine la Autoridad administrativa de la que dependan.", "Sólo se realizará cuando sea reclamado judicialmente.", "Ha de ser preferente y urgente.", "Es potestativo para los funcionarios."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los miembros del Tribunal de Cuentas gozan de la independencia e inamovilidad propia de:', '["Los miembros del Gobierno.", "Los Jueces.", "Los Funcionarios Públicos.", "Dichos miembros carecen de estas prerrogativas."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El informe anual que ha de emitir el Tribunal de Cuentas, ha de remitirlo a:', '["Al Gobierno.", "Las Cortes.", "Al Tribunal Constitucional.", "Al Defensor del Pueblo."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La justicia se administra en nombre del:', '["Juez o Tribunal que la imparta.", "Pueblo español.", "Rey.", "Poder judicial."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El titular de la Justicia es:', '["El Poder Judicial.", "El Rey.", "El Pueblo soberano.", "Los Jueces y los Tribunales por norma."]'::jsonb, 2, 'es'),
    ('e2a1b844d2d6c134d9884850d51f3bc8', 'El art. 117 de la Constitución española no incluye como una característica de los Jueces y Magistrados la:', '["Independencia.", "Responsabilidad.", "lnamovilidad.", "Las incluye todas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La ejecución de lo juzgado es competencia de:', '["Juzgados y Tribunales.", "Consejo General del Poder Judicial normalmente.", "Policía Judicial.", "Administración Pública Estatal."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los supuestos de suspensión o movilidad de los Jueces deben estar establecidos en:', '["Una Ley Orgánica.", "Un Reglamento.", "Una Ley Ordinaria.", "La Constitución."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Constitución española el procedimiento debe ser:', '["Gratuito siempre.", "Predominantemente oral.", "En audiencia pública.", "Motivado siempre."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La colaboración con los Jueces y Tribunales por los particulares es obligatoria:', '["En el proceso.", "Antes del procesamiento.", "Sólo cuando no exista proceso penal.", "En todo caso como norma general."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los Jueces y Tribunales deben elevar al Tribunal Constitucional:', '["La cuestión de inconstitucionalidad.", "El recurso de inconstitucionalidad.", "La inconstitucionalidad de las normas reglamentarias.", "Todo lo anterior."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Por funcionamiento anormal de la Administración de Justicia debe responder ...:', '["Propia Administración.", "Ministerio de Justicia solamente.", "Estado.", "Nadie."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La cúspide de la jurisdicción en España la ostenta el:', '["Consejo General del Poder Judicial.", "Ministerio Fiscal.", "Tribunal Constitucional.", "Tribunal Supremo."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La misión de velar por la independencia de los Tribunales y procurer ante estos la satisfacción del interés social es propia del/de los:', '["Poder Judicial.", "Consejo General del Poder Judicial.", "Ministerio Fiscal.", "Jueces y Tribunales."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El jurado no intervendrá en procesos:', '["De ningún tipo.", "Penales.", "Evidenciados en Audiencias Provinciales.", "Civiles."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Jurado en los Tribunales consuetudinarios:', '["No existe.", "Existe", "Ejerce como acción popular.", "Está integrado por Jueces y Magistrados."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La función del Jurado es:', '["Obligatoria y gratuita.", "Incompatible en todo caso.", "Remunerada y voluntaria.", "Nada de lo anterior es cierto."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La existencia del Jurado en los Tribunales Superiores de Justicia:', '["Es posible.", "No se va a dar nunca.", "Es su única sede.", "Se admite en toda materia."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Un Policía Local actuará como Policía Judicial:', '["En todo caso.", "Nunca.", "Cuando se le requiera al efecto.", "Previa autorización de su Presidente."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La asociación profesional de Jueces y Magistrados está:', '["Prohibida.", "Permitida.", "Ilegalizada.", "Admitida, si se hace mediante sindicato."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La declaración del estado de alarma lo es por:', '["Las Cortes Generales.", "El Gobierno, por quince días.", "El Congreso, por treinta días.", "El Gobierno, por treinta días prorrogables."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Para los supuestos de graves alteraciones de orden público está previsto declarar:', '["El estado de excepción.", "El estado de sitio.", "Estado de alarma.", "Ninguno de ellos."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La declaración del estado de sitio se realiza por el/las:', '["Congreso por mayoría absoluta.", "Gobierno, autorización previa del Congreso.", "Las Cortes.", "Senado a propuesta del Gobierno."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Para declarar el estado de sitio se necesita:', '["Aprobación de las Cortes.", "Mayoría absoluta del Congreso.", "Autorización del Gobierno.", "Autorización del Rey."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Constitución, las Entidades que forman parte de la organización territorial del Estado tienen la nota común de:', '["Autogobierno.", "Independencia.", "Autonomía.", "Financiación propi."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La titularidad de la soberanía española radica en el/las:', '["Cortes Generales como representantes del pueblo español.", "Rey como Jefe del Estado.", "Pueblo mismo.", "Nacionalidades y regiones que integran España."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La declaración del estado de alarma lo es por el/las:', '["Cortes Generales.", "Gobierno, por quince días.", "Congreso, por treinta días.", "Gobierno, por treinta días prorrogables por el Congreso."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Para los supuestos de graves alteraciones de orden público está previsto declarar el estado de:', '["Excepción.", "Sitio.", "Alarma.", "Ninguno de ellos."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las primeras elecciones democráticas celebradas en España tras la muerte de Franco tuvieron lugar en:', '["1975.", "1976.", "1977.", "1978."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El referéndum en el que se aprobó popularmente la Constitución se llevó a efecto el:', '["27 de diciembre de 1978.", "6 de diciembre de 1978.", "31 de octubre de 1978.", "29 de diciembre de 1979."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La ponencia encargada de redactar el borrador de la Constitución se constituyó en el:', '["Senado.", "Senado y Congreso.", "Congreso.", "Gobierno."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Si un poder público, en su actuación, infringe lo dispuesto en el Preámbulo de la Constitución:', '["Incurre en nulidad.", "Incurre en inconstitucionalidad.", "No pasa nada, salvo que, como consecuencia de esa actuación, se infrinja un artículo de la propia Constitución.", "Nada de lo anterior es cierto."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El principio en virtud del cual el ciudadano está amparado por una legislación no sujeta a continuos vaivenes es el de:', '["Legalidad.", "Publicidad normativa.", "Seguridad jurídica.", "Jerarquía normativa."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El principio en virtud del cual un Reglamento no puede contradecir una Ley es el de:', '["Legalidad.", "Jerarquía normativa.", "a y b son correctas.", "Seguridad jurídica."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Constitución, una norma que imponga una nueva pena más leve para un delito:', '["No se aplica retroactivamente.", "Puede aplicarse retroactivamente.", "Ha de ser reglamentaria.", "Atenta contra el principio de legalidad penal si se aplica retroactivamente."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Todos los españoles, respecto al castellano, tienen el:', '["Derecho-deber de conocerlo.", "Derecho de usar y deber de conocerlo.", "Derecho-deber de usarlo.", "Nada de lo anterior."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La capital del Estado en España es:', '["La propia de cada Comunidad Autónoma.", "Madrid.", "Aquella donde se establezca en cada momento el Gobierno.", "Aquella en la que resida generalmente el Rey."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Título de la Constitución que trata de la reforma constitucional es el:', '["Primero.", "Décimo.", "Noveno.", "Undécimo."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Defensor del Pueblo se regula en el siguiente Título y Capítulo de la Constitución, respectivamente:', '["Preliminar y 1º.", "Segundo y 41.", "Segundo y 3º.", "Primero y 4º."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Título de la CE que trata del Gobierno y la Administración es el:', '["Tercero.", "Cuarto.", "Quinto.", "Sexto."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los principios rectores de la política social y económica se regulan en el siguiente Capítulo y Título de la Constitución:', '["Segundo del Primero.", "Tercero del Primero.", "Tercero del Preliminar.", "Primero del Séptimo."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La derogación de una norma postconstitucional que vaya en contra de la Constitución se efectúa por el/la/las:', '["Propia Constitución.", "Tribunal Constitucional.", "Cortes Generales.", "Gobierno."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Constitución el Estado es:', '["Apolítico.", "Aconfesional.", "De bienestar social.", "Federal."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El derecho a la vida se consagra en el siguiente artículo de la Constitución:', '["10.", "16.", "15.", "24."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La pena de muerte en España:', '["Ha quedado abolida.", "Puede aplicarse en cualquier momento.", "Sólo se aplicará, en tiempo de guerra, a los militares.", "Rige sólo en el ámbito civil."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El proceso en el que se enjuicie a un presunto delincuente debe:', '["Ser sumario.", "No dilatarse.", "Entorpecer los instrumentos probatorios.", "Nada de lo anterior es cierto."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La entrada en un domicilio en caso de flagrante delito, sin autorización de su titular:', '["Puede dar lugar a la aplicación del habeas corpus.", "Requiere autorización previa de la autoridad judicial.", "Puede efectuarse en todo momento.", "No puede realizarse en momento alguno."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Cuando, al conocerse la comisión de un delito por una persona, se acude a su domicilio para detenerla:', '["Está obligada a franquear la entrada.", "Se necesitará autorización judicial para entrar.", "Pese a que no dé su consentimiento, se puede entrar.", "Nada de lo anterior es correcto."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La autorización previa para celebrar una manifestación pública:', '["La da el Subdelegado del Gobierno en la Provincia.", "Es ineludible.", "Sería inconstitucional.", "Se da cuando no se prevean alteraciones al orden público, con peligro para personas o bienes."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El tipo de sufragio que consagra la Constitución es el:', '["Proporcional.", "Universal.", "Censitario.", "a y b son correctas."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Además de la no autoinculpación, la Constitución prevé que no se está obligado a declarar sobre un hecho presuntamente delictivo en caso de:', '["Parentesco y afinidad.", "Cláusula de conciencia.", "Secreto profesional.", "a y b son correctas."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El principio de legalidad penal           está  íntimamente relacionado con el/la:', '["Arbitrariedad de los poderes públicos.", "Responsabilidad de éstos.", "Irretroactivad de las normas sancionadoras.", "Publicidad normativa."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La asunción de funciones constitucionales por la Reina consorte:', '["Está prevista como regla general.", "Depende de la voluntad del Rey.", "Está prohibida.", "Está limitada."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La tutoría del Rey puede recaer en:', '["Cualquier persona nombrada por las Cortes, en su caso.", "Sus hijos.", "Una, tres o cinco personas.", "Nada de lo anterior es cierto."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Una hija del Príncipe de Asturias ostentará este tratamiento:', '["Cuando su padre acceda a la condición de Rey, si es la primogénita.", "Al morir su padre.", "Al acceder a Rey su padre, si no tiene hermano varón.", "Cuando delegue en ella el propio Príncipe."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Regencia se ejerce:', '["Por mandato del Rey.", "En nombre de éste.", "Por mandato constitucional.", "b y c son correctas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La dirección de la defensa del Estado es competencia genuine del/de las:', '["Rey.", "Fuerzas Armadas.", "Gobierno.", "Todos ellos."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El refrendo de los actos del Rey está íntimamente relacionado con:', '["Su irresponsabilidad política.", "Su inhabilitación.", "La Regencia.", "Sus poderes discrecionales."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En caso de que el Rey sea menor de edad:', '["No tomará posesión de su cargo hasta su mayoría de edad.", "Ejercerá la Regencia el Príncipe Heredero.", "Ejercerá la Regencia su cónyuge.", "Nada de lo anterior es cierto."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Si el Príncipe Heredero tuviera descendientes y renunciara a sus derechos al trono:', '["Su cónyuge ejercería la Regencia hasta que su primogénito varón fuere mayor de edad.", "Su cónyuge ejercería la Regencia hasta que dicho primogénito fuera proclamado Rey.", "Se nombraría Princesa Heredera a su hermana mayor, si la hubiere.", "Nada de lo anterior es cierto."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La información sobre los asuntos del Estado es suministrada al Rey, esencialmente, por:', '["Su Casa Civil.", "El Consejo de Ministros.", "Las Cortes.", "El Presidente del Gobierno."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El juramento lo prestará el Rey ante el/las:', '["Cortes Generales.", "Gobierno.", "Miembros de la Familia Real.", "Pueblo español."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Si se agotan todas las líneas llamadas a la sucesión en la Corona de España, se:', '["Nombran Regentes.", "Instaura una nueva línea.", "Proclama la República.", "Establece una Dictadura."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La inhabilitación del Rey se reconoce por el/los/las:', '["Gobierno.", "Congreso.", "Cortes Generales.", "Tres Poderes constitucionales."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Regente nombrado en defecto de padre, madre, pariente mayor de edad o Príncipe Heredero mayor de edad se designa por el/las:', '["Propio Rey.", "Cortes Generales.", "Congreso.", "Consejo de Regencia."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Regencia se ejerce por mandato:', '["De las Cortes Generales.", "Del Rey.", "Constitucional.", "De nadie."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El número mínimo de Diputados previstos para el Congreso es de:', '["250.", "300.", "400.", "350."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'No es incompatible para ser elegido Diputado un:', '["Director General.", "Miembro de una Junta Electoral.", "Juez.", "Ministro."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Palma elige los siguientes Senadores:', '["Ninguno.", "Dos.", "Uno.", "Cuatro."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La intervención bélica de tropas españolas debe autorizarla el/las:', '["Gobierno.", "Rey.", "Cortes Generales.", "ONU."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Presidente de la Diputación Permanente del Congreso es el:', '["Del partido mayoritario.", "Portavoz del partido con mayor número de escaños.", "Presidente de la Cámara.", "Elegido por los Portavoces de los Grupos Parlamentarios."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La iniciativa gubernamental en el proceso de elaboración de Leyes:', '["Se plasma en un Proyecto de Ley.", "Se hace a través de Proposición de Ley.", "No existe.", "Es la popular."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La iniciativa legislativa parlamentaria:', '["Puede ser llevada a efecto por cualquiera de las Cámaras.", "Se manifiesta a través de Proyectos de Ley.", "Se efectúa a instancias de¡ Gobierno.", "Todo lo anterior es correcto."]'::jsonb, 0, 'es'),
    ('9df3936834d0d4eec8a58c80f23a15be', 'El mínimo de miembros integrantes de una Comisión de Investigación según el art. 76 de la Constitución es de:', '["Veintiuno.", "Mayoría simple.", "Mayoría absoluta.", "No se establece."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Co puede solicitar la celebración de una sesión extraordinaria de las Cortes el/la:', '["Mayoría absoluta de sus miembros.", "Diputación Permanente de ellas.", "Mesa de cada Cámara.", "Gobierno."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El primer período de sesiones de las Cámaras concluye:', '["Al finalizar su mandato.", "En enero.", "En diciembre.", "En junio."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'No puede delegarse en una Comisión       Legislativa Permanente la posibilidad de aprobar una Ley:', '["Tributaria.", "De Funcionarios Públicos.", "Orgánica.", "A y c son correctas."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'A efectos judiciales no se constituye como división del Estado el/la:', '["Comunidad Autónoma.", "Municipio.", "Partido Judicial.", "Lo son todos ellos."]'::jsonb, 3, 'es');

  -- Batch 1601-1800
  insert into public.question_bank (content_hash, question, options, correct_index, lang)
  values
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Partido Judicial se integra por:', '["Uno o más Municipios.", "Un solo Municipio o Provincia.", "Una o más Provincias.", "Una Comunidad Autónoma."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'No existe Tribunal Militar Territorial en:', '["Sevilla.", "La Coruña.", "Las Palmas.", "Barcelona."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Tampoco existe Tribunal Militar Territorial en:', '["Sevilla.", "Baleares.", "Madrid.", "Santa Cruz de Tenerife."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El segundo escalón de la Jurisdicción Militar lo constituye el/la/los:', '["Tribunal Militar Central.", "Tribunales Militares Territoriales.", "Juzgados Togados Militares.", "Sala de lo Militar del Tribunal Supremo."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El órgano judicial que se establece a nivel de partidos judiciales es el Juzgado de:', '["Primera Instancia e Instrucción.", "Lo Penal.", "Paz.", "Menores."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La instrucción de los sumarios de los que conoce la Sala de lo Penal de la Audiencia Nacional corresponde a la/los:', '["Propia Audiencia Nacional.", "Juzgados Centrales de Instrucción.", "Juzgados de lo Penal.", "Juzgados de Instrucción."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En el orden penal, los Juzgados de Paz pueden conocer de determinados procesos por:', '["Delitos.", "Delitos y faltas.", "Faltas.", "Infracciones administrativas."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los Juzgados de lo Contencioso-Administrativo existirán en el siguiente ámbito territorial:', '["Comarcal.", "Provincial.", "Municipal.", "De Comunidad Autónoma."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En la Audiencia Nacional no existe Sala de lo:', '["Penal.", "Contencioso-Administrativo.", "Civil.", "Social."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La jurisdicción del Tribunal Supremo abarca a:', '["Todas las materias.", "Las actividades de las Cortes.", "Todo el territorio nacional.", "Las cuestiones constitucionales"]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Sala de lo Militar en el Tribunal Supremo es la:', '["Sexta.", "Quinta.", "Cuarta.", "No existe como tal."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En el Tribunal Supremo, la Sala Cuarta se dedica a lo:', '["Penal.", "Contencioso-Administrativo.", "Militar.", "Social."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Con su Presidente, integran el Consejo General del Poder Judicial los siguientes miembros:', '["Doce.", "Veintiuno.", "Veinte.", "Trece."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Actualmente, el Congreso propone los        siguientes miembros del Consejo General del Poder Judicial:', '["Cuatro.", "Doce.", "Diez.", "Seis."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En materia de modificación de plantillas orgánicas de Jueces y Magistrados, el Consejo General del Poder Judicial:', '["Decide.", "Informa posteriormente.", "Informa previamente.", "Propone en todo caso."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La propuesta de nombramiento de los miembros de este Consejo General del Poder Judicial parte del:', '["Congreso y Senado.", "Gobierno.", "a y b son correctas.", "El Tribunal Constitucional, en parte."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Constitución establece que el título de Rey es el de:', '["Rey de los Españoles", "Rey del Estado", "Rey de España", "Rey Constitucional."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Podrá utilizar el Rey los demás títulos que correspondan a la Corona?:', '["No", "Sí", "Solamente los títulos hereditarios", "Solamente los títulos nobiliarios."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Rey ejerce las funciones que le atribuyen expresamente:', '["Las leyes", "La Constitución y las leyes", "Las leyes y la costumbre", "La Constitución, las leyes y la costumbre."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La persona del Rey es:', '["Inmune", "Irresponsable", "Inviolable", "Ninguna de las contestaciones anteriores es correcta."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La persona del Rey, ¿está sujeta a responsabilidad?:', '["No", "Sí", "Depende del acto constitucional que ejecute", "Depende del acto político que ejecute."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los actos del Rey:', '["Estarán refrendados según los casos", "Estarán siempre refrendados", "Estarán refrendados por el Jefe de la Casa Real", "Estarán refrendados si él lo solicita."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Tienen validez los actos del Rey sin el refrendo?:', '["No", "Sí", "Depende del acto que ejecute", "No, pero puede subsanarse posteriormente la falta de refrendo."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Corona de España es hereditaria en los sucesores de:', '["La Familia de los Borbones", "La Familia de los Austrias", "S. M. Don Juan Carlos I de Borbón", "S. M. Don Juan de Borbón."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La sucesión en el trono según el orden regular de primogenitura y representación supone que:', '["Es preferida siempre la persona de más edad a la de menos", "Es preferido siempre el grado más próximo al más remoto", "Es preferida siempre la línea anterior a las posteriores", "Es preferido siempre el varón a la mujer."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La sucesión en el trono según el orden regular de primogenitura y representación supone que en la misma línea:', '["Es preferida siempre la persona de más edad a la de menos", "Es preferido siempre el grado más próximo al más remoto", "Es preferida siempre la línea anterior a las posteriores", "Es preferido siempre el varón a la mujer."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La sucesión en el trono según el orden regular de primogenitura y representación supone que en el mismo grado:', '["Es preferida siempre la persona de más edad a la de menos", "Es preferido siempre el grado más próximo al más remoto", "Es preferida siempre la línea anterior a las posteriores", "Es preferido siempre el varón a la mujer."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La sucesión en el trono según el orden regular de primogenitura y representación supone que en el mismo sexo:', '["Es preferida siempre la persona de más edad a la de menos", "Es preferido siempre el grado más próximo al más remoto", "Es preferida siempre la línea anterior a las posteriores", "Es preferido siempre el varón a la mujer."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Príncipe heredero, desde su nacimiento o desde que se produzca el hecho que origine el llamamiento, tendrá la dignidad de:', '["Príncipe de España", "Príncipe de Asturias", "Infante de España", "Conde de Barcelona."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Príncipe heredero, ¿ostentará los demás títulos vinculados tradicionalmente al sucesor de la Corona de España?:', '["Sí", "No", "No, pues solamente los ostenta el propio Rey", "Sí, hasta que se origine el llamamiento."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Extinguidas todas las líneas llamadas en Derecho, ¿quién proveerá a la sucesión en la Corona?:', '["El Gobierno", "El Congreso", "Las Cortes Generales", "El Consejo de Regencia."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Extinguidas todas las líneas llamadas en Derecho, ¿como se proveerá a la sucesión en la Corona?:', '["En la forma que más convenga a los intereses de la Monarquía", "En la forma que más convenga a los intereses de España", "En la forma que más convenga a los intereses de la Casa Real", "En la forma que más convenga a los intereses de la sociedad."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La exclusión en la sucesión a la Corona se efectuará en aquellas personas que teniendo derecho a la sucesión en el trono contrajeren matrimonio contra la expresa prohibición:', '["Del Rey", "Del Rey y de la Reina", "Del Rey y de las Cortes Generales", "Del Rey y del Gobierno."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Aquellas personas que teniendo derecho a la sucesión en el trono contrajeren matrimonio contra la expresa prohibición de quienes pueden manifestarla, quedarán excluidas en la sucesión a la Corona:', '["Por sí", "Por sí y sus descendientes", "Por sí y sus ascendientes", "Por sus descendientes."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Reina consorte o el consorte de la Reina, ¿podrán asumir funciones constitucionales?:', '["No, ninguna", "No, salvo lo dispuesto para la Regencia", "Sí", "Sí, excepto la Regencia."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Cuando el Rey fuera menor de edad, ¿quién entrará a ejercer la Regencia en primer lugar?:', '["El padre del Rey", "El pariente mayor de edad más próximo a suceder en la Corona", "El padre o la madre del Rey", "El hermano mayor del Rey."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Cuando el Rey fuera menor de edad, ¿quién entrará a ejercer la Regencia en defecto de quien tuviera que ejercerla en primer lugar, según el orden establecido en la Constitución?:', '["El pariente mayor de edad más próximo a suceder en la Corona", "El hermano mayor de edad", "El padre o la madre del Rey", "Quien determinen las Cortes Generales."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Durante cuánto tiempo se ejercerá la Regencia?:', '["Durante cinco años como máximo", "Durante el tiempo de la mayoría de edad del Rey", "Durante el tiempo de la minoría de edad del Rey", "Durante el tiempo que determinen las Cortes Generales."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién reconocerá la imposibilidad del Rey para el ejercicio de su autoridad?:', '["El Gobierno", "El Congreso", "Las Cortes Generales", "El Consejo de Regencia."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Si el Rey se inhabilitara para el ejercicio de su autoridad, ¿quién entrará a ejercer inmediatamente la Regencia?:', '["El Príncipe heredero de la Corona, si fuera mayor de edad", "Aquél a quien le corresponda la Regencia, si el Príncipe heredero no fuera mayor de edad", "El Príncipe heredero de la Corona, en todo caso", "Son ciertas las respuestas a. y b."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Si no hubiere ninguna persona a quien corresponda la Regencia, ésta será nombrada por:', '["El Gobierno", "El Congreso", "Las Cortes Generales", "El Consejo de Regencia."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Si no hubiere ninguna persona a quien corresponda la Regencia, ésta se compondrá de:', '["Una persona", "Una o tres personas", "Una, tres o cinco personas", "Un número impar de personas."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué se exige para ejercer la Regencia?:', '["Ser español", "Ser mayor de edad", "Ser español y mayor de edad", "Ser español mayor de edad y miembro de la Casa Real."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Regencia se ejercerá por mandato:', '["Constitucional", "Del propio Rey", "De las Cortes Generales", "Del Consejo de Regencia."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Regencia se ejercerá siempre en nombre:', '["De la Monarquía", "Del Rey", "De las Cortes Generales", "Del Consejo de Regencia."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Será tutor del Rey menor:', '["El padre del Rey", "El pariente mayor de edad más próximo a suceder en la Corona", "El padre y la madre del Rey", "La persona que en su testamento hubiese nombrado el Rey difunto."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué requisitos se le exigen al tutor del Rey?:', '["Ser español", "Ser mayor de edad", "Ser mayor de edad y español de nacimiento", "Ser español de nacimiento."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Si el Rey no hubiese nombrado tutor, ¿quién lo será?:', '["El padre y la madre", "El padre o la madre, en todo caso", "El padre o la madre, mientras permanezcan viudos", "El padre."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En defecto de tutor del Rey según las previsiones constitucionales, ¿quién lo nombrará?:', '["Las Cortes Generales", "El Consejo de Regencia", "El Gobierno", "El Congreso."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Podrán acumularse los cargos de Regente y de tutor del Rey?:', '["No, en ningún caso", "Solamente en su padre o madre", "Solamente en su padre, madre o ascendientes directos", "Solamente en sus ascendientes directos o colaterales hasta el tercer grado de parentesco."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El ejercicio de la tutela es incompatible con el de:', '["La regencia", "Todo trabajo remunerado", "Todo cargo político", "Todo cargo o representación política."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Rey, al ser proclamado ante las Cortes generales, prestará juramento de:', '["Desempeñar fielmente sus funciones", "Guardar y hacer guardar la Constitución", "Guardar y hacer guardar las leyes", "Todas las contestaciones anteriores son correctas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Rey, al ser proclamado ante las Cortes generales, no prestará juramento de:', '["Respetar los derechos de los ciudadanos", "Respetar los derechos de las Comunidades Autónomas", "Guardar y hacer guardar las leyes", "Respetar los derechos de los territorios históricos."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Príncipe heredero, ¿prestará el mismo juramento que el Rey?:', '["No", "No, es un juramento voluntario", "Sí, al alcanzar la mayoría de edad", "Sí, al emanciparse."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Regente o Regentes, ¿prestarán el mismo juramento que el Rey?:', '["No", "No, es un juramento voluntario", "Sí, al producirse el llamamiento", "Sí, al hacerse cargo de sus funciones."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El tutor del Rey, ¿prestará el mismo juramento que el Rey?:', '["No", "No, es un juramento voluntario", "Sí, al producirse el llamamiento", "Sí, al hacerse cargo de sus funciones."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Quienes están obligados por la Constitución a prestar el mismo juramento que el Rey, ¿qué otro juramento deben prestar?:', '["El de fidelidad a la Monarquía", "El de fidelidad a España", "El de fidelidad al Rey", "El de fidelidad al Gobierno."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Corresponde al Rey:', '["Aprobar y promulgar las leyes", "Elegir y disolver las Cortes Generales", "Proponer la convocatoria de elecciones", "Ninguna de las contestaciones anteriores es correcta."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Respecto del Presidente del Gobierno, corresponde al Rey:', '["Proponer el candidato al cargo", "Nombrarlo", "Poner fin a sus funciones en los términos previstos en la Constitución", "Todas las contestaciones anteriores son ciertas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿El Rey puede presidir las sesiones del Consejo de Ministros?:', '["Sí, para ser informado de los asuntos de Estado", "Sí, cuando lo estime oportuno", "Sí, a petición del Presidente del Gobierno", "Sí, con todas las condiciones anteriores."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Puede el Rey ejercer el derecho de gracia?:', '["No, solamente puede hacerlo el Presidente del Gobierno", "Sí, con arreglo a su criterio", "Sí, con arreglo a la ley, pudiendo autorizar indultos generales", "Sí, con arreglo a la ley, que no podrá autorizar indultos generales."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién acredita a los embajadores y otros representantes diplomáticos?:', '["El Presidente del Gobierno", "El Rey", "El Presidente del Congreso", "El Ministro de Asuntos Exteriores."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Ante quién se acreditan los representantes extranjeros en España?:', '["Ante el Presidente del Gobierno", "Ante el Rey", "Ante el Presidente del Congreso", "Ante el Ministro de Asuntos Exteriores."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién manifiesta el consentimiento del Estado para obligarse internacionalmente por medio de tratados?:', '["El Presidente del Gobierno", "El Rey", "El Presidente del Congreso", "El Ministro de Asuntos Exteriores."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Al Rey la corresponde declarar la guerra?:', '["No, es competencia de las Cortes Generales", "Sí, previa autorización del Gobierno", "Sí, y hacer la paz, previa autorización del Gobierno", "Sí, y hacer la paz, previa autorización de las Cortes Generales."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los actos del Rey serán refrendados por:', '["El Presidente del Gobierno, siempre", "Los Ministros competentes, siempre", "El Presidente del Gobierno y, en su caso, por los Ministros competentes", "El Jefe de la Casa Real."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Algún acto del rey es refrendado por el Presidente del Congreso?:', '["No, ninguno", "Sí, la propuesta del Presidente del Gobierno", "Sí, el nombramiento del Presidente del Gobierno", "Sí, la propuesta y el nombramiento del Presidente del Gobierno."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Rey recibe de los Presupuestos del Estado una cantidad global para el sostenimiento de:', '["Su Familia", "Su Casa", "Su Familia y Casa", "Su Familia y Corona."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La cantidad que el Rey recibe de los Presupuestos del Estado, ¿cómo la distribuye?:', '["Equitativamente", "Libremente", "Proporcionalmente", "Según los criterios establecidos por el Ministerio de Hacienda."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Rey nombra y releva libremente a los miembros:', '["De la Corona", "Civiles de su Casa", "Militares de su Casa", "Civiles y militares de su Casa."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Cortes Generales representan:', '["A España", "Al pueblo español", "A las Comunidades Autónomas", "A todos los españoles mayores de edad."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Cortes están formadas por:', '["La Cámara Alta y la Cámara Baja", "El Congreso de Representantes y el Senado", "El Congreso de los Diputados y el Senado", "La Asamblea Nacional y el Senado."]'::jsonb, 2, 'es'),
    ('e947057ff2f42db277860ce0b90afaed', 'El Título de la Constitución que se refiere a las Cortes Generales es el:', '["Título II", "Título III", "Título IV", "Título V."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué competencia no corresponde a las Cortes Generales?:', '["Ejercen la potestad legislativa del Estado", "Imparten justicia", "Controlan la acción del Gobierno", "Aprueban los Presupuestos del Estado."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Cortes Generales son:', '["Inviolables", "Improrrogables", "Inmunes", "Indisolubles."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Alguien podrá ser miembro de las dos Cámaras simultáneamente?:', '["No, nadie", "Sí, cualquier ciudadano mayor de edad", "Solamente durante una legislatura", "Depende de lo que regule el Reglamento de cada Cámara."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Es incompatible la condición de miembro de:', '["Una Asamblea de Comunidad Autónoma con la de Diputado al Congreso", "Una Asamblea de Comunidad Autónoma con la de Senador", "Una Corporación Local con la de Diputado al Congreso", "Una Corporación Local con la de Senador."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los miembros de las Cortes Generales, ¿estarán ligados por mandato imperativo?:', '["Sí", "No", "Depende de la organización de cada partido político", "Depende de lo que disponga el Reglamento de las Cámaras."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El mandato de los miembros de las Cortes Generales es:', '["Imperativo", "Representativo", "Mancomunado", "Reglado."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las reuniones de Parlamentarios que se celebren sin convocatoria reglamentaria:', '["No vincularán a las Cámaras", "Pueden vincular a las Cámaras", "Son perfectamente válidas si así lo aprueban los asistentes", "Ninguna de las anteriores es correcta."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Congreso se compone de un mínimo de:', '["250 Diputados", "300 Diputados", "350 Diputados", "375 Diputados."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Congreso se compone de un máximo de:', '["250 Diputados", "300 Diputados", "350 Diputados", "400 Diputados."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los Diputados son elegidos por sufragio:', '["Universal, directo y secreto", "Universal, libre, directo y secreto", "Universal, igual, directo y secreto", "Universal, libre, igual, directo y secreto."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La circunscripción electoral para elección de Diputados del Congreso es:', '["El municipio", "El partido judicial", "La provincia", "La Comunidad Autónoma."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las poblaciones de Ceuta y Melilla estarán representadas por:', '["Un Diputado cada una de ellas", "Dos Diputados cada una de ellas", "Un Diputado para ambas", "Tres Diputados para ambas."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Constitución, ¿quién distribuirá el número total de Diputados?:', '["La propia Constitución", "El Reglamento del Congreso", "El Reglamento de las Cortes Generales", "La ley."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La distribución del número total de Diputados se realizará:', '["Asignando una representación mínima inicial a cada circunscripción", "Distribuyendo los demás en proporción a la población", "Asignando un número fijo por circunscripción", "Son ciertas las respuestas a. y b."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La elección se verificará en cada circunscripción atendiendo a criterios:', '["De representación mayoritaria", "De representación proporcional", "De representación censitaria", "De representación directa."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Congreso es elegido por:', '["3 años", "4 años", "5 años", "6 años."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El mandato de los Diputados termina:', '["Cinco años después de su elección", "El día siguiente a la disolución de la Cámara", "Cuatro años después de su elección o el día de la disolución de la Cámara", "Cuatro años después de su elección o el día siguiente a la disolución de la Cámara."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Son electores y elegibles:', '["Todos los ciudadanos", "Todos los españoles", "Todos los ciudadanos que estén en pleno uso de sus derechos civiles", "Todos los españoles que estén en pleno uso de sus derechos políticos."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La ley reconocerá y el Estado facilitará el ejercicio del derecho de sufragio a los españoles:', '["Que se encuentren privados de libertad", "Que se encuentren fuera del territorio de España", "Que se encuentren impedidos", "Que se encuentren incapacitados."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las elecciones tendrán lugar entre los:', '["30 días y 40 días desde la convocatoria", "30 días y 60 días desde la convocatoria", "30 días y 60 días desde la terminación del mandato", "30 días y 40 días desde la terminación del mandato."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Una vez celebradas las elecciones, el Congreso electo deberá ser convocado dentro de los:', '["20 días siguientes", "25 días siguientes", "30 días siguientes", "35 días siguientes."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En cada provincia se elegirán:', '["2 Senadores", "3 Senadores", "4 Senadores", "5 Senadores."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los Senadores son elegidos por sufragio:', '["Universal, directo y secreto", "Universal, libre, directo y secreto", "Universal, igual, directo y secreto", "Universal, libre, igual, directo y secreto."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En las provincias insulares, constituirá una circunscripción a efectos de elección de Senadores:', '["Cada isla", "Cada isla o agrupación de ellas", "Cada isla o agrupación de ellas, con Cabildo Insular", "Cada isla o agrupación de ellas, con Cabildo o Consejo Insular."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'No elige tres Senadores:', '["Gran Canaria", "Fuerteventura", "Mallorca", "Tenerife."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué isla de las siguientes elige un Senador?:', '["Ibiza ‐ Formentera", "Gomera", "Menorca", "Todas las islas citadas eligen un Senador."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Comunidades Autónomas designarán:', '["Un Senador", "Un Senador por cada millón de habitantes de su territorio", "Dos Senadores y otro más por cada millón de habitantes de su territorio", "Un Senador y otro más por cada millón de habitantes de su territorio."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién designa a los Senadores de cada Comunidad Autónoma?:', '["El Consejo de Gobierno, siempre", "El órgano colegiado superior, siempre", "La Asamblea Legislativa, siempre", "La Asamblea Legislativa o, en su defecto, el órgano colegiado superior."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Dónde se fija el procedimiento para la designación de Senadores de cada Comunidad Autónoma?:', '["En la Constitución", "En la Ley Orgánica del Régimen Electoral General", "En los respectivos Estatutos de Autonomía", "En el Reglamento del Senado."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Senado es elegido por:', '["3 años", "4 años", "5 años", "6 años."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El mandato de los Senadores termina:', '["Cinco años después de su elección", "El día siguiente a la disolución de la Cámara", "Cuatro años después de su elección o el día de la disolución de la Cámara", "Cuatro años después de su elección o el día siguiente a la disolución de la Cámara."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las causas de inelegibilidad e incompatibilidad de los Diputados y Senadores se determinan en:', '["La ley electoral", "La Constitución", "El Reglamento de las Cortes Generales", "La convocatoria de elecciones."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las causas de inelegibilidad e incompatibilidad de los Diputados y Senadores no incluirán:', '["A los componentes del Tribunal Constitucional", "A los miembros de las Juntas Electorales", "Al Defensor del Pueblo", "A los miembros del Gobierno."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La validez de las actas y credenciales de los miembros de ambas Cámaras estará sometida al control:', '["Judicial", "Político", "Fiscal", "Reglamentario."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los Diputados y Senadores gozarán de inviolabilidad:', '["Por los delitos cometidos", "Por las faltas cometidas", "Por las opiniones manifestadas en el ejercicio de sus funciones", "Por sus opiniones privadas."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La inmunidad de Diputados y Senadores supone que:', '["Sólo podrán ser detenidos en caso de flagrante delito", "No podrán ser inculpados sin la previa autorización de la Cámara respectiva", "No podrán ser procesados sin la previa autorización de la Cámara respectiva", "Todas las contestaciones anteriores son correctas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En las causas contra Diputados y Senadores será competente:', '["El Tribunal Constitucional", "Cualquier Sala del Tribunal Supremo", "La Sala de lo Penal del Tribunal Supremo", "La Asamblea Nacional."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los Diputados y Senadores percibirán una asignación que será fijada por:', '["El Ministerio de Hacienda", "El Congreso", "Las respectivas Cámaras", "El Gobierno."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Cámaras:', '["Establecen sus propios Reglamentos", "Aprueban autónomamente sus presupuestos", "Regulan el Estatuto del Personal de las Cortes Generales, de común acuerdo", "Todas las contestaciones anteriores son correctas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los Reglamentos de las Cámaras y su reforma, ¿serán sometidos a una votación final?:', '["No", "Sí, sobre su articulado", "Sí, sobre su totalidad, que requerirá la mayoría absoluta", "Sí, sobre su totalidad, que requerirá mayoría de dos tercios."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Cámaras eligen a:', '["Sus respectivos Presidentes", "Sus respectivos Presidentes y a los demás miembros de sus Mesas", "Los miembros de sus Mesas", "Los Secretarios de sus Mesas."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las sesiones conjuntas delas Cámaras serán presididas por:', '["El Rey", "El Presidente del Congreso", "El Presidente del Senado", "El Presidente de las Cortes Generales."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las sesiones conjuntas de las Cámaras se regirán:', '["Por el Reglamento de las Cortes Generales", "Por el Reglamento del Congreso", "Por el Reglamento del Senado", "Por el Reglamento de Régimen Interno."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Reglamento de las Cortes Generales:', '["No existe", "Será aprobado por mayoría absoluta de cada Cámara", "Será aprobado por mayoría absoluta del Congreso", "Será aprobado por mayoría absoluta del Senado."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los Presidentes de las Cámaras ejercen en nombre de las mismas en el interior de sus respectivas sedes:', '["Los poderes disciplinarios", "Los poderes disciplinarios y medidas correctivas", "Todos los poderes administrativos", "Todos los poderes administrativos y facultades de policía."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Cámaras se reunirán anualmente en:', '["Dos períodos ordinarios de sesiones", "Tres períodos ordinarios de sesiones", "Dos períodos extraordinarios de sesiones", "Tres períodos extraordinarios de sesiones."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El primer periodo ordinario de sesiones de las Cámaras es:', '["De enero a junio", "De febrero a junio", "De julio a diciembre", "De septiembre a diciembre."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El segundo periodo ordinario de sesiones de las Cámaras es:', '["De enero a junio", "De febrero a junio", "De julio a diciembre", "De septiembre a diciembre."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Cámaras podrán reunirse en sesiones extraordinarias a petición:', '["Del Gobierno", "De la Diputación Permanente", "De la mayoría absoluta de los miembros de cualquiera de las Cámaras", "Todas las respuestas anteriores son correctas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Sobre las sesiones extraordinarias de las Cámaras, resulta que:', '["Deberán convocarse sobre un orden del día determinado", "Serán clausuradas una vez que el orden del día haya sido agotado", "Deberán contar con la presencia de tres cuartas partes de miembros", "Son ciertas las respuestas a. y b."]'::jsonb, 3, 'es'),
    ('95286aa824b18e8857c72287aa97cd4c', 'Las Cámaras se reunirán en sesión conjunta:', '["Para ejercer las competencias no legislativas", "Para ejercer las competencias legislativas del Título I", "Para ejercer las competencias no legislativas que el Título II atribuye expresamente a las Cortes Generales", "Para ejercer las competencias legislativas que el Título VIII atribuye expresamente a las Cortes Generales."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Se decidirá por mayoría de cada Cámara:', '["La prestación del consentimiento del Estado para obligarse por medio de tratados o convenios", "Los acuerdos de cooperación entre las Comunidades Autónomas", "La distribución de recursos del Fondo de Compensación Interterritorial", "Todas las contestaciones anteriores son correctas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El procedimiento para la prestación del consentimiento del Estado para obligarse por medio de tratados o convenios se iniciará:', '["Por el Gobierno", "Por el Congreso", "Por el Senado", "Por las Cortes Generales."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El procedimiento para la distribución de recursos del Fondo de Compensación Interterritorial se iniciará:', '["Por el Gobierno", "Por el Congreso", "Por el Senado", "Por las Cortes Generales."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El procedimiento sobre los acuerdos de cooperación entre las Comunidades Autónomas se iniciará:', '["Por el Gobierno", "Por el Congreso", "Por el Senado", "Por las Cortes Generales."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En los casos de toma de decisiones por parte de las Cortes Generales, ¿qué ocurre si no hubiera acuerdo entre Senado y Congreso', '["Se desistirá del acuerdo", "Se repetirán las votaciones todas las veces que sean precisas", "Se intentará obtener por una Comisión Delegada de Diputados y Senadores", "Se intentará obtener por una Comisión Mixta compuesta de igual número de Diputados y Senadores."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En los casos de toma de decisiones por parte de las Cortes Generales, y a falta de acuerdo entre Senado y Congreso, ¿qué ocurre si no se aprueba el texto propuesto por la Comisión Mixta?', '["Nada, porque dicha Comisión no está prevista", "Que debe aprobarlo cada Cámara por mayoría simple", "Que decidirá el Congreso por mayoría absoluta", "Que decidirá el Senado por mayoría absoluta."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Cámaras funcionarán:', '["En Pleno exclusivamente", "En Pleno y por Delegaciones", "En Pleno y por Comisiones", "En Pleno, por Comisiones y por Delegaciones."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Podrán delegar las Cámaras la aprobación de proyectos o proposiciones de ley?', '["Sí, en las Comisiones Legislativas Permanentes", "Sí, en las Delegaciones Legislativas Permanentes", "Sí, en las Comisiones Legislativas solamente las proposiciones de ley", "No, no pueden delegar dichas competencias."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué órgano de las Cámaras podrá recabar en cualquier momento el debate y votación de cualquier Proyecto o proposición de ley que haya sido objeto de delegación?', '["El Pleno", "La Mesa", "La Comisión Legislativa", "El Presidente."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'No podrá delegarse en una Comisión Legislativa:', '["La reforma del Código Civil", "La reforma constitucional", "La reforma de Reales Decretos", "Ninguna de las materias anteriores."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién podrá nombrar Comisiones de investigación sobre cualquier asunto de interés público?', '["El Congreso", "El Senado", "Ambas Cámaras conjuntamente, en su caso", "Todas las contestaciones anteriores son correctas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las conclusiones de las Comisiones parlamentarias de investigación sobre cualquier asunto de interés público:', '["Serán vinculantes para los Tribunales", "Afectarán a las resoluciones judiciales", "Serán inmediatamente ejecutivas en vía judicial", "Ninguna de las contestaciones anteriores es correcta."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El resultado de la investigación realizada por las Comisiones parlamentarias de investigación sobre cualquier asunto de interés público:', '["Podrá ser comunicado al Ministerio Fiscal", "Tendrá que ser comunicado al Ministerio Fiscal", "Podrá ser comunicado al Ministerio Fiscal para el ejercicio de las acciones oportunas", "Podrá ser comunicado al Ministerio Fiscal para el ejercicio, cuando proceda, de las acciones oportunas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Será obligatorio comparecer a requerimiento de las Cámaras?', '["Sí", "No", "Depende del asunto requerido", "Depende del cargo que se ocupe."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién regulará las sanciones que puedan imponerse por incumplimiento de la obligación de comparecer a requerimiento de las Cámaras?:', '["Nadie, porque no es un acto obligatorio", "La ley", "La Constitución", "El Reglamento de las Cortes Generales."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Pueden recibir peticiones las Cámaras?:', '["No", "Sí, individuales", "Sí, colectivas", "Sí, individuales y colectivas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las peticiones presentadas ante las Cámaras:', '["No proceden", "Se harán siempre verbalmente", "Se harán siempre por escrito", "Se harán siempre verbalmente o por escrito."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Respecto de las peticiones presentadas ante las Cámaras:', '["Hay que decir que no están permitidas", "Está prohibida la presentación directa", "Está prohibida la presentación directa por manifestaciones ciudadanas", "Ninguna de las anteriores es correcta."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las peticiones que reciban las Cámaras:', '["Pueden ser remitidas por éstas al Gobierno", "Pueden ser remitidas por éstas al Defensor del Pueblo", "Tienen que ser remitidas por éstas al Gobierno", "Serán remitidas por éstas al Defensor del Pueblo."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué obligación constitucional recae sobre el Gobierno en relación con las peticiones que le remitan las Cámaras?:', '["Ninguna, pues no está prevista dicha remisión", "Está obligado a explicarse sobre su contenido", "Está obligado a explicarse sobre su contenido, siempre que las Cámaras lo exijan", "Puede explicarse sobre su contenido, si lo estima conveniente."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Diputación Permanente:', '["No existe", "Existe en el Congreso, exclusivamente", "Existe en el Senado, exclusivamente", "Existe en cada Cámara."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Diputación Permanente del Congreso o Senado, ¿cuántos miembros tendrá como mínimo?:', '["Ninguno, porque no existe", "Quince", "Veintiuno", "Veintitrés."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿A quiénes representan los miembros de la Diputación Permanente del Congreso o del Senado?:', '["A sí mismos", "A la Mesa de las Cámaras", "A los partidos políticos, en proporción al número de votos obtenidos", "A los grupos parlamentarios, en proporción a su importancia numérica."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién preside la Diputación Permanente del Congreso o del Senado?:', '["El Presidente de la Diputación Permanente", "El representante de más edad", "El Presidente de cada Cámara", "El Secretario de la Mesa."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'No corresponde a la Diputación Permanente de las Cámaras:', '["Asumir las facultades de las Cámaras si hubieran sido disueltas", "Asumir las facultades de las Cámaras si hubiera expirado su mandato", "Velar por los poderes de las Cámaras cuando no estén reunidas", "Todas las competencias anteriores le corresponden."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Corresponde a la Diputación Permanente de las Cámaras:', '["Pedir que las Cámaras se reúnan en sesiones ordinarias", "Pedir que las Cámaras se reúnan en sesiones extraordinarias", "Declarar el estado de excepción", "Proponer el Rey el candidato a Presidente de las Cámaras."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Diputaciones Permanentes, ¿seguirán ejerciendo sus funciones hasta la constitución de las nuevas Cortes Generales?', '["No, en ningún caso", "Sí, cuando expire el mandato de éstas", "Sí, en caso de disolución de éstas", "Sí, cuando expire el mandato o en caso de disolución de éstas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Reunida la Cámara correspondiente, la Diputación Permanente dará cuenta de:', '["Los asuntos pendientes", "Los asuntos tratados", "Sus decisiones", "Los asuntos tratados y de sus decisiones."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Para adoptar acuerdos las Cámaras deben estar reunidas:', '["Reglamentariamente", "Legalmente", "Debidamente", "Convenientemente."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Para adoptar acuerdos las Cámaras han de contar con la asistencia de:', '["Todos sus miembros", "La mayoría de sus miembros", "Las dos terceras partes sus miembros", "La tres quintas partes sus miembros."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los acuerdos de las Cámaras, para ser válidos, deberán ser aprobados por:', '["Todos sus miembros", "La mayoría de los miembros presentes", "La dos terceras partes sus miembros", "La mayoría absoluta de los miembros con derecho a voto."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿ Para la toma de acuerdos por las Cámaras, ¿se establecen mayorías especiales?:', '["Sí, en las leyes orgánicas", "Sí, en la propia Constitución", "Sí, las que para elección de personas establezcan los Reglamentos de las Cámaras", "Todas las contestaciones anteriores son correctas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El voto de Senadores y Diputados es:', '["Impersonal", "Indirecto", "Personal e indelegable", "Personal e intransferible."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las sesiones plenarias de las Cámaras, ¿serán públicas?:', '["Sí, siempre", "No, nunca", "Sí, salvo acuerdo en contrario de cada Cámara", "Sí, salvo que se trate materia reservada."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El acuerdo para que las sesiones plenarias de las Cámaras no sean públicas:', '["No podrá adoptarse", "Se adoptará por mayoría absoluta", "Se adoptará con arreglo al Reglamento", "Se adoptará por mayoría absoluta o con arreglo al Reglamento."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'No son leyes orgánicas:', '["Las relativas al Desarrollo de los derechos fundamentales", "Las relativas al desarrollo de las libertades públicas", "Las que aprueben los Estatutos de Autonomía", "Todas las anteriores son leyes orgánicas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Son leyes orgánicas:', '["Las que aprueban los Presupuestos Generales del Estado", "Las que aprueben el régimen electoral general", "Las que aprueben las bases del régimen local", "Las que aprueben el Estatuto del Presidente del Gobierno."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La mayoría exigida para la aprobación, modificación o derogación de las leyes orgánicas lo será:', '["En una enmienda a la totalidad", "En una sesión extraordinaria", "En una votación final sobre el conjunto del proyecto", "En una votación especial sobre el conjunto del proyecto."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Cortes Generales, ¿podrán delegar en el Gobierno la potestad de dictar normas con rango de ley?:', '["No, solamente podrá hacerlo el Congreso", "Sí, sobre cualquier materia", "Sí, excepto sobre materias propias de ley orgánica", "Sí, excepto sobre leyes de bases."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Cuando el objeto de la delegación legislativa que las Cortes Generales otorguen al Gobierno sea la formación de textos articulados, deberá realizarse mediante:', '["Una ley de bases", "Una ley ordinaria", "Un Decreto ‐ Ley", "Un Decreto Legislativo."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Cuando el objeto de la delegación legislativa que las Cortes Generales otorguen al Gobierno se trate de refundir varios textos legales en uno solo, deberá realizarse mediante:', '["Una ley de bases", "Una ley ordinaria", "Un Decreto ‐ Ley", "Un Decreto Legislativo."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La delegación legislativa habrá de otorgarse al Gobierno:', '["De forma abstracta", "Para materia genérica", "Sin fijación del plazo para su ejercicio", "Ninguna de las anteriores es correcta."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuándo se agota la delegación legislativa otorgada al Gobierno?:', '["Nunca", "Por el uso que de ella haga el Gobierno", "Por el uso que de ella haga el Gobierno mediante la publicación de cualquier norma", "Por el uso que de ella haga el Gobierno mediante la publicación de la norma correspondiente."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La delegación legislativa otorgada al Gobierno:', '["No podrá entenderse concedida de modo implícito", "No podrá entenderse concedida por tiempo indeterminado", "No podrá entenderse concedida de modo implícito o por tiempo indeterminado", "Ninguna de las anteriores es correcta."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Respecto de la delegación legislativa otorgada al Gobierno, ¿se podrá permitir la subdelegación a autoridades distintas del propio Gobierno?:', '["Sí", "No", "Sí, con autorización del Congreso", "Sí, si no se excede el ámbito de la delegación."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Respecto de la delegación legislativa otorgada al Gobierno mediante leyes de bases, éstas delimitarán con precisión:', '["El objeto de la delegación legislativa", "El alcance de la delegación legislativa", "Los principios y criterios que han de seguirse en su ejercicio", "Todas las anteriores son correctas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La autorización al Gobierno para refundir textos legales:', '["Determinará el ámbito normativo a que se refiere el contenido de la delegación", "Especificará si se circunscribe a la mera formulación de un texto único", "Especificará si se incluye la facultad de regularizar, aclarar y armonizar los textos legales que han de ser refundidos", "Todas las respuestas anteriores son correctas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las leyes de delegación legislativa, ¿podrán establecer en cada caso fórmulas adicionales de control?:', '["No", "Sí, si no se opone el Gobierno", "Sí, sin perjuicio de la competencia propia de los Tribunales", "Sí, ya que los Tribunales no tienen competencia para ejercer dicho control."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las leyes de bases no podrán en ningún caso:', '["Autorizar la modificación de la propia ley de bases", "Facultar para dictar normas con carácter retroactivo", "Regular materias reservadas a ley ordinaria", "Son ciertas las respuestas a. y b."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Cuando una proposición de ley o una enmienda fuera contraria a una delegación legislativa en vigor, el Gobierno:', '["Deberá respetar su tramitación", "Está facultado para oponerse a su tramitación", "Está facultado para plantear una enmienda a la totalidad", "Está facultado para plantear enmiendas parciales."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Cuando una proposición de ley o una enmienda fuera contraria a una delegación legislativa en vigor:', '["Deberá presentarse una proposición de ley para la derogación total de la ley de delegación", "Podrá presentarse una proposición de ley para la derogación parcial de la ley de delegación", "Podrá presentarse una proposición de ley para la derogación total o parcial de la ley de delegación", "Podrá presentarse un proyecto de ley para la derogación total o parcial de la ley de delegación."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las disposiciones del Gobierno que contengan legislación delegada recibirán el título de:', '["Leyes de bases", "Leyes ordinarias", "Decretos ‐ Leyes", "Decretos Legislativos."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Gobierno podrá dictar disposiciones             legislativas provisionales en caso de:', '["Extraordinaria y urgente necesidad", "Vigencia de los estados de alarma, excepción o sitio", "Calamidad pública", "Necesidad de tramitación urgente."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las disposiciones legislativas provisionales dictadas por el Gobierno tomarán la forma de:', '["Leyes de bases", "Leyes ordinarias", "Decretos ‐ Leyes", "Decretos Legislativo."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las disposiciones legislativas provisionales dictadas por el Gobierno podrán afectar:', '["Al ordenamiento de las instituciones básicas del Estado", "a los derechos de los ciudadanos", "A los deberes de los ciudadanos", "No podrán afectar a ninguna de las materias anteriores."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los Decretos ‐ Leyes deberán ser inmediatamente sometidos a debate y votación de totalidad:', '["En el Congreso de los Diputados", "En el Senado", "En las Cortes Generales", "En la Comisión de Delegaciones Legislativas del Congreso."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuándo debe convocarse al Congreso de los Diputados para someter un Decreto ‐ Ley a debate y votación de totalidad?:', '["No está prevista constitucionalmente dicha convocatoria", "En el plazo de los 15 días siguientes a su promulgación", "En el plazo de los 20 días siguientes a su promulgación", "En el plazo de los 30 días siguientes a su promulgación."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cómo puede pronunciarse el Congreso de los Diputados al someter un Decreto ‐ Ley a debate y votación de totalidad?:', '["Puede convalidarlo exclusivamente", "Puede convalidarlo o subsanarlo", "Puede convalidarlo o derogarlo", "Puede subsanarlo o derogarlo."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Para que el Congreso de los Diputados someta un Decreto ‐ Ley a debate y votación de totalidad y se pronuncie sobre el mismo:', '["El Reglamento establecerá un procedimiento abreviado", "La ley establecerá un procedimiento urgente", "El Reglamento establecerá un procedimiento especial y sumario", "Las Cortes Generales establecerán un procedimiento urgente y sumario."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Durante el plazo de que dispone el Congreso de los Diputados para someter un Decreto ‐ Ley a debate y votación de totalidad y pronunciarse sobre el mismo:', '["Se suspenderá la aplicación del Decreto ‐ Ley correspondiente", "El Congreso podrá tramitarlo como proyecto de ley", "Las Cortes podrán tramitarlo como proyecto de ley por el procedimiento de urgencia", "Las Cortes podrán tramitarlo como proyecto de ley por el procedimiento ordinario."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Constitución, la iniciativa legislative no corresponde:', '["Al Gobierno", "Al Congreso", "Al Senado", "A los órganos asamblearios ejecutivos de las Comunidades Autónomas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Respecto de la iniciativa legislativa, las Asambleas de las Comunidades Autónomas podrán solicitar del Gobierno la adopción de:', '["Una proposición de ley", "Un proyecto de ley", "Un Decreto ‐ Ley", "Un Decreto Legislativo."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Respecto de la iniciativa legislativa, las Asambleas de las Comunidades Autónomas podrán remitir a la Mesa del Congreso:', '["Una proposición de ley", "Un proyecto de ley", "Una propuesta legislativa", "Un borrador de ley."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Respecto de la iniciativa legislativa, cuando las Asambleas de las Comunidades Autónomas remitan a la Mesa del Congreso una proposición de ley, para su defensa podrán delegar ante dicha Cámara:', '["Un mínimo de dos miembros", "Un máximo de tres miembros", "Un mínimo de cuatro miembros", "Ninguna de las contestaciones anteriores es correcta, pues no procede dicha iniciativa."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La iniciativa legislativa popular se regula:', '["En la propia Constitución", "Por ley ordinaria", "Por ley orgánica", "Por reglamento."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Para ejercer la iniciativa legislativa popular se exigirán:', '["No menos de 400.000 firmas testimoniadas", "No menos de 500.000 firmas acreditadas", "No menos de 500.000 testimoniadas", "No menos de 1.000.000 de firmas autentificadas."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Procederá la iniciativa legislativa popular en materia:', '["Propia de ley ordinaria", "Tributaria", "De carácter internacional", "Propia de ley orgánica."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'No procederá la iniciativa legislativa popular:', '["En materia de obras públicas", "En lo relativo a la prerrogativa de gracia", "En asuntos de interés general", "En materia ideológica"]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los proyectos de ley serán aprobados:', '["Por la Mesa del Congreso", "En Consejo de Ministros", "Por las Cortes Generales", "Por los Grupos Parlamentario."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los proyectos de ley se someterán al Congreso acompañados de:', '["Una exposición de motivos", "Los antecedentes necesarios para pronunciarse sobre ellos", "Una exposición de motivos y de los antecedentes necesarios para pronunciarse sobre ellos", "Una exposición de motivos, una tabla derogatoria y los antecedentes necesarios para pronunciarse sobre ellos."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La tramitación de las proposiciones de ley:', '["Se efectuará en Consejo de Ministros", "Se regulará por los Reglamentos de las Cámaras", "Se regulará por ley orgánica", "Se regulará por ley ordinaria."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La prioridad debida a los proyectos de ley no impedirá:', '["El ejercicio de la iniciativa legislativa constitucional", "Su tramitación parlamentaria", "El ejercicio de acciones legislativas", "Todas las contestaciones anteriores son falsas."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué ocurrirá con las proposiciones de ley que tome en consideración el Senado?:', '["Nada, porque ello no es posible constitucionalmente", "Se tramitarán por el propio Senado", "Se remitirán al Congreso para su trámite en éste como tal proposición", "Se remitirán al Congreso para su conocimiento."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Aprobado un proyecto de ley ordinaria u orgánica por el Congreso de los Diputados, su Presidente dará inmediata cuenta del mismo:', '["Al Presidente del Gobierno", "Al Presidente del Senado, para su conocimiento", "Al Presidente del Senado, el cual lo someterá a la deliberación de éste", "A la Comisión Legislativa correspondiente."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Una vez recibido por el Senado un proyecto de ley ordinaria u orgánica aprobado por el Congreso de los Diputados, puede:', '["Oponer su veto al mismo", "Introducir enmiendas al mismo", "Oponer su veto o introducir enmiendas al mismo, mediante moción motivada", "Oponer su veto o introducir enmiendas al mismo, mediante mensaje motivado."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué plazo tiene el Senado para oponer su veto a proyectos de ley?:', '["Ninguno, porque no puede hacerlo", "Un mes", "Dos meses, a partir del día de la recepción del texto", "Dos meses, a partir del día de la aprobación del texto."]'::jsonb, 2, 'es');

  -- Batch 1801-2000
  insert into public.question_bank (content_hash, question, options, correct_index, lang)
  values
    ('4b830eab8fe6b21a82865850ecac45f6', 'El veto del Senado a los proyectos de ley deberá ser aprobado:', '["Por mayoría simple", "Por mayoría absoluta", "Por mayoría de dos tercios", "Ninguna de las contestaciones anteriores es correcta, pues el veto es improcedente."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En caso de veto del Senado, un proyecto de ley no podrá ser sometido al Rey para sanción sin que el Congreso ratifique el texto inicial:', '["Por mayoría simple", "Por mayoría absoluta", "Por mayoría de dos tercios", "Por mayoría de tres quintos."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Podrá el Congreso levantar por mayoría simple el veto del Senado a un proyecto de ley?:', '["No, pues deberá ser levantado por mayoría absoluta", "Sí, en cualquier momento", "Sí, una vez transcurrido un mes desde la interposición del mismo", "Sí, una vez transcurridos dos meses desde la interposición del mismo."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En caso que el Senado introduzca enmiendas en un proyecto de ley, ¿qué puede hacer sobre ellas el Congreso?:', '["Aceptarlas", "Pronunciarse sobre ellas", "Pronunciarse sobre ellas, aceptándolas o no por mayoría simple", "Pronunciarse sobre ellas, aceptándolas o no por mayoría absoluta."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿De qué plazo dispone el Senado para vetar o enmendar un proyecto de ley declarado urgente por el Gobierno o por el Congreso de los Diputados?:', '["Quince días", "Veinte días", "Un mes", "Dos meses."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Rey sancionará las leyes aprobadas por las Cortes Generales en el plazo de:', '["10 días", "15 días", "20 días", "Un mes."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Respecto de las leyes, ¿qué función no tiene el Rey?:', '["Las sanciona", "Las aprueba", "Las promulga", "Ordena su inmediata publicación."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las decisiones políticas de especial trascendencia podrán ser sometidas a:', '["Consulta popular", "Referéndum vinculante", "Referéndum vinculante de todos los votantes", "Referéndum consultivo de todos los ciudadanos."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién convoca un referéndum?', '["El Presidente del Congreso", "El Rey", "El Presidente del Gobierno", "El Congreso de los Diputado."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién propone la convocatoria de un referéndum?', '["El Presidente del Congreso", "El Rey", "El Presidente del Gobierno", "El Congreso de los Diputados."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién autoriza la convocatoria de un referéndum?', '["El Presidente del Congreso", "El Rey", "El Presidente del Gobierno", "El Congreso de los Diputados."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las condiciones y el procedimiento de las distintas modalidades de referéndum previstas en la Constitución se regula:', '["En la propia Constitución", "Por ley ordinaria", "Por ley orgánica", "Por reglamento."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Se podrá autorizar la celebración de tratados por los que se atribuya a una organización o institución internacional el ejercicio de competencias derivadas de la Constitución?', '["No, en ningún caso", "Sí, mediante reforma constitucional previa", "Sí, mediante ley orgánica", "Sí, mediante ley ordinaria."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿A quién corresponde la garantía del cumplimiento de los tratados y resoluciones emanadas de los organismos internacionales o supranacionales titulares de la cesión de competencias constitucionales?', '["A nadie, porque no es posible la cesión", "Al Congreso", "A las Cortes Generales", "A las Cortes Generales o al Gobierno, según los casos."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La prestación del consentimiento del Estado para obligarse por medio de tratados o convenios, ¿requerirá la previa autorización de las Cortes Generales?', '["No, nunca", "Sí, siempre", "Sí, en determinados casos", "Sí, si así lo reclama alguna de las Cámaras."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La prestación del consentimiento del Estado para obligarse por medio de tratados o convenios no requerirá la previa autorización de las Cortes Generales en el caso de:', '["Tratados de carácter político", "Tratados de carácter cultural", "Tratados de carácter militar", "Convenios de carácter militar."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'De la conclusión de los tratados o convenios que no requieran la previa autorización de las Cortes Generales, el Congreso y el Senado:', '["Serán informados", "Serán inmediatamente informados", "Tendrán que autorizarlos", "Tendrán que aprobarlos."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La celebración de un tratado internacional que contenga estipulaciones contrarias a la constitución:', '["Está prohibida", "Exigirá su adaptación a la Constitución", "Exigirá la previa revisión constitucional", "Exigirá la disolución de las Cámaras."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién puede declarar si un tratado internacional contiene estipulaciones contrarias a la Constitución?:', '["El Tribunal Supremo", "El Tribunal Constitucional", "El Congreso", "Las Cortes Generales."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién puede requerir la declaración de que un tratado internacional contiene estipulaciones contrarias a la Constitución?:', '["El Gobierno, exclusivamente", "El Gobierno o el Congreso", "El Gobierno o cualquiera de las Cámaras", "El Tribunal Constitucional."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los tratados internacionales, ¿formarán parte del ordenamiento interno?:', '["Sí, si han sido válidamente celebrados", "Sí, una vez publicados oficialmente en España", "Sí, una vez que sean ratificados por el Ministro de Asuntos Exteriores", "Son ciertas las respuestas a. y b."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las disposiciones de los tratados internacionales, ¿podrán ser derogadas, modificadas o suspendidas?:', '["No, nunca", "Sí, en la forma prevista en los propios tratados", "Sí, de acuerdo con las normas generales del Derecho internacional", "Son ciertas las respuestas b. y c."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué procedimiento se utilizará para la denuncia de los tratados y convenios internacionales?:', '["El que prevea el propio tratado o convenio", "El mismo que para su aprobación", "El que determinen las normas generales del Derecho Internacional", "El que se fije mediante ley orgánica."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'No dirige el Gobierno:', '["La política interior", "La política exterior", "La Administración civil", "Dirige todos los ámbitos anteriores."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'De acuerdo con la Constitución y las leyes, el Gobierno ejerce:', '["La función judicial", "La función ejecutiva", "La función ejecutiva y la potestad reglamentaria", "La función ejecutiva y la potestad legislativa."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Gobierno se compone:', '["De un Vicepresidente al menos", "De tres Vicepresidentes como máximo", "De los Vicepresidentes, en su caso", "De los Vicepresidentes, siempre."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién dirige la acción del Gobierno?:', '["Su Presidente", "Su Vicepresidente", "Todos sus miembros", "El Rey."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los miembros del Gobierno, ¿podrán ejercer otras funciones representativas?:', '["Sí, las que le asignen sus partidos políticos", "Sí, las que le asignen las Cortes Generales", "No, salvo que obtengan autorización de compatibilidad", "No, solamente ejercerán las propias del mandato parlamentario."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los miembros del Gobierno no podrán ejercer:', '["Otra función pública que no derive de su cargo", "Actividad profesional alguna", "Actividad mercantil alguna", "Ninguna de las actividades anteriores."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Respecto de los miembros del Gobierno, la ley regulará:', '["Su Estatuto", "Sus incompatibilidades", "Su Estatuto e incompatibilidades", "Ninguna de las materias anteriores, ya que se regularán por ley orgánica."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Rey propondrá un candidato a la Presidencia del Gobierno:', '["Directamente", "A través del Presidente del Congreso", "A través del Presidente del Congreso y del Senado", "A través de la Diputación Permanente del Congreso."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Rey propondrá un candidato a la Presidencia del Gobierno previa consulta con:', '["Los Diputados", "Los representantes designados por todos los Partidos políticos", "Los representantes designados por todos los Grupos políticos", "Los representantes designados por los grupos políticos con representación parlamentaria."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Rey propondrá un candidato a la Presidencia del Gobierno después de:', '["Cada renovación del Congreso de los Diputados", "En los demás supuestos constitucionales en que así proceda", "La celebración de elecciones generales, exclusivamente", "Son ciertas las respuestas a. y b."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El candidato propuesto para Presidente del Gobierno expondrá ante el Congreso de los Diputados:', '["El programa político del Gobierno que pretenda formar", "Las líneas generales de su actuación política", "El programa económico y social", "Su ideario político."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El candidato propuesto para Presidente del Gobierno solicitará al Congreso de los Diputados:', '["El apoyo de la Cámara", "La confianza de la Cámara", "El beneplácito de la Cámara", "La votación de la Cámara."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El candidato a Presidente del Gobierno será propuesto si obtiene el apoyo de:', '["La mayoría de las Cortes Generales", "La mayoría absoluta del Congreso de los Diputados", "La mayoría absoluta del Senado", "La mayoría del Congreso de los Diputados."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Presidente del Gobierno será nombrado por:', '["El Presidente del Congreso", "El Presidente de las Cortes Generales", "El Rey", "El Presidente del Senado."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Si el candidato a Presidente del Gobierno no obtiene la mayoría necesaria para su elección en la primera votación parlamentaria:', '["Se disolverán las Cortes Generales", "Se propondrá a otro candidato", "Se someterá la misma propuesta a nueva votación 48 horas después de la anterior", "Se someterá la misma propuesta a nueva votación 72 horas después de la anterior."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En la segunda votación parlamentaria a que se someta el candidato a Presidente del Gobierno la confianza se entenderá otorgada si obtuviera:', '["La mayoría de las Cortes Generales", "La mayoría absoluta del Congreso de los Diputados", "La mayoría absoluta del Senado", "La mayoría simple del Congreso de los Diputados."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Si efectuadas las votaciones previstas inicialmente al candidato a Presidente del Gobierno no se otorgase la confianza para la investidura:', '["Se disolverán las Cortes Generales", "Se propondrá a otro candidato", "Se someterá la misma propuesta a nueva votación 48 horas después", "Se tramitarán sucesivas propuestas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Si transcurrido el plazo correspondiente a partir de la primera votación de investidura ningún candidato a Presidente del Gobierno obtiene la confianza parlamentaria:', '["Se disolverán ambas Cámaras y se convocarán nuevas elecciones", "Se propondrá a otro candidato", "Se someterá la misma propuesta a nueva votación 48 horas después", "Se disolverá el Congreso."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué plazo existe a partir de la primera votación de investidura para que algún candidato a Presidente del Gobierno obtenga la confianza parlamentaria?:', '["Ninguno", "Un mes", "Dos meses", "Tres mese."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Si transcurrido el plazo correspondiente a partir de la primera votación de investidura ningún candidato obtiene la confianza Parlamentaria, ¿quién disolverá las Cortes Generales?:', '["Nadie, porque han de hacerse sucesivas propuestas", "El Presidente del Congreso", "El Presidente de las Cortes Generales", "El Rey, con el refrendo del Presidente del Congreso."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los demás miembros del Gobierno serán nombrados y separados por:', '["El Presidente del Gobierno", "El Rey, a propuesta de su Presidente", "El Rey, a propuesta del Presidente del Congreso", "El Rey, a iniciativa propia."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Gobierno no cesa:', '["Tras la celebración de procesos electorales", "Tras la celebración de elecciones generales", "En los casos de pérdida de la confianza parlamentaria", "Por dimisión o fallecimiento de su Presidente."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Gobierno cesante, ¿continuará en funciones?:', '["No", "Sí, durante dos meses como máximo", "Sí, hasta la toma de posesión del nuevo Gobierno", "Sí, hasta la celebración de elecciones."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La responsabilidad criminal del Presidente y los demás miembros del Gobierno será exigible, en su caso, ante:', '["La Audiencia Nacional", "El Consejo General del Poder Judicial", "El Tribunal Supremo", "La Sala de lo Penal del Tribunal Supremo."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Si se acusara al Presidente y los demás miembros del Gobierno por traición o por cualquier delito contra la seguridad del Estado en el ejercicio de sus funciones, sólo podrá ser planteada la acusación por iniciativa de:', '["La mayoría absoluta de los miembros del Congreso", "La mayoría de los miembros del Congreso", "La cuarta parte de los miembros del Congreso", "La cuarta parte de los miembros del Congreso y Senado."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Si se acusara al Presidente y los demás miembros del Gobierno por traición o por cualquier delito contra la seguridad del Estado en el ejercicio de sus funciones, sólo podrá ser planteada la acusación con la aprobación de:', '["La mayoría absoluta de los miembros del Congreso", "La mayoría de los miembros del Congreso", "La cuarta parte de los miembros del Congreso", "La cuarta parte de los miembros del Congreso y Senado."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La prerrogativa real de gracia, ¿será aplicable a los Casos de responsabilidad criminal del Presidente y los demás miembros del Gobierno?:', '["Sí", "No", "No, en el caso del Presidente del Gobierno", "Sí, previa autorización del Congreso."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Administración Pública sirve con objetividad:', '["Los intereses sociales", "Los intereses generales", "La actuación administrativa", "Los intereses sociales y generales."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Administración Pública actúa con sometimiento pleno:', '["A la ley", "A la ley y a los reglamentos", "A la ley y al Derecho", "A la ley y al Derecho Administrativo."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Administración Pública no actúa de acuerdo con el principio constitucional de:', '["Eficacia", "Jerarquía", "Eficiencia", "Actúa de acuerdo con todos los principios anteriores."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los órganos de la Administración del Estado son creados, regidos y coordinados de acuerdo con:', '["La ley", "La ley y los reglamentos", "La ley y el Derecho", "La ley y el Derecho Administrativo."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Constitución, la ley no regulará:', '["El estatuto de los funcionarios públicos", "El acceso a la función pública de acuerdo con los principios de mérito, capacidad y publicidad", "Las peculiaridades del ejercicio del derecho a sindicación de los funcionarios públicos", "Todas las contestaciones anteriores son correctas."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La ley regulará:', '["El acceso a la función pública de acuerdo con los principios de mérito y capacidad", "El sistema de incompatibilidades de los funcionarios públicos", "Las garantías para la imparcialidad en el ejercicio de las funciones de los funcionarios públicos", "Todas las contestaciones anteriores son correctas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Fuerzas y Cuerpos de seguridad estarán bajo la dependencia:', '["Del Gobierno", "De las Cortes Generales", "Del Congreso", "Del Estado Mayor."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Fuerzas y Cuerpos de seguridad no tendrán como misión:', '["Proteger el libre ejercicio de los derechos", "Proteger el libre ejercicio de libertades", "Garantizar la seguridad ciudadana", "Tendrán todas las misiones anteriores."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Fuerzas y Cuerpos de seguridad serán reguladas:', '["Mediante ley", "Mediante ley orgánica", "Mediante Decreto ‐ Ley", "Mediante Real Decreto."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La regulación de las Fuerzas y Cuerpos de seguridad determinará:', '["Sus funciones", "Los principios básicos de su actuación", "Sus estatutos", "Todas las contestaciones anteriores son correctas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La audiencia de los ciudadanos en el procedimiento de elaboración de las disposiciones administrativas que les afecten se efectuará:', '["Directamente", "A través de las organizaciones reconocidas por la ley", "A través de las asociaciones reconocidas por la ley", "Todas las contestaciones anteriores son correctas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Se facilitará el acceso de los ciudadanos a los archivos y registros administrativos salvo en lo que afecte a:', '["La seguridad y defensa del Estado", "La averiguación de los delitos", "La intimidad de las personas", "Todas las materias anteriores."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Constitución, el procedimiento a través del cual deben producirse los actos administrativos garantizará:', '["La defensa jurídica", "La audiencia del interesado, siempre", "La audiencia del interesado, cuando proceda", "La audiencia pública."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Respecto de la Administración, los Tribunales no controlan:', '["La potestad organizativa", "La potestad reglamentaria", "La legalidad de la actuación administrativa", "El sometimiento de la actuación administrativa a los fines que la justifican."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Constitución, ¿tendrán derecho los particulares a ser indemnizados por toda lesión que sufran a consecuencia del funcionamiento de los servicios públicos?:', '["Sí, en los términos establecidos por los reglamentos", "Sí, en cualquiera de sus bienes, excluidos sus derechos", "Sí, incluso en los casos de fuerza mayor", "Todas las anteriores son falsas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El supremo órgano consultivo del Gobierno es:', '["El Consejo Económico y Social", "El Consejo de Estado", "El Consejo del Gobierno", "El Consejo Consultivo del Gobierno."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Una ley orgánica regulará la composición y competencia:', '["Del Consejo Económico y Social", "Del Consejo de Estado", "Del Consejo del Gobierno", "Del Consejo Consultivo del Gobierno."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Gobierno responde parlamentariamente en su gestión política de forma:', '["Solidaria", "Mancomunada", "Individual", "Colegiada."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Gobierno responde parlamentariamente de su gestión política ante:', '["El Congreso de los Diputados", "El Senado", "Las Cortes Generales", "El Rey."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Cámaras y sus Comisiones podrán recabar la información y ayuda que precisen a través:', '["Del Presidente del Congreso", "Del Presidente del Senado", "De los Presidentes de las Cámaras", "Del Presidente del Gobierno."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Cámaras, ¿pueden reclamar la presencia de los miembros del Gobierno?:', '["No", "Sí, pero no sus Comisiones", "Sí, y también sus Comisiones", "No, pero sí sus Comisiones."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué facultades parlamentarias tienen los miembros del Gobierno?:', '["Tienen acceso a las sesiones de las Cámaras y a sus Comisiones", "Tienen la facultad de hacerse oír en ellas", "Podrán solicitar que informen ante las mismas funcionarios de sus Departamentos", "Todas las facultades anteriores."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién está sometido a las interpelaciones y preguntas que se le formulen en las Cámaras?:', '["El Presidente del Gobierno exclusivamente", "Los Ministros", "El Gobierno y cada uno de sus miembros", "El Presidente y el Vicepresidente del Gobierno."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Para interpelaciones y preguntas que se formulen en las Cámaras los Reglamentos establecerán un tiempo mínimo:', '["Semanal", "Quincenal", "Mensual", "Bimensual."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Toda interpelación parlamentaria podrá dar lugar a:', '["Una pregunta", "Una moción", "Una votación", "Una postulación."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Presidente del Gobierno puede plantear la cuestión de confianza ante:', '["El Congreso de los Diputados", "El Senado", "Las Cortes Generales", "El Rey."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Presidente del Gobierno puede plantear la cuestión de confianza:', '["A título personal", "Previa deliberación de la Mesa del Congreso", "Previa deliberación del Consejo de Ministros", "Previa decisión del Consejo de Ministros."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Presidente del Gobierno puede plantear la cuestión de confianza sobre:', '["Su gestión política", "Una decisión transcendental", "Una declaración de política general", "Una declaración programática."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Se entenderá otorgada la confianza parlamentaria al Presidente del Gobierno cuando vote a favor de la misma:', '["La mayoría simple de ambas Cámaras", "La mayoría simple de los Diputados", "La mayoría absoluta de ambas Cámaras", "La mayoría absoluta de los Diputados."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién puede exigir la responsabilidad política del Gobierno?:', '["El Congreso de los Diputados", "El Senado", "Las Cortes Generales", "El Rey."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cómo se puede exigir la responsabilidad política del Gobierno?:', '["Mediante el planteamiento de la cuestión de confianza", "Mediante la adopción de una moción", "Mediante una moción de censura", "Mediante la adopción de una reprobación parlamentaria."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Puede adoptarse una moción de censura parlamentaria?:', '["No, no está prevista en la Constitución", "Sí, por mayoría simple de las Cortes Generales", "Sí, por mayoría del Congreso de los Diputados", "Sí, por mayoría absoluta del Congreso de los Diputados."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Una moción de censura deberá ser propuesta por:', '["La cuarta parte de los Diputados como máximo", "La décima parte de los Diputados al menos", "La décima parte de Diputados y Senadores", "Ninguna respuesta es correcta, pues no puede plantearse tal moción."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La moción de censura habrá de incluir:', '["Una moción", "Un candidato a la Presidencia del Gobierno", "Una reprobación", "Una propuesta de disolución de las Cámaras."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Desde su presentación, una moción de censura no podrá ser votada hasta que transcurran:', '["2 días", "3 días", "4 días", "5 días."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Durante el plazo que transcurre entre la presentación de una moción de censura parlamentaria y su votación, ¿podrán presentarse mociones alternativas?:', '["No", "Sí, en cualquier día del mismo", "Sí, en los dos primeros días del plazo", "Sí, pero una vez que transcurra el plazo."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Si una moción de censura parlamentaria no fuera aprobada, ¿podrán presentar otra sus signatarios?:', '["Sí", "No, nunca", "No, durante el mismo período de sesiones", "No, durante la misma legislatura."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Si el Congreso niega su confianza al Gobierno:', '["Éste se someterá a una nueva moción de confianza", "Éste presentará su dimisión al Rey", "Éste presentará su dimisión ante las Cortes Generales", "Éste presentará su dimisión ante el propio Congreso."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Si el Congreso adopta una moción de censura, el Gobierno:', '["Se someterá a una moción de confianza", "Presentará su dimisión al Rey", "Presentará su dimisión ante las Cortes Generales", "Presentará su dimisión ante el propio Congreso."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Si el Congreso adopta una moción de censura, el candidato incluido en aquélla:', '["Presentará su programa de gobierno", "Se entenderá investido de la confianza de la Cámara", "Se someterá a una cuestión de confianza", "Requerirá la confianza de la Cámara."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Si el Congreso adopta una moción de censura, ¿qué hará el Rey con el candidato incluido en aquélla?:', '["Nada", "Lo propondrá para Presidente del Gobierno", "Lo nombrará Presidente del Gobierno", "Lo someterá a la confianza de la Cámara."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Presidente del Gobierno podrá proponer la disolución:', '["Del Congreso", "Del Senado", "De las Cortes Generales", "Todas las contestaciones anteriores son válidas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Presidente del Gobierno, ¿podrá proponer la disolución del Congreso, del Senado o de las Cortes Generales?:', '["No, solamente del Congreso", "Sí, previa deliberación del Consejo de Ministros", "Sí, mediante decisión propia", "Sí, autorizado por el Congreso."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién decretará la disolución del Congreso, del Senado o de las Cortes Generales?:', '["El Consejo de Ministros", "El Gobierno", "El Rey", "El Presidente del Gobierno."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El decreto de disolución del Congreso, del Senado o de las Cortes Generales:', '["No está previsto constitucionalmente", "Determinará la convocatoria de elecciones", "Fijará la fecha de las elecciones", "Autorizará la convocatoria de elecciones."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La propuesta de disolución del Congreso, del Senado o de las Cortes Generales no podrá presentarse:', '["Durante la vigencia del estado de alarma", "Cuando esté en trámite una moción de censura", "Cuando esté en trámite una cuestión de confianza", "Cuando esté en trámite una cuestión de censura."]'::jsonb, 1, 'es'),
    ('d8328ce402b7f69a855c4d8b91460daa', 'No procederá nueva disolución del Congreso, del Senado o de las Cortes Generales:', '["Antes de que transcurran seis meses desde la anterior", "Antes de que transcurra un año desde la anterior", "Antes de que transcurran dos años desde la anterior", "Antes de que transcurra un año desde la anterior, salvo el caso del artículo 99.5 de la Constitución."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los estados de alarma, de excepción y de sitio se regularán mediante:', '["Ley ordinaria", "Ley orgánica", "Decreto ‐ ley", "Decreto Legislativo."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El estado de alarma será declarado:', '["Por el Gobierno mediante Decreto acordado en Consejo de Ministros", "Por el Gobierno mediante Decreto acordado en Consejo de Ministros, previa autorización del Congreso de los Diputados", "Por la mayoría del Congreso de los Diputados", "Por la mayoría absoluta Del Congreso de los Diputados, a propuesta exclusiva del Gobierno."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El estado de excepción será declarado:', '["Por el Gobierno mediante Decreto acordado en Consejo de Ministros", "Por el Gobierno mediante Decreto acordado en Consejo de Ministros, previa autorización del Congreso de los Diputados", "Por la mayoría del Congreso de los Diputados", "Por la mayoría absoluta del Congreso de los Diputados, a propuesta exclusiva del Gobierno."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El estado de sitio será declarado:', '["Por el Gobierno mediante Decreto acordado en Consejo de Ministros", "Por el Gobierno mediante Decreto acordado en Consejo de Ministros, previa autorización del Congreso de los Diputados", "Por la mayoría del Congreso de los Diputados", "Por la mayoría absoluta del Congreso de los Diputados, a propuesta exclusiva del Gobierno."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Respecto del estado de alarma, es falso que:', '["Se declarará por un plazo máximo de veinte días", "Se dará cuenta del mismo al Congreso de los Diputados, reunido inmediatamente al efecto", "Sin la autorización del Congreso no podrá ser prorrogado su plazo", "El decreto que lo declare determinará el ámbito territorial a que se extienden sus efectos."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La duración del estado de excepción no podrá exceder de:', '["20, prorrogable por otros quince", "20 días prorrogables por otros veinte", "30 prorrogables por otro plazo no superior", "30 días prorrogables por otro plazo igual, con los mismos requisitos."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La autorización y proclamación del estado de excepción no deberá determinar expresamente:', '["Los efectos del mismo", "Su duración", "El ámbito territorial a que se extiende", "Todos los aspectos anteriores serán determinados."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La duración del estado de sitio:', '["Será determinado por el Congreso", "No podrá exceder de 20 días, prorrogable por otros quince", "No podrá exceder de 30 días", "No podrá exceder de 30 días, prorrogable por otro plazo igual."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Respecto del estado de sitio, el Congreso determinará:', '["Su ámbito territorial", "Su ámbito territorial y duración", "Su ámbito territorial, duración y condiciones", "Ninguna de las respuestas anteriores es correcta."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'No podrá procederse a la disolución del Congreso mientras esté declarado:', '["El estado de sitio", "El estado de excepción o sitio", "El estado de alarma, excepción o sitio", "El estado de guerra."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Si las Cámaras si no estuvieran en período de sesiones cuando se declare alguno de los estados de alarma, excepción o sitio, ¿qué ocurrirá?:', '["Nada", "Se disolverán", "Se convocarán elecciones inmediatamente", "Quedarán automáticamente convocadas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El funcionamiento de las Cámaras, ¿podrá interrumpirse durante la vigencia de los estados de alarma, excepción o sitio?:', '["Sí", "No, pero sí el de los demás poderes constitucionales del Estado", "No, ni el de los demás poderes constitucionales del Estado", "Depende de los términos de la declaración."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Disuelto el Congreso o expirado su mandato, si se produjera alguna de las situaciones que dan lugar a cualquiera de los estados de alarma, excepción o sitio, ¿qué ocurrirá?:', '["Parlamentariamente, nada", "Las competencias del Congreso serán asumidas por su Diputación Permanente", "Las competencias del Congreso serán asumidas por el Gobierno", "Las competencias del Congreso serán asumidas por la Mesa."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Constitución, la declaración de los Estados de alarma, de excepción y de sitio no modificarán el principio de responsabilidad:', '["Del Gobierno", "De los agentes del Gobierno", "Del Gobierno y de sus agentes", "Del Gobierno, de sus agentes y del poder judicial."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La justicia emana:', '["De las Cortes Generales", "Del pueblo", "Del Rey", "Del poder judicial."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La justicia se administra en nombre:', '["De las Cortes Generales", "Del pueblo", "Del Rey", "Del poder judicial."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La justicia se administra por:', '["Jueces", "Magistrados", "Jueces y Magistrados", "El poder judicial."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Respecto de Jueces y Magistrados, es cierto que son:', '["Integrantes del poder judicial", "Independientes", "Inamovibles", "Todas las respuestas anteriores son correctas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Respecto de Jueces y Magistrados, es falso que:', '["Son responsables", "Están sometidos únicamente al imperio de la ley", "Son inmunes", "Son inamovibles."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Sólo por alguna de las causas y con las garantías previstas en la ley los Jueces y Magistrados podrán ser:', '["Separados", "Separados o suspendidos", "Separados, suspendidos o trasladados", "Separados, suspendidos, trasladados o jubilados."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Corresponde exclusivamente a los Juzgados y Tribunales determinados por las leyes el ejercicio de:', '["La magistratura", "La acción judicial", "La potestad jurisdiccional en determinado tipo de procesos", "La potestad jurisdiccional en todo tipo de procesos."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los Juzgados y Tribunales:', '["Juzgan", "Juzgan y hacen ejecutar lo juzgado", "Encausan, juzgan y hacen ejecutar lo juzgado", "Encausan, procesan, juzgan y hacen ejecutar lo juzgado."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los Juzgados y Tribunales, ¿ejercerán más funciones que las señaladas en el apartado 117.3 de la Constitución?:', '["Sí", "No, salvo las jurisdiccionales", "No, salvo las que expresamente les sean atribuidas por la ley en garantía de cualquier derecho", "No, salvo las que le sean encomendadas directamente por las Cortes Generales."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La base de la organización y funcionamiento de los Tribunales es el principio de:', '["Independencia judicial", "Unidad jurisdiccional", "Inamovilidad", "Separación de poderes."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La ley regulará el ejercicio de la jurisdicción militar:', '["En el ámbito estrictamente castrense", "En los supuestos de estado de sitio", "De acuerdo con los principios de la Constitución", "Todas las anteriores son correctas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En el ámbito del poder judicial, la Constitución prohíbe los Tribunales:', '["Extraordinarios", "De excepción", "De Honor", "Sumarios."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué actos de Jueces y Tribunales es obligado cumplir?:', '["Las sentencias solamente", "Las sentencias y los autos", "Las sentencias y demás resoluciones firmes", "Las sentencias y las providencias."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Es obligado prestar la colaboración requerida por los Jueces y Tribunales:', '["En todo tipo de actuaciones judiciales", "En el curso del proceso", "En la ejecución de lo resuelto", "En el curso del proceso y en la ejecución de lo resuelto."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Será gratuita la justicia?:', '["No, nunca", "Sí, cuando así lo disponga la ley", "Sí, cuando así lo reconozcan los Jueces y Tribunales", "Sí, cuando así se solicite."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La justicia será gratuita en todo caso respecto de:', '["Quienes sean declarados pobres", "Los necesitados", "Quienes acrediten insuficiencia de recursos para litigar", "Quienes tengan rentas familiares inferiores al S.M.I."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Las actuaciones judiciales serán públicas?:', '["No, nunca", "Sí, siempre", "Sí, con las excepciones que prevean las leyes de procedimiento", "Sí, con las excepciones que declaren los Jueces y Tribunales."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El procedimiento judicial, ¿será oral?:', '["No, será preferentemente escrito", "Sí, sobre todo en materia civil", "Sí, predominantemente, sobre todo en materia criminal", "Sí, si así lo determinan los Jueces y Tribunales."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cómo serán las sentencias judiciales?:', '["Serán siempre orales", "Serán siempre motivadas", "Serán siempre motivadas y se pronunciarán en audiencia pública", "Serán siempre públicas."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Darán derecho a una indemnización:', '["Los daños causados por error judicial", "Los daños que sean consecuencia del funcionamiento anormal de la Administración de Justicia", "Los daños que sean consecuencia del funcionamiento normal de la Administración de Justicia", "Son ciertas las respuestas a. y b."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La indemnización por daños causados por error judicial correrán a cargo:', '["De quien los cause", "Del Ministerio de Justicia", "Del Estado", "Del Consejo General del Poder Judicial."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La ley orgánica del poder judicial determinará:', '["La constitución y funcionamiento de los Juzgados y Tribunales", "El estatuto jurídico de los Jueces y Magistrados de carrera", "El gobierno de los Juzgados y Tribunales", "Todas las contestaciones anteriores son correctas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Formarán un Cuerpo único:', '["Los Jueces", "Los Magistrados", "Los Jueces y Magistrados", "Los Jueces, Magistrados y Secretarios Judiciales."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El estatuto jurídico del personal al servicio de la Administración de Justicia estará determinado por:', '["Una ley específica", "La ley orgánica del poder judicial", "Un reglamento orgánico", "Un Real Decreto."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El órgano de gobierno del Poder Judicial es:', '["El Ministerio de Justicia", "La Comisión General del Poder Judicial", "El Consejo General del Poder Judicial", "El Gobierno."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La ley orgánica del Poder Judicial establecerá:', '["El estatuto de los miembros del Poder Judicial", "El régimen de incompatibilidades de los miembros del Poder Judicial", "Las funciones de los miembros del Poder Judicial", "Todas las contestaciones anteriores son correctas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Respecto del régimen de los miembros del poder judicial, la ley orgánica regulará en particular:', '["Los nombramientos", "Los nombramientos y ascensos", "Los nombramientos, ascensos e inspección", "Los nombramientos, ascensos, inspección y régimen disciplinario."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién será el Presidente del Consejo General del Poder Judicial?:', '["Uno de sus miembros", "El Presidente de la Audiencia Nacional", "El Presidente del Tribunal Supremo", "Quien designe el propio Consejo."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Consejo General del Poder Judicial estará integrado por:', '["El Presidente más veinte miembros", "Veinte miembros, incluido el Presidente", "El Presidente más doce miembros", "Quince miembros, incluido el Presidente."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién nombra a los miembros del Consejo General del Poder Judicial?:', '["El Congreso", "El Senado", "El Rey", "El Gobierno."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuánto dura el mandato de los miembros del Consejo General del Poder Judicial?:', '["Cuatro años", "Cinco años", "Seis años", "Tres años."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuántos miembros del Consejo General del Poder Judicial se nombran entre Jueces y Magistrados de todas las categorías judiciales?:', '["Ninguno", "10", "12", "8."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuántos miembros nombra el Congreso entre abogados y otros juristas para formar parte del Consejo General del Poder Judicial?:', '["Dos", "Tres", "Cuatro", "Cinco."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuántos miembros nombra el Senado entre abogados y otros juristas para formar parte del Consejo General del Poder Judicial?:', '["Dos", "Tres", "Cuatro", "Cinco."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué mayoría se exige al Congreso para designar a los miembros que formen parte del Consejo General del Poder Judicial entre abogados y otros juristas?:', '["Mayoría simple", "Mayoría absoluta", "Mayoría de dos tercios", "Mayoría de tres quintos."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué mayoría se exige al Senado para designar a los miembros que formen parte del Consejo General del Poder Judicial entre abogados y otros juristas?:', '["Mayoría simple", "Mayoría absoluta", "Mayoría de dos tercios", "Mayoría de tres quintos."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué requisitos deben cumplir los abogados y otros juristas que designe el Congreso y el Senado para formar parte del Consejo General del Poder Judicial?:', '["Deben ser de reconocido prestigio y con más de 10 años de ejercicio en su profesión", "Deben ser de reconocida competencia y con más de 10 años de ejercicio en su profesión", "Deben ser de reconocida competencia y con más de 15 años de ejercicio en su profesión", "Deben ser de reconocida fama y con más de 15 años de ejercicio en su profesión."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El órgano jurisdiccional superior en todos los órdenes (salvo lo dispuesto en materia de garantías constitucionales) es:', '["El Tribunal Constitucional", "El Tribunal Supremo", "La Audiencia Nacional", "El Consejo General del Poder Judicial."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Tribunal Supremo tiene jurisdicción:', '["En Madrid", "En toda la península", "En toda España", "En materia civil y penal exclusivamente."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Presidente del Tribunal Supremo será nombrado por:', '["El Congreso", "El Consejo General del Poder Judicial", "El Rey", "El Gobierno."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Presidente del Tribunal Supremo será nombrado a propuesta:', '["Del Congreso", "Del Consejo General del Poder Judicial", "Del Rey", "Del Gobierno."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Es competencia del Ministerio Fiscal promover la acción de la justicia en defensa:', '["De la legalidad", "De los derechos de los ciudadanos", "Del interés público tutelado por la ley", "Todas las respuestas anteriores son correctas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Es competencia del Ministerio Fiscal:', '["Velar por la independencia de los Tribunales", "Velar por la ejecución de sentencias", "Procurar ante los Tribunales la satisfacción del interés social", "Son ciertas las respuestas a. y c."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Ministerio Fiscal puede promover la acción de la justicia:', '["De oficio exclusivamente", "A petición de los interesados exclusivamente", "De oficio o a petición de los interesados", "De oficio, a petición de los interesados o por iniciativa judicial."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Ministerio Fiscal ejerce sus funciones por medio de:', '["Órganos propios", "Órganos judiciales", "Órganos administrativos", "Órganos ejecutivos."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Ministerio Fiscal ejerce sus funciones conforme a los principios de:', '["Nada, porque su regulación ha de ser mediante ley orgánica", "Su estructura", "Su estatuto orgánico", "Sus funciones."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Fiscal General del Estado será nombrado por:', '["El Congreso", "El Consejo General del Poder Judicial", "El Rey", "El Gobierno."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Fiscal General del Estado será nombrado a propuesta:', '["Del Congreso", "Del Consejo General del Poder Judicial", "Del Rey", "Del Gobierno."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Fiscal General del Estado será nombrado oído:', '["El Congreso", "El Consejo General del Poder Judicial", "El Rey", "El Gobierno."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Respecto de los procesos judiciales, los ciudadanos podrán ejercer:', '["La acción popular", "La acción pública", "La acusación particular", "La acusación pública."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los ciudadanos podrán participar en la Administración de Justicia mediante la institución:', '["De la acusación popular", "Del Jurado", "De los abogados y procuradores", "Del Ministerio Fiscal."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Podrán participar los ciudadanos en la Administración de Justicia mediante la institución del Jurado?:', '["No, en ningún caso", "Sí, en todo tipo de procesos", "Sí, en los procesos penales que la ley determine", "Sí, en los procesos civiles y penales que la ley determine."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Podrán participar los ciudadanos en algunos Tribunales de justicia?:', '["No, en ninguno de ellos", "Sí, en todos", "Sí, en los Tribunales consuetudinarios", "Sí, en los Tribunales consuetudinarios y tradicionales."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La policía judicial depende:', '["De los Jueces", "De los Tribunales", "Del Ministerio Fiscal", "Todas las respuestas anteriores son correctas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las funciones principales de la policía judicial son:', '["La averiguación del delito", "El aseguramiento del delincuente", "La reparación del daño causado", "Son ciertas las respuestas a. y b."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'No podrán desempeñar otros cargos públicos:', '["Los Jueces", "Los Jueces y Magistrados", "Los Jueces, Magistrados y Fiscales", "Los Jueces y Magistrados, así como los Fiscales mientras se hallen en activo."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'No podrán pertenecer a partidos políticos o sindicatos:', '["Los Jueces", "Los Jueces y Magistrados", "Los Jueces, Magistrados y Fiscales", "Los Jueces y Magistrados, así como los Fiscales mientras se hallen en activo."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La ley establecerá el sistema y modalidades de asociación profesional de:', '["Los Jueces", "Los Jueces y Magistrados", "Los Jueces, Magistrados y Fiscales", "Los Jueces y Magistrados, así como los Fiscales mientras se hallen en activo."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El régimen de incompatibilidades de los miembros del poder judicial se establecerá:', '["Por ley", "Por ley orgánica", "Por ley de bases", "Por Decreto ‐ Ley."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Constitución, toda la riqueza del país en sus distintas formas y sea cual sea su titularidad está subordinada:', '["Al interés general", "Al interés social", "Al desarrollo nacional", "A la prosperidad nacional."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En la actividad económica se reconoce la iniciativa:', '["General", "Ciudadana", "Pública", "Privada."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Constitución, ¿se podrá reservar al sector público recursos o servicios esenciales?:', '["No, en ningún caso", "Sí, mediante ley", "Sí, mediante ley, especialmente en caso de monopolio", "Sí, mediante ley orgánica, especialmente en caso de crisis económica."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Constitución, ¿se podrá acordar la intervención de empresas?:', '["No, en ningún caso", "Sí, mediante ley, cuando así lo exija el interés general", "Sí, mediante ley, en cualquier caso", "Sí, mediante ley orgánica, especialmente en caso de crisis económica."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Constitución, las formas de participación de los interesados en la Seguridad Social se establecerá:', '["Por el Gobierno", "Por ley", "Por ley orgánica", "Por Real Decreto."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Podrán participar los interesados en la actividad de los organismos públicos?:', '["No", "Sí, en aquéllos cuya función afecte directamente a la calidad de la vida", "Sí, en aquéllos cuya función afecte directamente al bienestar general", "Son ciertas las contestaciones b. y c."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los poderes públicos:', '["Promoverán eficazmente las diversas formas de participación en la empresa", "Fomentarán mediante una legislación adecuada las sociedades cooperativas", "Establecerán los medios que faciliten el acceso de los trabajadores a la propiedad de los medios de producción", "Todas las anteriores son correctas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los poderes públicos atenderán a la modernización y desarrollo de todos los sectores económicos, y en particular:', '["De la agricultura", "De la agricultura y de la ganadería", "De la agricultura, de la ganadería y de la pesca", "De la agricultura, de la ganadería, de la pesca y de la artesanía."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los poderes públicos atenderán a la modernización y desarrollo de todos los sectores económicos a fin de:', '["Mejorar el nivel de vida de todos los españoles", "Equiparar el nivel de vida de todos los españoles", "Mejorar la productividad nacional", "Mejorar la competitividad empresarial."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Respecto de la modernización y desarrollo de todos los sectores económicos, se dispensará un tratamiento especial a las zonas:', '["Francas", "Deprimidas", "Subdesarrolladas", "De montaña."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Estado, mediante ley, podrá:', '["Planificar la actividad económica general para atender a las necesidades colectivas", "Equilibrar y armonizar el desarrollo regional y sectorial", "Estimular el crecimiento de la renta y de la riqueza, y su más justa distribución", "Todas las contestaciones anteriores son correctas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién elaborará los proyectos de planificación económica?:', '["Las Cortes Generales", "El Gobierno", "El Ministerio de Economía", "La Secretaría de Estado de Economía."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los proyectos de planificación económica se elaborarán:', '["De acuerdo con las previsiones que sean suministradas por las Comunidades Autónomas", "Con el asesoramiento y colaboración de los sindicatos", "Con el asesoramiento y colaboración de otras organizaciones profesionales, empresariales y económicas", "Todas las contestaciones anteriores son correctas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El régimen jurídico de los bienes de dominio público y de los comunales se regulará:', '["Por ley", "Por ley orgánica", "Por Decreto ‐ Ley", "Por Real Decreto."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La desafectación de los bienes de dominio público y de los comunales se regulará:', '["Por ley", "Por ley orgánica", "Por Decreto ‐ Ley", "Por Real Decreto."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La regulación del régimen jurídico de los bienes de dominio público y de los comunales se inspirará en los principios de:', '["Intangibilidad, incompatibilidad e inembargabilidad", "Inalienabilidad, imprescriptibilidad e inembargabilidad", "Inalienabilidad, imprescriptibilidad e intangibilidad", "Desafectación, imprescriptibilidad y uso público."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'No es un bien de dominio público estatal en todo caso:', '["La zona marítimo ‐ terrestre", "Las playas", "El mar territorial", "El espacio exterior."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Es un bien de dominio público estatal en todo caso:', '["Los recursos naturales de la zona económica", "Los recursos económicos nacionales", "La plataforma continental", "Son ciertas las contestaciones a. y c."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Respecto del Patrimonio del Estado y el Patrimonio Nacional, la ley regulará:', '["Su administración", "Su administración y defensa", "Su administración, defensa y conservación", "Su administración, defensa, conservación y restauración."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La potestad originaria para establecer los tributos corresponde exclusivamente:', '["A las Cortes Generales, mediante ley orgánica", "Al Gobierno, mediante ley", "Al Estado, mediante ley", "Al Gobierno, mediante reglamentos."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Comunidades Autónomas y las Corporaciones locales, ¿podrán establecer y exigir tributos?:', '["No", "Solamente podrán administrar los estatales", "Sí, de acuerdo con sus Estatutos", "Sí, de acuerdo con la Constitución y las leyes."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Todo beneficio fiscal que afecte a los tributos del Estado deberá establecerse en virtud de:', '["Acuerdo", "Ley", "Ley orgánica", "Pacto."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las administraciones públicas sólo podrán contraer obligaciones financieras y realizar gastos de acuerdo con:', '["Los principios de política fiscal", "Las leyes", "Los Presupuestos Generales del Estado", "La situación económica."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿A quién corresponde la elaboración de los Presupuestos Generales del Estado?:', '["Al Gobierno", "Al Congreso", "Al Senado", "A las Cortes Generales."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿A quién corresponde el examen, enmienda y aprobación de los Presupuestos Generales del Estado?:', '["Al Gobierno", "Al Congreso", "Al Senado", "A las Cortes Generales."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los Presupuestos Generales del Estado tendrán carácter:', '["Semestral", "Anual", "Periódico", "Bianual."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los Presupuestos Generales del Estado incluirán la totalidad de los gastos e ingresos del:', '["Sector público estatal", "Sector público general", "Sector público estatal y autonómico", "Ámbito público."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En los Presupuestos Generales del Estado se consignará el importe de los beneficios fiscales que afecten a:', '["Los españoles", "Los tributos del Estado", "Los impuestos generales", "Los impuestos estatales y autonómicos."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Ante quién debe presentar el Gobierno los Presupuestos del Estado?:', '["Ante el Consejo de Ministros", "Ante el Congreso de los Diputados", "Ante el Senado", "Ante las Cortes Generales."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Con qué antelación debe presentar el Gobierno ante El Congreso de los Diputados los Presupuestos Generales del Estado?:', '["Al menos 2 meses antes de la expiración de los del año anterior", "Al menos 3 meses antes de la expiración de los del año anterior", "Al menos 3 meses antes del 1 de enero siguiente", "Ninguna de las anteriores es correcta."]'::jsonb, 1, 'es');

  -- Batch 2001-2200
  insert into public.question_bank (content_hash, question, options, correct_index, lang)
  values
    ('4b830eab8fe6b21a82865850ecac45f6', 'Si la Ley de Presupuestos no se aprobara antes del primer día del ejercicio económico correspondiente, ¿qué ocurrirá?:', '["Se suspenderán los ingresos y pagos del Estado", "Se considerarán automáticamente prorrogados los Presupuestos del ejercicio anterior hasta la aprobación de los nuevos", "Se considerarán indefinidamente prorrogados los Presupuestos del ejercicio anterior", "Se considerarán automáticamente prorrogados los Presupuestos del ejercicio anterior hasta el 31 de diciembre siguiente."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Aprobados los Presupuestos Generales del Estado, ¿podrá el Gobierno presentar proyectos de ley que impliquen aumento del gasto público o disminución de los ingresos?:', '["No, en ningún caso", "Sí, siempre que correspondan al mismo ejercicio presupuestario", "Sí, en cualquier caso", "Sí, con autorización de las Cortes Generale."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Toda proposición o enmienda que suponga aumento de los créditos o disminución de los ingresos presupuestarios:', '["Será rechazada", "Tendrá tramitación preferente", "Requerirá la conformidad del Gobierno para su tramitación", "Requerirá la conformidad del Congreso para su tramitación."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Ley de Presupuestos, ¿puede crear tributos?:', '["No, ni modificarlos", "Sí, con la conformidad del Gobierno", "No, pero podrá modificarlos cuando una ley tributaria sustantiva así lo prevea", "No, pero podrá modificarlos cuando cualquier ley así lo prevea."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Todas las Administraciones Públicas adecuarán sus actuaciones al principio de:', '["Estabilidad presupuestaria", "Equilibrio", "Economía", "Eficacia."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Estado y las Comunidades Autónomas no podrán incurrir en un déficit estructural que supere los márgenes establecidos:', '["Por los Presupuestos Generales del Estado", "Por el Fondo Monetario Internacional", "Por el Banco Central Europeo", "Por la Unión Europea para sus Estados Miembros, en su caso."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Dónde se fijará el déficit estructural máximo permitido al Estado y a las Comunidades Autónomas?:', '["En una Ley Orgánica", "En una Ley ordinaria", "En los Presupuestos Generales del Estado", "En una Ley Marco de Financiación."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El déficit estructural máximo permitido al Estado y a las Comunidades Autónomas se fijará en relación con:', '["Sus ingresos", "Su déficit público", "Su producto interior bruto", "Su producto interior neto."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Entidades Locales deberán presentar:', '["Equilibrio financiero", "Equilibrio presupuestario", "Equilibrio recaudatorio", "Equilibrio fiscal."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Estado y las Comunidades Autónomas habrán de estar autorizados por ley:', '["Para emitir deuda pública", "Para emitir bonos", "Para emitir contraer crédito", "Son ciertas las contestaciones a. y c."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los créditos para satisfacer los intereses y el capital de la deuda pública de las Administraciones se entenderán siempre incluidos:', '["En el estado de cuentas de sus presupuestos", "En el estado de gastos de sus presupuestos", "En el estado de ingresos y gastos de sus presupuestos", "En los gastos plurianuales."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El pago de los créditos para satisfacer los intereses y el capital de la deuda pública de las Administraciones gozará:', '["De prioridad absoluta", "De exenciones fiscales", "De beneficios fiscales", "De preferencia fiscal."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los créditos para satisfacer los intereses y el capital de La deuda pública de las Administraciones, ¿podrán ser objeto de enmienda o modificación?:', '["Sí, conforme a lo establecido en la Ley General Presupuestaria", "No, en ningún caso", "No, mientras se ajusten a las condiciones de la ley de emisión", "Sí, por mayoría absoluta del Congreso de los Diputados."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El volumen de deuda pública del conjunto de las Administraciones Públicas en relación con el producto interior bruto del Estado no podrá superar el valor de referencia establecido en:', '["La Ley Orgánica que se dicte al efecto", "El Tratado de Funcionamiento de la Unión Europea", "Las Leyes Generales de Presupuestos que se dicten cada año", "Las leyes."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los límites de déficit estructural y de volumen de deuda pública sólo podrán superarse en caso de:', '["Catástrofes naturales", "Catástrofes naturales o recesión económica", "Catástrofes naturales, recesión económica o situaciones de emergencia extraordinaria", "Catástrofes naturales, recesión económica, situaciones de emergencia extraordinaria o coyunturas internacionales desfavorables."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las circunstancias para superar los límites de déficit Estructural y de volumen de deuda pública serán apreciadas:', '["Por el Gobierno", "Por la mayoría absoluta de los miembros del Congreso de los Diputados", "Por el Parlamento Europeo", "Por la mayoría absoluta de las Cortes Generales."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Una Ley Orgánica desarrollará la participación, en los procedimientos respectivos, de los órganos de coordinación institucional entre las Administraciones Públicas en materia de:', '["Política fiscal y financiera", "Política económica", "Endeudamiento público", "Fiscalidad, tributación y recaudación."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Mediante Ley Orgánica se regulará:', '["La distribución de los límites de déficit y de deuda del Estado", "La distribución de los límites de déficit y de deuda entre las distintas Administraciones y los supuestos excepcionales de endeudamiento", "La distribución de los límites de déficit y de deuda entre las distintas Administraciones Públicas, los supuestos excepcionales de superación de los mismos y la forma y plazo de corrección de las desviaciones que sobre uno y otro pudieran producirse", "La distribución de los límites de déficit y de deuda del Estado, los supuestos excepcionales de superación de los mismos y la forma y plazo de emisión de deuda pública."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Mediante Ley Orgánica se regulará la responsabilidad de cada Administración Pública en caso de incumplimiento de:', '["Los plazos de pagos de la deuda pública", "Los objetivos de estabilidad presupuestaria", "Los objetivos de estabilidad financiera", "Los objetivos de déficit público."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Comunidades Autónomas adoptarán las disposiciones que procedan para la aplicación efectiva del principio de estabilidad:', '["En sus normas presupuestarias", "En sus presupuestarias", "En sus normas y decisiones presupuestarias", "En sus leyes."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Comunidades Autónomas adoptarán las disposiciones que procedan para la aplicación efectiva del principio de estabilidad de acuerdo con:', '["Sus respectivos Estatutos", "El Estado", "Las leyes estatales de presupuestos", "Los criterios generales que dicte la Unión Europea."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Tribunal de Cuentas es el supremo órgano fiscalizador:', '["De las cuentas del Estado", "De las cuentas y de la gestión económica del Estado", "De las cuentas y de la gestión económica y presupuestaria del Estado", "De las cuentas y de la gestión económica del Estado, así como del sector público."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Tribunal de Cuentas dependerá directamente:', '["Del Gobierno", "Del Congreso", "Del Senado", "De las Cortes Generales."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Tribunal de Cuentas ejercerá sus funciones en el examen y comprobación de la Cuenta General del Estado por delegación:', '["Del Gobierno", "Del Congreso", "Del Senado", "De las Cortes Generales."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Se rendirán al Tribunal de Cuentas y serán censuradas por éste las Cuentas:', '["Del Estado", "Del sector público estatal", "Del Estado y del sector público estatal", "Del Estado y del sector público estatal e institucional."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Tribunal de Cuentas remitirá a las Cortes Generales un informe:', '["Trimestral", "Semestral", "Anual", "Periódico."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En su informe remitido a las Cortes Generales, el Tribunal de Cuentas comunicará cuando proceda:', '["Las infracciones que, a su juicio, se hubieran cometido", "Las responsabilidades en que, a su juicio, se hubiera incurrido", "Las infracciones o responsabilidades en que, a su juicio, se hubiera incurrido", "Las sanciones que correspondan por las infracciones o responsabilidades contables."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los miembros del Tribunal de Cuentas gozarán de la misma independencia e inamovilidad y estarán sometidos a las mismas incompatibilidades que:', '["Los Jueces", "Los Magistrados", "Los Jueces y Magistrados", "Los Jueces, Magistrados y Fiscales."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La composición, organización y funciones del Tribunal de Cuentas se regulará mediante:', '["Ley", "Ley orgánica", "Decreto ‐ Ley", "Ley de bases."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cómo se organiza territorialmente el Estado?:', '["En municipios y en provincias", "En municipios, en partidos judiciales y en provincias", "En municipios y en Comunidades Autónomas", "En municipios, en provincias y en las Comunidades Autónomas que se constituyan."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Todas las entidades en que el Estado se organiza territorialmente gozan de:', '["Autodeterminación", "Entidad jurídica y política", "Autonomía para el establecimiento de sus presupuestos", "Autonomía para la gestión de sus respectivos intereses."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Respecto de su organización territorial, el Estado garantiza la realización efectiva del principio de:', '["Solidaridad", "Autonomía", "Autonomía financiera", "Corresponsabilidad."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Estado vela por el establecimiento entre las diversas partes del territorio español de un equilibrio:', '["Económico", "Económico y adecuado", "Económico, adecuado y justo", "Económico, adecuado, justo y pleno."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Estado vela por el establecimiento entre las diversas partes del territorio español de un equilibrio atendiendo en particular a las circunstancias:', '["Excepcionales", "Del hecho insular", "Del hecho peninsular", "Del hecho autonómico."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las diferencias entre los Estatutos de las distintas Comunidades Autónomas no podrán implicar en ningún caso:', '["Diferencias", "Privilegios económicos", "Privilegios sociales", "Privilegios económicos o sociales."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Todos los españoles tienen los mismos derechos y obligaciones:', '["En todo momento", "En su localidad de residencia", "En cualquier parte del territorio del Estado", "En su localidad de nacimiento."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Ninguna autoridad podrá adoptar medidas que directa o indirectamente obstaculicen:', '["La libertad de circulación de las personas", "La libertad de establecimiento de las personas", "La libre circulación de bienes en todo el territorio español", "Todas las anteriores son correctas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Constitución garantiza la autonomía de:', '["Los municipios", "La provincia", "Los partidos judiciales", "Las comarcas."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El gobierno y administración de los municipios corresponde a:', '["Sus Alcaldes", "Sus Concejales", "Sus respectivos Ayuntamientos", "Sus consistorios."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los Ayuntamientos están integrados por:', '["Los Alcaldes", "Los Concejales", "Los Alcaldes y los Concejales", "Los Alcaldes, los Concejales y los Secretarios."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los Alcaldes son elegidos por:', '["Los nacidos en el municipio", "Los vecinos del municipio", "Los residentes y transeúntes del municipio", "Ninguna de las contestaciones anteriores es correcta."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los Concejales serán elegidos por los vecinos del municipio mediante sufragio:', '["Universal, libre, directo y secreto", "Universal, igual, directo y secreto", "Universal, igual, libre y directo", "Universal, igual, libre, directo y secreto."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los Alcaldes serán elegidos:', '["Por los Concejales siempre", "Por los vecinos siempre", "Por los Concejales o por los vecinos", "Por los Concejales, por los vecinos o por los residentes."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Existirá en la Administración Local el régimen del concejo abierto?:', '["No, ha sido suprimido por la Constitución", "No, fue suprimido por la Ley de Bases del Régimen Local", "Sí, en todos los municipios", "Sí, la ley regulará las condiciones en las que proceda."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La provincia es una entidad local con:', '["Personalidad jurídica única", "Personalidad jurídica plena", "Personalidad jurídica propia", "Personalidad administrativa."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La provincia está determinada por la agrupación de:', '["Comarcas", "Partidos judiciales", "Municipios", "Mancomunidades."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La provincia forma parte de la división territorial para el cumplimiento de:', '["Las actividades del Estado", "Las acciones de gobierno", "Un interés social", "Una finalidad pública."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Cualquier alteración de los límites provinciales habrá de ser aprobada por:', '["El Congreso", "El Senado", "Las Cortes Generales", "El Gobierno."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Cualquier alteración de los límites provinciales habrá de ser aprobada mediante:', '["Ley", "Ley orgánica", "Ley de bases", "Ley marco."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El gobierno y la administración autónoma de las provincias estarán encomendados a:', '["Diputaciones exclusivamente", "Corporaciones de carácter representativo", "Diputaciones u otras Corporaciones de carácter representativo", "Diputaciones, Corporaciones y Cámaras Municipales."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Se podrán crear agrupaciones de municipios diferentes de la provincia?:', '["Sí", "No", "Sí, mediante ley orgánica", "No, excepto si se contempla en los Estatutos de Autonomía."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En los archipiélagos, las islas tendrán su administración propia en forma de:', '["Cabildos", "Consejos", "Cabildos o Consejos", "Cabildos, Consejos o Cámaras insulares."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Haciendas locales deberán disponer de los medios suficientes para el desempeño de las funciones que la ley atribuye a:', '["Los Ayuntamientos", "Las Diputaciones", "Las Corporaciones respectivas", "Los Municipios."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Haciendas locales se nutrirán fundamentalmente de:', '["Tributos propios", "Participación en los tributos del Estado", "Participación en los tributos de las Comunidades Autónomas", "Todas las anteriores son correctas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Podrán acceder a su autogobierno y constituirse en Comunidades Autónomas las provincias limítrofes con características:', '["Históricas comunes", "Históricas y culturales comunes", "Históricas, culturales y económicas comunes", "Históricas, culturales, sociales y económicas comunes."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Podrán acceder a su autogobierno y constituirse en Comunidades Autónomas los territorios:', '["Especiales", "Insulares", "Peninsulares", "De montaña."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Podrán acceder a su autogobierno y constituirse en Comunidades Autónomas las provincias:', '["Con autogobierno", "Con entidad regional probada", "Con entidad regional histórica", "Con entidad propia."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La iniciativa del proceso autonómico corresponde:', '["A todas las Diputaciones interesadas", "Al órgano interinsular correspondiente", "A las dos terceras partes de los municipios cuya población represente, al menos, la mayoría del censo electoral de cada provincia o isla", "Todas las anteriores son correctas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los requisitos para la iniciativa del proceso autonómico deberán ser cumplidos, desde el primer acuerdo adoptado al respecto por alguna de las Corporaciones locales interesadas, en el plazo de:', '["Tres meses", "Cuatro meses", "Seis meses", "Nueve meses."]'::jsonb, 2, 'es'),
    ('44cc9e46336e3d76940017f17f9a8879', 'En caso de no prosperar La iniciativa del proceso autonómico prevista en el artículo 143 de la Constitución, solamente podrá reiterarse pasados:', '["Dos años", "Tres años", "Cuatro años", "Cinco años."]'::jsonb, 3, 'es'),
    ('44cc9e46336e3d76940017f17f9a8879', 'Las Cortes Generales, mediante ley orgánica, podrán, por motivos de interés nacional:', '["Autorizar la constitución de una comunidad autónoma cuando su ámbito territorial no supere el de una provincia y no reúna las condiciones del apartado 1 del artículo 143", "Autorizar o acordar, en su caso, un Estatuto de autonomía para territorios que no estén integrados en la organización provincial", "Sustituir la iniciativa de las Corporaciones locales a que se refiere el artículo 143.2", "Todas las anteriores son correctas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Se admitirá la federación de Comunidades Autónomas?:', '["Sí, por motivos de interés nacional", "En ningún caso", "Sí, mediante ley orgánica", "Sí, mediante referéndum."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Podrán las Comunidades Autónomas celebrar convenios entre sí?:', '["No", "Sí, para la gestión de servicios nacionales", "Sí, para la gestión y prestación de servicios propios de las mismas", "Sí, por razones de interés nacional."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Respecto delos convenios que celebren las Comunidades Autónomas entre sí, los Estatutos de Autonomía:', '["No podrán regular nada", "Deberán regularlos detalladamente", "Podrán prever sus supuestos, requisitos y términos", "Deberán remitirse a la Constitución."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los convenios que celebren las Comunidades Autónomas entre sí deberán comunicarse:', '["Al Congreso", "Al Senado", "A las Cortes Generales", "Al Gobierno."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En los demás supuestos no previstos en la Constitución, los acuerdos de cooperación entre las Comunidades Autónomas:', '["Estarán prohibidos", "Necesitarán la autorización del Congreso", "Necesitarán la autorización del Senado", "Necesitarán la autorización de las Cortes Generales."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El proyecto de Estatuto de Autonomía será elaborado por una asamblea compuesta por:', '["Los miembros de la Diputación u órgano interinsular de las provincias afectadas", "Los Diputados y Senadores elegidos en las provincias afectadas", "Los representantes designados por la población", "Son ciertas las respuestas a. y b."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Una vez elaborado, el Proyecto de Estatuto de Autonomía será elevado:', '["Al Congreso, para su consideración", "Al Senado", "A las Cortes Generales, para su tramitación como ley", "Al Gobierno, para su tramitación como proyecto de ley."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es la norma institucional básica de cada Comunidad Autónoma?:', '["La Constitución", "Su Estatuto de Autonomía", "Las leyes de régimen local", "Las leyes estatales."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Respecto delos Estatutos decada Comunidad Autónoma, el Estado:', '["Los ratificará", "Los protegerá", "Los reconocerá y amparará", "Los reconocerá y amparará como parte integrante de su ordenamiento jurídico."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los Estatutos de autonomía deberán contener:', '["La designación de la Comunidad", "La denominación de la Comunidad que se elija", "La denominación de la Comunidad que mejor corresponda a su identidad histórica", "La denominación de la Comunidad que mejor corresponda a su identidad social."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los Estatutos de autonomía deberán contener las competencias asumidas dentro del marco establecido:', '["En las leyes", "En la Constitución", "En las bases para el traspaso de los servicios correspondientes a las mismas", "Son ciertas las respuestas b. y c."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La reforma de los Estatutos se ajustará al procedimiento establecido en:', '["Los mismos", "La Constitución", "Las leyes", "El Reglamento de la Asamblea Legislativa correspondiente."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La reforma de los Estatutos requerirá, en todo caso, la aprobación por:', '["El Congreso, mediante ley", "El Senado", "Las Cortes Generales, mediante ley orgánica", "El Gobierno, mediante Decreto ‐ Ley."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Comunidades Autónomas podrán                      asumir competencias sobre:', '["Relaciones internacionales", "Administración de Justicia", "Organización de sus instituciones de autogobierno", "Defensa y Fuerzas Armadas."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Comunidades Autónomas podrán asumir competencias sobre los proyectos, construcción y explotación de:', '["Los aprovechamientos hidráulicos de interés de la Comunidad Autónoma", "Los canales de interés de la Comunidad Autónoma", "Los regadíos de interés de la Comunidad Autónoma", "Todas las contestaciones anteriores son correctas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Comunidades Autónomas no podrán asumir competencias sobre:', '["Caza", "Pesca fluvial", "Ferias interiores", "Podrán asumir competencias sobre todas las materias anteriores."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Comunidades Autónomas podrán asumir competencias sobre el fomento del desarrollo económico de las mismas dentro de:', '["La política económica del Gobierno", "Los objetivos marcados por la política económica nacional", "Las prioridades económicas de la Administración General", "Su propia planificación económica."]'::jsonb, 1, 'es'),
    ('88f687385bed79ed556d261e5b494cb7', '¿Podrán las Comunidades Autónomas ampliar sucesivamente sus competencias dentro del marco establecido en el artículo 149 de la Constitución?:', '["No, en ningún caso", "Sí, transcurridos tres años", "Sí, transcurridos cinco años", "Sí, transcurridos cuatro años."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Estado no tiene competencia exclusiva sobre:', '["Nacionalidad", "Inmigración", "Emigración", "Tiene competencia exclusiva sobre todas las materias anteriores."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La regulación de las condiciones básicas que garanticen la igualdad de todos los españoles en el ejercicio delos derechos y en el cumplimiento de los deberes constitucionales es una competencia:', '["Exclusiva de las Comunidades Autónomas", "Exclusiva del Estado", "Compartida por el Estado y las Comunidades Autónomas", "Concurrente entre el Estado y las Comunidades Autónomas."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Estado tiene competencia exclusiva sobre:', '["Administración de Justicia", "Urbanismo", "Ordenación del territorio", "Vivienda."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Tiene competencia exclusiva el Estado sobre legislación procesal?:', '["Sí, en todos sus aspectos", "No, es una competencia compartida con las Comunidades Autónomas", "Sí, sin perjuicio de las especialidades que se deriven de las particularidades del derecho sustantivo de las Comunidades Autónomas", "Ninguna de las respuestas anteriores es correcta."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Tiene competencia exclusiva el Estado sobre legislación laboral?:', '["Sí, en todos sus aspectos", "No, es una competencia compartida con las Comunidades Autónomas", "Sí, sin perjuicio de su ejecución por los órganos de las Comunidades Autónomas", "Sí, sin perjuicio de su regulación por los órganos de las Comunidades Autónomas."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La autorización para la convocatoria de consultas populares por vía de referéndum es una competencia:', '["Exclusiva de las Comunidades Autónomas", "Exclusiva del Estado", "Compartida por el Estado y las Comunidades Autónomas", "Concurrente entre el Estado y las Comunidades Autónomas."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En legislación civil, es competencia exclusiva del Estado en todo caso:', '["Las reglas relativas a la aplicación y eficacia de las normas jurídicas", "Relaciones jurídico ‐ civiles relativas a las formas de matrimonio", "Ordenación de los registros e instrumentos públicos,", "Todas las respuestas anteriores son correctas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Respecto del sistema monetario, no es competencia exclusiva del Estado las materias de:', '["Divisas", "Cambio", "Convertibilidad", "Todas las materias anteriores son competencia del Estado."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Respecto de la actividad económica, ¿tiene el Estado competencia exclusiva?:', '["No, pertenece a las Comunidades Autónomas", "No, tiene competencias compartidas con las Comunidades Autónomas", "Sí, sobre sus bases y coordinación", "Sí, sobre las bases y coordinación de la planificación general."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En materia de Seguridad Social, ¿tiene el Estado competencia exclusiva?:', '["No, pertenece a las Comunidades Autónomas", "No, tiene competencias compartidas con las Comunidades Autónomas", "Sí, sobre legislación básica y régimen económico, sin perjuicio de la ejecución de sus servicios por las Comunidades Autónomas", "Sí, sobre legislación básica exclusivamente."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La legislación civil es competencia exclusive del Estado, sin perjuicio de la conservación, modificación y Desarrollo por las CC.AA. de los derechos:', '["Civiles", "Civiles o forales", "Civiles, forales o especiales", "Civiles, forales o especiales, allí donde existan."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En materia de Administración Pública, el Estado tiene competencia exclusiva sobre:', '["Las bases del régimen jurídico de las Administraciones Públicas y del régimen estatutario de sus funcionarios", "Legislación básica sobre contratos y concesiones administrativas", "Sistema de responsabilidad de todas las Administraciones Públicas", "Todas las contestaciones anteriores son correctas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Tiene el Estado competencia exclusive sobre el procedimiento administrativo común?:', '["No, pertenece a las Comunidades Autónomas", "No, tiene competencias compartidas con las Comunidades Autónomas", "Sí, sin perjuicio de las especialidades derivadas de la organización propia de las Comunidades Autónomas", "Sí, sobre legislación básica exclusivamente."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Tiene el Estado competencia exclusiva sobre pesca marítima?:', '["No, pues es una materia propia de las Comunidades Autónomas", "Sí, sin perjuicio de las competencias que en la ordenación del sector se atribuyan a las Comunidades Autónomas", "Sí, sobre la legislación básica", "Sí, sobre la legislación de desarrollo."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Tiene el Estado competencia exclusiva sobre ferrocarriles y transportes terrestres?:', '["No, pues es una materia propia de las Comunidades Autónomas", "Sí, siempre que transcurran por el territorio de más de una Comunidad Autónoma", "Sí, siempre que tengan un itinerario nacional", "Sí, siempre que transcurran por el territorio de una Comunidad Autónoma."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué competencias tiene el Estado sobre recursos y aprovechamientos hidráulicos?:', '["Ninguna", "Legislación, ordenación y concesión en todo caso", "Legislación, ordenación y concesión cuando las aguas discurran por más de una Comunidad Autónoma", "Legislación, ordenación y concesión cuando las aguas discurran por una Comunidad Autónoma."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué competencias tiene el Estado sobre instalaciones eléctricas?:', '["Ninguna", "Autorización de las instalaciones eléctricas cuando su aprovechamiento afecte a otra Comunidad", "Autorización de las instalaciones eléctricas cuando el transporte de energía salga del ámbito territorial de una Comunidad", "Son ciertas las respuestas b. y c."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Estado tiene competencia exclusiva en:', '["Legislación básica sobre montes", "Legislación básica sobre montes y aprovechamientos forestales", "Legislación básica sobre montes, aprovechamientos forestales y vías pecuarias", "Legislación básica sobre montes, aprovechamientos forestales, vías pecuarias y pesca en aguas interiores."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Tiene el Estado competencia exclusiva de legislación básica sobre protección del medio ambiente?:', '["Sí, sin que las Comunidades Autónomas tengan ninguna", "No", "Sí, sin perjuicio de las facultades de las Comunidades Autónomas de establecer normas adicionales de protección", "Es una competencia compartida con las Comunidades Autónomas."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Tiene el Estado competencia exclusiva sobre obras públicas?:', '["Sí, cuando sean de interés general", "Sí, cuando su realización afecte a más de una Comunidad Autónoma", "No", "Son ciertas las respuestas a. y b."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En materia de armas y explosivos, el Estado tiene competencia sobre:', '["Régimen de producción", "Régimen de producción y comercio", "Régimen de producción, comercio y tenencia", "Régimen de producción, comercio, tenencia y uso."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Estado tiene competencia exclusiva para dictar normas básicas del régimen de:', '["Prensa y radio", "Prensa, radio y televisión", "Prensa, radio y televisión y, en general, de todos los medios de comunicación social", "Todos los medios de comunicación social."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Sobre medios de comunicación social, ¿tienen alguna competencia las Comunidades Autónomas?:', '["No, es materia exclusiva del Estado", "Sí, tienen facultades de desarrollo de las normas básicas estatales", "Sí, tienen facultades de ejecución de las normas básicas estatales", "Sí, tienen facultades de desarrollo y ejecución de las normas básicas estatales."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Tienen las Comunidades Autónomas alguna competencia sobre museos, bibliotecas y archivos?:', '["No, es una competencia estatal", "Sí, es una competencia compartida con el Estado", "Sí, tienen competencias de gestión", "No, salvo que sean asumidas por los respectivos Estatutos."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La seguridad pública es una competencia:', '["De las Comunidades Autónomas", "Del Estado", "Compartida", "Exclusiva."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Tienen competencia las Comunidades Autónomas para la creación de policías?:', '["No", "Sí", "Sí, en la forma que se establezca en los respectivos Estatutos en el marco de lo que disponga una ley orgánica", "Sí, en la forma que se establezca en los respectivos Estatutos."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En materia de expedición y homologación de títulos académicos y profesionales, el Estado tiene competencia exclusiva para la regulación de:', '["Las condiciones de obtención, expedición, homologación y colegiación", "Las condiciones de obtención", "Las condiciones de obtención y expedición", "Las condiciones de obtención, expedición y homologación."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Sin perjuicio de las competencias que puedan asumir las Comunidades Autónomas, el Estado:', '["Considerará el servicio de la cultura como deber esencial", "Considerará el servicio de la cultura como atribución esencial", "Facilitará la comunicación cultural entre las Comunidades Autónomas", "Toda las contestaciones anteriores son correctas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las materias no atribuidas expresamente al Estado por la Constitución, ¿podrán corresponder a las Comunidades Autónomas?:', '["No, en ningún caso", "Sí, por delegación del Gobierno", "Sí, en virtud de sus respectivos Estatutos", "Sí, en virtud de pacto de Estado."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La competencia sobre las materias que no se hayan asumido por los Estatutos de Autonomía corresponderá:', '["Al Estado", "A las propias Comunidades Autónomas", "A las Cortes Generales", "Al Gobierno."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las normas del Estado, ¿prevalecerán en caso de conflicto sobre las de las Comunidades Autónomas?:', '["No, en ningún caso", "Sí, en todos los casos", "Sí, en todo lo que no esté atribuido a la exclusiva competencia de éstas", "Sí, en virtud de los respectivos Estatutos."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El derecho estatal, ¿será supletorio del derecho de las Comunidades Autónomas?:', '["Sí, en todo caso", "No, nunca", "Sí, en virtud de los respectivos Estatutos", "Solamente en materias de competencia exclusiva del Estado."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién puede atribuir a las Comunidades Autónomas mediante una ley marco la facultad de dictar normas legislativas en materias de competencia estatal?:', '["El Gobierno", "El Congreso", "El Senado", "Las Cortes Generales."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Respecto de la facultad legislativa atribuida a las Comunidades Autónomas sobre materias de competencia estatal, la ley marco correspondiente fijará:', '["Los principios", "Las bases", "Las directrices", "Todas las contestaciones anteriores son correctas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Podrá establecer cada ley marco la modalidad del control de las Cortes Generales sobre las normas legislativas de las Comunidades Autónomas?:', '["No", "Sí, sin perjuicio de la competencia de los Tribunales", "Sí, predominando sobre la competencia de los Tribunales", "Sí, mediante autorización del Gobierno."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Podrá el Estado transferir o delegar en las Comunidades Autónomas facultades correspondientes a materia de titularidad estatal?:', '["Sí, mediante ley orgánica", "Sí, mediante ley", "Sí, siempre que por su propia naturaleza sean susceptibles de transferencia o delegación", "Son ciertas las respuestas a. y c."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Cuando el Estado transfiera o delegue en las CC.AA. facultades correspondientes a materia de titularidad estatal, la ley preverá en cada caso:', '["La correspondiente transferencia de medios financieros", "La correspondiente transferencia de medios humanos", "La correspondiente transferencia de medios financieros y humanos", "La correspondiente transferencia de medios materiales."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Cuando el Estado transfiera o delegue en las Comunidades Autónomas facultades correspondientes amateriade titularidad estatal, la ley preverá en cada caso:', '["Las formas de control que se reserve la Comunidad Autónoma", "Las formas de control que se reserve el Estado", "Las formas de control judicial", "Las formas de control constitucional."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Estado podrá dictar leyes que establezcan los principios necesarios para armonizar las disposiciones normativas de las Comunidades Autónomas:', '["En casos de extrema necesidad", "Cuando éstas incumplan sus obligaciones", "Aun en el caso de materias atribuidas a la competencia de éstas", "Sobre materias de titularidad estatal."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La necesidad de que el Estado dicte leyes que establezcan los principios necesarios para armonizar las disposiciones normativas de las Comunidades Autónomas será apreciada:', '["Por el Congreso, por mayoría absoluta", "Por el Senado, por mayoría absoluta", "Por las Cortes Generales, por mayoría absoluta de cada Cámara", "Por las Cortes Generales, por mayoría de cada Cámara."]'::jsonb, 2, 'es'),
    ('444cb125c36ed231f964fc64c4501b29', 'No será preciso dejar transcurrir el plazo de cinco años a que se refiere el artículo 148.2 de la Constitución para ampliar las competencias autonómicas cuando la iniciativa del proceso autonómico sea acordada, además de por las Diputaciones o los órganos interinsulares correspondientes, por:', '["Las tres quintas partes de los Municipios de cada una de las provincias afectadas", "Las tres cuartas partes de los Municipios de cada una de las provincias afectadas", "La mitad de los Municipios de cada una de las provincias afectadas", "La mayoría absoluta de los Municipios de cada una de las provincias afectadas."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'No forma parte de la organización  institucional autonómica:', '["El Consejo de Gobierno", "La Asamblea Legislativa", "Presidente de la Comunidad Autónoma", "La Asamblea deliberante."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Asamblea Legislativa de las Comunidades Autónomas es elegida:', '["Mediante sufragio restringido", "Mediante sufragio universal", "Mediante sufragio censitario", "Mediante referéndum."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Asamblea Legislativa de las Comunidades Autónomas es elegida con arreglo al sistema de:', '["Representación directa", "Representación proporcional", "Representación libre", "Representación ponderada."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Asamblea Legislativa de las Comunidades Autónomas es elegida con arreglo a un sistema que asegure la representación:', '["De las ciudades principales", "De las diversas zonas del territorio", "De todos los pueblos", "De todas las comarcas."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En el ámbito autonómico, el Presidente y los miembros del Consejo de Gobierno serán políticamente responsables:', '["Ante la Asamblea autonómica", "Ante los ciudadanos", "Ante el Senado", "Ante las Cortes Generales."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Consejo de Gobierno de una Comunidad Autónoma tendrá funciones:', '["Ejecutivas exclusivamente", "Administrativas exclusivamente", "Ejecutivas y administrativas", "Legislativas, ejecutivas y administrativas."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Presidente de una Comunidad Autónoma es elegido:', '["Por el Consejo de Gobierno, de entre sus miembros", "Por la Asamblea, de entre sus miembros", "Por el Senado", "Por el Congreso."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Presidente de una Comunidad Autónoma es nombrado:', '["Por el Presidente del Gobierno", "Por la Asamblea, entre sus miembros", "Por el Rey", "Por el Consejo de Gobierno."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Corresponde al Presidente de una Comunidad Autónoma:', '["La dirección del Consejo de Gobierno", "La suprema representación de la respectiva Comunidad", "La representación ordinaria del Estado en la respective Comunidad", "Todas las contestaciones anteriores son correctas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Culminará la organización judicial en el ámbito territorial de la Comunidad Autónoma:', '["El Tribunal Supremo", "Un Tribunal Superior de Justicia, sin perjuicio de la jurisdicción que corresponde al Tribunal Supremo", "Una Audiencia Territorial, sin perjuicio de la jurisdicción que corresponde al Tribunal Supremo", "Un Tribunal Superior de Justicia, sin perjuicio de la jurisdicción que corresponde a la Audiencia Nacional."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En los Estatutos de las Comunidades Autónomas podrán establecerse los supuestos y las formas de participación de aquéllas:', '["En el gobierno del poder judicial", "En el nombramiento de jueces y magistrados", "En la organización de las demarcaciones judiciales del territorio", "En la provisión de vacantes del poder judicial."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En el ámbito autonómico, las sucesivas instancias procesales se agotarán habitualmente ante órganos judiciales radicados:', '["En ámbito estatal", "En el mismo territorio de la Comunidad Autónoma en que esté el órgano competente en primera instancia", "En el mismo territorio de la Comunidad Autónoma en que esté el órgano competente en segunda instancia", "Ninguna de las contestaciones anteriores es correcta."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Una vez sancionados y promulgados los respectivos Estatutos de Autonomía, solamente podrán ser modificados mediante los procedimientos:', '["Establecidos en la Constitución", "En ellos establecidos", "Establecidos por las Cortes Generales", "Establecidos por las leyes."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Una vez sancionados y promulgados los respectivos Estatutos, solamente podrán ser modificados mediante:', '["Referéndum nacional", "Referéndum local", "Referéndum entre los electores inscritos en los censos correspondientes", "Plebiscito regional."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Podrán los Estatutos establecer circunscripciones territoriales propias?:', '["No, en ningún caso", "Sí, mediante la agrupación de varios municipios", "Sí, mediante la agrupación de municipios limítrofes", "Sí, mediante la creación de Mancomunidades exclusivamente."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las circunscripciones territoriales propias establecidos por los Estatutos de Autonomía:', '["Están prohibidas", "Gozarán de plena autonomía", "Gozarán de plena personalidad jurídica", "Podrán tener personalidad propia."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El control de la actividad de los órganos de las CC.AA. relativo a la constitucionalidad de sus disposiciones normativas con fuerza de ley se ejercerá:', '["Por la jurisdicción contencioso ‐ administrativa", "Por el Gobierno", "Por el Tribunal Constitucional", "Por los Juzgados y Tribunales."]'::jsonb, 2, 'es'),
    ('51cc3a320f07eb2d9d76235bf400a25a', 'El control de la actividad de los órganos de las Comunidades Autónomas relativo al ejercicio de funciones delegadas a que se refiere el artículo 150.2 de la Constitución se ejercerá:', '["Por la jurisdicción contencioso ‐ administrativa", "Por el Gobierno, previo dictamen del Consejo de Estado", "Por el Tribunal Constitucional", "Por el Consejo de Estado."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El control de la actividad de los órganos de las Comunidades Autónomas relativo a la administración autónoma y sus normas reglamentarias se ejercerá:', '["Por la jurisdicción contencioso ‐ administrativa", "Por el Gobierno", "Por el Tribunal Constitucional", "Por los Juzgados y Tribunales."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El control de la actividad económica y presupuestaria de las Comunidades Autónomas se ejercerá:', '["Por el Gobierno", "Por el Tribunal de Cuentas", "Por los Tribunales Económico ‐ Administrativos", "Por las Cortes Generales."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién dirigirá la Administración del Estado en el territorio de la Comunidad Autónoma?:', '["El Presidente de la Comunidad Autónoma", "El Gobernador Civil", "Un Delegado nombrado por el Gobierno", "Un Delegado nombrado por las Cortes Generales."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién coordinará, cuando proceda, la Administración del Estado en el territorio de la Comunidad Autónoma con la administración propia de la Comunidad?:', '["El Presidente de la Comunidad Autónoma", "El Gobernador Civil", "Un Delegado nombrado por el Gobierno", "Un Delegado nombrado por las Cortes Generales."]'::jsonb, 2, 'es'),
    ('b6e4cc50005446c2885c6326b4a0c03d', 'Las medidas excepcionales previstas en el artículo 155 de la Constitución se tomarán contra una Comunidad Autónoma cuando:', '["No cumpla las obligaciones que la Constitución le imponga", "No cumpla las obligaciones que otras leyes le impongan", "Actuara de forma que atente gravemente al interés general de España", "Todas las contestaciones anteriores son correctas."]'::jsonb, 3, 'es'),
    ('b6e4cc50005446c2885c6326b4a0c03d', 'Las medidas excepcionales previstas en el artículo 155 de la Constitución podrán ser adoptadas contra una Comunidad Autónoma:', '["Por el Gobierno", "Por el Congreso", "Por el Senado", "Por las Cortes Generales."]'::jsonb, 0, 'es'),
    ('b6e4cc50005446c2885c6326b4a0c03d', 'Las medidas excepcionales previstas en el artículo 155 de la Constitución se tomarán contra una Comunidad Autónoma:', '["Para obligar a ésta al cumplimiento forzoso de sus obligaciones, exclusivamente", "Para la protección del interés general, exclusivamente", "Para obligar a ésta al cumplimiento forzoso de sus obligaciones, o para la protección del interés general", "Ninguna de las contestaciones anteriores es correcta."]'::jsonb, 2, 'es'),
    ('b6e4cc50005446c2885c6326b4a0c03d', 'Las medidas excepcionales previstas en el artículo 155 de la Constitución se tomarán contra una Comunidad Autónoma previo requerimiento:', '["Al Presidente de la Comunidad Autónoma", "Al Presidente de la Asamblea Legislativa correspondiente", "Al Presidente del Senado", "Al Presidente del Congreso."]'::jsonb, 0, 'es'),
    ('b6e4cc50005446c2885c6326b4a0c03d', 'Caso de no ser atendido el requerimiento constitucional, las medidas excepcionales previstas en el artículo 155 de la Constitución se tomarán contra una Comunidad Autónoma con la aprobación:', '["Por mayoría absoluta del Congreso", "Por mayoría absoluta del Senado", "Por mayoría absoluta de las Cortes Generales", "Por mayoría simple del Senado."]'::jsonb, 1, 'es'),
    ('b6e4cc50005446c2885c6326b4a0c03d', 'Para la ejecución de las medidas previstas en el artículo 155 de la Constitución, el Gobierno podrá:', '["Destituir a las autoridades de las Comunidades Autónomas", "Consultar con las autoridades de las Comunidades Autónomas", "Dar instrucciones a todas las autoridades de las Comunidades Autónomas", "Recabar información delas autoridades de las Comunidades Autónomas."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Comunidades Autónomas gozarán de autonomía financiera para el desarrollo y ejecución de sus competencias con arreglo a los principios de:', '["Coordinación con la Hacienda estatal", "Solidaridad entre todos los españoles", "Coordinación con las Haciendas locales", "Son ciertas las respuestas a. y b."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Comunidades Autónomas podrán                  actuar  como delegados o colaboradores del Estado para:', '["La recaudación de los recursos tributarios de aquél", "La gestión de los recursos tributarios de aquél", "La liquidación de los recursos tributarios de aquél", "Todas las contestaciones anteriores son correctas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los recursos de las Comunidades Autónomas estarán constituidos por:', '["Transferencias de un fondo de compensación interterritorial", "Otras asignaciones con cargo a los Presupuestos Generales del Estado", "Recargos sobre impuestos estatales", "Todas las contestaciones anteriores son correctas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los recursos de las Comunidades Autónomas no estarán constituidos por:', '["Rendimientos procedentes de su patrimonio", "Ingresos de derecho privado", "El producto de las operaciones de débito", "El producto de las operaciones de crédito."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'No es órgano del Consejo General del Poder Judicial las/el/la:', '["Pleno.", "Secciones.", "Vicepresidente.", "Comisión Permanente."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Vicepresidente en el Consejo General del Poder Judicial:', '["Es un cargo facultativo.", "Existe siempre.", "Se elige por la Comisión Permanente.", "No está prevista su existencia."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La mayoría que se exige en el Consejo General del Poder Judicial para proponer al Presidente del Tribunal Supremo es de:', '["Mayoría absoluta.", "Dos tercios.", "Mayoría simple.", "Tres quintos."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Consejo  General del Poder judicial propone el nombramiento de   los siguientes miembros del Tribunal Constitucional:', '["Dos.", "Cuatro.", "Cinco.", "Ninguno."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los miembros del Ministerio Fiscal se integran en:', '["Un Cuerpo único.", "Una estructura no jerarquizada.", "Una sola categoría.", "Categorías independientes."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los principios con arreglo a los cuales han de ejercer sus funciones los miembros del Ministerio Fiscal son los de:', '["Igualdad y legalidad.", "Imparcialidad e igualdad.", "Imparcialidad y legalidad.", "Legalidad y dependencia."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Fiscal General del Estado es designado por el:', '["Rey.", "Consejo General del Poder Judicial.", "Gobierno.", "Ninguno de ellos."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Una característica de la actuación del Ministerio Fiscal, en lo que a su organización interna se refiere, es la de:', '["Dependencia del Gobierno.", "Dependencia jerárquica.", "Parcialidad.", "lnamovilidad."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Nuestra Constitución trata de las relaciones entre el Gobierno y las Cortes Generales en su Título:', '["Tercero.", "Cuarto.", "Quinto.", "Sexto."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El ámbito donde es posible una mayor discrecionalidad por parte del Gobierno de la Nación es en el/la:', '["Aplicación de la Ley.", "Potestad reglamentaria.", "Dirección de la política.", "Función ejecutiva."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La función representativa de los miembros de] Gobierno se manifiesta en:', '["La Jefatura de los Ministerios.", "Su estatuto personal como tales.", "Su mandato parlamentario.", "Ninguna forma."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La coordinación de las funciones de los miembros del Gobierno es competencia del/de las:', '["Presidente del Gobierno.", "Vicepresidente del Gobierno.", "Ministerio de Administraciones Públicas.", "Comisiones Delegadas del Gobierno."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La propuesta del Rey de candidato a la Presidencia del Gobierno se canaliza a través del:', '["Presidente del Congreso.", "Gobierno en pleno.", "Senado y Congreso.", "Grupo político mayoritario."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La confianza al candidato a Presidente del Gobierno se otorga, en primera vuelta, por:', '["Mayoría absoluta de las Cortes.", "Mayoría absoluta del Congreso.", "Mayoría simple del Congreso.", "Mayoría simple de las Cortes."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La disolución de las Cámaras, por transcurso de dos meses desde la primera votación de investidura, sin obtención de la confianza parlamentaria por los candidatos, se refrenda por el:', '["Presidente del Gobierno.", "Rey.", "Presidente del Congreso.", "No necesita refrendo."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Gobierno, en relación con los Presupuestos Generales del Estado, los:', '["Aprueba.", "Convalida.", "Elabora.", "Ratifica."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'No se incluye como principio fundamental de la actuación de la Administración el de:', '["Coordinación.", "Cooperación.", "Legalidad.", "b y c son correctas."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La aprobación de exigencia de responsabilidad de un Ministro por un delito contra la seguridad del Estado en el ejercicio de sus funciones compete al/a la:', '["Sala de lo Penal del Tribunal Supremo.", "Mayoría absoluta de los miembros del Congreso.", "Cuarta parte de estos miembros.", "Consejo de Ministros."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La prerrogativa real de gracia respecto a la responsabilidad penal de un Ministro se refrenda por el:', '["Presidente del Congreso.", "Presidente del Tribunal Supremo.", "Presidente del Gobierno.", "No es posible esta medida."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Fuerzas y Cuerpos de Seguridad dependen del:', '["Ejército.", "Gobierno.", "Ministerio de Defensa.", "Rey."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Puede negarse el acceso a los ciudadanos a un archivo administrativo por motivo de:', '["Intimidad de las personas.", "Defensa del Estado.", "Política general.", "a y b son correctas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Si como consecuencia de un terremoto se cae sobre un ciudadano una farola que estaba en buen estado:', '["No está obligada a indemnizarle la Administración.", "Al ser un caso fortuito, sí debe hacerlo.", "Depende de la conducta del propio ciudadano el que tenga o no derecho a indemnización.", "La responsabilidad se exige al Estado como tal y no a la Administración."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El supremo órgano consultivo del Gobierno es el:', '["Ministerio Fiscal.", "Consejo de Estado.", "Consejo General del Poder Judicial.", "Consejo Económico y Social."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La responsabilidad solidaria del Gobierno ante el Congreso significa que:', '["Cada Ministro está sometido a las interpelaciones de las mismas.", "El Gobierno en sí responde ante el Congreso y no cada uno de sus miembros individualmente considerado.", "El Presidente es el que responde.", "Sólo puede ser obligado a dimitir por unanimidad."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La responsabilidad solidaria del Gobierno ante el Congreso de los Diputados es de carácter:', '["Judicial.", "Administrativo.", "Político.", "De los tres tipos anteriores."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La responsabilidad del Gobierno ante el Senado es:', '["Mancomunada.", "Individual.", "Solidaria.", "Inexistente."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El tiempo mínimo previsto para interpelaciones en las Cortes al Gobierno es:', '["Semanal.", "Trimestral.", "Mensual.", "En cada período de sesiones."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La explicación del Gobierno sobre el contenido de una petición individual presentada en las Cortes es:', '["Obligatoria en todo caso.", "Obligatoria cuando así lo exijan las Cámaras.", "Obligatoria cuando así se solicite en la propia petición.", "Discrecional."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El pronunciamiento sobre la cuestión de confianza es competencia del/de las:', '["Congreso exclusivamente.", "Senado cuando se plantee ante él.", "Congreso y Senado.", "Propio Gobierno."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La cuestión de confianza se plantea por el:', '["Presidente del Gobierno.", "Gobierno en sí.", "Congreso.", "Cualquier Ministro."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Respecto al planteamiento de la cuestión de confianza, el Consejo de Ministros:', '["Decide.", "Debe dictaminarlo favorablemente.", "Delibera.", "No tiene nada que hacer."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los signatarios de una moción de censura no pueden presentar otra en el/la:', '["Misma legislatura.", "Mismo período de sesiones.", "Ningún momento.", "Misma Cámara."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La disolución anticipada del Congreso o del Senado, se decreta por el:', '["Presidente del Gobierno.", "Presidente de la Cámara.", "Rey.", "Gobierno en pleno."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En las Comunidades Autónomas que siguen la vía común, el Proyecto de Estatuto será elaborado por la/los:', '["Asamblea de Parlamentarios que se constituye al efecto.", "Comisión Constitucional del Congreso de los Diputados.", "Diputación Provincial correspondiente.", "Miembros de la Diputación u órgano interinsular y por los Diputados y Senadores elegidos por ellas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El voto de ratificación por los Plenos del Senado y del Congreso se dará en el/las:', '["Comunidades Autónomas que siguen la vía común.", "Comunidades Autónomas que siguen la vía especial.", "Acceso a la autonomía de Ceuta y Melilla.", "Acceso a la autonomía de Gibraltar."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La responsabilidad política del Presidente de una Comunidad Autónoma se exige por el/la:', '["Sala de lo Penal del Tribunal Supremo.", "Congreso de los Diputados.", "Tribunal Superior de Justicia de la Comunidad Autónoma.", "Asamblea Legislativa de la Comunidad Autónoma"]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Asamblea Legislativa de las Comunidades Autónomas se elige:', '["Con criterios de representación territorial.", "Con criterios de representación proporcional.", "Por sufragio individual.", "Con criterios de representación provincial."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El principio de coordinación con la Hacienda estatal se consigue por:', '["El Fondo de Compensación lnterterritorial.", "Los preceptos de las sucesivas Leyes de Presupuestos Generales del Estado.", "La creación del Consejo de Política Fiscal y Financiera de las Comunidades Autónomas.", "Imperativo de la propia Constitución."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los Estatutos de Autonomía deberán contener el/las:', '["Competencias que se dejan al Estado y las que asume la Comunidad.", "Competencias que, en función de la Constitución, asume cada Comunidad Autónoma.", "Desarrollo de la Administración Autonómica.", "División provincial y órganos de gobierno."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En la reforma de los Estatutos intervienen las Cortes Generales:', '["Siempre.", "Nunca.", "Sólo cuanto se trata de Comunidades Autónomas que accedieron por la vía común.", "En las Comunidades Autónomas de vía especial exclusivamente."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los miembros de las Diputaciones u órganos interinsulares intervienen en la elaboración de los Estatutos de Autonomía:', '["En todo caso.", "Nunca.", "En las Comunidades Autónomas de vía común.", "En las Comunidades Autónomas de vía especial."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los Estatutos de Autonomía en la vía común se aprueban por el:', '["Congreso mediante Ley Orgánica.", "Congreso y Senado por Ley Orgánica.", "Congreso y Senado por Ley Ordinaria.", "Parlamento Autonómico solamente."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La más alta representación de una Comunidad Autónoma la ostenta el:', '["Presidente del Parlamento Autonómico.", "Presidente de la Comunidad Autónoma.", "Rey.", "Presidente del Gobierno."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La asunción de competencias y de mayor autonomía por las Comunidades es, como regla general:', '["Regresiva.", "Progresiva.", "Automática.", "Inmediata."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En la elaboración por la vía común de los Estatutos de Autonomía:', '["No intervienen los Municipios afectados.", "Intervendrán en todo caso.", "Sólo intervienen las Diputaciones Provinciales u órganos interinsulares.", "Sólo intervienen los Municipios y los Diputados y Senadores."]'::jsonb, 0, 'es'),
    ('dbac364db37e7b0eab8a21adcc6002fb', 'El principio de solidaridad consagrado por el art. 138 de la Constitución exige una atención especial a:', '["Las Comunidades Autónomas de economía más deprimida.", "Las Entidades Locales Menores.", "Todas las partes del territorio nacional.", "Las Islas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El establecimiento de un sistema fiscal más favorable por una Comunidad Autónoma respecto de las demás:', '["Puede hacerse en cualquier caso.", "Está absolutamente prohibido.", "Forma parte de las medidas para fomentar la industria autóctona.", "Debe basarse en una Ley de Bases estatal."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Constitución, las Haciendas Locales deben:', '["Ser autosuficientes.", "Carecer de recursos propios.", "Supeditarse a la estatal.", "Nada de lo anterior es cierto."]'::jsonb, 3, 'es');

  -- Batch 2201-2400
  insert into public.question_bank (content_hash, question, options, correct_index, lang)
  values
    ('4b830eab8fe6b21a82865850ecac45f6', 'El carácter de cauce inmediato de participación ciudadana se predica del/de la:', '["Comunidad Autónoma.", "Municipio.", "Estado.", "Provincia."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La administración descentralizada de núcleos de población separados, bajo la denominación de aldeas, anteiglesias, etc., se refiere a las:', '["Entidades de ámbito territorial inferior al municipal.", "Mancomunidades.", "Comarcas.", "Áreas Metropolitanas."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Tiene el carácter de división territorial para el cumplimiento de las actividades del Estado un/una:', '["Comarca.", "Municipio.", "Provincia.", "Comunidades Autónomas."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Un Colegio Oficial de Abogados:', '["Tiene personalidad jurídica propia.", "Carece de esta personalidad.", "Depende del Ente que lo crea.", "Sólo tiene personalidad respecto de los asuntos que determine la Ley."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El substrato de una Fundación es una:', '["Pluralidad de bienes.", "Pluralidad de personas.", "Comunidad de bienes.", "Comunidad de Entes."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Respecto de los partidos políticos, sindicatos y asociaciones empresariales, en la Constitución se exige que:', '["Las cuotas de sus afiliados financien las actividades del partido, sindicato o asociación.", "Los miembros que ostenten funciones ejecutivas sean elegidos mediante el voto libre, igual, directo y secreto de sus afiliados.", "Anualmente procedan a dar publicidad a su presupuesto de gastos e ingresos.", "Su estructura interna y su funcionamiento sean democráticos."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El ejercicio del derecho a la libre sindicación:', '["No tiene constitucionalmente limitación alguna.", "Puede exceptuarse o limitarse por Ley a las Fuerzas Armadas.", "Implica al mismo tiempo el deber de todo trabajador de afiliarse obligatoriamente a un sindicato libremente elegido por el.", "Ninguna de las respuestas anteriores es correcta."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los sindicatos de trabajadores y las asociaciones empresariales deberán contribuir a la:', '["Formación de partidos políticos.", "Elección de Diputados y Senadores.", "Defensa y promoción de los intereses económicos y sociales de sus afiliados.", "Son correctas las respuestas a. y c."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los españoles tienen derecho a participar en los asuntos públicos:', '["Solo a través de los Diputados y Senadores libremente elegidos por sufragio universal.", "Solo de forma directa.", "De forma directa y a través de los Diputados y Senadores libremente elegidos por sufragio universal.", "De forma directa y a través de sus representantes libremente elegidos por sufragio universal."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El derecho de petición consiste en que los ciudadanos puedan dirigirse a los poderes públicos en solicitud:', '["De cualquier cosa, aunque no se basen en derechos o intereses reconocidos en normas jurídicas.", "De derechos o intereses legítimos.", "Del ejercicio de derechos constitucionales.", "Del ejercicio de derechos fundamentales."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Excepto en lo concerniente a miembros de las Fuerzas Armadas o de Cuerpos sometidos a disciplina militar, ¿cómo puede ejercerse el derecho de petición por los demás ciudadanos?', '["De forma individual o colectiva.", "Solo a título individual.", "Solo de forma colectiva.", "Solo de forma individual o a través de asociaciones legalmente reconocidas."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los miembros de las Fuerzas Armadas o de Cuerpos sometidos a disciplina militar, ¿pueden ejercer el derecho de petición?', '["Si, pero solamente a título individual.", "Si, en las mismas condiciones que los demás ciudadanos.", "Si, pero solo pueden hacerlo de forma colectiva.", "No, en ningún caso."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Constitución, la enseñanza básica será:', '["Reglada.", "Obligatoria.", "Gratuita.", "Obligatoria y gratuita."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Constitución, la enseñanza universitaria será:', '["Reglada.", "Obligatoria.", "Gratuita.", "Ninguna de las respuestas anteriores es correcta."]'::jsonb, 3, 'es'),
    ('ac2842cb28fc1b51e5fe9d5ea3303e0f', 'Los derechos de propiedad y herencia se reconocen en la Constitución:', '["En el art. 33.", "En la Sección Primera del Capítulo Segundo del Título l.", "En el art. 36.", "En el Capítulo Tercero del Título l."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los derechos de propiedad y herencia:', '["Se configuran constitucionalmente como derechos absolutos, sin limitación alguna.", "Sobre el derecho de propiedad caben limitaciones, pero no así sobre el derecho a la herencia.", "Sobre el derecho a la herencia caben limitaciones, pero no así sobre el derecho de propiedad.", "Por su función social, ambos derechos son susceptibles de delimitación legal."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'De acuerdo con la Constitución:', '["Los poderes públicos pueden disponer la expropiación forzosa sin limitación alguna, pero siempre mediante la correspondiente indemnización.", "En su caso, la expropiación se realizara de conformidad con lo dispuesto en las leyes, cuando obedezca a causa justificada de interés para la Administración Pública y mediante la correspondiente indemnización.", "En su caso, la expropiación se realizara de conformidad con lo dispuesto en las leyes, cuando obedezca a razones de Estado y mediante la correspondiente indemnización.", "En su caso, la expropiación se realizara de conformidad con lo dispuesto en las leyes, cuando obedezca a causa justificada de utilidad pública o interés social y mediante la correspondiente indemnización."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Corno garantías del derecho de propiedad, la Constitución establece, entre otras, la prohibición de:', '["Establecer impuestos sobre el patrimonio.", "Establecer impuestos sobre la herencia.", "Establecer impuestos de carácter confiscatorio.", "Intervenir empresas."]'::jsonb, 2, 'es'),
    ('20ee6516d34f1b346bd2afade410d7c8', 'El derecho al trabajo se plasma en la Constitución:', '["En el art. 35.", "En la Sección Primera del Capitulo Segundo del Titulo l.", "En el art. 40.", "En el Capítulo Tercero del Título I."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Al regular el derecho al trabajo, la Constitución prohíbe expresamente la discriminación por razón de:', '["Edad.", "Sexo.", "Estado civil.", "Opinión o cualquier otra condición o circunstancia personal o social."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En lo que concierne al derecho al trabajo, la Constitución se remite:', '["Al Estatuto de los Trabajadores.", "A la Ley de Libertad Sindical.", "Al Estatuto de los Trabajadores y a la Ley de Libertad Sindical.", "Al Estatuto de los Trabajadores y a la Ley General de la Seguridad Social."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Conforme a la dispuesto en la Constitución, el derecho a la negociación colectiva:', '["Se ciñe exclusivamente a la que colectivamente puedan pactar los trabajadores de una empresa, divididos en categorías o grupos profesionales, con su propio empresario.", "Abarca tan solo a lo que puedan pactar colectivamente todos los trabajadores de una empresa, sin dividirse en categorías o grupos profesionales, con su propio empresario.", "Abarca no solo a lo que puedan pactar colectivamente los trabajadores de una empresa, divididos o no en categorías o grupos profesionales, con su propio empresario, sino también a los pactos entre organizaciones de empresarios y trabajadores.", "Solo pueden ejercer tal derecho, en nombre de los trabajadores, las centrales sindicales mayoritarias."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Respecto de los convenios colectivos, la Constitución garantiza:', '["El mantenimiento del poder adquisitivo de los salarios.", "Su revisión anual.", "Su fuerza vinculante.", "Son correctas las respuestas a. y c."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El derecho a la huelga:', '["Es susceptible de ciertas limitaciones en su ejercicio para asegurar el mantenimiento de los servicios esenciales de la comunidad.", "Se configura constitucionalmente como un derecho absoluto de los trabajadores, sin limitación alguna.", "Está expresamente prohibido en la Constitución para los funcionarios públicos.", "Solo pueden ejercer tal derecho, en nombre de los trabajadores, las centrales sindicales mayoritarias."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El derecho al cierre patronal:', '["Es susceptible de ciertas limitaciones en su ejercicio para asegurar el mantenimiento de los servicios esenciales de la comunidad.", "Se configura constitucionalmente como un derecho absoluto de los empresarios, sin limitación alguna.", "Está expresamente prohibido en la Constitución para las empresas públicas.", "Sólo pueden ejercer tal derecho, en nombre de los empresarios, las organizaciones empresariales más representativas."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Constitución, todo ciudadano deberá contribuir al sostenimiento de los gastos públicos:', '["De forma equitativa.", "De acuerdo con su respectiva capacidad económica.", "De forma progresiva.", "De acuerdo con su respectiva renta."]'::jsonb, 1, 'es'),
    ('b8911eea94f4c829211669faec5cb38c', 'Los principios rectores de la política social y económica se establecen en la Constitución:', '["En el Capitulo II del Titulo l.", "En el Capitulo III del Titulo l.", "En el Capitulo IV del Titulo l.", "En el Capitulo V del Titulo l."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Dentro de los principios rectores de la política social y económica no se contempla:', '["La redistribución de la renta.", "El fomento del deporte.", "La política orientada a combatir la inflación.", "La atención a los disminuidos físicos."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los derechos fundamentales y libertades públicas que se contemplan en la Sección Primera del Capitulo Segundo del Título I de la Constitución pueden regularse:', '["Solo por Ley orgánica.", "Por Ley orgánica o por Ley ordinaria, pero nunca por Decreto-ley o Decreto legislativo.", "Por Ley orgánica, por Ley ordinaria o por Decreto-ley, pero nunca por Decreto legislativo.", "Por Ley orgánica, ley ordinaria, Decreto-ley o Decreto legislativo."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El recurso y la cuestión de inconstitucionalidad se plantean ante:', '["El Tribunal Constitucional.", "Los Tribunales Ordinarios.", "El primero, ante el Tribunal Constitucional; la segunda, ante los Tribunales ordinarios.", "El primero, ante el Tribunal Constitucional; la segunda, ante el Defensor del Pueblo."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El recurso de inconstitucionalidad puede ser instado:', '["Por cualquier persona física en demanda de protección de derechos y libertades fundamentales.", "Solo por el Presidente del Gobierno.", "Entre otros, por cincuenta Diputados o cincuenta Senadores.", "Solo por el Defensor del Pueblo."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La cuestión de inconstitucionalidad puede ser planteada por:', '["Cualquier persona física en demanda de protección de derechos y libertades fundamentales.", "El Presidente del Gobierno o por el Defensor del Pueblo.", "Jueces y Tribunales.", "Las tres respuestas anteriores son correctas."]'::jsonb, 2, 'es'),
    ('2b6edcfa0c4ac251d50667a54353381c', 'El recurso de amparo protege:', '["Exclusivamente los derechos fundamentales y libertades públicas que se contemplan en la Sección Primera del Capitulo Segundo del Título I de la Constitución.", "Exclusivamente los derechos fundamentales y libertades públicas que se contemplan en la Sección Primera del Capitulo Segundo del Título I de la Constitución y, además, el derecho de igualdad ante la Ley, regulado en el art. 14.", "Exclusivamente los derechos fundamentales y libertades públicas que se contemplan en la Sección Primera del Capitulo Segundo del Titulo I de la Constitución y, además, el derecho de igualdad ante la Ley, regulado en el art. 14, junto con la objeción de conciencia, prevista en el art. 30.", "Los derechos y libertades que se contemplan en los Capítulos Primero y Tercero del Titulo I de la Constitución."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En su caso, el recurso de amparo se planteará ante:', '["El Tribunal Constitucional.", "Los Tribunales ordinarios.", "El Defensor del Pueblo.", "Las tres respuestas anteriores son correctas."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El recurso de amparo puede ser planteado:', '["Por cualquier persona, a título individual.", "Solo por el Defensor del Pueblo.", "Solo por el Presidente del Gobierno.", "Solo por cincuenta Diputados o cincuenta Senadores."]'::jsonb, 0, 'es'),
    ('2b6edcfa0c4ac251d50667a54353381c', 'Ante los Tribunales ordinarios, y mediante un procedimiento basado en los principios de preferencia y sumariedad, pueden invocarse:', '["Exclusivamente los derechos y libertades públicas que se con- templan en la Sección Primera del Capitulo Segundo del Título I de la Constitución.", "Exclusivamente los derechos fundamentales y libertades públicas que se contemplan en la Sección Primera del Capitulo Segundo del Título I de la Constitución y, además, el derecho de igualdad ante la Ley, regulado en el art. 14.", "Exclusivamente los derechos fundamentales y libertades públicas que se contemplan en la Sección Primera del Capitulo Segundo del Título I de la Constitución y, además, el derecho de igualdad ante la Ley, regulado en el art. 14, junto con la objeción de conciencia, prevista en el art. 30.", "Los derechos y libertades públicas que se contemplan en los Capítulos I y III del Título I de la Constitución."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En nuestro país, el Defensor del Pueblo es una institución que se recoge por vez primera en:', '["La Constitución de 1978.", "El Fuero de los Españoles del anterior régimen.", "La Constitución de Cádiz de 1812.", "La Constitución de 1931."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En qué país hizo su aparición la figura del Defensor del Pueblo?', '["En Francia.", "En Suecia.", "En EEUU.", "En Alemania."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La misión fundamental del Defensor del Pueblo se centra en la defensa de:', '["Todos los preceptos constitucionales.", "Los derechos contemplados en el Título I de la Constitución.", "Los derechos fundamentales y libertades públicas que se contemplan en la Sección Primera del Capitulo Segundo del Título I de la Constitución.", "Los derechos contemplados en el Título I de la Constitución no susceptibles de recurso de amparo."]'::jsonb, 1, 'es'),
    ('0e2f03652b13a7299db1a1ecb0d8028a', '¿En qué precepto constitucional se define el Defensor del Pueblo?', '["En el art. 30.", "En el art. 45.", "En el art. 54.", "En el art. 60."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Defensor del Pueblo se configura constitucionalmente como alto comisionado:', '["Del pueblo.", "De las Cortes Generales.", "Del Poder Judicial.", "Del Gobierno."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Para el cumplimiento de sus fines, el Defensor del Pueblo puede inspeccionar', '["Las decisiones del Gobierno de naturaleza política.", "La actividad de la Administración.", "La actividad de las Cortes Generales.", "Las tres respuestas anteriores son correctas."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Defensor del Pueblo es designado:', '["Por el pueblo.", "Por el Rey.", "Por las Cortes Generales.", "Por el Gobierno."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En el desempeño de sus funciones, el Defensor del Pueblo actúa:', '["Siempre de oficio.", "Siempre a instancia de parte interesada.", "De oficio o a instancia de parte interesada.", "A instancia de las Cortes Generales."]'::jsonb, 2, 'es'),
    ('dadaf5d59a71b5e405e17158a0bbfb19', 'Los estados excepcionales previstos en la Constitución (alarma, excepción y sitio) no están regulados:', '["En el Titulo V.", "En el Titulo donde se contemplan las relaciones entre el Gobierno y las Cortes Generales.", "En el art. 116.", "No es correcta ninguna de las tres respuestas anteriores."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Como característica común en la declaración de los tres estados excepcionales cabe citarse, entre otras, la de:', '["Precisar de autorización parlamentaria previa.", "Tener un ámbito territorial determinado.", "Ser susceptibles de suspensión ciertos derechos fundamentales y libertades públicas.", "Tener topes máximos de tiempo fijados en la Constitución."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En cuanto a las situaciones de gravedad estimadas por los poderes públicos competentes para declarar los estados excepcionales, y en orden de menor a mayor gravedad, dicha ordenación de estados será:', '["Alarma, excepción y sitio.", "Excepción, alarma y sitio.", "Alarma, sitio y excepción.", "Excepción, sitio y alarma."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién puede declarar el estado de alarma?', '["El Congreso de los Diputados.", "El Gobierno, previa autorización del Congreso de los Diputados.", "El Gobierno, para posteriormente dar cuenta al Congreso de los Diputados.", "El Gobierno, para posteriormente dar cuenta a las Cortes Generales."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En principio, el estado de alarma se declarará por un plazo máxima de:', '["Quince días.", "Treinta días.", "Sesenta días.", "En la Constitución no se fija plazo alguno."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Declarado el estado de alarma:', '["Solo es susceptible de suspensión el derecho a la inviolabilidad del domicilio.", "Entre otros, puede suspenderse el derecho a salir y entrar libremente de España.", "Entre otros, puede suspenderse el derecho a la huelga.", "No es susceptible de suspensión ningún derecho constitucional."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El plazo per el que en principia se declara el estado de alarma, ¿puede ser prorrogado?', '["Si, por otros quince días.", "Si, por otros treinta días.", "Si, por otros sesenta días.", "Si, pero en la Constitución no se fija plazo máximo alguno para la prórroga."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En su caso, la prórroga del estado de alarma deberá ser declarada por:', '["El Congreso de los Diputados.", "El Gobierno, previa autorización del Congreso de los Diputados.", "El Gobierno, para posteriormente dar cuenta al Congreso de los Diputados.", "El Gobierno, para posteriormente dar cuenta a las Cortes Generales."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Que órgano puede declarar el estado de excepción?', '["EI Congreso de los Diputados.", "El Gobierno, previa autorización del Congreso de los Diputados.", "Las Cortes Generales.", "El Gobierno, para posteriormente dar cuenta al Congreso de los Diputados."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En principio, el estado de excepción se declarará por un plazo máximo de:', '["Quince días.", "Treinta días.", "Sesenta días.", "En la Constitución no se fija plazo alguno."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Puede ser prorrogado el plazo por el que en principio se declara el estado de excepción?', '["Si, por otros quince días.", "Si, por otros treinta días.", "Si, por otros sesenta días.", "Si, pero en la Constitución no se fija plaza máxima alguno para la prórroga."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Señale, de entre los propuestos, el orden cronológico a seguir en la elaboración de las leyes.', '["1) Iniciativa legislativa; 2) Deliberación, discusión y votación; 3) Promulgación; 4) Sanción; 5) Publicación.", "1) Iniciativa legislativa; 2) Deliberación, discusión y votación; 3) Promulgación; 4) Publicación; 5) Sanción.", "1) Iniciativa legislativa; 2) Deliberación, discusión y votación; 3) Sanción; 4) Publicación; 5) Promulgación.", "1) Iniciativa legislativa; 2) Deliberación, discusión y votación; 3) Sanción; 4) Promulgación; 5) Publicación."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Al indicar que una Ley es de 18 de marzo de 1988, la que se está diciendo es que en esa fecha:', '["Se aprobó par las Cortes Generales.", "Se sanciono.", "Se promulgo.", "Se publica."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La iniciativa legislativa no corresponde:', '["Al Gobierno.", "Al Congreso y al Senado.", "A las Asambleas de las Comunidades Autónomas.", "A la iniciativa popular que reúna 400.000 firmas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Si es el Gobierno quien inicia el proceso legislativo, al texto que envía a las Cortes se le conoce con el nombre de:', '["Proyecto de Ley.", "Proposición de Ley.", "Borrador de Ley.", "Decreto legislativo."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Si la iniciativa legislativa parte de una de las Cámaras, al texto que se propone se le denomina:', '["Proyecto de Ley.", "Proposición de Ley.", "Borrador de Ley.", "Decreto legislativo."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Asambleas legislativas de las Comunidades Autónomas están facultades para:', '["Remitir a la Mesa del Congreso un proyecto de Ley.", "Solicitar del Gobiemo la adopción de una proposición de Ley.", "Remitir a la Mesa del Congreso un Decreto-Ley.", "Remitir a la Mesa del Congreso una proposición de Ley o solicitor del Gobierno la adopción de un proyecto de Ley."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La iniciativa legislativa popular debe acompañarse de, al menos:', '["300.000 firmas.", "400.000 firmas.", "500.000 firmas.", "1.000.000 firmas."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'No precede la iniciativa legislativa popular en materias:', '["Propias de Ley ordinaria.", "De carácter económico.", "Relativas a la prerrogativa de gracia.", "Las tres respuestas anteriores son correctas."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los proyectos de Ley enviados a las Cortes son presentados por el Gobierno:', '["En la Mesa de las Cortes.", "En la Mesa del Congreso.", "En la Mesa del Senado.", "El texto original en la Mesa del Congreso y una Exposición de Motivos en la Mesa del Sena."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Recibido un proyecto de Ley por la Mesa:', '["Se procede a su toma de consideración y, de resultar favorable, se ordena su publicación en el Boletín Oficial de las Cortes.", "Se ordena su inmediata publicación en el Boletín Oficial de las Cortes.", "Se estudia la conveniencia o no de su publicación por la Junta de Portavoces.", "Solo se ordena su inmediata publicación si el Gobierno o el Congreso de los Diputados lo declaran de urgente tramitación."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Recibida una proposición de Ley par la Mesa del Congreso:', '["Se procede a su toma de consideración y, de resultar favorable, se ordena su publicación en el Boletín Oficial de las Cortes.", "Se ordena su inmediata publicación en el Boletín Oficial de las Cortes.", "Se estudia la conveniencia o no de su publicación par la Junta de Portavoces.", "Solo se ordena su inmediata publicación si el Gobierno la declara de urgente tramitación."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Aprobado por el Congreso un proyecto de Ley, su Presidente:', '["Ordenara su inmediata publicación en el Boletín de las Cortes.", "Dará inmediata cuenta del mismo al Presidente del Senado.", "Dispone del plazo de quince días para dar cuenta del mismo al Presidente del Senado.", "Dispone del plazo de un mes para dar cuenta del mismo al Presidente del Senado."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Es preciso que los proyectos y proposiciones de Ley se aprueben por las dos Cámaras?', '["Si, en todo caso.", "Si se aprueban en el Congreso pero no en el Senado, pueden volver de nuevo al Congreso y quedar aprobados par mayoría simple.", "En el caso de veto por parte del Senado, es preciso que el Congreso rectifique el texto inicial.", "Ninguna de las respuestas anteriores es correcta."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Senado, para aprobar, enmendar o vetar los proyectos o proposiciones de Ley aprobados por el Congreso, dispone normalmente, a partir de la recepción del texto, de un plaza de:', '["Quince días.", "Un mes.", "Dos meses.", "Tres meses."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Que órgano es competente para declarar la urgente tramitación de un proyecto de Ley?', '["El Gobiemo o el Congreso.", "Solo el Congreso.", "Solo el Gobierno.", "El Gobiemo, el Congreso o el Senado."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Si el proyecto de Ley aprobado por el Congreso es declarado de urgente tramitación, ¿de que plazo dispone el Senado, a partir de su recepción, para aprobarlo, vetarlo o enmendarlo?', '["Veinte días.", "Quince días.", "Un mes.", "Dos meses."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Para Ia sanción de las leyes, el Rey dispone de:', '["Veinte días.", "Quince días.", "Un mes.", "Dos meses."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las leyes entran en vigor:', '["El mismo día de su completa publicación en el Boletín Oficial del Estado.", "Al día siguiente de su completa publicación en el Boletín Oficial del Estado.", "En todo caso, a los veinte días de su completa publicación en el Boletín Oficial del Estado.", "A los veinte días de su completa publicación en el Boletín Oficial del Estado, si en ellas no se dispusiere otra cosa."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Puede publicarse hoy una Ley en el Boletín Oficial del Estado para que empiece a obligar hoy mismo?', '["No.", "Si, pero se tiene que indicar expresamente en el texto.", "Solo si se trata de leyes ordinarias.", "Solo si se trata de leyes orgánicas."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Puede publicarse hoy una Ley en el Boletín Oficial del Estado para que empiece a obligar dentro de un año?', '["No.", "Si, pero se tiene que indicar expresamente en el texto.", "Solo si se trata de leyes ordinarias.", "Solo si se trata de leyes orgánicas."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuando se implantaron en nuestro país las leyes orgánicas?', '["En la Constitución de 1978.", "En la Constitución de 1831.", "En la Constitución de 1912.", "En las Leyes Fundamentales del régimen anterior."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En que articulo de la Constitución se determinan las materias reservadas a leyes orgánicas?', '["81.", "83.", "91.", "94."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En su día, los diferentes Estatutos de Autonomía fueron aprobados mediante:', '["Leyes orgánicas.", "Leyes ordinarias.", "Leyes orgánicas, en algunos casos.", "Leyes ordinarias, en algunos casos."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Entre las leyes que deben ser orgánicas, se encuentran:', '["Las relativas al desarrollo de los derechos fundamentales y de las libertades públicas.", "Las que aprueben las normas básicas del Régimen Local.", "Las que establezcan los principios necesarios para armonizar las disposiciones normativas de las Comunidades Autónomas.", "Las tres respuestas anteriores son correctas."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Si las Cortes Generales aprueban una Ley par la que se condecora a un determinado funcionario publica, estamos en presencia:', '["De una Ley en sentido material, pero no en sentido formal.", "De una Ley en sentido formal, pero no en sentido material.", "De una Ley en sentido formal y material.", "De un Decreto legislativo."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las leyes orgánicas:', '["Pueden ser aprobadas par las Comisiones legislativas.", "Deben ser aprobadas por las Comisiones legislativas.", "Pueden ser aprobadas par las Comisiones legislativas, si estas son permanentes.", "Deben ser aprobadas par el Pleno de las Cámaras."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las leyes ordinarias:', '["Pueden ser aprobadas por las Comisiones legislativas o por las Comisiones de investigación.", "Deben ser aprobadas por las Comisiones legislativas.", "Pueden ser aprobadas por las Comisiones legislativas.", "Deben ser aprobadas por el Pleno de las Cámaras."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Cortes Generales, ¿deben prestar su autorización previa al Gobierno para celebrar tratados internacionales?', '["Si, en todo caso.", "No, en ningún caso.", "No necesariamente, pero en todo caso deberán ser puntualmente informadas de su conclusión.", "No, y sin que necesariamente tengan que estar informadas de su conclusión."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Si, por medio de un tratado, nuestro país atribuye a una organización internacional el ejercicio de competencias derivadas de la Constitución:', '["Se precisa un puro acto formal de las Cortes por el que se presta el consentimiento.", "Se precisa una Ley orgánica que lo autorice.", "Se tiene que reformar previamente la Constitución.", "Basta con que las Cortes sean informadas inmediatamente de su conclusión."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En el supuesto de que un tratado internacional celebrado par España contenga estipulaciones contrarias a la Constitución:', '["Se precisa un puro acta formal de las Cortes por el que se presta el consentimiento.", "Se precisa una Ley orgánica que la autorice.", "Se tiene que reformar previamente la Constitución.", "Basta con que las Cortes sean informadas inmediatamente de su conclusión."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Para que España celebre un tratado internacional de carácter militar:', '["Se precisa un puro acta formal de las Cortes par el que se presta el consentimiento.", "Se precisa una Ley orgánica que la autorice.", "Se tiene que reformar previamente la Constitución.", "Basta con que las Cortes sean informadas inmediatamente de su conclusión."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Para que nuestro país celebre un tratado internacional que afecte a la integridad territorial del Estado:', '["Se precisa un puro acto formal de las Cortes par el que se presta el consentimiento.", "Precisa Ley orgánica que la autorice.", "Se tiene que reformar previamente la Constitución.", "Basta con que las Cortes sean informadas de su conclusión."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de las afirmaciones siguientes es correcta?', '["Las Cortes Generales, integradas por el Congreso y el Senado, representan a los partidos políticos y coaliciones electorales que han obtenido algún escaño.", "Las Cortes Generales, integradas por el Congreso, el Senado y las Asambleas Legislativas de las Comunidades Autónomas, representan al pueblo español.", "Las Cortes Generales, integradas por el Congreso y el Senado, representan al pueblo español.", "Las Cortes Generales, integradas por el Congreso, el Senado y el Tribunal Constitucional, representan al pueblo español."]'::jsonb, 2, 'es'),
    ('2a4ba259076b977b77507b8216bd6b29', 'Las Cortes Generales son tratadas en la Constitución:', '["En su Titulo III.", "En su Titulo IV.", "En su Titulo V.", "En su Titulo Vl."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Cortes Generales estarán formadas por órganos:', '["Ejecutivos de naturaleza representativa, deliberante, inviolable y continua.", "Legislativos de naturaleza representativa, resolutiva, inviolable y continua.", "Legislativos de naturaleza sustitutiva, deliberante, inviolable y continua.", "Legislativos de naturaleza representativa, deliberante, inviolable y continua."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El carácter continuo de las Cortes Generales hace referencia a que:', '["Sus órganos ejercen sus funciones de forma ininterrumpida, incluso en vacaciones, excepto en los casos de disolución o expiración del mandato.", "Sus órganos ejercen sus funciones de forma ininterrumpida, incluso en vacaciones y en los casos de disolución o expiración del mandato.", "Los asuntos tratados en ellas deben tramitarse en la misma sesión, sin interrupción alguna.", "Las leyes deben aprobarse en la misma sesión, sin interrupción alguna."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La continuidad de las Cortes Generales se logra mediante la existencia de las llamadas:', '["Comisiones Legislativas.", "Comisiones Permanentes.", "Diputaciones Permanentes.", "Mesas Permanentes."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'EI Senado es la Cámara:', '["De mayor protagonismo en la vida parlamentaria.", "De representación territorial.", "Encargada preferentemente de los asuntos internacionales.", "Consultiva."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué denominación recibe el órgano rector de cada una de las Cámaras legislativas?', '["Comisión Legislativa.", "Comisión Permanente.", "Diputación Permanente.", "Mesa."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Diputaciones Permanentes del Congreso y Senado están formadas, respectivamente, por:', '["21 miembros.", "Un mínimo de 21 miembros.", "Un máximo de 21 miembros.", "21 miembros, pero de la Diputación Permanente del Senado forman parte, además, diecisiete representantes de las Comunidades Autónomas."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién preside cada una de las Diputaciones Permanentes?', '["Los Diputados o Senadores que, a tales efectos, sean elegidos par las propias Cámaras.", "Los Presidentes de cada Cámara.", "Los Vicepresidentes primeros de cada Cámara.", "Los Secretarios primeros de cada Cámara."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El acta del Rey, mediante el cual propone Presidente del Gobierno, y ¿quien debe refrendarlo?', '["El Presidente de las Cortes.", "El Presidente del Congreso.", "El Presidente del Senado.", "El anterior Presidente del Gobierno."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En el supuesto de que ningún candidato a Presidente del Gobierno obtenga la confianza parlamentaria que precisa, ¿quien refrenda la disolución de las Cortes?', '["EI Presidente de las Cortes.", "El Presidente del Congreso.", "El Presidente del Senado.", "El anterior Presidente del Gobierno."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Comisiones legislativas:', '["Solamente debaten los proyectos y proposiciones de Ley, pero su aprobación se somete al Pleno de las Cámaras.", "Pueden aprobar todos los proyectos y proposiciones de Ley, sin limitación alguna.", "Pueden aprobar proyectos y proposiciones de Ley, con ciertas limitaciones o prohibiciones establecidas en el Reglamento de cada Cámara pero no en la Constitución.", "Pueden aprobar proyectos y proposiciones de Ley, con ciertas limitaciones o prohibiciones previstas expresamente en la Constitución."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Comisiones Legislativas, ¿pueden aprobar leyes orgánicas?', '["Si, en todo caso.", "No, en ningún caso.", "Solamente pueden hacerlo con autorización expresa de la Mesa de cada Cámara.", "Solamente pueden hacerlo con autorización expresa de ambas Cámaras, tomada para cada Ley por mayoría absoluta."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Comisiones Legislativas, ¿pueden aprobar leyes de bases?', '["Si, en todo caso", "No, en ningún caso.", "Solamente pueden hacerlo con autorización expresa de la Mesa de cada Cámara.", "Solamente pueden hacerlo con autorización expresa de ambas Cámaras, tomada para cada ley por mayoría absoluta."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Cámaras se reúnen anualmente en dos periodos ordinarios de sesiones:', '["De seis meses cada uno.", "El primero, de enero a junio, y el segundo, de septiembre a diciembre.", "El primero, de septiembre a diciembre, y el segundo, de febrero a junio.", "El primero, de septiembre a diciembre, y el segundo, de febrero a julio."]'::jsonb, 2, 'es'),
    ('dadaf5d59a71b5e405e17158a0bbfb19', 'Las Cámaras pueden reunirse en sesión extraordinaria:', '["Solo durante los periodos ordinarios de sesiones.", "Solo en periodo vacacional.", "En cualquier momento.", "Solo para declarar o autorizar alguno de los estados excepcionales previstos en el art. 116 de la Constitución."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'No pueden solicitar sesiones extraordinarias de las Cámaras:', '["El Gobierno.", "Las respectivas Diputaciones Permanentes.", "La mayoría simple de los miembros de las respectivas Cámaras.", "Ninguna de las respuestas anteriores es correcta."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Normalmente, los acuerdos de las Cámaras se adoptan:', '["Por mayoría simple.", "Por mayoría absoluta.", "Por mayoría de dos tercios.", "Por mayoría de tres quintos."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En el supuesto de que a una sesión del Congreso asistan 200 Diputados, puede aprobarse una Iey que no requiere mayoría cualificada con 10 votos afirmativos, 9 negativos y 181 abstenciones?', '["Si.", "No, porque no hay quórum de asistencia.", "No, porque se requieren, al menos, 101 votos afirmativos.", "No, porque se requiere que voten, afirmativa o negativamente, 101 miembros."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'SI a una sesión del Congreso asisten 120 Diputados, ¿podrá aprobarse una Ley que no requiere mayoría cualificada con 45 votos afirmativos, 5 negativos y 70 abstenciones?', '["Si.", "No, porque no hay quórum de asistencia.", "No, porque se requieren, al menos, 61 votos afirmativos.", "No, porque se requiere que voten, afirmativa o negativamente, 61 miembros."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Una de las siguientes afirmaciones no está bien formulada.', '["El quórum de asistencia a las Cámaras legislativas es de la mitad más uno de los miembros que las componen.", "El voto de los miembros de las Cortes Generales es personal e indelegable.", "Los miembros de las Cortes Generales están ligados por mandato imperativo.", "Nadie puede ser, a la vez, miembro del Congreso y del Senado."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Pueden ser elegidos Diputados o Senadores:', '["El Defensor del Pueblo y sus Adjuntos.", "El Director General de RTVE y los Directores de las sociedades estatales de este Ente Publico.", "El Gobernador y Subgobernador del Banco de España.", "Ninguna de las respuestas anteriores es correcta."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según Ia Constitución, el Congreso estará integrado por un mínimo de:', '["300 y un máximo de 350 Diputados.", "200 y un máximo de 400 Diputados.", "300 y un máximo de 400 Diputados.", "250 y un máximo de 350 Diputados."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los miembros del Congreso son elegidos por un periodo de:', '["Cinco años.", "Cuatro años.", "Tres años.", "Dos años."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Dentro de los Imites mínimo y máximo fijados en la Constitución, el numero de miembros del Congreso es determinado en cada momento por:', '["El Gobierno.", "EI Presidente del Congreso.", "El Tribunal Constitucional.", "Ley."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En la actualidad, el Congreso lo componen:', '["250 Diputados.", "300 Diputados.", "350 Diputados.", "400 Diputados."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'De las siguientes afirmaciones señale la correcta.', '["Los Senadores pueden ser simultáneamente miembros de una Asamblea Legislativa de Comunidad Autónoma.", "Los Diputados pueden ser simultáneamente miembros de una Asamblea Legislativa de Comunidad Autónoma.", "Los Diputados pueden ser al mismo tiempo Senadores.", "Los Diputados y Senadores pueden ser elegidos entre militares profesionales en activo."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿De qué fecha es la vigente Ley orgánica del Régimen Electoral General?', '["19 de junio de 1985.", "1 de enero de 1984.", "17 de julio de 1983.", "21 de septiembre de 1983."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En la elección de Diputados al Congreso, la circunscripción electoral es:', '["La provincia.", "La provincia y las islas.", "La provincia y las ciudades de Ceuta y Melilla.", "La provincia, las islas y las ciudades de Ceuta y Melilla."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En la provincia de Valencia se elegirán:', '["Igual número de Diputados al Congreso que en la provincia de Teruel.", "Mayor número de Senadores que en la provincia de Huelva.", "Mayor número de Diputados al Congreso que en la provincia de Guipúzcoa.", "Son correctas las respuestas b. y c."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Una de las características de la actual organización administrative española es la:', '["Institucionalización.", "Descentralización.", "Concentración.", "Centralización."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según se establece en la LOFAGE, la Administración del Estado posee personalidad Jurídica:', '["Propia.", "Plena.", "Unica.", "Independiente."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cabe hablar de organización periférica en el seno de la Administración de las Comunidades Autónomas?', '["No, en ningún caso.", "Si, en cualquier caso.", "Sí, pero sólo en las Comunidades históricas.", "Si, pero solo en las Comunidades pluriprovinciales."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'No es un ente público territorial:', '["El Estado.", "Una Comunidad Autónoma.", "El Municipio.", "El SENPA."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Dentro de la Administración del Estado, ¿cual de estas organizaciones piramidales es correcta?', '["Gobierno, Ministerio, Servicios, Direcciones Generales, Negociados y Secciones.", "Gobierno, Ministerio, Direcciones Generales, Secciones, Negociados y Servicios.", "Gobierno, Ministerio, Direcciones Generales, Negociados, Secciones y Servicios.", "Gobierno, Ministerio, Direcciones Generales, Servicios, Secciones y Negociados."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En las Comunidades Autónomas, ¿qué denominación reciben las organizaciones que dentro de su territorio asumen funciones similares a los Ministerios estatales?', '["Comisiones.", "Departamentos.", "Consejerías.", "Cámaras."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Una de las características que se mencionan, referidas todas ellas a la Administración estatal, es incorrecta:', '["Posee una personalidad jurídica única.", "Constituye la organización instrumental del Estado concebida coma unidad política.", "Se compone de órganos jerárquicamente subordinados y ordenados en base al principio de mando de línea.", "Se estructura en forma departamental, la cual indica que cada uno de los miembros del Gobierno encabeza una estructura jerárquica denominada Ministerio."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Estado autonómico español no responde al principio de:', '["Autonomía.", "Independencia.", "Solidaridad.", "Variedad."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La libertad de actuación del Estado autonómico se concreta en estas manifestaciones. Señale la incorrecta:', '["La titularidad de potestades normativas.", "La titularidad en materia de competencias específicas.", "La garantía del libre ejercicio de las competencias, o sea, sin intromisiones por parte del Estado.", "Las tres respuestas anteriores son incorrectas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los entes públicos no territoriales integran la denominada Administración:', '["Periférica.", "Autonómica.", "Local.", "Institucional y Corporativa."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los entes institucionales y corporativos, ¿se hallan bajo la tutela de algún ente público?', '["No, en ningún caso.", "Si, bajo la tutela del Estado.", "Si, bajo la tutela de cualquier ente público.", "Si, bajo la tutela de un ente público territorial."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Son entes públicos no territoriales:', '["Los Organismos Autónomos.", "Las Entidades Públicas Empresariales.", "Los colegios profesionales.", "Las tres respuestas anteriores son correctas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En el concepto de ente público es esencial la existencia de:', '["Ingresos propios.", "Personalidad jurídica y patrimonio propios.", "Funcionarios propios.", "Régimen monopolístico."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En cuanto a la Administración institucional rige el principio del:', '["Numerus clausus.", "Numerus apertus.", "Numerus clausus o numerus apertus, según los casos.", "Numerus clausus para las de tipo fundacional y numerus apertus para las de tipo corporativo."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los Organismos Autónomos:', '["No pueden tener ingresos propios.", "Son entes de tipo fundacional.", "Son entes de tipo corporativo.", "Sólo pueden ser estatales."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los Colegios de Médicos:', '["Son entes de tipo fundacional.", "Son entes de tipo corporativo.", "No se hallan bajo la tutela de ningún ente territorial.", "Son correctas las respuestas b. y c."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'De los organismos o establecimientos que a continuación se indican, ¿cuál de ellos no tiene la consideración de ente público?', '["Jefatura de Tráfico.", "Servicio Nacional de Productos Agrarios (SENPA).", "Gerencia de Informática de la Seguridad Social.", "Consejo Superior de Investigaciones Científicas."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La naturaleza jurídica de Radio-Televisión Española es la de:', '["Una sociedad civil.", "Una sociedad mercantil.", "Una sociedad anónima.", "Un ente público."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Por regla general, el personal que presta sus servicios en los Organismos Autónomos es:', '["Funcionario.", "Laboral.", "Mercantil.", "Funcionario, laboral o mercantil."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Por lo general, el personal que presta sus servicios en las Entidades Publicas Empresariales es:', '["Funcionario.", "Laboral.", "Mercantil.", "Funcionario, laboral o mercantil."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Constitución española de 1978:', '["Autoriza la federación de Comunidades Autónomas.", "Prohíbe la federación de Comunidades Autónomas.", "Autoriza la federación de Comunidades Autónomas cuando sean limítrofes y tengan características históricas, culturales y económicas comunes.", "No establece nada en relación a la federación de Comunidades Autónomas."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Diputaciones son:', '["Órganos de gobierno y administración de las provincias.", "Órganos de gobierno y administración de las comarcas.", "Órganos de gobierno y administración de las mancomunidades.", "Órganos de gobierno y administración de las pedanías."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La isla, en los archipiélagos balear y canario, forma parte de:', '["La Administración del Estado.", "La Administración Institucional.", "La Administración Local.", "La Administración Autonómica."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En los Municipios con Comisión de Gobierno el número de Tenientes de Alcalde:', '["No podrá exceder del número de miembros de dicha Comisión.", "No podrá ser superior a cinco.", "No podrá ser superior a la mitad de miembros de dicha Comisión.", "No podrá ser superior a diez."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'No forman parte de la Administración Local:', '["Las comarcas.", "Las provincias.", "Las áreas metropolitanas.", "Las Comunidades Autónomas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué plazo debe transcurrir para que las Comunidades Autónomas puedan ampliar sus competencias, reformando sus Estatutos?', '["Dos años.", "Tres años.", "Cinco años.", "No es necesario que transcurra plazo alguno."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La creación de Áreas Metropolitanas, par las Comunidades Autónomas, ha de hacerse:', '["Mediante Decreto.", "Mediante Ley.", "No corresponde dicha facultad a las Comunidades Autónomas.", "Por Ley o por Decreto, según los casos."]'::jsonb, 1, 'es'),
    ('4306b11ccdff5320e8d87fda3b90c64d', 'Los Alcaldes, según el articulo 140 de la Constitución, serán elegidos por:', '["Los Concejales o los vecinos.", "Las Cortes Generales.", "Los Gobernadores Civiles.", "El Presidente del Gobierno."]'::jsonb, 0, 'es'),
    ('4306b11ccdff5320e8d87fda3b90c64d', 'Según la Constitución, articulo 140, el gobierno y la administración de los municipios corresponde:', '["A sus respectivos Ayuntamientos.", "Al Gobierno de la Nación.", "A los Diputados Provinciales.", "A las personas que designen los respectivos Alcaldes."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Hacienda de las Corporaciones Locales, según la Constitución, se va a nutrir fundamentalmente:', '["De tributos propios.", "De la participación en los tributos del Estado y de las CCAA.", "De la participación exclusiva en los tributos del Estado.", "Tanto a. como b..."]'::jsonb, 3, 'es'),
    ('04455183553c3f44aefd122e098cf856', 'Los recursos del Fondo de Compensación Interterritorial a que hace referencia el articulo 158.2 de la Constitución, serán distribuidos:', '["Por el Gobierno de la Nación entre las Comunidades Autónomas.", "Por las Cortes Generales entre las CCAA y provincias, en su caso.", "Por el Gobierno de la Nación entre las CCAA y provincias, en su caso.", "Por las Cortes Generales entre las CCAA, provincias y municipios."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cual de las siguientes no es una Entidad local territorial.', '["La provincia.", "Las Áreas Metropolitanas.", "Los Organismos Autónomos.", "Las comarcas."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Si ninguno de los candidatos a Alcalde obtiene la mayoría necesaria para ser proclamado Alcalde, ¿que ocurre?', '["Es proclamado Alcalde el que obtuviere la mayoría simple en segunda votación.", "Es proclamado Alcalde el que obtuviere un tercio de los votos en segunda votación.", "Es proclamado Alcalde el Concejal que encabece la lista que haya obtenido mayor número de votos populares en el correspondiente municipio.", "Es proclamado Alcalde el Concejal que elija el Presidente del Gobierno."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Antes de comenzar el ejercicio de sus funciones, el Alcalde deberá Jurar o prometer el cargo ante:', '["El Rey.", "EI Ayuntamiento Pleno.", "Las Cortes Generales.", "El Presidente de la Diputación."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cual de las siguientes materias no entra dentro de las competencias de los municipios?', '["Cementerios.", "Alumbrado público.", "Abastos y mataderos.", "Fuerzas Armadas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Con anterioridad a la Constitución de 1978:', '["Se reconocía el derecho a la autonomía de las nacionalidades, pero no de las regiones.", "Se reconocía el derecho a la autonomía de las regiones, pero no de las nacionalidades.", "Se reconocía el derecho a la autonomía de las nacionalidades y de las regiones.", "No se reconocía el derecho a la autonomía de las nacionalidades ni de las regiones."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Comisión de Gobierno es un órgano que ha de existir necesariamente:', '["En todos los municipios.", "En los municipios con población de derecho superior a 5.000 habitantes.", "En los municipios con población de derecho superior a I 0.000 habitantes.", "Dicha Comisión no es un órgano necesario en los Ayuntamientos."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Cuando el Alcalde se ausente del termino municipal por más de 24 horas sin haber conferido delegación o cuando por causa imprevista le hubiere sido imposible otorgarla ¿quien le sustituirá?', '["EI Presidente del Ayuntamiento.", "La Comisión de Gobierno.", "La persona que designe el Pleno del Ayuntamiento.", "El Teniente de Alcalde a quien corresponda."]'::jsonb, 3, 'es'),
    ('971eab75c602ebdbf689854ede4f018a', '¿En que articulo de la Constitución española de 1978 se reconoce y garantiza el derecho a la autonomía de las nacionalidades y regiones que integran la Nación española?', '["Artículo 2.", "Artículo 143.", "Artículo 137.", "Artículo 151."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Indicar cual de las siguientes afirmaciones es correcta:', '["La diferencia entre los Estatutos de las diferentes Comunidades Autónomas no podrá implicar, en ningún caso, privilegios económicos o sociales.", "Los españoles ostentan diferentes derechos y obligaciones dependiendo del municipio donde habiten.", "Las Comunidades Autónomas pueden obstaculizar la libre circulación de bienes en el territorio español.", "Cualquier Comunidad Autónoma puede impedir el establecimiento en su territorio de españoles de otras Comunidades Autónomas."]'::jsonb, 0, 'es'),
    ('88f687385bed79ed556d261e5b494cb7', '¿En qué artículo de la Constitución española de 1978 se contemplan las competencias que pueden asumir las Comunidades Autónomas?', '["Artículo 149.", "Artículo 148.", "Artículo 151.", "Artículo 137."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Constitución española, el Estado podrá transferir a las Comunidades Autónomas facultades correspondientes a materias de titularidad estatal que por su propia naturaleza sean susceptibles de transferencia. Dicha transferencia se deberá realizar:', '["Mediante Ley ordinaria.", "Mediante Decreto Ley.", "Mediante Ley Orgánica.", "Mediante Decreto Legislativo."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las materias no atribuidas expresamente al Estado por la Constitución podrán corresponder:', '["A las provincias españolas.", "A los municipios que las reclamen.", "A las Comunidades Autónomas, en virtud de sus respectivos Estatutos de Autonomía.", "A las Comunidades Autónomas, mediante Ley Orgánica u ordinaria."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de las siguientes denominaciones de Comunidades Autónomas no es correcta?', '["Asturias.", "Rioja.", "Castilla-La Nueva.", "Castilla-León."]'::jsonb, 2, 'es'),
    ('967c177f0466dc7212becc05a7eab32c', 'La organización territorial del Estado viene recogida en la Constitución:', '["En su Título VIII.", "En su Título VI.", "En su Título V.", "En su Título X."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Estado se organiza territorialmente en:', '["Municipios.", "Municipios, provincias y comarcas.", "Comunidades Autónomas.", "Municipios, provincias y en las Comunidades Autónomas que se constituyan."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las entidades fundamentales que forman la Administración Local son:', '["El Municipio, la Provincia y la Región.", "El Municipio y la Provincia.", "La Comarca y la Provincia.", "La Comarca y el Municipio."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Uno de los siguientes no es un principio general de la organización territorial del Estado:', '["Libertad de circulación.", "Solidaridad.", "Discriminación.", "Igualdad."]'::jsonb, 2, 'es'),
    ('feba4d61a34a3d0ffc926ece6b77e6da', '¿En que articulo de la Constitución se reconoce el derecho a la autonomía de las nacionalidades y regiones que integran la Nación española?', '["En su articulo 137.", "En su articulo 2.", "En su articulo 149.", "En su articulo 158."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La alteración de los limites provinciales deberá ser aprobada:', '["Por las Cortes Generales mediante Ley Orgánica.", "Por la Asamblea Legislativa de la Comunidad Autónoma a que pertenezca la provincia afectada.", "Por las Cortes mediante Ley Ordinaria.", "Por el Gobierno mediante Decreto."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los Concejales de los Ayuntamientos serán elegidos por:', '["EI Presidente de la Diputación.", "El Gobierno.", "Los vecinos del municipio.", "El Alcalde."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los Municipios:', '["Son dependientes del Gobierno.", "Carecen de personalidad jurídica plena.", "Carecen absolutamente de autonomía.", "Gozan de personalidad jurídica plena."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En los archipiélagos, las islas tendrán además su administración propia en forma de:', '["Comisiones Permanentes.", "Delegaciones del Gobierno.", "Juntas Administrativas.", "Cabildos o Consejos."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes es un órgano necesario en los Ayuntamientos de más de 5000 habitantes?', '["La Comisión del Gobierno.", "La Comisión Permanente.", "El Presidente de la Diputación Provincial.", "El Consejo de Gobierno."]'::jsonb, 0, 'es'),
    ('feba4d61a34a3d0ffc926ece6b77e6da', 'El tratamiento constitucional de la Administración Local, ¿en qué artículos de la Constitución se recoge?', '["En los artículos 137, 138 y 139.", "En sus artículos 143 a 150.", "En sus artículos 140, 141 y 142.", "En sus artículos 2, 137, 141 y 149."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿De qué fecha es originaria la vigente Ley de Bases del Régimen Local?', '["De 18 de abril de l 986.", "De I 5 de julio de l 975.", "De 2 de octubre de l 952.", "De 2 de abril de I 985."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cual de los siguientes no es un órgano que ha de existir en las Diputaciones Provinciales?', '["La Comisión de Gobierno.", "EI Pleno de los Diputados.", "El Senado Provincial.", "El Presidente."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'De los siguientes, uno no es un órgano necesario en los Ayuntamientos:', '["El Alcalde.", "Los Tenientes de Alcalde.", "El Pleno.", "La Comisión Permanente."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Administración Local forma parte de:', '["La Administración Central del Estado.", "La Administración Pública.", "La Administración Autonómica.", "La Administración Institucional."]'::jsonb, 1, 'es'),
    ('971eab75c602ebdbf689854ede4f018a', '¿Que articulo de la Constitución española vigente regula expresamente los municipios?', '["El artículo 2.", "EI artículo 137.", "EI artículo 140.", "El artículo 141."]'::jsonb, 2, 'es'),
    ('971eab75c602ebdbf689854ede4f018a', '¿Qué articulo regula la provincia?', '["El artículo 2.", "El artículo 140.", "El artículo 137.", "El artículo 141."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿que Real Decreto Legislativo ha venido a aprobar el texto refundido de las disposiciones legales vigentes en materia de Régimen Local?', '["Ninguno, puesto que esta pendiente de aprobación.", "El Real Decreto Legislativo 7/1985.", "El Real Decreto Legislativo 781/1986.", "Ninguno, pues el indicado texto refundido ha sido aprobado por Ley Orgánica."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Constitución, la provincia es:', '["Una Entidad institucional publica no territorial carente de personalidad.", "Una Entidad Local con personalidad jurídica propia.", "Una Entidad Local no territorial con personalidad jurídica.", "Una Entidad Local con personalidad jurídica derivada y no propia."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la actual Constitución española, la provincia viene determinada por.', '["La agrupación de comarcas y división territorial para el cumplimiento de las actividades del Estado.", "La agrupación de Entidades Locales no territoriales.", "La agrupación de municipios y división territorial para el cumplimiento de las actividades del Estado.", "La agrupación de municipios y división territorial para el cumplimiento de las actividades de las Comunidades Autónomas."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la vigente Constitución española, ¿pueden crearse agrupaciones de municipios diferentes a la provincia?', '["No, por prohibirlo la Constitución.", "Sí.", "Solamente cuando la permita el Gobierno de la Nación, por interés político.", "Si, pero exclusivamente a efectos electorales."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes no es un elemento constitutivo de la provincia?', '["Organización.", "Soberanía.", "Territorio.", "Población."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El territorio provincial está compuesto por:', '["La suma de los territorios municipales de todos los municipios que lo integran.", "La suma de los territorios de las comarcas que la integran.", "La suma de los territorios de las Entidades locales menores que la integran.", "La mitad del territorio de la Comunidad Autónoma donde se encuentra."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Pueden modificarse la denominación y capitalidad de las provincias?', '["No, en ningún caso.", "Si, cuando lo determine el Gobierno.", "Solamente por ley aprobada por las Cortes Generales.", "Solamente cuando lo decida el Presidente de la Corporación."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La población de la provincia viene determinada por:', '["La suma de los residentes de las capitales más importantes que la integran.", "La suma de las poblaciones de los municipios que la integran.", "El número de residentes y transeúntes de la capital de la provincia.", "El número de residentes inscritos en el Padrón Provincial."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En cuál de las siguientes materias no podrán asumir competencias las Comunidades Autónomas?', '["Defensa y Fuerzas Armadas.", "Ordenación del territorio, urbanismo y vivienda.", "Organización de sus instituciones de autogobierno.", "Montes y aprovechamientos forestales."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En cual de las siguientes materias no podrán asumir competencias las Comunidades Autónomas?', '["Asistencia social.", "Artesanía.", "Seguridad e higiene.", "Administración de Justicia."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La reforma de los Estatutos de Autonomía requerirá:', '["La aprobación por las Cortes Generales, mediante Ley Orgánica.", "La aprobación por la Asamblea legislativa de la Comunidad Autónoma respectiva.", "Autorización previa del Gobierno.", "La previa propuesta por parte del Consejo de Gobierno de la Comunidad Autónoma respectiva."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Comunidades Autónomas son:', '["Entes públicos de carácter territorial, sin poder de autogobierno.", "Entes privados de carácter territorial.", "Entes públicos de carácter institucional.", "Entes públicos de carácter territorial dotados de autonomía política y administrativa."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de las siguientes precisiones no se ha de contener necesariamente en los Estatutos de Autonomía?', '["La expresión de las provincias que limitan con la Comunidad Autónoma.", "La denominación de la Comunidad.", "La denominación, organización y sede de las instituciones autónomas propias.", "La delimitación de su territorio."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En cuál de las siguientes materias no podrán asumir competencias las Comunidades autónomas?', '["Legislación sobre propiedad intelectual e industrial.", "Ferias interiores.", "Promoción del deporte.", "Obras publicas de interés de la Comunidad Autónoma en su propio territorio."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Son los Estatutos de Autonomía parte integrante del ordenamiento jurídico estatal?', '["Si, en todo caso.", "En ningún caso.", "No, salvo que así lo acuerden las Cortes Generales por mayoría absoluta.", "Si, con algunas salvedades."]'::jsonb, 0, 'es'),
    ('a8473cff232aa60e058708112efd56bd', '¿Qué camino es más rápido para la elaboración de los Estatutos de las Comunidades Autónomas?', '["El del articulo 4 de la Constitución.", "El del articulo 151 de la Constitución.", "El del articulo 143 de la Constitución.", "EI del articulo 158 de la Constitución."]'::jsonb, 1, 'es'),
    ('12237ba96a770fcb5a967965c77827b5', 'Iniciado el procedimiento para la elaboración de un Estatuto de Autonomía por la vía del articulo 151, y una vez el proyecto de Estatuto ha sido aprobado en cada provincia, ¿cual es el paso siguiente a dar?.', '["Elevarlo al Gobierno de la Nación.", "Someterlo a sanción por el Rey.", "Elevarlo a las Cortes Generales.", "Elevarlo al Presidente del Gobierno para su aprobación."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es la norma institucional básica de cada Comunidad Autónoma?', '["La Constitución Autonómica.", "Su Estatuto de Autonomía.", "La Ley Orgánica que al respecto dicte cada Comunidad Autónoma", "Ninguna pues se somete a todas y cada una de las Leyes del Estado."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de estas frases es verdadera?', '["La Constitución entrará en vigor el día siguiente de su publicación en el BOE.", "La Constitución fue publicada en las lenguas existentes en España.", "La Constitución entró en vigor el día 27 de diciembre de 1978.", "La Constitución Española es flexible."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Nuestra Constitución no tiene:', '["9 Disposiciones Adicionales.", "11 Títulos.", "1 Disposición final.", "169 Artículos."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Fuerzas Armadas, según la Constitución:', '["Defienden la independencia de España, su soberanía y su integridad.", "Garantizan la soberanía e independencia de España y defienden su integridad territorial.", "Garantizan la soberanía e independencia de España y defienden su ordenamiento constitucional.", "Garantizan la integridad de España y su ordenamiento constitucional y defienden su soberanía e independencia."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Constitución Española garantiza:', '["La irretroactividad de todas las normas jurídicas.", "La irretroactividad de las disposiciones sancionadoras que limiten derechos individuales.", "La irretroactividad de las disposiciones sancionadoras no favorables.", "La irretroactividad de las normas favorables no restrictivas de derechos individuales."]'::jsonb, 2, 'es');

  -- Batch 2401-2600
  insert into public.question_bank (content_hash, question, options, correct_index, lang)
  values
    ('4b830eab8fe6b21a82865850ecac45f6', 'La libertad de empresa:', '["No es reconocida expresamente en la Constitución.", "Se reconoce en el marco de la planificación económica estatal, de acuerdo con la Constitución.", "Se reconoce en la Constitución, en el marco de la economía de mercado.", "La reconoce la Constitución, en el marco de la economía capitalista."]'::jsonb, 2, 'es'),
    ('27688c24b51134855be832acefe310a4', 'Según el art. 55 de la Constitución, la suspensión de los derechos fundamentales (arts. 15 a 29) se regularán:', '["Mediante Ley Ordinaria.", "Mediante Ley Orgánica.", "La suspensión será realizada por el juez.", "La Constitución no prevé nada al respecto."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de estos derechos podrá ser suspendido en el estado de alarma?', '["Derecho de reunión.", "Derecho de asociación.", "Derecho de huelga.", "Ningún derecho."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Constitución, la detención preventiva no podrá tener una duración superior a:', '["48 horas.", "36 horas.", "72 horas.", "No lo establece."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los adjuntos y asesores del Defensor del Pueblo:', '["Cesarán automáticamente en el momento de toma de posesión del nuevo Defensor.", "Serán nombrados por el voto favorable de 3/5 partes de los miembros del Congreso.", "Son nombrados y separados por el Presidente del Congreso y del Senado.", "Son elegidos por las Cortes Generales."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La condición de Defensor del Pueblo no es incompatible con:', '["La permanencia como excedente en cualquier Administración.", "El desempeño de funciones directivas.", "El ejercicio de la profesión de abogado.", "La condición de Senador."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Defensor del Pueblo es elegido por:', '["Las Cortes Generales, por 5 años.", "Las Cortes Generales por cada legislatura.", "Las Cortes Generales.", "Referéndum por 5 años."]'::jsonb, 0, 'es'),
    ('95286aa824b18e8857c72287aa97cd4c', 'El Defensor del Pueblo es el Alto Comisionado de las Cortes Generales para la defensa de:', '["La Constitución y el resto del Ordenamiento Jurídico.", "Lo derechos comprendidos en el Título I de la Constitución.", "Los derechos del Título II de la Constitución.", "Las garantías de los derechos y deberes fundamentales."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿A través de qué instrumento jurídico podrán reconocerse las banderas y enseñas propias de cada una de las Comunidades Autónomas?:', '["Por la propia Constitución.", "Por medio de Ley Orgánica de la correspondiente Comunidad Autónoma.", "Por los Estatutos de Autonomía correspondientes.", "Por Ley Ordinaria aprobada en las Cortes Generales."]'::jsonb, 2, 'es'),
    ('1cf384e30cb1ca80449f88fc14235b2a', 'La declaración que hace el artículo 9.1 de la vigente Constitución de que los ciudadanos y demás poderes públicos están sujetos a la Constitución y al resto del ordenamiento jurídico, supone la constitucionalización de:', '["El principio de jerarquía normativa.", "El principio de legalidad.", "El principio de seguridad jurídica.", "Todos los anteriores."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'De los que seguidamente se relacionan, podrá ser exigido ante los Tribunales ordinarios por un procedimiento basado en los principios de preferencia y sumariedad:', '["El derecho de defender a España.", "El derecho a la educación.", "El derecho a contraer matrimonio.", "Todos los anteriores."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de las siguientes funciones está atribuida expresamente por la Constitución al Rey?', '["Elaborar los Presupuestos de su Casa y Familia y los remite a las Cortes Generales.", "Elaborar los Presupuestos Generales del Estado.", "Representar al pueblo español.", "Nombrar libremente a los miembros civiles y militares de su casa."]'::jsonb, 3, 'es'),
    ('d8328ce402b7f69a855c4d8b91460daa', 'Respecto a los actos del Rey, ¿Cuál de las siguientes alternativas es correcta?', '["Los refrenda el Presidente del Gobierno y, en su caso, los Ministros correspondientes.", "Es responsable el Rey de sus propios actos.", "Los actos no necesitan ser refrendados.", "Los refrenda el Presidente del Gobierno, los Ministros, en su caso, y el Presidente del Congreso de los Diputados en la disolución del art. 99."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En el supuesto de que el Rey fuese inhabilitado, ¿quién deberá reconocer dicha inhabilitación?', '["El Tribunal Constitucional.", "El Gobierno de la Nación.", "El Congreso de los Diputados.", "Ninguna es correcta."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Constitución, las abdicaciones a la Corona, ¿cómo se hacen?', '["Mediante el mecanismo previsto en la Constitución.", "Por las Cortes Generales en sesión conjunta de ambas Cámaras.", "Mediante una Ley Orgánica.", "Mediante una Ley Orgánica, si plantean dudas de hecho o de derecho."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Para el Congreso de los Diputados, cada provincia cuenta con:', '["Dos Diputados.", "Un mínimo inicial de dos Diputados.", "Tres Diputados.", "Un mínimo inicial de cuatro Diputados."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuántos Diputados tienen en el Congreso Ceuta y Melilla?', '["Por un Diputado cada una.", "Por un mínimo inicial de un Diputado cada una.", "Por dos Diputados cada una.", "Por un mínimo inicial de dos Diputados cada una."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las elecciones de Diputados al Congreso se efectúan mediante el sistema de candidaturas de listas:', '["Abiertas.", "Cerradas.", "Libres.", "Secretas."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de las características siguientes responde mejor al Sistema de elección de Senadores representantes de provincias?', '["Cada elector puede dar su voto al candidato o candidatos que crea convenientes, existiendo limitación en cuanto al número de candidatos a votar por cada elector.", "Cada elector debe dar su voto a una sola lista de candidatos, sin introducir en ella modificación ni alteración alguna.", "Cada elector solo puede dar su voto al candidato que figura en primer lugar de una lista.", "Cada elector puede dar su voto al candidato o candidatos que crea convenientes, sin que haya limitación alguna en cuanto a los candidatos a votar por cada elector."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de las características siguientes responde mejor al Sistema de listas cerradas?', '["Cada elector debe dar su voto a una sola lista de candidatos, sin introducir en ella modificación ni alteración alguna.", "Cada elector solo puede dar su voto a candidatos que figuren por orden correlativo en la correspondiente lista.", "Cada elector puede dar su voto al candidato o candidatos que crea convenientes, sin que exista limitación alguna.", "Cada elector puede dar su voto al candidato o candidatos que crea convenientes, con un máximo de candidatos a votar por cada elector."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El numero inicial de Diputados del Congreso asignado a cada provincia favorece a las provincias:', '["Menos pobladas.", "Más pobladas.", "Mas pequeñas, territorialmente hablando.", "Mas grandes, territorialmente hablando."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'A partir de la terminación del mandato de las anteriores Cámaras, las elecciones legislativas tienen lugar:', '["Entre los 30 y 60 días.", "Antes de los 60 días.", "Entre los 30 y 90 días.", "Antes de los 90 días."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En que Cámara se aplica la atribución de escaños por el Sistema D''Hondt?', '["En el Congreso.", "En el Senado.", "En ambas Cámaras.", "En ninguna de las Cámaras."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La atribución de escaños por el sistema D''Hondt favorece a:', '["Las provincias menos pobladas.", "Las provincias más pobladas.", "Los partidos políticos y coaliciones mayoritarios.", "Los partidos políticos y coaliciones minoritarios."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Congreso electo, ¿cuándo debe ser convocado?', '["A los veinticinco días de la celebración de las elecciones.", "A los treinta días de la celebración de las elecciones.", "Dentro de los veinticinco días siguientes de la celebración de las elecciones.", "Entre los treinta y sesenta días de la celebración de las elecciones."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En todo caso, quedaran sin escaño en el Congreso aquellas candidaturas que no obtengan en las elecciones, al menos:', '["Un 3 por 100 de los votos validos emitidos en la circunscripción.", "Un 3 por 100 del censo electoral de la circunscripción.", "Un 3 por 100 de los votos emitidos en la circunscripción.", "Un 5 por 100 de los votos emitidos en la circunscripción."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En una determinada provincia, donde deben elegirse seis Diputados al Congreso, se han presentado cinco coaliciones electorales, A, B, C, D y E, habiendo obtenido respectivamente 200.000, 120.000, 50.000, 42.000 y 10.000 votos. En estas condiciones, ¿cuántos Diputados corresponderán a cada una de las citadas coaliciones?', '["A: 4 Diputados; B: 1 Diputados; C: 1 Diputado.", "A: 4 Diputados; B: 2 Diputados.", "A: 3 Diputados; B: 2 Diputados; C: 1 Diputado.", "A: 3 Diputados; B: 1 Diputado; C: 1 Diputado; D: 1 Diputado."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En las elecciones al Senado, la circunscripción electoral es:', '["La provincia.", "La provincia, las islas y las ciudades de Ceuta y Melilla.", "La provincia y las ciudades de Ceuta y Melilla.", "La provincia, las islas con Cabildo o Consejo Insular y las ciudades de Ceuta y Melilla."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Además de las provincias, islas con cabildo o consejo y Ceuta y Melilla, designan Senadores:', '["Los municipios que sean capitales de provincia.", "Los municipios que superen el millón de habitantes.", "Las Comunidades Autónomas.", "Las tres respuestas anteriores son correctas."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuántos Senadores se eligen en cada provincia peninsular?', '["Dos.", "Cuatro.", "Los mismos que en cada provincia insular.", "Son correctas las respuestas b. y c..."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las ciudades de Ceuta y Melilla están representadas cada una por:', '["Un Senador.", "Dos Senadores.", "Tres Senadores.", "Cuatro Senadores."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'A la isla de Gran Canaria le corresponden:', '["Dos Senadores.", "Tres Senadores.", "Cuatro Senadores.", "Cinco Senadores."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Ala isla de Menorca le corresponderán:', '["Dos Senadores.", "Tres Senadores.", "Cuatro Senadores.", "Ninguna de las respuestas anteriores es correcta."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En la provincia de Santa Cruz de Tenerife se eligen:', '["Tres Senadores.", "Cuatro Senadores.", "Cinco Senadores.", "Seis Senadores."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Con independencia de los que le corresponden por Comunidad Autónoma uniprovincial, la provincia de Baleares tiene asignados:', '["Tres Senadores.", "Cuatro Senadores.", "Cinco Senadores.", "Seis Senadore."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Con independencia de los que les correspondan por Comunidad Autónoma, el numero total de Senadores asignados a las tres provincias insulares se eleva a:', '["Diecisiete.", "Dieciséis.", "Quince.", "Catorce."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Con independencia de los que correspondan por Comunidades Autónomas, el número total de Senadores que se asignan a las provincias peninsulares se eleva a:', '["350.", "208.", "188.", "168."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué órgano es competente para designar a los Senadores que representan a las Comunidades Autónomas?', '["El Presidente de la Comunidad Autónoma.", "La Asamblea Legislativa respectiva.", "El Consejo de Gobierno de la Comunidad Autónoma.", "Los Presidentes de las Diputaciones Provinciales de la Comunidad Autónoma."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El número total de Senadores elegidos por las Comunidades Autónomas se eleva aproximadamente a:', '["39.", "48.", "55.", "74."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Prescindiendo de los que representan a las Comunidades Autónomas, ¿cuántos Senadores se eligen en las distintas circunscripciones electorales?', '["350.", "208.", "188.", "168."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Con independencia de los elegidos por las provincias que la integran, ¿cuantos Senadores designará la Comunidad Autónoma de Castilla-León, si tiene una población de 2.700.000 habitantes?', '["Uno.", "Dos.", "Tres.", "Cuatro."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Entre los que se le asignan por provincia y por Comunidad Autónoma uniprovincial, ¿cuántos Senadores corresponden en total a Navarra, si tiene una población de 560.000 habitantes?', '["Cuatro.", "Cinco.", "Seis.", "Siete."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El número total de Senadores elegidos en las distintas circunscripciones electorales y los que representan a las Comunidades Autónomas, se eleva aproximadamente a:', '["243.", "247.", "256.", "350"]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En una provincia peninsular, los electores de Senadores darán su voto:', '["De manera exclusiva a una sola lista.", "A los cuatro candidatos que crean convenientes.", "A los tres candidatos que crean convenientes.", "A un máximo de tres candidatos."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Son proclamados Senadores en cada circunscripción electoral:', '["Los candidatos que resulten de la aplicación del sistema D''Hondt.", "Los cuatro primeros candidatos de la lista que haya obtenido mayor número de votos, excepto en las islas con Cabildo o Consejo insular, y en Ceuta y Melilla.", "Los candidatos que hayan obtenido mayor número de votos.", "Por orden correlativo, los candidatos de la lista que haya obtenido mayor número de votos."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La inmediata puesta a disposición judicial derivada del «habeas corpus», se produce por:', '["Detención ilegal.", "Prisión ilegal.", "Prisión preventiva.", "Detención preventiva."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los Tribunales de Honor están prohibidos respecto de los/la/las:', '["Sindicatos y Organizaciones Profesionales.", "Administración Civil y Militar.", "Organizaciones Profesionales y la primera de estas Administraciones.", "Los anteriores."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'EI secreto profesional, constitucionalmente, sirve para:', '["Ejercer con libertad una profesión titulada.", "La libertad de creación científica y técnica.", "No declarar sobre hechos presuntamente delictivos.", "Todo la anterior."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La fundación de una Internacional Sindical por un sindicato español:', '["Es libre.", "Está prohibida.", "Debe plasmarse en un Tratado Internacional.", "Nada de la anterior es cierto."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El ejercicio del derecho de petición a través de una manifestación ciudadana:', '["No se admite.", "Se admite en algún caso.", "Se admite, salvo para los militares.", "Ni se admite ni se prohíbe."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Nuestro sistema tributario ha de ser:', '["Regresivo e igualitario.", "Progresivo y generalizado.", "Confiscatorio.", "Justo y regresivo."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Se produce una rotura definitiva del vínculo conyugal, debiendo regularse según la Constitución, en caso de:', '["Cese de la convivencia matrimonial.", "Disolución del matrimonio.", "Separación.", "En todos ellas."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Fundaciones son:', '["Patrimonios adscritos a un fin de interés general.", "Administración Corporativa.", "Entidades Privadas con fines de carácter también privado.", "Asociaciones de personas para conseguir fines de interés general."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La asistencia de todo orden a los              hijos  habidos extraconyugalmente:', '["No está prevista en la Constitución.", "Es un deber de los padres.", "Se dispensará por Instituciones de Beneficencia.", "Se dispensa solo a los discapaces."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La especulación urbanística, según la Constitución:', '["Debe evitarse.", "Está permitida", "Genera plusvalías para la colectividad.", "Pueden hacerla los poderes públicos."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'No es susceptible de recurso de amparo el derecho a:', '["Sindicación.", "Investigación científica.", "Secreto de las comunicaciones.", "Lo son todos ellos."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'No es susceptible de recurso de amparo el derecho a', '["Libertad de cátedra.", "Negociación colectiva.", "Manifestación.", "Huelga."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Es susceptible de recurso de amparo el derecho a', '["Libre sindicación.", "Petición.", "Cláusula de conciencia.", "Lo están todos ellos."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Una vez declarado el estado de excepción no se puede suspender el derecho/libertad de:', '["Huelga.", "Enseñanza.", "Adopción de medidas de conflicto colectivo.", "Libertad de circulación."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Durante el estado de excepción, un detenido conserva el derecho de/a:', '["Setenta y dos horas para ser puesto a disposición judicial.", "Secreto de comunicaciones.", "Asistencia de Letrado.", "Ninguno de ellos."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Se puede suspender, con motivo de investigaciones relativas a bandas armadas, el derecho de:', '["Huelga.", "Inviolabilidad del domicilio.", "Libertad de circulación.", "B y c son correctas."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'No puede llevarse a cabo una expropiación forzosa si no:', '["Media una causa de utilidad publica e interés social.", "Se da una indemnización al particular.", "Se regula reglamentariamente.", "A y b son ciertas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los ingresos y gastos del Estado de cada año se contienen en el/los:', '["Planes económicos.", "Decretos que dicte el Gobierno.", "Presupuestos del mismo.", "Nada de lo anterior."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los Presupuestos Generales del Estado se aprueban por:', '["Ley de Cortes.", "Decreto del Gobierno.", "Decreto del Presidente del Gobierno.", "Orden del Ministerio de Economía y Hacienda."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La planificación de la actividad económica, por su parte, debe hacerse a través de:', '["Ley de las Cortes Generales.", "Simple consenso entre el Gobierno y los Consejos de Gobierno de las Comunidades Autónomas.", "Decreto del Ministerio de Economía y Hacienda.", "Acuerdo entre el Gobierno y los Sindicatos y Organizaciones Empresariales."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Pueden crear tributos:', '["Las Cortes Generales.", "Las Corporaciones Locales.", "Los Parlamentos Autonómicos.", "Todos ellos."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'A pesar de la denominación del Titulo I de la Constitución (De los derechos y deberes fundamentales), los derechos fundamentales propiamente dichos se recogen:', '["En la Sección Primera del Capitulo Primero de dicho Titulo.", "En la Sección Segunda del Capitulo Primero de dicho Titulo.", "En la Sección Primera del Capitulo Segundo de dicho Titulo.", "En la Sección Segunda del Capitulo Segundo de dicho Titulo."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Sección primera del capítulo segundo del título I comprende los artículos:', '["15 al 29, ambos inclusive.", "14 al 29, ambos inclusive.", "15 al 55, ambos inclusive.", "14 al 55, ambos inclusive."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La garantía constitucional de que nadie podrá ser privado de la nacionalidad española se asegura:', '["A todos los españoles.", "A los españoles de origen y a los súbditos de países iberoamericanos que han adquirido la nacionalidad española por residencia continuada en España.", "A los españoles de origen y a quienes no poseen doble nacionalidad.", "Solamente a los españoles de origen."]'::jsonb, 3, 'es'),
    ('2b6edcfa0c4ac251d50667a54353381c', 'En el art. 14 de la Constitución se declara que los españoles son iguales ante la Ley, disponiendo que no podrá prevalecer discriminación alguna, entre otras, por razón de:', '["Nacimiento.", "Raza.", "Sexo.", "Las tres respuestas anteriores son correctas."]'::jsonb, 3, 'es'),
    ('2b6edcfa0c4ac251d50667a54353381c', 'Entre las circunstancias citadas en el art. 14 de la Constitución con respecto a la no discriminación, no se cita expresamente:', '["La religión.", "La opinión.", "La edad.", "La raza."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La abolición de la pena de muerte se consagra constitucionalmente:', '["En todos los casos y circunstancias.", "Excepto en lo que puedan disponer las leyes civiles para tiempos de guerra.", "Excepto en lo que puedan disponer las leyes militares para los estados de alarma, excepción y sitio.", "Excepto en lo que puedan disponer las leyes militares para tiempos de guerra."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El aborto:', '["Se menciona en la Constitución por su propio nombre.", "Solamente se permite en nuestro país en determinados casos y circunstancias.", "Se permite en nuestro país sin restricción alguna.", "Ninguna de las respuestas anteriores es correcta."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Libertades ideológicas y religiosas:', '["Son derechos constitucionales sin limitación alguna.", "No se recogen expresamente en la Constitución.", "Son derechos constitucionales con la sola limitación de la que pueda establecer la Ley en los casos de alarma, excepción y sitio.", "Son derechos constitucionales con la sola limitación, en sus manifestaciones, que la necesaria para el mantenimiento del orden público protegido par la ley."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Respecto a su ideología, religión o creencias, ninguna persona puede ser obligada por nadie a manifestarse en tal sentido.', '["Cierto, en todo caso.", "Falso, en todo caso.", "Solo puede ser obligada por Jueces o Tribunales.", "Solo puede ser obligada cuando se trate de asuntos políticos."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La tortura y penas o tratos inhumanos o degradantes atentan contra el derecho:', '["A la libertad personal y seguridad jurídica.", "A la libertad de expresión.", "Al honor y a la intimidad personal y familiar.", "A la vida y a la integridad física y moral."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Constitución, los poderes públicos:', '["Velarán porque el catolicismo tenga carácter estatal.", "Velarán porque todas las confesiones tengan carácter estatal.", "Solamente mantendrán relaciones de cooperación con la Iglesia Católica.", "Mantendrán relaciones de cooperación con la Iglesia Católica y las demás confesiones."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Una de las manifestaciones del derecho a la libertad personal y seguridad Jurídica, consagrado en la Constitución, radica en que la detención preventiva ha de durar:', '["En todo caso, 72 horas.", "En todo caso, 48 horas.", "El tiempo mínimo necesario para la realización de las averiguaciones tendentes al esclarecimiento de los hechos, pero, en todo caso, el detenido deberá ser puesto en libertad o a disposición de la autoridad judicial en el plazo máximo de 72 horas.", "El tiempo mínimo necesario para la realización de las averiguaciones tendentes al esclarecimiento de los hechos, pero, en todo caso, el detenido deberá ser puesto en libertad o a disposición de la autoridad judicial en el plazo máximo de48 horas."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Constitución, respecto al penado:', '["Prohíbe el trabajo remunerado en todos los casos.", "Reconoce el derecho al trabajo remunerado, pero solo cuando se trate de trabajos forzados.", "Prohíbe los trabajos forzados.", "Ninguna de las respuestas anteriores es correcta."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Corno finalidades de las penas privativas de libertad se señalan en la Constitución:', '["La reeducación y reinserción social del penado.", "El arrepentimiento y reinserción social del penado.", "La formación profesional y el arrepentimiento del penado.", "La formación profesional y reeducación del penado"]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Constitucionalmente está consagrado el derecho:', '["Al honor, a la fama y a la propia imagen.", "A la fama, a la intimidad personal y a la propia imagen.", "Al honor, a la intimidad personal y a la propia imagen.", "A la fama, al honor, a la intimidad personal y a la propia imagen."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En la Constitución se proclama que el domicilio es inviolable. No obstante:', '["En todos los casos podrá efectuarse la entrada o registro en el mismo con el consentimiento del titular.", "Además del consentimiento del titular, hace falta en todos los casos resolución judicial.", "Aun con el consentimiento del titular y resolución judicial hay casos en que la entrada o registro no puede legalmente llevarse a cabo.", "Ninguna de las respuestas anteriores es correcta."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'A falta de consentimiento del titular y de resolución judicial, la entrada o registro del domicilio puede llevarse a cabo en caso de:', '["Delito político.", "Fragante delito.", "Delito contra la propiedad.", "Ninguna de las respuestas anteriores es correcta."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Constitución, al limitar el uso de la informática, tiende a garantizar:', '["El honor y la intimidad personal y familiar de los ciudadanos y el pleno ejercicio de sus derechos.", "El secreto de las comunicaciones entre ordenadores por vía telefónica.", "Los derechos de autor en programas informáticos.", "El secreto profesional."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El derecho que asiste a los españoles de salir y entrar en el territorio nacional:', '["Puede ser negado por cualquier motivo.", "Solo puede ser negado por motivos políticos.", "Solo puede ser negado por motivos ideológicos.", "No puede ser negado por motivos ideológicos o políticos."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Uno de los derechos constitucionales que a continuación se mencionan está mal formulado.', '["El derecho a la libertad de expresión mediante la palabra, la prensa y la imprenta.", "El derecho a la producción y creación literaria, artística, científica y técnica.", "El derecho a la libertad de cátedra.", "El derecho a comunicar y recibir libremente información veraz por cualquier medio de difusión. No obstante, el Gobierno podrá ejercer la censura previa en prensa, radio y televisión."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El derecho a la libertad de cátedra quiere indicar que:', '["Las cátedras tienen que adjudicarse por libre designación, esto es, sin previa oposición, concurso o concurso-oposición.", "Los catedráticos tienen derecho a enseñar conforme a sus propios criterios y con los métodos que estimen más convenientes.", "Los catedráticos y profesores tienen derecho a enseñar conforme a sus propios criterios y con los métodos que estimen más convenientes.", "Los alumnos pueden elegir libremente las asignaturas que consideren convenientes para su formación universitaria o profesional."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Constitución, en cuanto al ejercicio del derecho de reunión en lugares no considerados de transito:', '["Lo reconoce sin restricción alguna.", "Exige comunicación previa a la autoridad.", "Exige autorización previa.", "No exige autorización previa."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En los supuestos de ejercicio del derecho de reuniones en lugares de tránsito y manifestaciones, la Constitución exige:', '["Autorización previa, la cual puede no concederse por los motivos que se estimen oportunos.", "Comunicación previa a la autoridad, la cual podrá prohibirla por motivos que estime oportunos.", "Comunicación previa a la autoridad, la cual podrá prohibirla cuando existan razones fundadas de alteración del orden público, con peligro para personas o bienes.", "Autorización previa, la cual puede no concederse cuando existan razones fundadas de alteración del orden público, con peligro para personas o bienes."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Aun cuando en la Constitución se reconoce el derecho de asociación, se prohíben expresamente las asociaciones:', '["Secretas.", "De carácter paramilitar.", "Con fines de lucro.", "Secretas y de carácter paramilitar."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Constitución Española establece el mantenimiento de un régimen de Seguridad Social:', '["Público.", "Privado.", "Complementado por los poderes públicos.", "Tutelado por los poderes públicos."]'::jsonb, 0, 'es'),
    ('88f687385bed79ed556d261e5b494cb7', 'Conforme al artículo 149.1.17º de la C.E., el Estado tiene competencia exclusiva sobre la siguiente materia:', '["Asistencia social.", "Sanidad e Higiene.", "Legislación básica y régimen económico de la Seguridad Social, sin perjuicio de la ejecución de sus servicios por las Comunidades Autónomas.", "Sobre todas las materias señaladas."]'::jsonb, 2, 'es'),
    ('183e5b4b31d7d16991eeafb86513c71f', 'Es cierto que el artículo 41 de la C.E. establece en relación con la Seguridad Social:', '["Que la asistencia y prestaciones complementarias no serán libres.", "El mantenimiento de un régimen de Seguridad Social para quienes realicen actividad laboral, exclusivamente.", "Que la asistencia y prestaciones complementarias serán libres.", "La garantía de prestaciones sólo en situaciones de desempleo."]'::jsonb, 2, 'es'),
    ('95286aa824b18e8857c72287aa97cd4c', 'En la C.E., la protección a la salud se contempla en el Título I, en el Capítulo dedicado a:', '["Los españoles y extranjeros.", "Los principios rectores de la política social y económica.", "Derechos y libertades.", "Garantía de las libertades y derechos fundamentales."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Texto Refundido de la Ley General de la Seguridad Social de 1994 entró en vigor el:', '["20 de junio.", "29 de junio.", "1 de septiembre.", "20 de julio."]'::jsonb, 2, 'es'),
    ('613172bc3ecc3d5634c035bf04e83ac1', 'Conforme al artículo 81 de la Ley General de la Seguridad Social, la titularidad del patrimonio de la Seguridad Social corresponde:', '["Al Estado.", "Al Ministerio de Trabajo y Asuntos Sociales.", "A la Tesorería General de la Seguridad Social.", "A las Entidades Gestoras."]'::jsonb, 2, 'es'),
    ('8af99ad49019582e0833e38b25d40cf6', 'La garantía del percibo de pensiones adecuadas y periódicamente actualizadas a favor de la tercera edad, se recoge:', '["En el artículo 49 C.E.", "En el artículo 50 C.E.", "En el artículo 43 C.E.", "En ninguno de los artículos señalados."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La enajenación de los bienes inmuebles integrados en el patrimonio de la Seguridad Social requerirá autorización de:', '["La Tesorería General de la Seguridad Social.", "Del Ministerio de Trabajo y Asuntos Sociales cuando su valor, según tasación, no exceda de las cuantías fijadas en la Ley de Patrimonio de Estado.", "Del Ministerio de Trabajo y Asuntos Sociales, siempre.", "Del Gobierno, siempre."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Dentro de las competencias del Estado, corresponde al Ministerio de Trabajo y Asuntos Sociales, en relación con las materias reguladas en la Ley General de la Seguridad Social.', '["Proponer al Gobierno los Reglamentos generales para su aplicación.", "La dirección y tutela de las Entidades Gestoras.", "La inspección de la Seguridad Social a través de la Inspección de Trabajo y Seguridad Social.", "Todas las respuestas son correctas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según el articulo primero de la Constitución, ¿cuáles son los valores superiores de su ordenamiento jurídico?', '["La justicia, la libertad, la seguridad jurídica y la legalidad", "La libertad, la igualdad, la justicia y la legalidad.", "La justicia, la libertad, la igualdad y el pluralismo político", "La igualdad, la seguridad, la justicia y la libertad."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Constitución española comienza:', '["En el capítulo primero.", "En el titulo primero.", "En el título preliminar.", "En el preámbulo."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es el modelo de Constitución progresista, cercano a nuestro texto constitucional?', '["La Constitución de 1812.", "La Constitución de 1931.", "La Constitución de 1869.", "La Constitución de 1935."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En el periodo de transición política destaca un texto normativo de fundamental importancia, ¿cuál es?', '["La Ley para la Reforma Política.", "La Ley Fundamental a la Sucesión en la Jefatura del Estado.", "La Ley Orgánica de Referéndum.", "La Ley Orgánica del Estado."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El texto definitivo de la Constitución fue aprobado, en sesiones separadas, por ambas Cámaras, el día:', '["31 de Octubre de 1978.", "30 de Octubre de 1978.", "15 de Junio de 1978.", "29 de Diciembre de 1978."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'De los siguientes caracteres, ¿cuál de ellos califica mejor a la Constitución?', '["Es una Constitución elástica", "Es una Constitución perfectamente acabada", "Es una Constitución de tipo federal", "Es una Constitución muy rígida."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿De cuántos artículos está compuesto el preámbulo de la Constitución?', '["Ninguno.", "Diez.", "Cinco.", "Uno."]'::jsonb, 0, 'es'),
    ('e7635585740de7b10b819c221029a513', 'La Constitución está compuesta de un titulo preliminar y diez títulos; ¿sabes a qué titulo pertenece el enunciado "De las relaciones entre el Gobierno y las Cortes Generales"?', '["Titulo cuarto.", "Titulo quinto.", "Titulo tercero.", "Titulo segundo."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuándo entró en vigor nuestra Constitución?', '["A los veinte días de su publicación en el Boletín Oficial del Estado.", "El mismo día de su publicación.", "EI día 27 de Diciembre de 1978.", "Cuando fue sancionada par el Rey."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los poderes del Estado, según la Constitución, emanan del:', '["Pueblo.", "Del propio ordenamiento jurídico.", "De las Cortes.", "De la Monarquía parlamentaria."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Constitución consta de una disposición final y otra derogatoria, pero, ¿sabes si tiene alguna disposición adicional o transitoria?', '["Tiene cuatro disposiciones adicionales y nueve transitorias.", "Tiene nueve disposiciones adicionales y cuatro transitorias.", "Solo tiene ocho disposiciones transitorias.", "Tiene nueve disposiciones adicionales y ocho transitorias."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El castellano es la lengua oficial y todos los españoles tienen respeto a la misma:', '["El derecho de conocerla.", "El deber de conocerla y el derecho a usarla.", "La obligación de utilizarla.", "El deber de valerse del castellano, corno lengua oficial."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es el instrumento fundamental para la participación política?', '["Las asociaciones de vecinos.", "El referéndum.", "La acción popular.", "Los partidos políticos."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En qué fecha fue sancionada por el Rey la Constitución actual?', '["27 de Noviembre de 1978.", "27 de Diciembre de 1978.", "29 de Diciembre de 1978.", "1 de Enero de 1978."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las bases de la organización militar se regularán mediante:', '["Ley orgánica.", "Real Decreto.", "Ley ordinaria.", "Acuerdo conjunto de ambas cámaras legislativas."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Constitución garantiza, entre otros principios:', '["La irretroactividad de las disposiciones sancionadoras no favorables.", "La irretroactividad de las disposiciones sancionadoras favorables.", "La retroactividad de las disposiciones sancionadoras no favorables.", "La retroactividad general de las disposiciones legales."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Cortes constituyentes se configuraron como resultado de las elecciones celebradas:', '["El día 16 de julio de 1976.", "El día 15 de junio de 1977.", "El día 16 de junio de 1978.", "El día 15 de julio de 1976."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cómo se pudieron celebrar unas elecciones democráticas antes de la vigencia de la Constitución?', '["Utilizando parcialmente la Ley constitutiva de las Cortes anteriores.", "A través de las normas establecidas por el Real Decreto Ley de 18 de marzo de 1977.", "Acudiendo a la Ley republicana reguladora de las elecciones democráticas.", "Mediante la Ley Orgánica del Estado de 1967."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El constitucionalismo español empieza a comienzos del siglo:', '["XIX.", "X.", "XVIII.", "XVII."]'::jsonb, 0, 'es'),
    ('1cf384e30cb1ca80449f88fc14235b2a', 'EI articulo dos de la Constitución compatibiliza la unidad de la nación con un derecho destacado reiteradamente a lo largo de su articulado. ¿Sabes citar algún artículo de la Constitución que aluda a dicho principio?', '["El articulo 9.", "El articulo 137.", "El articulo 24.", "El articulo 167."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es la primera Constitución que efectúa un reconocimiento expreso de los partidos políticos?', '["Constitución de 1812.", "Constitución de 1931.", "Constitución de 1978.", "Constitución de 1845."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En las Constituciones se suelen distinguir dos partes:', '["Una parte dogmática (estructura. y una parte orgánica (estamentos).", "Una parte dispositiva y una parte resolutoria.", "Una parte formal sin articulado y una parte sustancial ordenada en artículos.", "Una parte dogmática (principios y libertades públicas) y una parte orgánica (poderes públicos)."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Cuál es la primera de las denominadas Declaraciones de Derechos que tanto proliferaron a lo largo del siglo XVIII:', '["La Declaración de Derechos de Virginia.", "La Declaración de Derechos del Hombre y del Ciudadano.", "La Declaración de Derechos y Libertades.", "La Proclamación belga de libertades y derechos."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Constitución garantiza el principio de legalidad, ¿qué entiende Vd. por este principio?', '["Que cualquier actuación de los poderes públicos deberá regularse por la Ley.", "El sometimiento de la Administración a la Ley y al derecho.", "Que la Ley ocupa un lugar preeminente sobre otras disposiciones normativas.", "Que las Cortes son las únicas facultadas para hacer normas con rango de Ley."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las garantías jurídicas, como el principio de legalidad, la jerarquía normativa, la seguridad jurídica, vienen reguladas en un fundamental artículo de nuestra Constitución, ¿cuál es?', '["Articulo dos.", "Articulo cinco.", "Articulo ocho.", "Articulo nueve."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿La Constitución tiene un valor normativo directo?', '["No, puesto que ha de desarrollarse reglamentariamente.", "No, ya que existen las leyes de desarrollo.", "Sí.", "Solamente en su parte orgánica."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El proceso de la transición política española culmina con la Ley de Reforma Política, de 4 de Enero de 1977 que va a instrumentalizar el cambio político; pero, ¿sabes de cuántos artículos se integra?', '["Diez artículos.", "Cinco artículos.", "Veinte artículos.", "Cincuenta y cinco artículos."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La propuesta de revisión total de la Constitución requerirá para su aprobación el voto de la mayoría de ambas Cámaras con el quorum de votación de:', '["Los dos tercios de sus miembros.", "Las tres quintas partes.", "La mayoría absoluta.", "La mayoría de los presentes."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'No podrá iniciarse la reforma constitucional en los casos siguientes:', '["Durante la vigencia del estado de alarma.", "Durante la vigencia del estado de excepción.", "Durante la vigencia del estado de sitio.", "Durante la vigencia de alguno de los tres estados citados."]'::jsonb, 3, 'es'),
    ('e7635585740de7b10b819c221029a513', 'Aprobada la reforma parcial de la Constitución, siempre que no afecte al Título Preliminar, a la Corona y a los derechos fundamentales y libertades públicas, ¿será preceptiva su ratificación por referéndum?', '["Si, es obligatoria.", "No, salvo cuando la soliciten una décima parte de los miembros de cualquiera de las Cámaras.", "Si, cuando lo soliciten la mayoría de los miembros de cualquiera de las Cámaras.", "Sí, cuando lo solicite la mayoría absoluta de los miembros de cualquiera de las Cámaras."]'::jsonb, 1, 'es'),
    ('e7635585740de7b10b819c221029a513', 'Si la reforma constitucional afectase al Título Preliminar, al Título II o a los derechos fundamentales y libertades públicas, la ratificación por referéndum, una vez aprobada por las Cortes:', '["Será obligatoria.", "Será potestativa.", "Deberá ser solicitada por la mayoría absoluta de cada Cámara.", "Deberá ser solicitada por la mayoría simple de cada Cámara."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El referéndum de 6 de Diciembre de 1 978 se instrumentalizó a través de una pregunta; ¿cuál fue?', '["¿Aprueba Vd. el nuevo estado de derecho establecido por la Constitución?.", "¿Ratifica Vd. la forma política del Estado establecido por la Constitución?.", "¿Aprueba el proyecto de constitución?.", "¿Acata Vd. el nuevo sistema político?."]'::jsonb, 2, 'es'),
    ('967c177f0466dc7212becc05a7eab32c', 'Si se pretendiera reformar el Titulo VIII de la Constitución, ¿qué quórum de votación por parte de ambas Cámaras sería necesario?', '["Mayoría de tres quintos.", "Mayoría de dos tercios.", "Mayoría simple.", "Mayoría absoluta."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Se dice que la Constitución de 1978 es una Constitución inacabada, ¿por qué?', '["Por su excesiva rigidez.", "Por su carácter no vinculante.", "Por su abundante llamada a la Ley orgánica.", "Por el elevado número de disposiciones transitorias."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'De las siguientes respuestas, ¿cuál de ellas considera Vd. que es la más correcta?', '["Las Cortes aprueban la Constitución.", "EI pueblo español ratifica la Constitución.", "El Rey sanciona la Constitución.", "Todas las respuestas son correctas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las disposiciones adicionales y transitorias de la Constitución están en su mayor parte dedicadas a problemas relacionados con:', '["Los principios rectores del nuevo régimen.", "La garantía de protección de los derechos en el proceso de adecuación política.", "La derogación del ordenamiento jurídico anterior.", "La ordenación del territorio."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El articulo dos de nuestra Constitución plasma una calificación del Estado que se traduce en:', '["Un estado autonómico.", "Un régimen monárquico y parlamentario.", "Un estado social y democrático de derecho.", "Un estado jerarquizado."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué órgano es el intérprete supremo de la Constitución?', '["El Rey.", "El Tribunal Constitucional.", "El Tribunal Supremo.", "El Consejo de Estado."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Una de las diferencias entre regímenes monárquicos y republicanos radica:', '["En que el Monarca esta conferido normalmente de facultades más amplias que el Presidente de la República.", "En el carácter vitalicio del titular de la Corona.", "En la forma de designación de los representantes populares del poder legislativo.", "En que el Monarca asume la titularidad de la Corona, pero no la Jefatura del Estado."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Nuestro país ha conocido:', '["Una etapa republicana.", "Dos etapas republicanas.", "Tres etapas republicanas.", "Cuatro etapas republicanas."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Dentro de las diferentes formas monárquicas, el Rey esta conferido:', '["De las mismas facultades en la Monarquía absoluta que en la constitucional.", "De menores facultades en la Monarquía constitucional que en la parlamentaria.", "De las mismas facultades en la Monarquía constitucional que en la parlamentaria.", "De mayores facultades en la Monarquía constitucional que en la parlamentaria."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Monarquía parlamentaria se caracteriza por el hecho de que el Rey:', '["Comparte con el Parlamento las funciones legislativas.", "Ostenta la Presidencia del Parlamento.", "Debe gozar de la confianza del Parlamento.", "Carece de funciones ejecutivas y legislativas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Una forma política en la que el Rey gobierna no es en ningún caso una Monarquía:', '["Parlamentaria.", "Constitucional.", "Absoluta.", "Soberana."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la vigente Constitución:', '["La forma política del Estado español es la Monarquía parlamentaria.", "El Rey no es el Jefe del Estado.", "EI Rey no ostenta el mando supremo de las Fuerzas Armadas.", "Las tres anteriores son correctas."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Entre las funciones que en la Constitución se atribuyen al Rey se encuentra la de:', '["Nombrar al Presidente del Gobierno, sin más tramites, una vez conocidos los resultados de las elecciones generales.", "Nombrar y separar a los miembros del Gobierno, a propuesta de su Presidente.", "Ejercer el derecho de gracia y conceder indultos generales.", "Las tres respuestas anteriores son correctas."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Corresponde al Rey sancionar y promulgar:', '["Los proyectos de Ley.", "Las proposiciones de Ley.", "Las leyes.", "Las tres respuestas anteriores son correctas."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'De las siguientes afirmaciones hay una que no es correcta respecto a la persona del Rey.', '["Es el símbolo de la unidad del Estado.", "Es responsable de todos sus actos.", "Es el Jefe del Estado.", "Es inviolable."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Rey debe sancionar las leyes en el plazo máximo de:', '["Diez das.", "Quince días.", "Veinte días.", "Treinta días."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Puede el Rey negarse a sancionar las leyes?', '["Si, en todo caso.", "No, en ningún caso.", "Sólo cuando sean claramente inconstitucionales.", "Sólo cuando impidan el ejercicio de derechos fundamentales."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La sanción de las leyes:', '["Debe ser refrendada par el Presidente del Congreso de los Diputados.", "Debe ser refrendada par el Presidente del Senado.", "Debe ser refrendada por el Presidente del Gobierno.", "No necesita refrendo."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Entre las funciones del Rey no figura la de:', '["Proponer el candidato a la Presidencia del Gobierno.", "Proponer el nombramiento de los miembros del Gobierno.", "Convocar las Cortes Generales.", "Convocar elecciones."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Rey convocara el Congreso de los Diputados:', '["Dentro de los veinticinco días siguientes a la celebración de las elecciones.", "Dentro de los veinte días siguientes a la celebración de las elecciones.", "Dentro de los quince días siguientes a la celebración de las elecciones.", "No es función del Rey convocar el Congreso."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Corona de España es hereditaria en los sucesores:', '["De la dinastía borbónica.", "De S.M. don Alfonso XIII.", "Del Príncipe de Asturias.", "De S.M. don Juan Carlos I de Borbón."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'No caracteriza a la Corona de España:', '["Simbolizar la unidad y permanencia del Estado.", "La Presidencia ordinaria del Consejo de Ministros.", "El mando supremo de las Fuerzas Armadas.", "Las tres respuestas anteriores son correctas."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Puede una mujer ostentar la titularidad de la Corona de España?', '["Si, pero solo como Reina consorte.", "Si, y con mayor probabilidad que los varones.", "Si, con igual probabilidad que los varones.", "Si, pero con menor probabilidad que los varones."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Reina consorte o el consorte de la Reina, ¿pueden asumir funciones constitucionales?', '["Si, en todo caso.", "No, en ningún caso.", "No, salvo lo dispuesto para la Regencia.", "Si, en todo caso, pero con la expresa autorización de las Cortes Generales."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Constitución, la sucesión en el trono seguirá el orden:', '["Descendente, nunca ascendente.", "Regular de las líneas establecidas en Derecho común para la herencia.", "Regular de primogenitura y representación.", "Regular de líneas y grados."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En Ia sucesión el trono:', '["Dentro del mismo grado de parentesco se prefiere siempre la persona de más edad a la de menos.", "Dentro del mismo grado de parentesco se prefiere el varón a la mujer.", "Se prefiere en todos los casos la persona de más edad a la de menos.", "Se prefiere en todos los casos el varón a la mujer."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Príncipe heredero de la Corona de España tiene la dignidad de:', '["Príncipe de España.", "Príncipe de Asturias.", "Príncipe de España y los demás títulos vinculados tradicionalmente al sucesor de la Corona de España.", "Príncipe de Asturias y los demás títulos vinculados tradicionalmente al sucesor de la Corona de España."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En el supuesto de que se extingan todas las líneas Ilamadas en Derecho a la sucesión a la Corona de España:', '["Decidirán las Cortes Generales.", "Decidirá el pueblo en referéndum.", "Se nombrará Rey al Regente.", "Ninguna de las respuestas anteriores es correcta."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Puede ostentarse el cargo de Rey siendo menor de edad?', '["Si.", "Si, pero para ello se precisa la expresa autorización de las Cortes Generales.", "No, porque el Rey será en todo caso el Regente.", "No, porque el Rey era en todo caso su tutor."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'De acuerdo con la Constitución, una persona con derechos sucesorios al trono quedaría automáticamente excluida en la sucesión a la Corona si contrae matrimonio contra la expresa prohibición:', '["Del Rey.", "De las Cortes Generales.", "Del Rey o de las Cortes Generales.", "Del Rey y de las Cortes Generales."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las abdicaciones, renuncias y dudas que surjan en el orden de sucesión a la Corona deberán resolverse por:', '["La Casa de Su Majestad el Rey.", "Ley orgánica.", "Ley ordinaria.", "El Consejo de Ministros."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Para merecer la Regencia, ¿se exige en la Constitución algún requisito especial?', '["No, ninguno.", "Si, ser español de nacimiento y mayor de edad.", "Si, ser español y mayor de edad.", "Si, ser mayor de edad."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Regente ejerce las funciones del Rey mientras este:', '["Sea menor de edad.", "Se encuentre inhabilitado para el ejercicio de sus funciones.", "Sea menor de edad o se encuentre inhabilitado para el ejercicio de su autoridad.", "Ninguna de las respuestas anteriores es correcta."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En el supuesto de que el Rey fuera menor de edad, la Regencia seria ejercida en primer lugar:', '["Por su padre o madre.", "Por la persona mayor de edad más próxima a suceder en la Corona.", "Por su abuelo paterno.", "Por la persona que en su testamento hubiese nombrado el Rey difunto."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Si no vivieran el padre o madre, la Regencia se ejercería:', '["Por la persona más próxima a suceder en la Corona.", "Por la persona que en su testamento hubiese nombrado el Rey difunto.", "Por el abuelo paterno del Rey.", "Por la persona mayor de edad más próxima a suceder en la Corona."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En el caso de que el Rey mayor de edad se inhabilitare para el ejercicio de su autoridad, la Regencia seria ejercida en primer lugar:', '["En todo caso, por el Príncipe heredero.", "Por el padre del Rey.", "Por el Príncipe heredero, si es mayor de edad.", "Por la persona de más edad más próxima a suceder en la Corona."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Para que la inhabilitación del Rey se lleve a efecto, es preciso que sea reconocida por.', '["Las Cortes Generales.", "El Gobierno.", "Las Cortes Generales o el Gobierno.", "Las Cortes Generales y el Gobierno."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'De no existir persona a quien corresponda la Regencia, ¿qué órgano es competente para nombrarla?', '["Las Cortes Generales.", "El Gobierno.", "Las Cortes Generales o el Gobierno.", "Las Cortes Generales y el Gobierno."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'De no existir persona a quien corresponda la regencia, ¿cuantas personas deben ser nombradas para ejercer la Regencia?', '["Una, en todo caso.", "Varias, en todo caso.", "Una, tres o cinco, que sean parientes del Rey.", "Ninguna de las respuestas anteriores es correcta."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Por vía testamentaria, ¿puede el Rey nombrar Regente del nuevo Rey?', '["No, puesto que aunque lo nombrara, no tendría validez alguna.", "Sí, y en todo caso tendría plena validez.", "Sólo si la autorizan las Cortes Generales.", "Sólo si la autoriza el Gobierno."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En el supuesto de que el padre del Rey contrajera nuevo matrimonio desempeñando la Regencia:', '["No hay ningún impedimento para que la siga desempeñando.", "Tendría que renunciar al cargo y las Cortes Generales nombraran un nuevo Regente.", "Tendrá que renunciar al cargo y la Regencia pasaría a ejercerse por el pariente del Rey mayor de edad más próximo a suceder en la Corona.", "Tendrá que renunciar al cargo y el tutor del Rey será automáticamente el nuevo Regente."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Por vía testamentaria, ¿puede el Rey nombrar tutor del nuevo Rey?', '["Sí.", "No.", "Sólo si lo autoriza el Gobierno.", "Sólo si lo autorizan las Cortes Generales."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los cargos de Regente y de tutor del Rey, ¿pueden ostentarse simultáneamente por la misma persona?', '["Nunca.", "Si, en todo caso.", "Solo si recaen sobre el padre o la madre del Rey.", "Solo si recaen sobre el padre, la madre o un ascendiente directo del Rey."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En su caso, el cargo de tutor del Rey será desempeñado en primer lugar:', '["Por el padre o la madre del Rey.", "Por la persona que en su testamento hubiese nombrado el Rey difunto.", "Por la persona mayor de edad más próxima a suceder en la Corona.", "Por la persona que nombren las Cortes Generales."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El cargo de tutor del rey será desempeñado en primer lugar por la persona que figure en el testamento, pero ¿precisa algún requisito especial?', '["No, ninguno.", "Si, ser español de nacimiento y mayor de edad.", "Si, ser español y mayor de edad.", "Si, ser mayor de edad."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En defecto de la persona a que se refieren las dos preguntas anteriores, ¿quien desempeñaría el cargo de tutor del Rey?', '["El padre o la madre del Rey.", "La persona que en su testamento hubiese nombrado el Rey difunto.", "La persona de más edad más próxima a suceder en la Corona.", "El padre o la madre del Rey, mientras permanezcan viudos."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Si el padre del Rey contrae matrimonio al tiempo de desempeñar el cargo de tutor del Rey:', '["No hay ningún impedimento para que lo siga ejerciendo.", "Tendrá que renunciar al cargo y las Cortes Generales nombraran a un nuevo tutor.", "Tendrá que renunciar al cargo y este pasaría a ejercerse por el pariente del Rey mayor de edad más próximo a suceder en la Corona.", "Tendrá que renunciar al cargo y éste pasaría a ejercerse por el Regente."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'De no existir nadie a quien legalmente corresponda el cargo de tutor del Rey, ¿cuantas personas serán nombradas por el órgano competente para ejercer tal cargo?', '["Una sola.", "Varias.", "Una, tres o cinco, parientes del Rey.", "Una, tres o cinco."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En todo caso, el ejercicio de la tutela del Rey es incompatible con el:', '["De la Regencia.", "De Diputado o Senador.", "Desempeño de toda actividad comercial, financiera o industrial.", "Son correctas las respuestas b. y c."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El tutor del Rey:', '["Ejerce las funciones del Rey mientras este es menor de edad.", "Ejerce las funciones del Rey mientras este se encuentra inhabilitado para el ejercicio de su autoridad.", "Desempeña funciones de representación privada del Rey.", "Las tres respuestas anteriores son correctas."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En el caso de que contrajera matrimonio la hermana mayor del Rey estando desempeñando las funciones de Regente y tutor del Rey:', '["No hay impedimento alguno para que las siga desempeñando.", "Deberá renunciar a ambos cargos.", "Deberá renunciar al cargo de Regente, pero no al de tutor.", "La situación aludida es inconstitucional."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Rey no puede:', '["Distribuir libremente la cantidad global que recibe para el sostenimiento de su Familia y Casa Real.", "Declarar la guerra a otros países, ni aun con autorización de las Cortes Generales.", "Conceder indultos generales.", "Presidir las sesiones del Consejo de Ministros, a petición del Presidente del Gobierno."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La cantidad global destinada al sostenimiento de la Familia y Casa Real:', '["Debe ser justificada posteriormente por el Monarca, con indicación de las partidas que han sido asignadas.", "No figura en los Presupuestos Generales del Estado, lo cual indica que se concede por el Gobierno sin aprobación parlamentaria.", "Figura en los Presupuestos Generales del Estado, por lo que se concede con aprobación parlamentaria.", "Son correctas las respuestas a. y c."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La irresponsabilidad del Rey se circunscribe:', '["A todas sus actuaciones, sean publicas o privadas.", "A las actuaciones ejercidas en el desempeño de su cargo.", "Exclusivamente a sus actuaciones refrendadas.", "Exclusivamente a sus actuaciones sin refrendo."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Por medio del refrendo, de los actos del Rey se responsabilizan:', '["Las Cortes Generales.", "El Gobierno.", "El Gobierno o las Cortes Generales.", "Las personas que la otorgan."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los actos del Rey deben ser refrendados por:', '["El Presidente del Gobierno.", "Los Ministros.", "El Presidente del Congreso de los Diputados.", "Todos los citados, según los casos y circunstancias."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los actos del Rey sin refrendo:', '["Carecen siempre de validez, sin excepción alguna.", "Carecen de validez, excepto los actos relativos al nombramiento y cese de los miembros civiles y militares de su Casa Real.", "Carecen de validez, excepto los actos relativos al nombramiento y cese de los miembros civiles y militares de su Casa Real, y los que se refieran a la concesión de honores y distinciones con arreglo a las leyes.", "Trasladan la responsabilidad a las personas que constitucionalmente debían prestar el refrendo."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La propuesta y nombramiento del Presidente del Gobierno, ¿quien deberá refrendarla?', '["El anterior Presidente del Gobierno.", "El Ministro de Relaciones con las Cortes.", "El Presidente del Congreso.", "Ninguno de los citados."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Respecto a la dimisión del Rey:', '["Solo puede decretarla el Gobierno, previa autorización de las Cortes Generales por mayoría absoluta.", "Solo pueden decretarla las Cortes Generales, por mayoría simple.", "Solo pueden decretarla las Cortes Generales, por mayoría absoluta.", "Constitucionalmente, nadie puede obligar al Rey a dimitir."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La organización territorial del Estado se contempla fundamentalmente en la Constitución en el Titulo:', '["Vl.", "VII.", "VIII.", "IX."]'::jsonb, 2, 'es'),
    ('44cc9e46336e3d76940017f17f9a8879', 'Para las Comunidades Autónomas, en la Constitución se establece coma vías de acceso a la autonomía:', '["La general u ordinaria del art. 143; la del art. 145; y la del art. 151.", "La general u ordinaria del art. 143; la del art. 144; y la del art. 151.", "La general u ordinaria del art. 143; la del art. 144; la del art. 151; y la del art. 144, mejorado.", "La general u ordinaria del art. 143; la del art. 144; la del art. 151; y la del art. 151,mejorado."]'::jsonb, 1, 'es'),
    ('44cc9e46336e3d76940017f17f9a8879', 'La mayoría de las Comunidades Autónomas existentes accedieron a la autonomía por la vía:', '["General u ordinaria del art. 143.", "Del art. 144.", "Del art. 145.", "Del art. 151."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los Estatutos de Autonomía son definidos en la Constitución como la norma institucional básica:', '["Del Estado de las Autonomías.", "De cada Comunidad Autónoma, pero no integrantes del ordenamiento jurídico estatal.", "De cada Comunidad Autónoma y parte integrante del ordenamiento jurídico estatal.", "De les Comunidades Autónomas y de la Administración Local."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los Estatutos de Autonomía deben plasmarse en:', '["Leyes de Bases.", "Leyes orgánicas.", "Leyes ordinarias.", "Leyes de transferencias."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Actualmente, de los Estatutos de Autonomía posibles, se han aprobado:', '["Todos.", "Todos, excepto los de los Cabildos Insulares.", "Todos, excepto los de Ceuta y Melilla.", "Todos, excepto los de los Consejos Insulares."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las ciudades de Ceuta y Melilla, se han constituido en Comunidades Autónomas?', '["No.", "Si.", "Solo Ceuta.", "Sólo Melilla."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Constitución, la denominación de la Comunidad Autónoma será:', '["Libre.", "La que mejor corresponda a su identidad histórica.", "La que decidan los órganos de gobierno de la propia Comunidad.", "La que mejor corresponda a su identidad propia."]'::jsonb, 1, 'es'),
    ('88f687385bed79ed556d261e5b494cb7', 'Las materias sobre las que el Estado tiene competencia exclusive vienen enumeradas en la Constitución:', '["En el art. 149.1.", "En el art. 148.1.", "En el art. 150.", "En un artículo distinto de los anteriores."]'::jsonb, 0, 'es'),
    ('88f687385bed79ed556d261e5b494cb7', 'Las materias sobre las que las Comunidades Autónomas puede asumir competencias desde su constitución vienen enumeradas en el texto constitucional:', '["En el art. 149.1.", "En el art. 148.1.", "En el art. 150.", "En un artículo distinto de los anteriores."]'::jsonb, 1, 'es');

  -- Batch 2601-2800
  insert into public.question_bank (content_hash, question, options, correct_index, lang)
  values
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Comunidades Autónomas                    pueden  asumir competencias en materia de:', '["Sanidad e higiene.", "Legislación sobre pesas y medidas.", "Administración de Justicia y derecho de asilo.", "Son correctas las respuestas a. y c."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las competencias sobre ferrocarriles:', '["Son exclusivas del Estado.", "Pueden ser asumidas por las Comunidades Autónomas en el caso de trenes de vía estrecha.", "Pueden ser asumidas par las Comunidades Autónomas cuando su itinerario se desarrolle íntegramente en su territorio.", "Pueden ser asumidas por una Federación de Comunidades Autónomas cuando su itinerario se desarrolle íntegramente en el territorio de las Comunidades Federadas."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La competencia sobre los puertos:', '["Es exclusiva del Estado.", "Es exclusiva de las Comunidades Autónomas.", "Puede ser asumida por las Comunidades Autónomas cuando se trate de puertos de refugio, puertos y aeropuertos deportivos y, en general, los que no desarrollen actividades comerciales.", "Ninguna de las respuestas anteriores es correcta."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Pueden ser creados Cuerpos de policía propios por parte de las Comunidades Autónomas?', '["No, en ningún caso.", "Sí, en todo caso.", "Si, pero la forma que se establezca en sus respectivos Estatutos y en el marco de lo que disponga una Ley ordinaria.", "Si, pero en la forma que se establezca en sus respectivos Estatutos y en el marco de lo que disponga una Ley orgánica."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En cuanto a la convocatoria de consultas populares por vía de referéndum:', '["La actuación en todo lo que concierne a esta materia corresponde con exclusividad al Estado.", "Puede ser asumida por las Comunidades Autónomas, aunque la autorización para celebrarlas es competencia exclusiva estatal.", "Puede ser asumida par las Comunidades Autonomías de acuerdo con lo que disponga en una Ley de Bases.", "Puede ser realizada por las Comunidades Autónomas sin necesidad de autorización estatal."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Indique cual de las competencias que a continuación se expresan no es exclusiva del Estado.', '["La legislación básica sobre montes, aprovechamientos forestales y vías pecuarias.", "La promoción del deporte y de la adecuada utilización del ocio.", "Dictar las bases del régimen estatutario de los funcionarios de las Comunidades Autónomas.", "Dictar las normas básicas del régimen de prensa, radio y televisión, en general, de todos los medios de comunicación social."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En todo caso, el Derecho estatal:', '["Prevalece sobre el Derecho de las Comunidades Autónomas.", "Es supletorio del Derecho de las Comunidades Autónomas.", "Estará armonizado con el Derecho de las Comunidades Autónomas.", "Ninguna de las anteriores es correcta."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Son órganos institucionales autonómicos:', '["La Asamblea Legislativa, el Delegado del Gobierno, el Consejo de Gobierno y el Presidente de la Comunidad.", "La Asamblea Legislativa, el Consejo de Gobierno, el Presidente de la Comunidad y los Presidentes de las Diputaciones Provinciales.", "La Asamblea Legislativa, el Consejo de Gobierno y el Presidente de la Comunidad.", "La Asamblea Legislativa, el Consejo de Gobierno, el Tribunal Superior de Justicia y el Presidente de la Comunidad."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La suprema representación de la Comunidad Autónoma recae sobre:', '["El Presidente de la Comunidad.", "El Presidente de la Asamblea Legislativa.", "El Delegado del Gobierno en la Comunidad Autónoma.", "El Presidente del Tribunal Superior de Justicia."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'AI Presidente de la Comunidad Autónoma le corresponde:', '["La Presidencia de la Asamblea Legislativa.", "La dirección del Consejo de Gobierno.", "La Presidencia del Tribunal Superior de Justicia.", "Las tres anteriores son correctas."]'::jsonb, 1, 'es'),
    ('17b0de0db55795b44abc1d0057137f31', 'El Tribunal Superior de Justicia de las Comunidades Autónomas es un órgano:', '["Estatal, previsto en el art. 152 de la Constitución.", "Autonómico.", "Exclusivamente con competencia civil.", "Estatal, previsto en el art. 81 de la Constitución."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La representación ordinaria del Estado en la Comunidad la ostenta:', '["El Presidente de la Comunidad.", "EI Presidente de la Asamblea Legislativa.", "El Delegado del Gobierno en la Comunidad Autónoma.", "El Presidente del Tribunal Superior de Justicia."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'EI control de los actos administrativos y de las normas reglamentarias de las Comunidades Autónomas corresponde:', '["A la jurisdicción contencioso-administrativa.", "Al Tribunal Constitucional.", "Al Gobierno de la Nación.", "A los órganos jurisdiccionales propios de las Comunidades Autónomas."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Presidente de la Comunidad Autónoma es elegido por:', '["Sufragio universal, libre, igual, directo y secreto en los términos que establece la Ley.", "La Asamblea Legislativa de la Comunidad, de entre sus miembros.", "El Consejo de Gobierno de la Comunidad, de entre sus miembros.", "La Asamblea Legislativa de la Comunidad, pero sin que necesariamente tenga que serlo de entre sus miembros."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los miembros de las Asambleas Legislativas de las Comunidades Autónomas son elegidos:', '["Por los Alcaldes de los municipios que las integran.", "Por sufragio universal.", "Por las Cortes Generales.", "Por los Concejales electos de los municipios que las integran."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En la Constitución se establece que la elección de los miembros de las Asambleas Legislativas de las Comunidades Autónomas debe realizarse mediante un sistema de representación proporcional que asegure, en todo caso, la representación:', '["De los diversos Municipios del territorio.", "De las Provincias del territorio.", "De los diversos partidos judiciales del territorio.", "De las diversas zonas del territorio."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Presidente de la Comunidad responde de su gestión política ante:', '["Las Cortes Generales.", "La Asamblea Legislativa de la Comunidad Autónoma.", "El Tribunal Superior de Justicia de la Comunidad Autónoma.", "El Presidente del Gobierno de la Nación."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Comunidades Autónomas pueden obtener recursos:', '["Por recargos sobre impuestos estatales.", "Mediante el establecimiento de sus propios impuestos.", "Por rendimientos de sus bienes patrimoniales.", "Las tres respuestas anteriores son correctas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La adopción de medidas tributarias por parte de las Comunidades Autónomas sobre bienes situados fuera de su territorio tiene que ser previamente autorizada por:', '["Las Cortes Generales, mediante ley orgánica.", "Las demás Comunidades Autónomas afectadas.", "El Consejo de Ministros, a propuesta del Ministro de Economiza y Hacienda.", "La pregunta esta mal formulada, dado que la adopción de tales medidas esta expresamente prohibida en la Constitución."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El control de la actividad económica y presupuestaria de los órganos e instituciones de las Comunidades Autónomas la ejerce:', '["El Tribunal de Cuentas.", "La jurisdicción contencioso-administrativa.", "El Gobierno de la Nación.", "El Tribunal Constitucional."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los miembros del Consejo de Gobierno responden de su gestión política ante:', '["Las Cortes Generales.", "La Asamblea Legislativa de la Comunidad Autónoma.", "El Tribunal Superior de Justicia de la Comunidad Autónoma.", "El Presidente del Gobierno de la Nación."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La creación del denominado Fondo de Compensación Interterritorial responde al principio de:', '["Igualdad.", "Solidaridad.", "Suficiencia financiera.", "desconcentración."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los recursos del Fondo de Compensación Interterritorial son distribuidos entre las distintas Comunidades Autónomas:', '["Por las Cortes Generales.", "Por el Tribunal de Cuentas.", "De mutuo acuerdo por todas ellas.", "Proporcionalmente a la población de derecho de cada una."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Constitución, los recursos del Fondo de Compensación Interterritorial serán distribuidos entre las Comunidades Autónomas y, en su caso, entre:', '["Los Municipios.", "Las Mancomunidades de Municipios.", "Las Comarcas.", "Las Provincia."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las cantidades recibidas par las Comunidades Autónomas del Fondo de Compensación Interterritorial:', '["Pueden destinarse a cualquier clase de gasto.", "Deben destinarse a gastos de inversión.", "Deben destinarse al sector agrícola.", "Deben destinarse a la amortización de deudas."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Puede el Estado transferir o delegar en las Comunidades Autónomas facultades de titularidad estatal?', '["Nunca, en ningún caso.", "Sólo en favor de las Comunidades históricas.", "Si, en todos los casos.", "Si, pero siempre que se trate de materias susceptibles de transferencia o delegación."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Una ley marco se caracteriza por:', '["Transferir o delegar en las Comunidades Autónomas facultades correspondientes a materias de titularidad estatal.", "Establecer los principios necesarios para armonizar las disposiciones normativas de las Comunidades Autónomas, aun en el caso de materias atribuidas a la competencia de estas últimas.", "Atribuir a las Comunidades Autónomas, en materia de titularidad estatal, la facultad de dictar para sí mismas normas legislativas dentro de unos principios, bases y directrices.", "Atribuir a las Comunidades Autónomas, en materia de titularidad estatal o autonómica, la facultad de dictar para sí mismas normas legislativas dentro de unos principios, bases y directrices."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las leyes marco:', '["Son leyes ordinarias.", "Son leyes orgánicas.", "Requieren mayoría de tres quintos en Congreso y Senado.", "Requieren mayoría de dos tercios en Congreso y Senado."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las normas legislativas que, al amparo de las leyes marco, emanen de las Comunidades Autonómicas, serán en todo caso controladas por:', '["Las Cortes Generales.", "El Tribunal Constitucional.", "Los Tribunales Superiores de Justicia.", "La jurisdicción contencioso-administrativa."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Mediante una Ley de transferencias, las Comunidades Autónomas asumen facultades correspondientes a materias de titularidad:', '["Estatal que, por su propia naturaleza, son susceptibles de transferencia o delegación.", "Estatal que, por su propia naturaleza, no son susceptibles de transferencia o delegación.", "Autonómica previstas en sus propios estatutos.", "Autonómica no previstas en sus propios Estatutos."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las leyes de transferencias:', '["Son leyes ordinarias.", "Son leyes orgánicas.", "Requieren mayoría de tres quintos en Congreso y Senado.", "Requieren mayoría de dos tercios en Congreso y Senado."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La finalidad de una Ley de armonización es la de:', '["Refundir en un solo texto legal las disposiciones normativas de las Comunidades Autónomas.", "Dar uniformidad a las disposiciones normativas de las Comunidades Autónomas.", "Dotar de flexibilidad a las disposiciones normativas de las Comunidades Autónomas.", "Atribuir a las Comunidades Autónomas de la facultad de dictar para si mismas disposiciones normativas."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Para que pueda dictarse una Ley de armonización es preciso que:', '["Lo soliciten dos o más Asambleas Legislativas de Comunidades Autónomas.", "Lo solicite el Gobierno de la Nación.", "Lo exija el interés general, circunstancia que debe ser apreciada par las Cortes Generales por mayoría simple.", "Lo exija el interés general, circunstancia que debe ser apreciada por las Cortes Generales por mayoría absoluta."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las leyes de armonización:', '["Son leyes ordinarias", "Son leyes organicas.", "Requieren mayoría de tres quintos en Congreso y Senado.", "Requieren mayoría de dos tercios en Congreso y Senado."]'::jsonb, 0, 'es'),
    ('2b6edcfa0c4ac251d50667a54353381c', 'El recurso de amparo procede para la protección de los derechos y libertades reconocidos en los artículos 14 a 29 de la Constitución, y además a:', '["El derecho de propiedad.", "La objeción de conciencia.", "El derecho del trabajo de los españoles no sometidos a pena privativa de libertad.", "El derecho a la protección de la salud."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El nombramiento de Delegados del Gobierno en las comunidades autónomas será:', '["Por Real Decreto acordado por el Presidente del Gobierno.", "Por Real Decreto acordado en Consejo de Ministros a propuesta del Presidente del Gobierno.", "Nombrado por el Rey, tras oir al Presidente del Gobierno.", "Nombrado por el Presidente de Gobierno, a propuesta del Ministro del Interior."]'::jsonb, 1, 'es'),
    ('95286aa824b18e8857c72287aa97cd4c', '¿El ejercicio del derecho a sindicarse libremente, podría regularse a través de un Decreto-Ley?', '["Sólo en caso de necesidad y urgencia.", "Sí, con autorización del Congreso de los Diputados.", "En ningún caso, al tratarse de un derecho fundamental regulado en el Título I de la Constitución.", "Sí, cuando se tramite por el procedimiento de urgencia."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Se distingue entre parte dogmática y parte orgánica en la Constitución de 1978?:', '["No, su estructura es única, estando dividida en títulos.", "Sí, la parte dogmática agruparía los grandes principios y derechos que inspiran el desarrollo del Estado, mientras que la parte orgánica se referiría a la Organización del Estado.", "Sí, la parte dogmática sería el preámbulo y el resto formaría la parte orgánica.", "Son todas falsas."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿El preámbulo de la Constitución, es una norma de aplicación directa?:', '["Sí, por tratarse de una parte integrante de la norma fundamental", "Sí, porque recoge los principios garantizados mediante la Constitución.", "No, porque su concreción no es posible, dado su carácter genérico y ambiguo.", "No, porque no forma parte de la Constitución."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La soberanía, según la Constitución de 1.978 reside en:', '["La Corona.", "El Gobierno.", "La Nación.", "El pueblo español."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En el Preámbulo, la Soberanía reside en la Nación, mientras que según el Artículo 1º, reside en el pueblo español. ¿Qué es correcto?:', '["Lo dispuesto en el Preámbulo dado su carácter ideológico.", "Lo dispuesto en el Artículo 1º, puesto que el Preámbulo no tiene virtualidad normativa, y no es aplicable.", "Es de aplicación el Artículo 1º, por encontrarse situado con posterioridad, por lo que las normas posteriores derogan a las anteriores.", ""]'::jsonb, 1, 'es'),
    ('e7635585740de7b10b819c221029a513', 'La Constitución está formada por:', '["Un Título Preliminar y 10 Títulos más, así como una Disposición Final.", "Un Preámbulo, un Título Preliminar y 10 Títulos más.", "Un Preámbulo, un Título Preliminar, 10 Títulos, y por 4 Disposiciones Adicionales, 9 Transitorias, 1 Derogatoria y una Final.", "Un Título Preliminar, 10 títulos, 4 Disposiciones Adicionales, 9 Transitorias y una Final."]'::jsonb, 2, 'es'),
    ('2b6edcfa0c4ac251d50667a54353381c', '¿Se puede interponer Recurso de Amparo ante el Tribunal Constitucional con el fin de defender los siguientes Derechos?:', '["Los recogidos en el Título Preliminar.", "Los recogidos en el Capítulo Segundo del Título 1º.", "Los recogidos en el Artículo 14, la Sección 2ª del Capítulo Segundo del Título 1º.", "Los recogidos en el Artículo 14, la Sección 1ª del Capítulo Segundo del Título 1º y el Artículo 3.3."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Que tipo de derechos cuentan con la protección de acudir ante el Tribunal Constitucional mediante la interposición de un recurso de inconstitucionalidad y únicamente pueden ser regulados por ley?:', '["Los recogidos en la Sección segunda del Capítulo Segundo del Título I.", "Los recogidos en la Sección segunda del Capítulo Segundo, del Título I, excepto el derecho a la objeción de conciencia y el derecho a la igualdad ante la Ley.", "Los recogidos en la Sección segunda del Capítulo segundo del Título I, excepto el derecho a la objeción de conciencia.", "Los recogidos en la Sección primera del Capítulo segundo del Título I."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Puede existir discrepancia entre los Derechos recogidos en la Constitución y los establecidos en la Declaración Universal de Derechos Humanos?:', '["Sí, el catálogo de los Derechos recogidos en la Constitución es más amplio.", "No, todas las normas internacionales están supeditadas a la Constitución.", "Sí, porque la Constitución tiene mayor rango normativo.", "No, porque todas las normas que afecten a los derechos y libertades, han de ser interpretados conforme a la Declaración Universal de Derechos Humanos."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Puede un español de origen ser privado de su nacionalidad?:', '["Sí, por adquisición de otra nacionalidad distinta.", "Sí, por matrimonio y residencia con una personal de otro país.", "No, no puede ser privado por los poderes públicos.", "No, salvo que se haya fugado fuera de España."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuántos Artículos tiene la Constitución Española de 1.978?:', '["200.", "185", "100.", "169 y 4 Disposiciones Adicionales, 9 Transitorias y 1 Final."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Que es el Habeas Corpus?:', '["Un procedimiento judicial utilizado en caso de vulneración de un derecho fundamental.", "Un procedimiento judicial dispuesto para los casos de tortura.", "Un procedimiento judicial que impide la vulneración del derecho a la igualdad de todos los españoles.", "Es un procedimiento judicial que impide las detenciones ilegales."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué es el Habeas Corpus?:', '["Un recurso administrativo.", "Un recurso judicial", "Un procedimiento administrativo.", "Un procedimiento judicial."]'::jsonb, 3, 'es'),
    ('f2b1d0058935cd2de44729c198f92a7b', '¿En caso de delito de terrorismo, es posible la entrada policial en un domicilio particular para efectuar un registro, sin consentimiento del dueño?:', '["Sí, porque se trata de un caso de fuerza mayor.", "Sí, siempre y cuando se cuente con autorización judicial previa.", "No, porque ha sido declarada inconstitucional la Ley Orgánica de Seguridad.", "No, porque se estaría vulnerando el Artículo 18, que declara al domicilio inviolable."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La detención preventiva no puede durar más de:', '["72 horas.", "Del tiempo estrictamente necesario para la realización de las averiguaciones de los hechos.", "48 horas.", "Con correctas la a. y la b."]'::jsonb, 3, 'es'),
    ('95286aa824b18e8857c72287aa97cd4c', '¿En qué ocasiones pueden ser alegados ante la Jurisdicción ordinaria los principios reconocidos en el Capítulo 3º del Título I?:', '["Sólo se pueden alegar directamente.", "Sólo se pueden alegar de acuerdo con lo que dispongan las leyes que los desarrollen.", "Sólo se pueden alegar de acuerdo con lo que dispongan las leyes reguladoras del Poder Judicial.", "Sólo se pueden alegar de acuerdo con lo que disponga la Ley Orgánica del Poder Judicial."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Defensor del Pueblo puede interponer:', '["Cuestión de inconstitucionalidad.", "Recurso de amparo y cuestión de inconstitucionalidad.", "Cuestión de inconstitucionalidad y recurso de inconstitucionalidad.", "Recurso de amparo y recurso de inconstitucionalidad."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La creación de Comunidades Autónomas:', '["Es un Derecho de ejercicio obligatorio.", "Es un deber.", "Es un Derecho y un deber al mismo tiempo.", "Es un Derecho que podrá ejercitarse o no, a voluntad de esos entes territoriales a los que se les reconoce."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los Estatutos de Autonomía se aprueban por:', '["Leyes Orgánicas.", "Leyes Ordinarias.", "Leyes Autonómicas.", "Leyes Marco."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El contenido mínimo de los Estatutos de Autonomía:', '["La determinación de las competencias asumidas por la Comunidad", "La denominación de la Comunidad y la delimitación de su territorio.", "La denominación, organización y sede de las instituciones de la Comunidad Autónoma.", "La denominación de la Comunidad, la delimitación de su territorio, la denominación, organización y sede de sus instituciones y las competencias asumidas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Territorialmente España se constituye en:', '["Un Estado Regional.", "Un Estado Centralizado.", "Un Estado Integrado.", "Un Estado Autonómico."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En el Ordenamiento Jurídico Español, la norma de mayor rango jerárquico es:', '["El Tratado de Maastricht.", "La Corona.", "La Constitución.", "El Tratado de adhesión a la Unión Europea."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'España se constituye en un Estado social y democrático de Derecho, lo que supone que:', '["Es únicamente una definición sin valor normativo alguno", "No hay diferencia entre un Estado Social y otro Liberal.", "Supone el reconocimiento de unos fines a los que el Estado ha de atender y el sometimiento a la Ley.", "No existen los Estados Sociales ni Democráticos de Derecho."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Hubiese variado en algo que, en vez de decir que la forma política del Estado español es la Monarquía Parlamentaria, se hubiese dicho la forma de Gobierno?:', '["No, porque el Rey reina pero no gobierna.", "Sí, porque con la redacción actual, el Estado no existiría si no existiese la Monarquía Parlamentaria.", "Sí, porque entonces el Presidente del Gobierno, sería el máximo representante del Estado español.", "Sí porque en realidad el Parlamento al que elige es al Gobierno."]'::jsonb, 1, 'es'),
    ('3a11c2b472c7513e9665bb35b5573066', 'Según el Artículo 15 que garantiza el derecho a la vida y a la integridad física, se afirma que:', '["Todas las personas tienen derecho a la vida.", "Todos los españoles tienen derecho a la vida", "Todos tienen derecho a la vida", "Todos los ciudadanos tienen derecho a la vida."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿La pena de muerte ha sido abolida en España?:', '["Si, en todos los casos.", "Sí, salvo en caso de guerra y por decisión de los Tribunales militares bajo su jurisdicción.", "No, únicamente en tiempo de paz.", "No, porque en el Código Penal aún sigue vigente."]'::jsonb, 0, 'es'),
    ('e7635585740de7b10b819c221029a513', '¿Cuál es el único Título que está a su vez dividido en Capítulos y Secciones?:', '["El Título Preliminar.", "El Título I", "El Título VIII.", "El Título IV."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cabe algún tipo de recurso contra las Sentencias del Tribunal Constitucional?', '["Si, recurso de amparo.", "Si, recurso de revisión.", "No cabe recurso alguno", "Únicamente cabe recurso de apelación."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Está previsto en la Constitución Española de 1.978, la institución del jurado?:', '["No, lo prevé una Ley Orgánica.", "Si, en la forma y respecto a todos los procesos.", "Solo para los procesos penales.", "Ninguna de las anteriores es correcta."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los derechos y libertades reconocidos en el capítulo segundo del título primero de la Constitución, podrán regularse:', '["Necesariamente por la Ley Orgánica.", "Solo por Ley.", "Por Decreto-Ley.", "No podrán regularse."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Presidente del Tribunal Constitucional se nombra por el Rey a propuesta de:', '["El propio Tribunal.", "El Presidente del Gobierno.", "El Gobierno.", "El Consejo General del Poder Judicial."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Dónde reside la soberanía nacional?:', '["En el Rey", "En el Parlamento", "En el Gobierno", "En el Pueblo."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Si un poder público, en su actuación, infringe lo dispuesto en el preámbulo de la Constitución:', '["Incurre en nulidad.", "Incurre en inconstitucionalidad.", "No pasa nada, salvo que, coma consecuencia de esa actuación, se infrinja un artículo de la Constitución.", "Nada de la anterior es cierto."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El principio en virtud del cual el ciudadano esta amparado por una legislación no sujeta a continuos vaivenes es el de:', '["Legalidad.", "Publicidad normativa.", "Seguridad jurídica.", "Jerarquía normativa."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'EI principio en virtud del cual un Reglamento no puede contradecir una Ley es el de:', '["Legalidad.", "Jerarquía normativa.", "A y b son correctas.", "Seguridad jurídica."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Defensor del Pueblo se regula en el siguiente Titulo y Capitulo de la Constitución, respectivamente:', '["Preliminar y 1º.", "Segundo y 4º.", "Segundo y 3º.", "Primero y 4º."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Titulo de la CE que trata del Gobierno y la Administración es el:', '["Tercero.", "Cuarto.", "Quinto.", "Sexto."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los principios rectores de la política social y económica se regulan en el siguiente Capitulo y Titulo de la Constitución:', '["Segundo del Primero.", "Tercero del Primero.", "Tercero del Preliminar.", "Primero del Séptimo."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La derogación de una norma postconstitucional que vaya en contra de la Constitución se efectúa par el/la/las:', '["Propia Constitución.", "Tribunal Constitucional.", "Cortes Generales.", "Gobierno."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Constitución entro en vigor el día:', '["27 de diciembre de 1978.", "29 de diciembre de 1978.", "1 de enero de 1979.", "31 de octubre de 1978."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Entre los valores superiores de nuestro ordenamiento jurídico no se encuentra el de:', '["Justicia.", "Igualdad.", "Libertad.", "Seguridad jurídica."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La interdicción de la arbitrariedad de los poderes públicos significa que:', '["Pueden actuar arbitrariamente.", "Gozan de amplias potestades discrecionales.", "Se les prohíbe taxativamente actuar con arbitrariedad.", "Pueden revisar en vía administrativa sus actos ilegales."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Constitución, el instrumento fundamental para la participación política son los/las:', '["Sindicatos y Asociaciones Empresariales.", "Fuerzas y Cuerpos de Seguridad.", "Cortes Generales.", "Partidos Políticos."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Titulo de la Constitución que trata del Poder Judicial es el:', '["Tercero.", "Quinto.", "Cuarto.", "Sexto."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Por su parte, al Tribunal Constitucional, se dedica el Titulo:', '["Décimo.", "Octavo.", "Noveno.", "Ninguno."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El titular de la soberanía española es el/las:', '["Rey.", "Cortes Generales.", "Gobierno de la Nación.", "Pueblo español."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Constitución, una disposición sancionadora que sea favorable a un delincuente que este cumpliendo condena:', '["No se le aplica retroactivamente.", "Cuando los Tribunales de Justicia la estimen oportuno, se le aplicara retroactivamente.", "Se le aplicara en todo caso.", "Solo se le aplicara si le aumenta la condena."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Constitución, las normas deben:', '["Ser retroactivas.", "Aprobarse solo por las Cortes.", "Publicarse necesariamente.", "Ser arbitrarias."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Garantizar la soberanía e independencia de España, defender su integridad territorial y el ordenamiento constitucional es competencia de los/de las:', '["Cortes Generales.", "Fuerzas Armadas.", "Sindicatos y Asociaciones Empresariales.", "Fuerzas y Cuerpos de Seguridad."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La dignidad de la persona, los derechos inviolables que le son inherentes, el libre desarrollo de la personalidad, el respeto a la Ley y a los derechos de los demás son el fundamento del:', '["Orden jurídico y la paz social.", "Orden político y dicha paz social.", "Orden social y la paz jurídica.", "Orden constitucional y la paz política."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La mayoría de edad en España se produce al:', '["Emanciparse.", "Empadronarse coma cabeza de familia.", "Jurar la Constitución.", "Cumplir los 18 años."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Constitución se ha reformado el:', '["27 de diciembre de 1978.", "27 de agosto de 1992.", "25 de julio de 1992.", "Nunca."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La reforma de la Constitución se ha efectuado para:', '["Conceder el sufragio activo a los extranjeros.", "Conceder el sufragio pasivo a los extranjeros.", "Reconocer todo tipo de sufragio a los españoles.", "Autorizar la firma del Tratado de Maastricht."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Se dice que una Constitución es impuesta cuando:', '["Nace del compromiso entre el poder y las fuerzas políticas y sociales.", "Tiene su origen en la concesión voluntaria del poder político.", "Surge de una decisión adoptada par el pueblo.", "Proviene de una decisión ajena a la voluntad mayoritaria del pueblo."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Una Constitución es pactada si:', '["Nace del compromiso entre el poder y las fuerzas políticas y sociales.", "Tiene su origen en la concesión voluntaria del poder político.", "Surge de una decisión adoptada por el pueblo.", "Proviene de una decisión ajena a la voluntad mayoritaria del pueblo."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Constituciones espontáneas:', '["Nacen del compromiso entre el poder y las fuerzas políticas y sociales.", "Tienen su origen en la concesión voluntaria del poder político.", "Surgen de una decisión adoptada por el pueblo.", "Provienen de una decisión ajena a la voluntad mayoritaria del pueblo."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Que Constitución española se aprobó durante el reinado de Alfonso XII?', '["La de 1931.", "La de 1876.", "La de 1869.", "La de 1845."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Hubo un General, catalán para más señas, que tuvo especial trascendencia en la gestación de la Constitución española de 1869. ¿A quién nos estamos refiriendo?', '["Al General Pavia.", "Al General Mola.", "Al General Prim.", "Al General Martínez Campos."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Tras el fallecimiento de Franco, ¿quién ostentó en primer término la Presidencia del Gobierno de la Nación?', '["Arias Navarro.", "Adolfo Suarez.", "Leopoldo Calvo Sotelo.", "Felipe González."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué nombre recibió la Ley-puente que permitió reformar las Leyes Fundamentales del régimen del general Franco y pasar a una nueva legitimidad respetando dichas Leyes?', '["Ley de Bases de la Constitución de 1978.", "Ley de Reforma Politiza.", "Ley de Referéndum Nacional.", "Ley del Proceso Democrático."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién ostentaba la Presidencia del Gobierno en el momento de aprobarse la Ley puente que permitió reformar las leyes fundamentales del régimen de Franco?', '["Arias Navarro.", "Adolfo Suarez.", "Leopoldo Calvo Sotelo.", "Felipe González."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Ley puente que permitió reformar las leyes fundamentales del régimen de Franco fue ratificada por el pueblo español en referéndum:', '["El 20 de noviembre de 1975.", "B 15 de diciembre de 1976.", "El 20 de febrero de 1977.", "El 20 de diciembre de 1977."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Constitución de 1978 fue ratificada:', '["Por los Presidentes de las Diputaciones Provinciales.", "Por los principales partidos políticos.", "Por las centrales sindicales mayoritarias.", "Por el pueblo español en referéndum."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'De la Ponencia encargada de redactar el borrador de la Constitución de 1978 no formó parte:', '["Manuel Fraga Iribarne.", "Miguel Roca.", "Alfonso Guerra.", "Gregorio Peces Barba."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuando fue aprobada por las Cortes Generales la vigente Constitución española?', '["El 30 de octubre de 1978.", "El 31 de octubre de 1978.", "EI 6 de noviembre de 1978.", "El 27 de diciembre de 1978."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Constitución española de 1978 fue ratificada por el pueblo en referéndum. ¿Sabría recordar en qué fecha?', '["El 30 de octubre de 1978.", "El 31 de octubre de 1978.", "El 6 de diciembre de 1978.", "El 29 de diciembre de 1978."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'EI Rey sanciono la Constitución de 1978 el:', '["31 de octubre de 1978.", "6 de diciembre de 1978", "27 de diciembre de 1978", "29 de diciembre de 1978."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Constitución española entró en vigor:', '["Al día siguiente de la publicación de su texto oficial en el Boletín Oficial del Estado.", "EI mismo día de la publicación de su texto oficial en el Boletín Oficial del Estado.", "El 27 de diciembre de 1978.", "El 1 de enero de 1979."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la materia que tratan, los artículos de la Constitución se agrupan en primer término en:', '["Apartados.", "Secciones.", "Títulos.", "Capítulos."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Algunos Títulos de la Constitución española se dividen en:', '["Apartados.", "Capítulos.", "Secciones.", "Ninguna de las respuestas anteriores es correcta."]'::jsonb, 3, 'es'),
    ('e7635585740de7b10b819c221029a513', 'La vigente Constitución se compone de:', '["Un Preámbulo, un Título Preliminar y diez Títulos más.", "Un Preámbulo, un Título Preliminar y nueve Títulos más.", "Un Preámbulo, un Título Preliminar y once Títulos más.", "Un Preámbulo, un Título Preliminar y ocho Títulos más."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Constitución de 1978 contiene:', '["Una disposición adicional, una transitoria, una derogatoria y una final.", "Nueve disposiciones adicionales, cuatro transitorias, una derogatoria y una final.", "Cuatro disposiciones adicionales, nueve transitorias, dos derogatorias y una final.", "Cuatro disposiciones adicionales, nueve transitorias, una derogatoria y una final."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Constitución española tiene un total de:', '["179 artículos.", "169 artículos.", "188 artículos.", "196 artículos."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Qué Títulos de la Constitución están divididos en Capítulos?', '["Los Títulos I, II, III y X.", "Los Títulos I, III y VIII.", "Todos los Títulos, excepto el Preliminar.", "Todos los Títulos, incluido el Preliminar."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Qué Capitulo o Capítulos de la Constitución están divididos en Secciones?', '["El Capitulo Segundo del Título I, dividido en dos Secciones, y el Capitulo Segundo del Título Ill, que se divide en tres Secciones.", "EI Capitulo Segundo del Título I, dividido en dos Secciones, existiendo en dicho Capitulo un artículo, el 16, no incluido en ninguna de las Secciones.", "EI Capitulo Segundo del Título I, dividido en dos Secciones, existiendo en dicho Capitulo un artículo, el 15, no incluido en ninguna de las Secciones.", "EI Capitulo Segundo del Título I, dividido en dos Secciones, existiendo en dicho Capitulo un artículo, el 14, no incluido en ninguna de las Secciones."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Constitución española no tiene:', '["Un Título dedicado al Poder Judicial.", "Una disposición final.", "Once Titulas.", "Cuatro disposiciones transitorias."]'::jsonb, 3, 'es'),
    ('e7635585740de7b10b819c221029a513', 'El Título Preliminar y el Titulo I de la Constitución española forman básicamente su parte:', '["Dogmática.", "Programática.", "Estatutaria.", "Orgánica."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los Títulos de la Constitución que no forman la parte dogmática forman su parte:', '["Dogmática.", "Programática.", "Estatutaria.", "Orgánica."]'::jsonb, 3, 'es'),
    ('95286aa824b18e8857c72287aa97cd4c', 'En cuántos Capítulos se encuentra dividido el Titulo I de la Constitución?', '["En dos.", "En tres.", "En cuatro.", "En cinco."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Constitución, la soberanía nacional reside en:', '["El Gobierno.", "Las Cortes Generales.", "El Jefe del Estado.", "El pueblo español."]'::jsonb, 2, 'es'),
    ('e7635585740de7b10b819c221029a513', 'En qué Título constitucional se reconocen las diferentes lenguas oficiales españolas?', '["En el Título Preliminar.", "En el Titulo f.", "En el Titulo II.", "En el Titulo III."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Corona es tratada en la Constitución en el Titulo:', '["Preliminar.", "I.", "II.", "III."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'A las Cortes Generales dedica la Constitución su Título:', '["II", "III.", "IV.", "VI."]'::jsonb, 0, 'es'),
    ('2a4ba259076b977b77507b8216bd6b29', 'Donde establece la Constitución la forma del nombramiento del Presidente del Gobierno y de los Ministros, así como su cese y responsabilidades?', '["En su Título III.", "En su Título IV.", "En su Título V.", "En su Título Vl."]'::jsonb, 3, 'es'),
    ('95286aa824b18e8857c72287aa97cd4c', 'El Título I de la Constitución trata:', '["De los derechos y deberes fundamentales.", "De la organización territorial del Estado.", "De la Corona.", "De los Estatutos de Autonomía."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'De las relaciones entre el Gobierno y las Cortes Generales se ocupa la Constitución en su Titulo:', '["Vl.", "VII.", "VIll.", "Ninguna de las respuestas anteriores es correcta."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Título Vl de la Constitución trata:', '["De las relaciones entre el Gobierno y las Cortes Generales.", "De la organización territorial del Estado.", "Del Gobierno y la Administración.", "Del Poder Judicial."]'::jsonb, 3, 'es'),
    ('e947057ff2f42db277860ce0b90afaed', 'En cuanto al número de artículos que contiene, ¿cuál es el Titulo más extenso de la Constitución?', '["EI Titulo l.", "El Titulo II.", "El Titulo X.", "Ninguna de las respuestas anteriores es correcta."]'::jsonb, 0, 'es'),
    ('857475475c8a7246d12ca020018f4668', 'En cuanto al número de artículos que contiene, ¿cuál es el Titulo más breve de la Constitución?', '["El Titulo l.", "EI Titulo ll.", "El Titulo X.", "Ninguna de las respuestas anteriores es correcta."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué denominación recibe el supremo órgano consultivo del Gobierno?', '["Consejo de Estado.", "Consejo del Reino.", "Tribunal Constitucional.", "Defensor del Pueblo."]'::jsonb, 0, 'es'),
    ('4af6a20cba6bd704465dfedc0a363f4c', 'En que Título constitucional se aborda la elaboración de los presupuestos generales del Estado?', '["En el Titulo VIll.", "En el Titulo IX.", "En el Titulo X.", "Ninguna es correcta."]'::jsonb, 3, 'es'),
    ('c480f8e0b6a7a2bf595e0aca8f82ffb9', 'Los criterios básicos de la Administración Local son fijados en la Constitución:', '["En su Título VII.", "En su Título VIII.", "En su Título IX.", "Ninguna de las respuestas anteriores es correcta."]'::jsonb, 1, 'es'),
    ('967c177f0466dc7212becc05a7eab32c', 'Las competencias que pueden asumir las Comunidades Autónomas se contemplan en la Constitución:', '["En el mismo Titulo que regula los principios básicos de Municipios y Provincias.", "En el Titulo VIII.", "En el Titulo que Ileva par rotulo de la organización territorial del Estado.", "Las tres respuestas anteriores son correctas."]'::jsonb, 3, 'es'),
    ('c480f8e0b6a7a2bf595e0aca8f82ffb9', 'Al Tribunal Constitucional dedica la Constitución:', '["Su Titulo VII.", "Su Titulo Vlll.", "Su Titulo IX.", "Un Titulo distinto de los anteriores."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En virtud de la disposición adicional primera de la Constitución, ¿podrán los navarros, si así se contemplara en su antiguo Fuero, participar en las elecciones de Diputados, Senadores, Concejales, Alcaldes o miembros del Parlamento navarro, antes de cumplir los 18 años?', '["Podrán ser electores, pero no elegibles.", "Podrán ser elegibles, pero no electores.", "Podrán ser electores y elegibles.", "No podrán ser electores ni elegibles."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En virtud de la disposición adicional primera de la Constitución, los navarros menores de edad podrán efectuar en el ámbito privado aquellas operaciones o acciones amparadas por su Fuero, aunque no se reconozcan en el Derecho común.', '["Cierto.", "Falso.", "Se exceptúan las transmisiones de bienes inmuebles.", "Se exceptúan las operaciones de préstamo."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La vigente Constitución española no establece entre sus principios básicos:', '["Un Estado social y democrático de Derecho.", "Una monarquía parlamentaria.", "Un sistema parlamentario bicameral.", "Un Estado unitario centralizado."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'A cuál de las Constituciones españolas se le conoce popularmente con el nombre de «La Pepa»?', '["A la de Bayona, de 1808.", "A la de Cádiz, de 1812.", "A la de 1931.", "A la de 1978."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'De las relaciones entre el Gobierno y las Cortes Generales se ocupa la Constitución en su Título:', '["VI", "VII", "VIII", "Ninguna de las respuestas anteriores es correcta."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Como finalidades de las penas privativas de libertad se señalan en la Constitución:', '["La reeducación y reinserción social del penado", "El arrepentimiento y reinserción social del penado", "La formación profesional y el arrepentimiento del penado", "La formación profesional y reeducación del penado."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué órgano es competente para declarar el estado de sitio?', '["Las Cortes Generales, por mayoría absoluta de los miembros de ambas Cámaras", "El Congreso de los Diputados, por mayoría absoluta, a propuesta del Consejo de Estado", "El Congreso de los Diputados, por mayoría absoluta, a propuesta del Gobierno", "El Gobierno, previa autorización del Congreso de los Diputados por mayoría absoluta."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Qué órgano es competente para conocer de la instrucción y enjuiciamiento de las causas contra un Magistrado de un Tribunal Superior de Justicia?:', '["La Sala de lo Civil y Penal de dicho Tribunal", "La Sala de lo Penal de la Audiencia Nacional", "La Sala de lo Penal del Tribunal Supremo", "Una Sala formada por el Presidente del Tribunal Superior de Justicia, los Presidentes de la Sala y el Magistrado más moderno de cada una de ellas."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En la sucesión al trono:', '["Dentro del mismo grado de parentesco se prefiere siempre la persona de más edad a la de menos", "Dentro del mismo grado de parentesco se prefiere el varón a la mujer", "Se prefiere en todos los casos la persona de más edad a la de menos", "Se prefiere en todos los casos el varón a la mujer."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'De no existir persona a quien corresponda la Regencia, ¿qué órgano es competente para nombrarla?:', '["Las Cortes Generales", "El Gobierno", "Las Cortes Generales o el Gobierno", "Las Cortes Generales y el Gobierno."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Comisión Permanente del Consejo General del Poder Judicial está compuesta por:', '["3 vocales y el Presidente del CGPJ", "4 vocales y el Presidente del CGPJ", "5 vocales y el Presidente del CGPJ", "6 vocales."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Para que el pleno del Consejo General del Poder Judicial esté válidamente constituido se precisa que se hallen presentes, como mínimo:', '["La mitad de sus miembros", "Catorce de sus miembros, con asistencia del Presidente o de quien le sustituya legalmente", "Dieciséis de sus miembros, con asistencia del Presidente o quien legalmente le sustituya", "La mitad más uno de sus miembros."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Comisiones Legislativas de las Cortes Generales, ¿pueden aprobar leyes orgánicas?:', '["Sí, en todo caso", "No, en ningún caso", "Solamente pueden hacerlo con autorización expresa de la Mesa de la Cámara", "Solamente pueden hacerlo con autorización expresa de ambas Cámaras, tomada para cada ley por mayoría absoluta."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Vicepresidente del Consejo General del Poder Judicial es elegido:', '["Por mayoría simple", "Por mayoría de 2/3", "Por mayoría de 3/5", "Por mayoría absoluta."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los Reglamentos que dicte el Consejo General del Poder Judicial sobre personal, ¿quién debe aprobarlos?:', '["La Comisión de Calificación", "La Comisión Disciplinaria", "La Comisión Permanente", "El Pleno."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Presidente del Tribunal Supremo y del Consejo General del Poder Judicial tomará posesión de su cargo:', '["Ante los Plenos del Tribunal Supremo y del Consejo General del Poder Judicial, en sesión conjunta", "Ante el Consejo General del Poder Judicial en pleno", "Ante las Cámaras, en sesión conjunta", "Ante el Rey."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Es preciso que los proyectos y proposiciones de ley se aprueben por las dos Cámaras legislativas:', '["Sí, en todo caso", "Si se aprueban en el congreso pero no en el Senado, pueden volver de nuevo al Congreso y quedar aprobados por mayoría simple", "En el caso de veto por parte del Senado, es preciso que el Congreso rectifique el texto inicial", "Ninguna de las respuestas anteriores es correcta."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Cuando las Cortes fijan unas directrices para que el Gobierno las desarrolle mediante legislación delegada, dichas directrices se plasman en una ley:', '["De autorización", "Orgánica", "De Bases", "De delegación."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La prerrogativa real de gracia no puede aplicarse al Presidente y demás miembros del Gobierno:', '["En ningún supuesto", "En ningún caso de responsabilidad criminal", "Solamente no puede aplicarse por delito de traición", "Solamente no puede aplicarse por cualquier delito contra la seguridad del Estado."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En el estado de sitio son susceptibles de suspensión, entre otros, el derecho:', '["A la asistencia de abogado en las diligencias policiales y judiciales", "A adoptar medidas de conflicto colectivo por parte de empresarios y trabajadores", "De negarse a prestar declaración", "Las tres respuestas anteriores son correctas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los Presidentes de los Tribunales Superiores de Justicia, ¿por cuánto tiempo se nombran?:', '["Por tres años", "Por cinco años", "Por ocho años", "Por diez años."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Quién ostenta la suprema representación de la Comunidad Autónoma?:', '["El Presidente de la Comunidad", "El Presidente de la Asamblea Legislativa", "El Delegado del Gobierno en la Comunidad Autónoma", "El Presidente del Tribunal Superior de Justicia."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Qué órgano conoce de los recursos contra las resoluciones de los Juzgados de lo Social en una misma Comunidad Autónoma?:', '["La Audiencia Provincial", "El Tribunal superior de Justicia", "La Audiencia Nacional", "Ninguna de las respuestas anteriores es correcta."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La finalidad de una ley de armonización es la de:', '["Refundir en un solo texto legal las disposiciones normativas de las Comunidades Autónomas", "Dar uniformidad a las disposiciones normativas de las Comunidades Autónomas", "Dotar de flexibilidad a las disposiciones normativas de las Comunidades Autónomas", "Atribuir a las Comunidades Autónomas de la facultad de dictar para sí mismas disposiciones normativas."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El procedimiento de habeas corpus se encuentra regulado por:', '["Ley Orgánica de 24 de mayo de 1984", "Ley de 24 de mayo de 1984", "Ley Orgánica de 1 de julio de 1985", "Ley de 1 de julio de 1985."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las cantidades recibidas por las Comunidades Autónomas del Fondo de Compensación Interterritorial:', '["Pueden destinarse a cualquier clase de gasto", "Deben destinarse a gastos de inversión", "Deben destinarse al sector agrícola", "Deben destinarse a la amortización de deudas."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Por cuántos Diputados están representadas en el Congreso las ciudades de Ceuta y Melilla?:', '["Por un Diputado cada una", "Por un mínimo inicial de un Diputado cada una", "Por dos Diputados cada una", "Por un mínimo inicial de dos Diputados cada una."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué Títulos de la Constitución están divididos en Capítulos?:', '["Los Títulos I, II, III y X", "Los Títulos I, III y VIII", "Todos los Títulos, excepto el Preliminar", "Todos los Títulos, incluido el Preliminar."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Por regla general, las actuaciones judiciales serán:', '["Públicas", "Gratuitas", "Secretas", "Gratuitas y públicas."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los proyectos de ley enviados a las Cortes son presentados por el Gobierno:', '["En la Mesa de las Cortes", "En la Mesa del Congreso", "En la Mesa del Senado", "El texto original en la Mesa del Congreso y una Exposición de Motivos en la Mesa del Senado."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los límites provinciales pueden ser alterados mediante:', '["Real Decreto", "Ley", "Ley Orgánica", "Ley de la Comunidad Autónoma."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Existe en nuestro sistema jurídico algún tipo de control del sometimiento de la Administración a los fines que la justifican?:', '["No, es la propia Administración la que analiza el correcto cumplimiento de sus fines", "Sí, el control de los Tribunales", "Sí, el control parlamentario", "No, eso atentaría contra el principio de separación de poderes."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Constitución, el Gobierno lo componen, además del Presidente:', '["Los Ministros", "Los Vicepresidentes, en su caso, y los Ministros", "Los Vicepresidentes, en su caso, los Ministros y los Secretarios de Estado", "Los Vicepresidentes, en su caso, los Ministros y los demás miembros que establezca la ley."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Audiencia Nacional está integrada por las Salas:', '["De lo civil y penal", "De lo civil, penal y contencioso-administrativo", "De lo penal, social y contencioso-administrativo", "De lo civil, penal, social y contencioso-administrativo."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El ejercicio del derecho a la huelga se encuentra regulado en:', '["El Real Decreto 6/1985, de 3 de septiembre", "La Ley Orgánica 2 de agosto de 1985", "El Real Decreto-Ley 17/1977, de 4 de marzo", "El Real Decreto Legislativo 4/1987, de 6 de abril."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Como máximo, el mismo candidato a presidente del Gobierno puede someterse para su investidura a:', '["Dos votaciones", "Tres votaciones", "Cuatro votaciones", "Ninguna es correcta."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Puede ser reelegido el Presidente del Tribunal Supremo?:', '["No", "Sí, por una sola vez, para un nuevo mandato", "Sí, hasta un máximo de tres", "Sí, siendo el único límite la jubilación del mismo."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los Jueces de Paz nombrados prestarán juramento ante:', '["La Sala de Gobierno del Tribunal Superior de Justicia", "El Juez de Primera Instancia e Instrucción", "El Ministro de Justicia", "El Pleno del Ayuntamiento."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué número de Concejales corresponderán a un Municipio de 380.000 residentes?:', '["27", "29", "31", "33."]'::jsonb, 1, 'es'),
    ('d8328ce402b7f69a855c4d8b91460daa', 'Si el Presidente del Gobierno no supera la cuestión de confianza:', '["Será automáticamente sustituido por el Vicepresidente primero del Gobierno", "Será automáticamente sustituido por la persona que designe el Congreso, por mayoría simple", "El Gobierno presentará su dimisión al Rey, disolviéndose las Cortes y convocándose nuevas elecciones generales", "El Gobierno presentará su dimisión al Rey, procediéndose al proceso de investidura previsto en el art. 99 de la Constitución, sin celebración de elecciones generales."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En qué Municipios hay Comisión de Gobierno?:', '["En todos", "Sólo en los de más de 5.000 habitantes", "Por lo menos, en los de más de 5.000 habitantes", "En los que son capital de Provincia."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Secretario de Estado es un órgano:', '["Con rango de Ministro", "Intermedio entre el Ministro y el Subsecretario", "Con rango de Subsecretario", "Intermedio entre el Subsecretario y el Director General."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Sala especial o innominada del Tribunal Supremo está formada por:', '["El presidente del Tribunal Supremo, los Presidentes de Sala y el Magistrado más antiguo y el más moderno de cada una de ellas", "El Presidente del Tribunal Supremo y un número impar de Magistrados", "El Presidente del Tribunal Supremo y los Presidentes de cada una de las Salas", "El Presidente del Tribunal Supremo, los Presidentes de Salas y un número de Magistrados igual al de éstos."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La responsabilidad política del Gobierno tiene carácter:', '["Solidario", "Indistinto", "Mancomunado", "Subsidiario."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El control de los actos administrativos y de las normas reglamentarias de las Comunidades Autónomas corresponde:', '["A la jurisdicción contencioso-administrativa", "Al Tribunal Constitucional", "Al Gobierno de la Nación", "A los órganos jurisdiccionales propios de las Comunidades Autónomas."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Comisiones Legislativas de las Cortes Generales:', '["Solamente debaten los proyectos y proposiciones de ley, pero su aprobación se somete al Pleno de las Cámaras", "Pueden aprobar todos los proyectos y proposiciones de ley, sin limitación alguna", "Pueden aprobar proyectos y proposiciones de ley, con ciertas limitaciones o prohibiciones establecidas en el Reglamento de cada Cámara pero no en la Constitución", "Pueden aprobar proyectos y proposiciones de ley, con ciertas limitaciones o prohibiciones previstas expresamente en la Constitución."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Cuál de las competencias que a continuación se expresan no es exclusiva del Estado?:', '["La legislación básica sobre montes, aprovechamientos forestales y vías pecuarias", "La promoción del deporte y de la adecuada utilización del ocio", "Dictar las bases del régimen estatutario de los funcionarios de las Comunidades autónomas", "Dictar las normas básicas del régimen de prensa, radio y televisión, en general, de todos los medios de comunicación social."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Señale, de entre los propuestos, el orden cronológico a seguir en la elaboración de las leyes:', '["1) Iniciativa legislativa; 2) Deliberación, discusión y votación; 3) Promulgación; 4) Sanción; 5) Publicación", "1) Iniciativa legislativa; 2) Deliberación, discusión y votación; 3) Promulgación; 4) Publicación; 5) Sanción", "1) Iniciativa legislativa; 2) Deliberación, discusión y votación; 3) Sanción; 4) Publicación; 5) Promulgación", "1) Iniciativa legislativa; 2) Deliberación, discusión y votación; 3) Sanción; 4) Promulgación; 5) Publicación."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El nombramiento del Presidente del Tribunal Supremo se lleva a cabo mediante:', '["Ley", "Real Decreto refrendado por el Presidente del Gobierno", "Real Decreto refrendado por el Ministerio de Justicia", "Orden del Ministerio de Justicia."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Si las Cortes Generales aprueban una ley por la que se condecora a un determinado funcionario público estamos en presencia:', '["De una ley en sentido material, pero no en sentido formal", "De una ley en sentido formal, pero no en sentido material", "De una ley en sentido formal y material", "De un Decreto legislativo."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Sala de lo Civil del Tribunal Supremo conoce:', '["De los recursos de amparo", "De la instrucción y enjuiciamiento de las causas contra Magistrados de la Audiencia Nacional o de un Tribunal Superior de Justicia", "De los recursos de casación, revisión y otros extraordinarios en materia civil que establezca la ley", "De los recursos que establezca la ley contra las resoluciones del Tribunal de Cuentas."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Presentada una moción de censura al Gobierno ¿puede presentarse otras mociones alternativas?:', '["No, por lo menos hasta que se proceda a la votación de aquélla", "Sí, durante los dos días siguientes a la presentación de aquélla", "Sí, durante los cuatro días siguientes a la presentación de aquélla", "Sí, durante los cinco días siguientes a la presentación de aquélla."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En el caso de que un Real Decreto-Ley no llegue a convalidarse en el plazo de que se dispone para ello:', '["El Gobierno está obligado a dictar otro, en el plazo más breve posible", "Las Cortes Generales están obligadas a dictar una ley que lo sustituya, en el plazo más breve posible", "El Decreto-ley perdería toda su vigencia", "Son correctas las respuestas a. y c."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los sindicatos de trabajadores y las asociaciones empresariales deben contribuir a la:', '["Formación de partidos políticos", "Elección de Diputados y Senadores", "Defensa y promoción de los intereses económicos y sociales de sus afiliados", "Son correctas las respuestas a. y c."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Una de las competencias que se citan es exclusiva del Estado:', '["Relaciones internacionales", "Bases del régimen minero y energético", "Régimen aduanero y arancelario", "Las tres respuestas anteriores son correctas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Rey convocará el Congreso de los Diputados:', '["Dentro de los veinticinco días siguientes a al celebración de las elecciones", "Dentro de los veinte días siguientes a la celebración de las elecciones", "Dentro de los quince días siguientes a la celebración de las elecciones", "No es función del Rey convocar el Congreso."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'A efectos judiciales, el Estado se organiza territorialmente en:', '["Partidos", "Partidos y Comarcas", "Municipios, Partidos, Provincias y Comunidades Autónomas", "Municipios, Partidos, Comarcas, Provincias y Comunidades Autónomas."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'A la tecnología empleada en la automatización de oficinas se conoce con el nombre de:', '["Ofimática", "Informática", "Telemática", "Teleinformática."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los órganos administrativos son:', '["Unidades administrativas", "Unidades administrativas integradas por una esfera de competencias", "Unidades administrativas integradas por una esfera de competencias y un conjunto de medios materiales que son ejercitadas y utilizadas, respectivamente, por una o varias personas que se encuentran adscritas a la unidad de que se trate", "Unidades administrativas integradas por una esfera de competencias que son ejercitadas y utilizadas por una o varias personas que se encuentran adscritas a la unidad de que se trate."]'::jsonb, 2, 'es'),
    ('f4d779306e5e370d317e85e71441d704', 'El artículo 60 de la LRJAPPAC establece que los actos administrativos serán objeto de publicación:', '["Cuando así lo establezca la Constitución", "Cuando así lo establezcan las normas reguladoras de cada procedimiento", "Cuando lo aconsejen razones de interés público apreciadas por el órgano competente", "Son correctas las respuestas b. y c."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Son competencias propias de las Diputaciones Provinciales:', '["La asistencia económica y técnica a los Municipios de su territorio", "La prestación de servicios públicos supranacionales", "La prestación en su caso, de servicios públicos supracomarcales", "Las tres respuestas anteriores son correctas."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Pueden ser creados Cuerpos de policía propios por parte de las Comunidades Autónomas?:', '["No, en ningún caso", "Sí, en todo caso", "Sí, pero la forma que se establezca en sus respectivos estatutos y en el marco de lo que disponga una ley ordinaria", "Sí, pero en la forma que se establezca en sus respectivos Estatutos y en el marco de lo que disponga una ley orgánica."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Si una ley de las Cortes Generales legisla sobre materias que son competencia de las Asambleas Legislativas de las Comunidades Autónomas:', '["No ocurre nada", "Tiene superioridad jerárquica la ley de las Cortes Generales", "La ley de las Cortes Generales se declara inconstitucional", "La ley de las Asambleas Legislativas de las Comunidades Autónomas se declara inconstitucional."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Forma parte de la Administración pública las Administraciones de las Comunidades Autónomas?:', '["No, ya que las Comunidades Autónomas no se regulan en la Ley de la Jurisdicción contencioso-administrativa", "Sólo la de las Comunidades con autonomía plena", "No, es una Administración especial", "Sí, a todos los efectos."]'::jsonb, 3, 'es'),
    ('069ea8292d42d243ea511ca9143c9715', 'La legislación autonómica está sujeta a una serie de limitaciones. ¿Cuál de las siguientes es incorrecta?:', '["A la reserva constitucional a favor de las Cortes Generales, solo en materias reservadas a leyes orgánicas", "A sus límites territoriales, salvo en los casos de convenios y acuerdos de cooperación y acuerdos de cooperación con otras Comunidades Autónomas previstos en el artículo 145.2 de la Constitución", "A las relaciones internacionales, por ser materia reservada al Estado y porque los Tratados Internacionales son de superior jerarquía que los propios Estatutos de las Comunidades Autónomas", "Al interés general, según el artículo 150.3 de la Constitución."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Debido a la disposición de sus teclas, los teclados españoles de un ordenador se suelen denominar:', '["QWERTY", "QEWRTY", "QWRETY", "QWRTEY."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'De forma excepcional, ¿dónde puede tener su sede la Delegación del Gobierno en las Comunidades Autónomas?:', '["Sólo en la ciudad más importante de la Comunidad", "Donde la tenga la Asamblea legislativa de la Comunidad", "Donde lo determine el Consejo de Ministros", "Donde lo determine el Consejo de Ministros o lo disponga expresamente el Estatuto de Autonomía de la Comunidad Autónoma respectiva."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las notificaciones defectuosas surtirán efecto a partir de la fecha en que el interesado:', '["Realice actuaciones que supongan el conocimiento del contenido de la resolución", "Interponga el recurso que proceda", "No acuda al emplazamiento", "Son correctas las respuestas a. y b."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En la Comisión de Gobierno de las Diputaciones Provinciales pueden delegar atribuciones:', '["Sólo el Presidente de la Corporación", "Sólo el Pleno", "Sólo el Presidente y el Pleno", "El Presidente, el Pleno y cualquier otro órgano provincial."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Son órganos fundamentales en todos los Ayuntamientos:', '["El Alcalde y el Pleno", "El Alcalde, los Tenientes de Alcalde y el Pleno", "El Alcalde, los Tenientes de Alcalde, el Pleno y la Comisión Permanente", "El Alcalde, los Tenientes de Alcalde, el Pleno y la Comisión de Gobierno."]'::jsonb, 1, 'es');

  -- Batch 2801-3000
  insert into public.question_bank (content_hash, question, options, correct_index, lang)
  values
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién nombra al Fiscal General del Estado?:', '["Las Cortes Generales, a propuesta del Consejo General del Poder Judicial y oído el Gobierno", "El Rey, a propuesta del Gobierno y oído el Consejo General del Poder Judicial", "El Rey, a propuesta de la Junta de Fiscales de Sala y oído el Gobierno", "El Rey, a propuesta del Consejo General del Poder Judicial y oído el Gobierno."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Normalmente, ¿dónde tiene su sede la Delegación del Gobierno en las Comunidades Autónomas?:', '["En la ciudad más importante de la Comunidad", "Donde la tenga la Asamblea legislativa de la Comunidad", "Donde la tenga el Consejo de Gobierno de la Comunidad", "Donde lo determine el Consejo de Ministros."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En qué artículo de la LRJAPPAC se regulan las notificaciones defectuosas?:', '["52", "54", "58", "60."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Está facultado el Alcalde para delegar determinadas competencias en los Tenientes de Alcalde?:', '["Sí, en todo caso", "No, en ningún caso, ya que simplemente sustituyen al Alcalde en casos de ausencia, vacante o enfermedad", "Sólo en los Ayuntamientos donde no exista Comisión de Gobierno", "Sólo en los Ayuntamientos donde no existan Concejales Delegados."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En qué artículo de la Constitución se determinan las materias reservadas a leyes orgánicas?:', '["81", "83", "91", "94."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los Vocales del Consejo General del Poder Judicial que no procedan de la carrera judicial:', '["Deben pertenecer a Cuerpos de la Administración de Justicia, distintos de los de Jueces y Magistrados, con una antigüedad de más de quince años", "Deben pertenecer a Cuerpos de la Administración de Justicia, distintos de los Jueces y Magistrados, tener una antigüedad de más de quince años y hallarse en servicio activo", "Deben ser abogados o juristas de reconocida competencia, con más de quince años en el ejercicio de su profesión", "Deben ser abogados o juristas con más de quince años en el ejercicio de su profesión."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En todo caso, quedarán sin escaño en el Congreso aquellas candidaturas que no obtengan en las elecciones, al menos:', '["Un 3 por 100 de los votos válidos emitidos en la circunscripción", "Un 3 por 100 del censo electoral de la circunscripción", "Un 3 por 100 de los votos emitidos en la circunscripción", "Un 5 por 100 de los votos emitidos en la circunscripción."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué órgano municipal tiene atribuida la aprobación de Ordenanzas?:', '["El Alcalde", "El Pleno", "El Alcalde o el Pleno, según sea la clase de Ordenanza de que se trate", "La Comisión de Gobierno."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Puede ostentarse el cargo de Rey siendo menor de edad?:', '["Sí", "Sí, pero para ello se precisa la expresa autorización de las Cortes Generales", "No, porque el Rey será en todo caso el Regente", "No, porque el Rey será en todo caso su tutor."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los Secretarios Generales tienen rango de:', '["Subsecretario", "Director General", "Secretario de Estado", "Secretario General Técnico."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los Secretarios Generales son nombrados por:', '["El Rey, a propuesta del Presidente del Gobierno", "El Presidente del Gobierno, a propuesta del Ministro respectivo", "El Gobierno, a propuesta del Ministro correspondiente", "El Ministro correspondiente."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cómo son nombrados los Subsecretarios?:', '["Por el Rey, a propuesta del Presidente del Gobierno", "Por el Presidente del Gobierno, a propuesta del Ministro respectivo", "Por el Gobierno, a propuesta del Ministro correspondiente", "Por el Ministro correspondiente."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según el artículo primero de la Constitución, España se constituye en:', '["Un Estado parlamentario.", "Un Estado democrático y parlamentario.", "Un Estado social y democrático de derecho.", "Un Estado social y parlamentario de derecho."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Cuál de los siguientes no se destaca como un valor superior del ordenamiento jurídico nacional en el artículo primero de la Constitución:', '["La libertad.", "La igualdad.", "La monarquía.", "La justicia."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Constitución, las normas relativas a los derechos fundamentales se interpretarán de conformidad con:', '["La Declaración Universal de Derechos Humanos.", "El principio de igualdad.", "Lo establecido por los tribunales ordinarios de justicia.", "Lo establecido por las Leyes."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes derechos de las personas ha de ser violado por la Administración para que se pueda interponer el derecho de amparo constitucional?', '["El derecho a contraer matrimonio libremente.", "El derecho a la protección de la salud.", "El derecho a la huelga.", "El derecho a la Seguridad Social."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué órgano resuelve el derecho de amparo constitucional?', '["El Tribunal Constitucional en todos los casos.", "Los tribunales de justicia ordinarios en un proceso sumario.", "Según se trate o no de un derecho fundamental, el primero o el segundo.", "El Defensor del Pueblo."]'::jsonb, 0, 'es'),
    ('693f71bb3d5175bdba8c71e67b094cbb', 'Los derechos fundamentales de los ciudadanos son:', '["Son todos los mencionados en el Título I de la Constitución.", "Son todos los mencionados en el Capítulo I del Título I de la CE.", "Son todos los mencionados en el Capítulo II del Título I de la CE.", "Ninguna de las anteriores respuestas es correcta."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El derecho a la educación puede ser regulado por:', '["Ley Orgánica.", "Decreto Ley.", "Decreto Legislativo.", "Ley Ordinaria."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Gobierno no puede aprobar:', '["Decretos Legislativos.", "Decretos Leyes.", "Reglamentos.", "Leyes Orgánicas."]'::jsonb, 3, 'es'),
    ('2a4ba259076b977b77507b8216bd6b29', 'El mantenimiento de un régimen público de Seguridad Social es:', '["Un derecho fundamental de los ciudadanos.", "Un principio rector de la política social y económica.", "Un derecho que puede reclamarse mediante el recurso de amparo.", "Un derecho recogido en el Título III de la CE."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La regulación del derecho a la Seguridad Social puede hacerse mediante:', '["Ley Orgánica.", "Decreto Ley.", "Decreto Legislativo.", "Reglamento."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Al Rey no le corresponde entre sus funciones:', '["Aprobar las Leyes.", "Expedir los Decretos acordados en Consejo de Ministros.", "Nombrar al Presidente del Gobierno.", "Nombrar a los Ministros."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Para ser nombrado Regente, en cualquier caso, es necesario:', '["Ser español y mayor de edad.", "Ser español de nacimiento y mayor de edad.", "Ser mayor de edad y pertenecer a alguna línea de descendencia de la Corona.", "Ser miembro de las Cortes Generales."]'::jsonb, 0, 'es'),
    ('971eab75c602ebdbf689854ede4f018a', 'El artículo 2 de la CE reconoce el derecho a la autonomía de:', '["Las regiones que integran la nación.", "Las nacionalidades que integran la nación.", "Las nacionalidades y regiones que integran la nación.", "Ninguna es correcta."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El castellano es la lengua oficial del Estado, pero las demás lenguas españolas, ¿pueden tener carácter oficial en su respective autonomía?', '["Sí, si la región tiene Estatuto de Autonomía.", "Sí, si lo autoriza el Estado.", "Sí, si así se recoge en su respectivo Estatuto de Autonomía.", "No, en ningún caso."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Todos los poderes públicos están sujetos a la Constitución, así se prevé en el propio texto constitucional en su artículo:', '["1", "2", "3", "9."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los miembros del Tribunal Constitucional son elegidos:', '["Por los miembros de las Cortes Generales.", "De entre los miembros de las Cortes Generales y por ellos mismos.", "De entre los miembros de las Cortes Generales pero por el Gobierno.", "De entre los miembros de las Cortes Generales por el Defensor del Pueblo."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Defensor del Pueblo es elegido:', '["Por los miembros de las Cortes Generales.", "De entre los miembros de las Cortes Generales y por ellos mismos.", "De entre los miembros de las Cortes Generales pero por el Gobierno.", "De entre los miembros de las Cortes Generales por el Rey."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Puede el Rey presidir el Consejo de Ministros?', '["Sí, a petición propia.", "Sí, a petición del Presidente del Gobierno.", "Sí, en la primera reunión de cada legislatura.", "No, en ningún caso."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Leyes que se aprueban en las Cortes son sancionadas por:', '["El Presidente del Gobierno.", "El Rey.", "El Presidente del Congreso de los Diputados.", "El Presidente del Tribunal Constitucional."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Cortes no pueden tramitar una proposición de ley por iniciativa:', '["Popular.", "Del Presidente del Gobierno.", "Del Congreso de los Diputados.", "De un Parlamento Autonómico."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La disolución de las Cámaras legislativas puede solicitarla:', '["El Rey", "El Presidente del Gobierno.", "El Presidente de cada Cámara.", "Nadie, las Cámaras tan sólo se disuelven automáticamente cuando transcurren cuatro años desde que se constituyen tras las elecciones."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Gobierno del Poder Judicial corresponde a:', '["El Consejo General del Poder Judicial.", "El Tribunal Supremo.", "El Tribunal Constitucional.", "El Ministerio de Justicia."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los miembros del Tribunal Constitucional son nombrados:', '["Por el Rey.", "Por el Presidente del Tribunal Supremo.", "Por el Presidente del Gobierno.", "Por el Ministro de Justicia."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La reforma de la Constitución no puede iniciarse por:', '["Iniciativa popular.", "Iniciativa del Gobierno.", "Iniciativa del Congreso de los Diputados.", "Iniciativa del Parlamento de una Comunidad Autónoma."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Reforma de la Constitución necesita referéndum para su aprobación:', '["En todo caso.", "Nunca.", "Sí, pero únicamente en el caso de que lo solicite una parte de los miembros de las Cámaras.", "Ninguna es totalmente correcta."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La entrada en vigor de la Constitución es del año:', '["1980.", "1978.", "1975.", "1977."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'No corresponde al Rey, según la Constitución Española:', '["Nombrar y separar a los Ministros.", "Autorizar indultos generales.", "Convocar elecciones generales.", "Disolver las Cortes."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La reforma no esencial de la Constitución necesita para su aprobación:', '["El voto favorable de tres quintas partes de cada Cámara.", "El voto favorable de dos terceras partes.", "El voto favorable de tres cuartas partes.", "El voto favorable de la mayoría absoluta de cada Cámara."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Esta mayoría (la de la reforma no esencial de la CE) podría sustituirse por:', '["Mayoría absoluta del Senado y 3/5 del Congreso.", "Mayoría absoluta del Congreso y de 2/3 del Senado.", "Mayoría absoluta del Senado y de 2/3 del Congreso.", "Mayoría absoluta de ambas Cámaras."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La reforma de la Constitución no puede iniciarse:', '["Durante el estado de alarma.", "Durante el estado de excepción.", "Durante el estado de excepción ni el de sitio.", "En ninguno de los tres casos."]'::jsonb, 3, 'es'),
    ('81b4196a9a98f87bf76f9a564d328a4d', 'Cuál es el sistema de Gobierno en España que establece el artículo 1 de la Constitución:', '["El Estado Social y Democrático de Derecho.", "La Democracia Parlamentaria.", "La Monarquía Parlamentaria.", "El Bicameral."]'::jsonb, 2, 'es'),
    ('971eab75c602ebdbf689854ede4f018a', 'El artículo 2 de la constitución reconoce el derecho a la autonomía de:', '["Las nacionalidades y regiones que integran la Nación.", "Las nacionalidades que ya aprobaron históricamente su Estatuto de Autonomía.", "Las regiones con tradición autonómica.", "Las regiones que autorice el Estado."]'::jsonb, 0, 'es'),
    ('e7635585740de7b10b819c221029a513', 'En el título preliminar de la Constitución se establecen una serie de principios del ordenamiento jurídico de la Nación, cuál de los que se citan a continuación no está entre ellos:', '["Jerarquía de las normas.", "Eficacia.", "Irretroactividad de las disposiciones sancionadoras no favorables.", "Seguridad jurídica."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Corresponde al Rey, según la Constitución:', '["Sancionar y aprobar las Leyes.", "Sancionar y aprobar las Leyes aprobadas en las Cortes.", "Convocar y disolver las Cortes Generales.", "Aprobar los Decretos expedidos en Consejo de Ministros."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Estatuto de los Trabajadores, como norma básica que regula el derecho al trabajo, debe aprobarse:', '["Mediante ley ordinaria, exclusivamente.", "Mediante ley ordinaria o Decreto Legislativo.", "Mediante ley ordinaria, Decreto Legislativo o Decreto Ley.", "Mediante Ley orgánica."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los derechos recogidos entre los principios rectores de la política social y económica deben regularse mediante:', '["Mediante ley ordinaria, exclusivamente.", "Mediante ley ordinaria o Decreto Legislativo.", "Mediante ley ordinaria, Decreto Legislativo o Decreto Ley.", "Mediante Ley orgánica."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El derecho a la objeción de conciencia debe regularse mediante:', '["Mediante ley ordinaria, exclusivamente.", "Mediante ley ordinaria o Decreto Legislativo.", "Mediante ley ordinaria, Decreto Legislativo o Decreto Ley.", "Mediante Ley orgánica."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Puede iniciarse la tramitación de una Ley orgánica por iniciativa popular?', '["Sí, si se trata de regular materia reservada a dicho tipo de Ley.", "No, salvo autorización del Congreso.", "No, salvo autorización de las Cortes Generales.", "No, en ningún caso."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los Decretos Leyes deben ser convalidados:', '["En un plazo de treinta días, por las Cortes Generales.", "En un plazo de un mes, por el Congreso de los Diputados.", "En un plazo de treinta días, por el Congreso de los Diputados.", "En un plazo de diez días, por el Rey."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Qué derechos pueden ser suspendidos durante el estado de alarma:', '["Ninguno.", "La libertad de reunión y de libre circulación de las personas.", "Los mismos que el el estado de excepción.", "Los derechos de huelga y de manifestación."]'::jsonb, 0, 'es'),
    ('e7635585740de7b10b819c221029a513', 'En el Título preliminar de la Constitución se propugnan unos valores superiores del ordenamiento jurídico, entre los que no se encuentra:', '["El pluralismo político.", "La libertad.", "La justicia.", "La fraternidad."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La sanción del Rey a las leyes es refrendada por:', '["El Presidente del Congreso, salvo que se trate de refrendar un Decreto Legislativo o Decreto Ley, en cuyo caso es refrendada por el Presidente del Gobierno.", "El Presidente del Congreso en todo caso.", "El Presidente del Gobierno en todo caso.", "El Presidente de las Cortes Generales."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El heredero al trono perdería sus derechos como tal:', '["Si contrajera matrimonio contra la expresa prohibición de sus padres.", "Si contrajera matrimonio contra la expresa prohibición de las Cortes Generales.", "Si contrajera matrimonio contra la expresa prohibición del Rey y de las Cortes.", "Si contrajera matrimonio con persona sin dinastía real."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Si el heredero al trono pierde sus derechos, los derechos de sucesión pasarían a:', '["La persona que fuera sucesor de dicho heredero.", "La persona que siguiera en el orden de sucesión de dicho heredero.", "La persona que designen las Cortes Generales.", "La persona que designe el Rey."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Príncipe heredero de la Corona, en caso de inhabilitación del Rey para el ejercicio de su autoridad:', '["No puede ejercer la Regencia.", "Puede ejercer la Regencia si es designado para ello por el Rey.", "Puede ejercer la Regencia si es mayor de edad.", "Puede ejercer la Regencia en cualquier momento."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Si no hubiera ninguna persona a quien corresponda la Regencia, ésta será nombrada por:', '["El Rey.", "El Presidente del Gobierno.", "El Congreso de los Diputados.", "Las Cortes Generales."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El estado de sitio debe ser declarado:', '["Por el Rey, a propuesta del Gobierno.", "Por el Rey, a propuesta de la mayoría absoluta del Congreso.", "Por la mayoría absoluta del Congreso.", "Por las Cortes Generales."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los referéndums consultivos sobre decisiones políticas de especial transcendencia son convocados por:', '["El Rey.", "El Presidente del Gobierno.", "El Presidente del Congreso de los Diputados.", "Ninguno de ellos."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los Decretos Legislativos son:', '["Normas con rango de reglamento que se aprueban en las Cortes.", "Normas con rango de reglamento que aprueba el Gobierno.", "Normas con rango de ley que aprueban las Cortes.", "Normas con rango de ley que aprueba el Gobierno."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La duración del estado de excepción no puede exceder de:', '["Un mes.", "Treinta días, prorrogables por otros treinta.", "Quince días.", "El tiempo que autorice el Congreso."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La potestad reglamentaria corresponde a:', '["El Congreso.", "Las Cortes.", "El Gobierno.", "La Administración."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Rey sanciono la Constitución de 1978 el:', '["31 de octubre de 1978.", "6 de diciembre de 1978", "27 de diciembre de 1978", "29 de diciembre de 1978."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La participación es:', '["Un principio democrático.", "Un principio constitucional.", "Una obligación.", "Un principio de igualdad."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cómo responde el Gobierno en su gestión política ante el Congreso de los Diputados?', '["De forma global", "Shogun imperativo legal", "De acuerdo con sus normas de actuación políticas", "Solidariamente."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿A través de quien, pueden recabar información las Cámaras y sus Comisiones?', '["A través de los Senadores y Diputados", "A través del Presidente del Congreso", "A través de los Presidentes", "Todas los respuestas son falsas."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué articulo establece la facultad de los miembros del Gobierno de hacerse oir en las Cámaras?', '["El 108", "El 111", "El 110- 1", "El 110-2."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Pueden reclamar las Cámaras la presencia de los miembros del Gobierno ''?', '["Si", "Si, si la autoriza el Presidente", "Sólo si lo aprueba par mayoría", "Sólo si quiere el Gobierno."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Dónde se establecen los tiempos semanales para las interpelaciones y preguntas a los miembros del Gobierno, por parte de las Cámaras?', '["En el Diario de sesiones", "En la Ley", "En los Reglamentos", "En el Congreso y Senado respectivamente."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué articulo dice que toda interpelación podrá dar lugar a una moción en la que la Cámara manifieste su posición?', '["El 111.2", "El 111.1", "El 111.3", "El 111.4."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Necesita autorización el Presidente por parte de sus Ministros para presentar la cuestión de confianza?', '["Si, es preceptivo", "No", "Debe haber deliberación previa del Consejo de Ministros", "Si, de la mayoría de los Ministros."]'::jsonb, 2, 'es'),
    ('f8f1b0ed50680a576518f7eaa08671b8', 'De acuerdo con el art. 112 de la Constitución, la cuestión de confianza se entenderá otorgada cuando vote a favor de la misma:', '["La mayoría simple de los Diputados", "La mayoría de 3/5", "La mayoría absoluta", "La décima parte de los Diputados."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La moción de censura deberá ser propuesta al menos por:', '["La mayoría simple de los Diputados", "Las 3/4 partes de los Diputados", "Las 2/3 partes de los Diputados", "Décima parte de los Diputados."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La moción de censura no podrá ser votada hasta que transcurran:', '["3 días desde su presentación", "6 días desde su presentación", "5 días desde su presentación", "48 horas desde su presentación."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién está capacitado para negar la confianza al Gobierno?', '["El congreso", "El Rey", "Las Cortes Generales", "El Pueblo Español."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Hay que incluir candidato en la moción de censura?', '["No, lo deciden las Cortes", "Sólo en algún caso", "Sí", "Todas las respuestas son falsas."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién puede decretar la disolución de las Cortes Generales?', '["El Rey", "El Presidente del Gobierno", "El Gobierno en Pleno", "El Presidente de las Cortes."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Dónde se fijará la fecha de las elecciones una vez disueltas las Cámaras?', '["En el diario de sesiones", "En el B.O.E.", "En el decreto de disolución", "Todas les respuestas son correctas."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Se podrá presentar la propuesta de disolución cuando esté en tramite una moción de censura?', '["Sí, no tienen nada que ver una con otra", "Sí, pero se paralizará la moción de censura", "Sólo si la aprueba el Consejo de Estado", "No."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'No procederá nueva disolución antes que transcurra un año desde el anterior, salvo lo dispuesto en el Art.:', '["99.4", "99.6", "99.3", "99.5."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Por medio de que Ley se regularán los estados de alarma, excepción y sitio?', '["Orgánica", "Ordinaria", "Especial", "Decreto-Ley."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es el plazo máximo del Estado de Alarma?', '["15 días", "10 días", "1 año", "5 meses."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quien determinará el ámbito territorial del Estado de Alarma?', '["El Gobierno el propio decreto", "El Rey", "El Congreso", "El Presidente del Gobierno."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién deberá autorizar al Gobierno para declarar el Estado de Excepción?', '["EI Rey", "El Senado", "El Congreso de los Diputados", "El pueblo español."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuántos días se podrá prorrogar el Estado de excepción?', '["12 días", "31 días", "2 meses", "30 días."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién puede proponer exclusivamente el Estado de sitio?', '["El Gobierno", "El Rey", "El Congreso", "El Senado."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Si el Congreso, está disuelto, ¿Quién pude declarar el Estado de sitio?', '["El Rey", "EI Presidente del Gobierno", "La Diputación Permanente del Congreso", "Nadie."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuáles son los Estados no habituales o excepcionales?', '["Alarma", "Sitio", "Excepción", "Todas las respuestas son correctas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿La declaración de los estados de alarma, excepción y sitio, modifica la responsabilidad del Gobierno?', '["No", "Si", "En algunas cosas", "Todas las respuestas son falsas."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El derecho a la libertad de cátedra:', '["Está contemplado en la Ley de Reforma Universitaria de 1983, pero no en la Constitución Española.", "Es un postulado doctrinal sin respaldo normativo.", "Está expresamente reconocido y protegido en la Constitución Española.", "Su ejercicio puede, excepcionalmente, ser objeto de censura previa."]'::jsonb, 2, 'es'),
    ('2a6468bc4f93d82dcd681e03abfdd7d4', 'La declaración contenida en el Art. 11.2) de la Constitución Española de que ningún español de origen podrá ser privado de su nacionalidad:', '["Es una simple declaración programática, pero susceptible de limitaciones mediante Ley Orgánica.", "Tiene carácter absoluto, sin limitaciones.", "No está siquiera contenida en la Constitución.", "No está contenida en la Constitución pero ha sido objeto de reconocimiento jurisprudencial."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Constitución Española, la sanción y promulgación de las leyes corresponde:', '["Al Parlamento.", "Al Presidente del Congreso de los Diputados", "Al Presidente del Senado", "Al Rey"]'::jsonb, 3, 'es'),
    ('425d57b101ca23eb5a6fbd2f9eb19dab', 'De acuerdo con el Art. 68 de la Constitución Española, el Congreso se compone de:', '["Un mínimo de 350 y un máximo de 400 Diputados", "Un mínimo de 300 y un máximo de 400 Diputados", "Un mínimo de 250 y un máximo de 350 Diputados", "378 Diputados."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Constitución Española, además de los senadores que corresponden a cada provincia o circunscripción, las Comunidades Autónomas designarán:', '["Un Senador y otro más por cada millón de habitantes de su territorio.", "Un solo Senador, independientemente de los habitantes de su territorio.", "Dos Senadores, independientemente de los habitantes de su territorio.", "Cuatro Senadores cada una de ellas."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Constitución Española, la moción de censura deberá ser propuesta al menos por:', '["La quinta parte de los Diputados.", "La décima parte de los Diputados.", "La mayoría simple de los Diputados.", "La cuarta parte de los Diputados."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Constitución Española, el Presidente del Tribunal Supremo será nombrado:', '["Por el Consejo General del Poder Judicial.", "Por el Rey a propuesta del Consejo General del Poder Judicial.", "Por acuerdo de los Presidentes de Sala del Tribunal Supremo.", "Por el Rey, previo informe del Tribunal Constitucional"]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Constitución Española, la responsabilidad criminal del Presidente y de los demás miembros del Gobierno será exigible, en su caso:', '["Ante la Audiencia Nacional.", "Ante el Tribunal Constitucional.", "Ante el Consejo General del poder Judicial.", "Ante la Sala de lo Penal del Tribunal Supremo."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Constitución Española, la federación de Comunidades Autónomas:', '["Requiere la aprobación en referéndum de las Comunidades Autónomas afectadas.", "Corresponde al Congreso de los Diputados mediante Ley Orgánica.", "Corresponde al Congreso de los Diputados mediante Ley Ordinaria.", "Está expresamente prohibida."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Constitución Española, la detención preventiva tiene una duración máxima de:', '["48 horas.", "24 horas.", "72 horas.", "No tiene límite temporal."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Constitución Española, ¿a quién corresponde declarar la guerra y hacer la paz?', '["Al Rey, previa autorización de las Cortes Generales.", "Al Presidente del Gobierno.", "A las Cortes Generales, previa autorización del Rey.", "Al Tribunal Constitucional."]'::jsonb, 0, 'es'),
    ('425d57b101ca23eb5a6fbd2f9eb19dab', 'Según el artículo 68.2 de la Constitución Española, la representación de las provincias de Ceuta y Melilla en el Congreso es de:', '["Un Diputado.", "Tres Diputados.", "Cinco Diputados.", "Dos Diputados."]'::jsonb, 0, 'es'),
    ('5ad7c64f39fd1a1442e43a426a7b76dc', 'El artículo 26 de la Constitución Española prohíbe los Tribunales de Honor en:', '["El ámbito de la Administración Civil exclusivamente.", "El ámbito de la Administración Civil y de las Organizaciones Profesionales.", "El ámbito de la Administración Militar.", "NO existe tal prohibición en la Constitución."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Constitución Española, la cuestión de inconstitucionalidad puede ser planteada por:', '["Cualquier órgano judicial.", "El Defensor del Pueblo.", "Toda persona natural o jurídica que invoque un interés legítimo.", "Las Asambleas legislativas de las Comunidades Autónomas."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Constitución Española, los Alcaldes son elegidos:', '["Siempre por los vecinos en elecciones periódicas.", "Por los Concejales en todo caso.", "En unos casos por los vecinos y en otros por los concejales.", "Por los Diputados Provinciales."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Constitución Española, el Derecho a la Libertad y a la Seguridad deberá ser desarrollado por una:', '["Ley ordinaria.", "Ley de bases.", "Real Decreto.", "Ley orgánica."]'::jsonb, 3, 'es'),
    ('69cc02d6fa341204e8baa32de1fad3f6', 'Según el artículo 87.1 de la Constitución Española, ¿a quién corresponde la iniciativa legislativa?', '["Sólo al Congreso.", "A las Cortes Generales en exclusiva.", "Al Gobierno, al Congreso y al Senado.", "Al Poder Judicial."]'::jsonb, 2, 'es'),
    ('20a5bba8654dc19329d4d323187575a8', 'El artículo 27 de la Constitución Española NO contempla:', '["Que los poderes públicos garantizan el derecho que asiste a los padres para que sus hijos reciban la formación religiosa y moral que esté de acuerdo con sus propias convicciones.", "El derecho a la educación.", "Que la enseñanza básica es obligatoria y gratuita.", "El derecho a la protección de la salud."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Una de las siguientes funciones NO está comprendida en el ámbito de la Autonomía de las Universidades:', '["La aprobación de sus Estatutos y demás normas de funcionamiento interno.", "La elección, designación y remoción de sus órganos de gobierno.", "El establecimiento y modificación de sus plantillas.", "La expedición de sus Títulos y Diplomas."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El sometimiento de la Administración a la ley y al derecho es una consecuencia del:', '["Principio de coordinación", "Principio de legalidad", "Principio de proporcionalidad", "Principio de eficacia."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La descentralización funcional se realiza a través de:', '["Los entes locales", "Los entes territoriales", "Los entes institucionales", "Los entes internacionales."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Desconcentración es:', '["La alteración de las atribuciones entre órganos administrativos sin personalidad jurídica propia, incluidos dentro de una misma Administración Pública", "La transferencia de competencias de la Administración del Estado a las Comunidades Autónomas.", "La transferencia de competencias de la Administración del Estado a los entes locales.", "La alteración de las atribuciones entre órganos administrativos con personalidad jurídica propia, incluidos en distintas Administraciones Públicas."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Según la Constitución Española, los Estatutos de Autonomía se aprueban mediante:', '["Ley ordinaria.", "Ley básica.", "Ley orgánica.", "Ley autonómica."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Señalen la afirmación correcta:', '["La potestad reglamentaria es una competencia exclusiva del Gobierno de la nación.", "Un decreto tiene un rango jerárquico superior a una orden ministerial.", "Son leyes ordinarias las relativas al desarrollo de los derechos fundamentales y de las libertades públicas.", "El Congreso de los Diputados podrá delegar en el Gobierno la potestad de dictar normas con rango de ley sobre cualquier materia."]'::jsonb, 1, 'es'),
    ('28c562f4839afaef4b7d5af7d5a0b3d8', 'Según el artículo 103 de la C.E. los órganos de la Administración del Estado:', '["Son creados, regidos y coordinados por los poderes públicos.", "Son creados, regidos y coordinados por la Constitución.", "Son creados, regidos y coordinados de acuerdo con la ley.", "Son creados, regidos y coordinados por el Gobierno."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de estas disposiciones tiene mayor rango en la jerarquía normativa?', '["Decreto Legislativo.", "Ley Orgánica.", "Orden Ministerial.", "Real Decreto."]'::jsonb, 1, 'es'),
    ('18063efe1bcece549c4579598468f9fb', 'Según el artículo 106 de la Constitución Española: ¿Quién controla la potestad reglamentaria y la legalidad de la actuación administrativa?', '["El Tribunal de La Haya.", "El Consejo General del Poder Judicial.", "El Congreso de los Diputados.", "Los Tribunales."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Una disposición legislativa provisional dictada por el Gobierno en caso de extraordinaria y urgente necesidad es:', '["Un decreto legislativo.", "Una ley marco.", "Un decreto-ley.", "Una ley de transferencia."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué tienen en común los Decretos Legislativos y los Decretos Leyes?', '["Ambas normas emanan del poder legislativo.", "Ambas tienen rango de Ley Orgánica.", "Tienen el mismo valor que las Leyes Ordinarias y ambas emanan del ejecutivo.", "No tienen nada en común."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los Diputados son elegidos por:', '["Sufragio universal, indirecto y secreto.", "El Rey, a propuesta del Presidente del Congreso.", "Sufragio universal, libre, igual, directo y secreto.", "Los miembros del Senado."]'::jsonb, 3, 'es'),
    ('87715a4750c94339b4ba74aa163ff884', 'La Constitución garantiza la libertad ideológica, religiosa y de culto en:', '["Artículo 25.", "Artículo 16.", "Artículo 17.", "Artículo 18."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '"Toda persona tiene derecho a la libertad y a la seguridad". Lo recoge la Constitución y es un:', '["Principio político.", "Derecho excepcional.", "Derecho social.", "Derecho fundamental."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Presidente del Tribunal Supremo es nombrado por:', '["El Presidente del Gobierno.", "El Presidente del Senado.", "El Rey.", "El propio Pleno del Tribunal."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La jurisdicción de los Juzgados de lo Penal se ejerce en la demarcación territorial de:', '["La Provincia.", "El Partido Judicial.", "El Municipio.", "El Estado."]'::jsonb, 0, 'es'),
    ('913657972c03f72eda057943f8f031d5', 'El derecho de participación de los ciudadanos en los asuntos públicos se regula dentro de la Constitución en:', '["Artículo 23.", "Artículo 21.", "Artículo 22.", "Artículo 24."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Presidente del Tribunal Supremo es, a su vez:', '["Presidente del Tribunal Constitucional.", "Presidente de la Audiencia Nacional.", "Presidente del Tribunal Superior de Justicia de Madrid.", "Presidente del Consejo General del Poder Judicial."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El mando supremo de las Fuerzas Armadas lo ostenta:', '["El Presidente del Gobierno.", "El Ministro de Defensa.", "El Rey.", "El Capitán General de los Ejércitos."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Señale cuál de las siguientes afirmaciones es cierta:', '["La justicia emana de los jueces y magistrados, integrantes del Poder Judicial.", "La justicia emana del pueblo y se administra por el Rey.", "La justicia se administra por el Rey en nombre del pueblo.", "La justicia emana del pueblo y se administra en nombre del Rey por jueces y magistrados."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El estado de excepción:', '["Es declarado por el Gobierno, previa autorización del Congreso de los Diputados.", "Es declarado por el Congreso de los Diputados, previa autorización del Gobierno.", "Es declarado por el Gobierno, mediante decreto acordado en Consejo de Ministros, dando cuenta al Congreso de los Diputados.", "Es declarado por la mayoría absoluta del Congreso de los Diputados, a propuesta exclusiva del Gobierno."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La aprobación de los Presupuestos Generales del Estado corresponde:', '["Al Gobierno.", "A las Cortes Generales.", "Al Senado.", "Al Congreso de los Diputados."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Los Estatutos de Autonomía se aprueban:', '["Por ley ordinaria.", "Por ley orgánica.", "Por reglamento.", "Por aquella ley que el propio Estatuto indique."]'::jsonb, 1, 'es'),
    ('20bc0ea92eb63d34c503f6f420e6d3c6', 'El poder judicial se regula en la Constitución:', '["En el Título VI.", "En el Título VII.", "En el Título VIII.", "En el Título IX."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Sala Tercera del Tribunal Supremo es:', '["De lo civil.", "De lo penal.", "De lo social.", "De lo contencioso-administrativo."]'::jsonb, 3, 'es'),
    ('88f687385bed79ed556d261e5b494cb7', 'Las Comunidades Autónomas podrán asumir competencias de la lista expuesta en la Constitución en:', '["Artículo 149.", "Artículo 148.", "Artículo 152.", "Artículo 147."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Por qué procedimiento deberá elegirse a los representantes que participen en asuntos políticos?', '["Por votación.", "Por elección directa.", "Por elección libre.", "Por concurso."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién propone el candidato a presidente de Gobierno a través del Congreso de los Diputados?', '["S.M. el Rey.", "El Senado.", "El Consejo de Ministros.", "El Presidente del Congreso."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Pueden las Comunidades Autónomas utilizar las banderas y reseñas junto a la bandera de España en los actos oficiales?', '["No.", "Sí.", "Cuando lo permita el Gobierno.", "Cuando lo permitan las Cortes."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué ejercen los ciudadanos mediante la acción del jurado?', '["La justicia social.", "La defensa ciudadana.", "Los intereses sociales.", "La acción popular."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién protege el libre ejercicio de los Derechos y Deberes Fundamentales?', '["El Gobierno.", "El Tribunal Constitucional.", "Las Fuerzas y Cuerpos de Seguridad del Estado.", "El Consejo General del Poder Judicial."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Comunidades Autónomas podrán adoptar acuerdos de cooperación, previa autorización de...', '["Las Cortes Generales.", "El Gobierno.", "El Tribunal Supremo.", "EL Tribunal Constitucional."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'De los tres Poderes del Estado, ¿cuál ejerce el Gobierno?', '["El legislativo.", "El ejecutivo.", "El judicial.", "Todos los anteriores."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Las Comunidades Autónomas podrán adoptar acuerdos de cooperación, previa autorización de…', '["Las Cortes Generales.", "El Gobierno.", "El Tribunal Supremo.", "EL Tribunal Constitucional."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién podrá autorizar al Gobierno para comprometerse sobre tratados o convenios de carácter militar?', '["S.M. el Rey.", "Las Cortes Generales.", "El Tribunal Supremo.", "El Fiscal General del Estado."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué órgano elige al Defensor del Pueblo?', '["El Gobierno.", "Las Cortes Generales.", "El Tribunal Constitucional.", "El Fiscal General del Estado."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién sancionó la Constitución española?', '["El Gobierno.", "EL Senado.", "Las Cortes Generales.", "S.M. el Rey."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Ante qué órgano podrá impugnar el Gobierno las resoluciones y disposiciones adoptadas por las Comunidades Autónomas?', '["Congreso.", "Cortes Generales.", "Tribunal Supremo.", "Tribunal Constitucional."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué nombre reciben los hijos de los reyes?', '["Príncipes.", "Infantes.", "Descendientes.", "Sucesores."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿A quién representan los diputados?', '["A la provincia.", "Al municipio.", "A la región.", "A la nación."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué órgano puede exigir la responsabilidad política al Gobierno a través de una “moción de censura”?', '["El Senado.", "El Congreso.", "Las Cortes Generales.", "El Consejo General del Poder Judicial."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'El Rey sanciona en plazo de 15 días las leyes aprobadas por…', '["El Gobierno.", "El Senado.", "El Congreso.", "Las Cortes Generales."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Todos debemos contribuir al sostenimiento de los gastos públicos, de acuerdo con nuestra:', '["Capacidad económica.", "Obligación política.", "Conciencia social.", "Capacidad intelectual."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿De qué Cámara se exige la mayoría absoluta para la aprobación, modificación o derogación de las leyes orgánicas?', '["Del Congreso.", "Del Senado.", "De las Cortes Generales.", "De al Cámara de los Lores."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuántas salas tiene el Tribunal Constitucional?', '["Tres.", "Cuatro.", "Seis.", "Dos."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿A qué está subordinada la riqueza del País?', '["A las necesidades del Gobierno.", "A la defensa nacional.", "A la investigación y desarrollo.", "Al interés general."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En caso de objeción de conciencia, ¿qué podrá imponer la ley?', '["Una multa.", "Una condena.", "Una prestación social.", "Una prestación económica."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué religión tiene en España carácter estatal?', '["La católica.", "La protestante.", "La evangélica.", "Ninguna."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'No es necesaria autorización previa para reunirse o manifestarse cuando sea…', '["Pacífica.", "Sin armas.", "Autorizada.", "La “a” y la “b”."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cómo es la Constitución Española?', '["Flexible.", "Rígida.", "Semirígida.", "Cambiable."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué estado podrá declarar el Gobierno cuando se produzcan catástrofes, epidemias, etc.?', '["Alarma.", "Excepción.", "Sitio.", "Cualesquiera de las anteriores."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quiénes podrán gozar del derecho de asilo en España?', '["Los apátridas.", "Los inmigrantes.", "Los extranjeros.", "La “a” y la “c”."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿A qué órgano corresponde garantizar la seguridad ciudadana?', '["Al Gobernador Civil.", "Al Ministerio del Interior.", "Al Gobierno.", "A las Fuerzas y Cuerpos de Seguridad del Estado."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué título tiene el Jefe del Estado español?', '["El presidente del gobierno.", "El primer ministro.", "El Rey de España.", "El de presidente del Tribunal Constitucional."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Constitución se fundamenta en la indisoluble unidad de:', '["La Nación española.", "Las Comunidades Autónomas.", "Las lenguas del Estado.", "La sociedad española."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es la norma jurídica suprema del Estado español?', '["La Constitución.", "Las Leyes Orgánicas.", "Los Decretos-Leyes.", "Los Decretos-Legislativos."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué tipo de ley regula los Estatutos de una Comunidad Autónoma?', '["Una Ley de Bases.", "Un Decreto-Ley.", "Un Decreto Legislativo.", "Una Ley Orgánica."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'De los tres Poderes del Estado, ¿cuál ejercen los jueces y magistrados?', '["El legislativo.", "El judicial.", "El ejecutivo.", "Todos los anteriores."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿A qué días de su promulgación entran en vigor los Decretos – Ley?', '["20 días.", "45 días.", "30 días.", "15 días."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién propone el candidato a Presidente de Gobierno a través del Congreso de los Diputados?', '["S.M. el Rey.", "El Senado.", "El Consejo de Ministros.", "El Presidente del Congreso."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de las siguientes leyes no elabora las Cortes Generales?', '["Leyes Orgánicas.", "Leyes Ordinarias.", "Leyes de Bases.", "Decretos de Ley."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué debe hacer el Gobierno si dimite su Presidente?', '["Abdicar.", "Renunciar.", "Cesar.", "Convocar elecciones."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién dispone de 15 días para sancionar las leyes aprobadas por las Cortes?', '["El Congreso.", "El Rey.", "El Presidente del Gobierno.", "El Presidente del Senado."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién es el Jefe del Estado español?', '["El Rey.", "El Presidente del Gobierno.", "El Presidente de las Cortes.", "El Fiscal General del Estado."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué persona tiene facultad para juzgar y sentenciar?', '["El procurador.", "El abonado.", "El fiscal.", "El juez."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'De los tres Poderes del Estado, ¿qué órgano ejerce el Poder Legislativo?', '["El Gobierno.", "Los jueces.", "Las Cortes Generales.", "Los Fiscales."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Pueden votar los españoles que se encuentren fuera del Territorio Nacional?', '["Sí.", "No.", "En determinadas circunstancias.", "Cuando no vuelvan a España."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿A qué Cámara se someten los "proyectos de ley" aprobados en Consejo de Ministros?', '["Al Senado.", "Al Congreso.", "A la Cámara Alta.", "A la Cámara de los Comunes."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es el número máximo de diputados admitidos por la Constitución?', '["300.", "350.", "400.", "600."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué tribunal controla las actividades presupuestarias de las Comunidades Autónomas?', '["El Tribunal Supremo.", "El Tribunal Constitucional.", "El Tribunal de Cuentas.", "Hacienda."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Por qué se dice que las Cortes Generales son un órgano bicameral?', '["Por tener dos presidentes.", "Por tener diputados y senadores.", "Por estar integradas por dos Cámaras.", "Por tener dos estrados."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿A qué órgano corresponde la iniciativa legislativa?', '["Al Congreso.", "Al Senado.", "Al Gobierno.", "A todos los anteriores."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Ante qué Cámara debe responder el Gobierno de su gestión política?', '["Congreso.", "Senado.", "Cortes Generales.", "Cámara de los Comunes."]'::jsonb, 0, 'es'),
    ('3a11c2b472c7513e9665bb35b5573066', '¿Cuál es la mayoría que debe alcanzarse en las Cortes para proceder a la reforma del artículo 15 de la Constitución?', '["3/5.", "2/3.", "Mayoría absoluta.", "2/5."]'::jsonb, 1, 'es'),
    ('1cf384e30cb1ca80449f88fc14235b2a', '¿En qué artículo de la Constitución se recogen los fundamentos del orden político?', '["En el artículo 9.3.", "En el artículo 1.1.", "En el artículo 10.", "En el artículo 11."]'::jsonb, 2, 'es'),
    ('a4081b50999b05cd6634630ecd0c54b6', 'Según lo dispuesto en el artículo 53 de la Constitución, relativo a las garantías de las libertades y derechos fundamentales, el derecho a sindicarse libremente:', '["Es un derecho que informará la legislación positiva, la práctica judicial y la actuación de los poderes públicos.", "Se podrá tutela ante los Tribunales ordinarios por un procedimiento basado en los principios de preferencia y sumariedad.", "Al encontrarse dentro de la Sección 2ª del Capítulo II del Título Primero de la Constitución, sólo puede resolverse ante el Tribunal Constitucional mediante el recurso de amparo.", "El citado artículo no establece nada al respecto."]'::jsonb, 1, 'es'),
    ('5a557b60b74583595d7566115ef77cc4', '¿Qué sector social aparece especialmente protegido en el artículo 48 de la Constitución?', '["La familia.", "Los consumidores.", "La juventud.", "Los ancianos."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'En el ordenamiento jurídico español el tratamiento automatizado de datos personales está regulado por:', '["Ley Orgánica 1/1982, de 5 de mayo, de protección civil del derecho al honor, a la intimidad personal y familiar y a la propia imagen.", "Convenio del Consejo de Europa, de 28 de enero de 1981, para la protección de las personas con respecto al tratamiento automatizado de datos de carácter personal.", "Ley Orgánica 15/1999, de 13 de diciembre, de Protección de Datos de Carácter personal.", "Ley Orgánica 5/1992, de 9 de octubre, de regulación del tratamiento automatizado de los datos de carácter personal."]'::jsonb, 2, 'es'),
    ('b8911eea94f4c829211669faec5cb38c', 'La seguridad jurídica está garantizada en nuestra Constitución de una forma expresa:', '["En el Preámbulo.", "En el Título Preliminar.", "En la Sección Primera del Capítulo II del Título I.", "En el Título IV."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La celebración de reuniones en lugares de tránsito público y de manifestaciones deberán ser comunicadas por escrito a la autoridad gubernativa correspondiente:', '["Con una antelación de 48 horas.", "Con una antelación mínima de 10 días naturales.", "Con una antelación mínima de 5 días naturales.", "No es necesaria tal comunicación."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Para poder establecerse prestaciones patrimoniales de carácter público:', '["Las mismas deberán hacerse con arreglo a la ley.", "Deberá dictarse una ley orgánica adecuada a cada caso concreto.", "La Constitución sólo reconoce las prestaciones personales, por lo que no podrán establecerse prestaciones patrimoniales.", "Las mismas responderán a criterios de oportunidad y deberán regularse mediante ley orgánica."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'La Junta de Defensa Nacional será presidida por:', '["El Ministro de Defensa en todo caso.", "El Jefe del Estado Mayor del Ejército de Tierra.", "El Ministro de Defensa, cuando no asista a la misma el Presidente del Gobierno.", "El Presidente del Gobierno, cuando no asista a la misma su Majestad el Rey."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'De acuerdo con nuestra Constitución, la responsabilidad criminal del Presidente y de los demás miembros del Gobierno, en el ejercicio de sus funciones:', '["Será exigible ante la Sala de lo Penal de la Audiencia Nacional.", "En el caso de acusación por cualquier delito contra la seguridad del Estado, sólo podrá plantearse por iniciativa de la mayoría absoluta de los miembros del Congreso.", "En el caso de acusación por cualquier delito contra la seguridad del Estado, aquélla deberá aprobarse por la mayoría absoluta del Congreso.", "En el caso de delitos contra la Seguridad del Estado, podrá tener lugar la prerrogativa real de gracia."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién sanciona los estatutos de autonomía?', '["El Jefe del Estado.", "Las Cortes Generales.", "El Congreso de los Diputados.", "El Senado."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de las siguientes competencias no es exclusiva del Estado?', '["Las bases del régimen minero.", "Las bases del régimen energético.", "La legislación sobre propiedad industrial.", "La sanidad y la higiene."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué artículo de la ley de régimen jurídico y del procedimiento administrativo común establece los actos que deben ser motivados?', '["El 54.", "El 53.", "El 52.", "El 51."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Ante quién jura su cargo el Príncipe Heredero?', '["Ante el Rey.", "Ante las Cortes Generales.", "Ante el Senado.", "Ante el Gobierno."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué tipo de actos puede convalidar la Administración?', '["Los actos nulos.", "Los actos firmes.", "Los actos definitivos.", "Los actos anulables."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuántos Títulos tiene la ley de régimen jurídico de las administraciones Públicas y del procedimiento administrativo común?', '["Nueve.", "Ocho.", "Diez.", "Doce."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', 'Si el procedimiento se inicia a instancia de parte ¿quién lo inicia?', '["El interesado.", "El órgano instructor.", "El órgano superior al órgano instructor.", "El órgano inferior al órgano instructor."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cómo se denomina el sistema de gestión de servicios públicos en el que la Administración y un empresario participan en los resultados de la explotación en la proporción que establezcan en el contrato?', '["Gestión interesada.", "Sociedad de economía mixta.", "Arrendamiento.", "Concesión."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cómo se adquiere la condición de vecino?', '["Con la inscripción en el Padrón.", "Residencia permanente en un municipio.", "Nacimiento en el término municipal.", "Con la permanencia continuada, aunque no se trate de residencia habitual."]'::jsonb, 0, 'es');

