  values
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué tipo de personalidad tiene la provincia?', '["Propia.", "Plena.", "Ilimitada.", "Pública."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué tipo de personalidad tiene el municipio?', '["Propia.", "Plena.", "Ilimitada.", "Pública."]'::jsonb, 1, 'es'),
