    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué complemento retribuye las especiales condiciones de trabajo?', '["El complemento de destino.", "El complemento específico.", "El complemento de productividad.", "Las gratificaciones."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es la edad máxima para que el hijo huérfano de un funcionario de la Administración local perciba la pensión de orfandad?', '["21 años.", "22 años.", "23 años.", "24 años."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes es un soporte de acceso secuencial?', '["Las cintas perforadas.", "Los discos rígidos.", "Los discos ópticos.", "Los diskettes."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes es un soporte de acceso directo?', '["Los discos rígidos.", "Las tarjetas perforadas.", "Las cintas perforadas.", "Las citas magnéticas."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién aprueba la oferta de empleo público en un Ayuntamiento?', '["El Alcalde.", "El Pleno.", "La Comisión de Gobierno.", "El Pleno y el Alcalde."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuántas disposiciones derogatorias tiene la Constitución?', '["Una.", "Dos.", "Tres.", "Nueve."]'::jsonb, 0, 'es'),
    ('f401ed7a839a2ad0e99c3819bd59c8ca', '¿Cuál es el primer artículo del Título II de la Constitución?', '["El artículo 52.", "El artículo 53.", "El artículo 54", "El artículo 56."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuántos periodos de sesiones celebran las Cámaras?', '["Dos.", "Uno.", "Tres.", "Cinco."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de las siguientes figuras forma parte del Gobierno?', '["Los Ministros.", "Los Secretarios de Estado.", "Los Directores Generales.", "Los Secretarios Generales."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuántos Diputados como mínimo pueden presentar una moción de censura?', '["Mayoría simple.", "Mayoría absoluta.", "1/10 parte del número total.", "2/3 del número total."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es el número máximo de Diputados que pueden formar el Congreso?', '["250.", "300.", "350.", "400."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es el número mínimo de Diputados que pueden formar el Congreso?', '["250.", "300.", "350.", "400."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Quién nombra al personal eventual del Ayuntamiento?', '["El Pleno.", "El Alcalde.", "La Comisión de Gobierno.", "El Teniente de Alcalde delegado."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuándo puede seguirse el procedimiento negociado en un Ayuntamiento para contratar un servicio?', '["Cuando no supere el 10 % de los recursos ordinarios del presupuesto.", "Cuando no supere el 5% de los recursos ordinarios del presupuesto.", "Cuando no supere el 15% de los recursos ordinarios del presupuesto.", "Cuando no supere el 20% de los recursos ordinarios del presupuesto."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuándo puede seguirse el procedimiento negociado en un Ayuntamiento para contratar una obra?', '["Cuando no supere el 10 % de los recursos ordinarios del presupuesto.", "Cuando no supere el 5% de los recursos ordinarios del presupuesto.", "Cuando no supere el 15% de los recursos ordinarios del presupuesto.", "Cuando no supere el 20% de los recursos ordinarios del presupuesto."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuándo puede seguirse el procedimiento negociado en un Ayuntamiento para contratar un suministro?', '["Cuando no supere el 10 % de los recursos ordinarios del presupuesto.", "Cuando no supere el 5% de los recursos ordinarios del presupuesto.", "Cuando no supere el 15% de los recursos ordinarios del presupuesto.", "Cuando no supere el 20% de los recursos ordinarios del presupuesto."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cómo se denomina a la información que suministra un ciudadano para confeccionar el censo?', '["Horizontal.", "Descendente.", "Directa.", "Ascendente."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de las siguientes no es una competencia asignada a los Municipios?', '["Protección del medio ambiente.", "Prestación de servicios sociales.", "Prestación de servicios de reinserción social.", "Ordenación del tráfico en vías urbanas e interurbanas."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿A qué hora se celebra la sesión constitutiva de una Diputación?', '["A las 12.", "A las 10.", "A las 11.", "A las 9."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿A qué hora se celebra la sesión constitutiva de un Ayuntamiento?', '["A las 12.", "A las 10.", "A las 11.", "A las 9."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué Tratamiento ostenta el Alcalde de Badajoz?', '["Excelentísimo.", "Ilustrísimo.", "Señoría.", "Ilustrísimo."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuántos concejales se eligen en un municipio que cuente con 25.000 habitantes?', '["21.", "17.", "19.", "23."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es la regla general del régimen de adopción de los acuerdos del Pleno?', '["Mayoría absoluta.", "Mayoría simple.", "Mayoría de 2/3.", "Mayoría de 1/3."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cómo se denominan las votaciones en las que la voluntad de los miembros se manifiesta por signos convencionales?', '["Nominales.", "Ordinarias.", "Secretas.", "Unánimes."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuántos concejales se eligen en un municipio que cuente con 2.000 habitantes?', '["5.", "7.", "9.", "12."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuántos concejales se eligen en un municipio que cuente con 99.000 habitantes?', '["23.", "27.", "25.", "29."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál de los siguientes medios se utiliza para el cobro de deudas líquidas?', '["El apremio sobre el patrimonio.", "La multa coercitiva.", "La compulsión sobre las personas.", "La ejecución subsidiaria."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es el plazo para resolver un recurso de alzada?', '["Un mes.", "Dos meses.", "Tres meses.", "Seis meses."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es el plazo para presentar un recurso extraordinario de revisión?', '["Un mes o tres meses.", "Dos meses o cuatro años.", "Tres meses o cuatro años.", "Seis meses o dos años."]'::jsonb, 2, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué tipo de recurso se puede interponer contra el acuerdo de acumulación de expedientes?', '["Recurso de alzada.", "Recurso extraordinario de revisión.", "Recurso potestativo de reposición.", "No cabe ningún tipo de recurso."]'::jsonb, 3, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En qué casos está obligado un ciudadano a facilitar información a los Administración?', '["En los casos establecidos en la ley.", "En todos los casos.", "En los casos establecidos por vía reglamentaria.", "Exclusivamente en los casos señalados en la Constitución."]'::jsonb, 0, 'es'),
    ('4ed946112b9521dd4550bc43abd6b4f4', '¿Qué artículo de la ley de régimen jurídico de las Administraciones Públicas y del procedimiento administrativo común establece quienes tienen capacidad de obrar?', '["El artículo 29.", "El artículo 30.", "El artículo 31.", "El artículo 33."]'::jsonb, 1, 'es'),
    ('e947057ff2f42db277860ce0b90afaed', '¿Qué Título de la Constitución regula la Corona?', '["El Título II.", "El Título I.", "El Título III.", "El Título IV."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cómo se denomina el acto en el que se manifiesta la voluntad de la Administración generalmente por escrito?', '["Expreso.", "Presunto.", "Firme.", "Definitivo."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Qué órgano gobierna la Administración local provincial en las Islas Baleares?', '["Los Cabildos Insulares.", "Los Consejos Insulares.", "Las Diputaciones Provinciales.", "La Comunidad Autónoma porque es uniprovincial."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿En qué Diputaciones existe Comisión de Gobierno?', '["En todas las Diputaciones.", "En las Diputaciones de las provincias que superen el millón de habitantes.", "En aquellas en las que lo establezca el Pleno.", "En aquellas en las que lo establezca la Comisión de Gobierno."]'::jsonb, 0, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuál es el número máximo de Vicepresidentes de la Diputación?', '["Cinco.", "Un tercio del número de miembros de la Comisión de Gobierno.", "La mitad más uno del número de miembros de la Comisión de Gobierno.", "La mitad de miembros de la Comisión de Gobierno."]'::jsonb, 1, 'es'),
    ('4b830eab8fe6b21a82865850ecac45f6', '¿Cuándo es llamado el Príncipe Heredero a la regencia?', '["Cuando el Rey se inhabilite.", "Cuando cumpla la mayoría de edad.", "Cuando el Rey se ausente de España.", "Cuando el Rey abdique."]'::jsonb, 0, 'es'),
    ('1cf384e30cb1ca80449f88fc14235b2a', '¿Cuál de los siguientes principios no se recoge en el artículo 9.3 de la Constitución?', '["Seguridad jurídica.", "Jerarquía normativa.", "Legalidad.", "Retroactividad."]'::jsonb, 3, 'es'),
